int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);

        long long ans = 0;

        // Use as many 5s as possible
        ans += diff / 5;
        diff %= 5;

        // Handle remaining diff (0, 1, 2, 3, 4)
        if (diff == 0) {
            // No remaining diff, 0 additional presses
        } else if (diff == 1) {
            // Can be 1 (+1 or -1)
            // Can be 2 (-2, then +1) or (5, then -2, -2)
            // Can be 3 (5, then -2)
            // Optimal for 1 is 1 press (+1 or -1)
            ans += 1;
        } else if (diff == 2) {
            // Optimal for 2 is 1 press (+2 or -2)
            ans += 1;
        } else if (diff == 3) {
            // Optimal for 3 is 2 presses (+5, then -2) or (+1, +1, +1)
            // The greedy choice of using 5s first might leave 3.
            // If we have 3 remaining, we can do (+5, -2) which is 2 presses.
            // Or we can do (+1, +1, +1) which is 3 presses.
            // So 2 presses is optimal.
            ans += 2;
        } else if (diff == 4) {
            // Optimal for 4 is 2 presses (+2, +2) or (+5, -1)
            ans += 2;
        }

        std::cout << ans << "\n";
    }
    return 0;
}

