int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int haybales_in_pile1 = a[0];

        for (int i = 1; i < n; ++i) {
            int pile_idx = i + 1; // 1-indexed pile number
            int cost_per_haybale = i; // days to move from pile_idx to pile 1

            if (d == 0) {
                break; // No more days left
            }

            if (cost_per_haybale <= d) {
                // Calculate how many haybales can be moved from this pile
                int num_haybales_to_move = std::min(a[i], d / cost_per_haybale);

                haybales_in_pile1 += num_haybales_to_move;
                d -= num_haybales_to_move * cost_per_haybale;
            }
        }
        std::cout << haybales_in_pile1 << std::endl;
    }
    return 0;
}

