void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only numbers up to 2048 are useful for forming 2048
            counts[s_val]++;
        }
    }

    // Simulate the merging process
    // Iterate through powers of two from smallest to largest
    // 1, 2, 4, 8, ..., 1024
    for (int p = 1; p < 2048; p *= 2) {
        if (counts[p] >= 2) {
            counts[p * 2] += counts[p] / 2;
        }
    }

    if (counts[2048] > 0) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

