#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    long long current_sum = 0;
    long long cost = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        // If current_sum becomes negative, it means we have a deficit
        // that must have been "paid for" by moving value from a later index
        // to an earlier index. This costs coins.
        // The amount of deficit is -current_sum.
        // This deficit must be covered by some future positive values.
        // To cover it, we effectively move value from some j > i to some k <= i.
        // The most efficient way to cover a deficit at index i (meaning current_sum < 0)
        // is to imagine that the required value came from some j > i.
        // This means we performed operations (j, k) where j > k.
        // If k <= i, then this operation (j, k) costs 1 coin.
        // The total deficit accumulated up to this point (current_sum < 0)
        // must be covered by such costly operations.
        // The number of coins is the absolute value of the deficit.
        if (current_sum < 0) {
            cost += -current_sum;
            current_sum = 0; // Reset current_sum to 0, as this deficit has been "paid for"
                             // and effectively moved to the left of the current point.
        }
    }
    std::cout << cost << std::endl;
}

