#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position.
        // The presence of 1 or -1 doesn't matter for equality, only for change.

        // Update has_pos_one and has_neg_one for subsequent elements
        // This is crucial: a[i] itself can be used to modify a[j] for j > i.
        // So, if a[i] was 1 or -1, it contributes to the available modifiers.
        // The values in 'a' array are fixed for the purpose of determining
        // if a 1 or -1 is available at an index less than the current index.
        // The problem states "Add a_i to a_j", where a_i is the current value.
        // However, since we process from left to right, and a_i can only be
        // affected by a_k where k < i, the original values of a_k (k < i)
        // are what determine if a 1 or -1 is available *before* a_i is modified.
        // The logic here is that if we need to change b[i], we need a 1 or -1
        // from an index < i. The original a[k] values for k < i determine this.
        // So, has_pos_one and has_neg_one should track if there was an original 1 or -1
        // at any index < current_i.
        // The initial scan for has_pos_one and has_neg_one covers this.
        // The loop should just check against the *initial* availability of 1s and -1s
        // up to index i-1.
        // The current implementation of has_pos_one and has_neg_one is correct
        // because it tracks if *any* element a[k] with k < i was 1 or -1.
        // This is because a[k] (k < i) can only be changed by a[p] (p < k).
        // So, if an original a[k] was 1, it can be used as 1. If it was -1, it can be used as -1.
        // If it was 0, it can be used as 0.
        // The crucial part is that if we need to increase a[i], we need a 1 from some a[k] (k < i).
        // If we need to decrease a[i], we need a -1 from some a[k] (k < i).
        // The `has_pos_one` and `has_neg_one` flags correctly track if such an `a[k]` (k < i) exists.
        // The flags are updated *after* checking a[i] vs b[i], so they reflect availability for a[i+1].
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

