            // d - sqrt(d^2 - 4d):
            // We need to check if d >= sqrt(d^2 - 4d).
            // Squaring both sides (both are non-negative for d >= 4):
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So both a and b will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
