#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_req: minimum value a[i] must be to satisfy a[0] < a[1] < ... < a[i]
    // If a[i] is to be part of an increasing sequence starting from 0,
    // a[i] must be at least i.
    // More precisely, a[i] must be at least a[i-1]+1.
    // If we assume a[0] can be 0, then a[i] must be at least i.
    // We can always decrease a[i] to i if a[i] >= i.
    // So, we need to check if a[i] >= i for all i in the increasing part.
    // Let's define `left_possible[i]` as true if `a[0], ..., a[i]` can be made strictly increasing
    // such that `a[j]` is at least `j`.
    std::vector<bool> left_possible(n);
    left_possible[0] = (a[0] >= 0); // a[0] can be 0

    for (int i = 1; i < n; ++i) {
        if (left_possible[i-1] && a[i] >= i) {
            left_possible[i] = true;
        } else {
            left_possible[i] = false;
        }
    }

    // Calculate suffix_min_req: minimum value a[i] must be to satisfy a[i] > a[i+1] > ... > a[n-1]
    // If a[i] is to be part of a decreasing sequence ending at 0,
    // a[i] must be at least (n-1-i).
    // We can always decrease a[i] to (n-1-i) if a[i] >= (n-1-i).
    // So, we need to check if a[i] >= (n-1-i) for all i in the decreasing part.
    // Let's define `right_possible[i]` as true if `a[i], ..., a[n-1]` can be made strictly decreasing
    // such that `a[j]` is at least `n-1-j`.
    std::vector<bool> right_possible(n);
    right_possible[n-1] = (a[n-1] >= 0); // a[n-1] can be 0

    for (int i = n - 2; i >= 0; --i) {
        if (right_possible[i+1] && a[i] >= (n - 1 - i)) {
            right_possible[i] = true;
        } else {
            right_possible[i] = false;
        }
    }

    // A sharpened array requires a peak at index k (0-indexed).
    // For this k, the prefix a[0]...a[k] must be strictly increasing,
    // and the suffix a[k]...a[n-1] must be strictly decreasing.
    // The conditions we derived (a[i] >= i for left part, a[i] >= n-1-i for right part)
    // ensure that we can form sequences like 0, 1, ..., k and k, k-1, ..., 0.
    // If a[i] >= i for i <= k, we can make a[0]...a[k] into 0, 1, ..., k.
    // If a[i] >= n-1-i for i >= k, we can make a[k]...a[n-1] into (n-1-k), (n-1-(k+1)), ..., 0.
    // The peak element a[k] must satisfy both conditions.
    // So, we need to find if there exists an index k such that:
    // 1. left_possible[k] is true (meaning a[0]...a[k] can be 0, 1, ..., k)
    // 2. right_possible[k] is true (meaning a[k]...a[n-1] can be k-(k-(n-1)), ..., 0, which is k, k-1, ..., 0 if we consider the values relative to k)
    // More precisely, for a peak at index k, we need:
    // a[0] >= 0, a[1] >= 1, ..., a[k] >= k
    // AND
    // a[k] >= n-1-k, a[k+1] >= n-1-(k+1), ..., a[n-1] >= 0
    //
    // The `left_possible[i]` array checks if `a[j] >= j` for all `j <= i`.
    // The `right_possible[i]` array checks if `a[j] >= (n-1-j)` for all `j >= i`.
    //
    // If both `left_possible[k]` and `right_possible[k]` are true, it means:
    // For the left part: we can make `a'_0 = 0, a'_1 = 1, ..., a'_k = k`.
    // For the right part: we can make `a'_k = (n-1-k), a'_{k+1} = (n-1-(k+1)), ..., a'_{n-1} = 0`.
    //
    // The peak element `a_k` must be strictly greater than `a_{k-1}` and `a_{k+1}`.
    // If we choose `a'_k = k` (from the left part requirement) and `a'_k = (n-1-k)` (from the right part requirement),
    // we need to ensure that `a'_k` is large enough to satisfy both.
    // The actual value of `a'_k` would be `max(k, n-1-k)`.
    // But we can choose any value for `a'_k` as long as `a'_k <= a_k` and `a'_k > a'_{k-1}` and `a'_k > a'_{k+1}`.
    //
    // The conditions `a[i] >= i` for `i <= k` and `a[i] >= (n-1-i)` for `i >= k` are sufficient.
    // If these hold, we can construct the sharpened array:
    // `a'_i = i` for `0 <= i < k`
    // `a'_i = n-1-i` for `k < i <= n-1`
    // `a'_k = max(k, n-1-k) + 1` (or any value that works, e.g., `k` if `k > n-1-k`, or `n-1-k` if `n-1-k > k`)
    //
    // Let's re-evaluate the conditions for a peak at index `k`.
    // We need to be able to make `a'_0 < a'_1 < ... < a'_k` and `a'_k > a'_{k+1} > ... > a'_{n-1}`.
    // The minimum values for the left side are `0, 1, ..., k`. So we need `a_i >= i` for `0 <= i <= k`.
    // The minimum values for the right side are `0, 1, ..., n-1-k` (in reverse order).
    // So we need `a_i >= (n-1-i)` for `k <= i <= n-1`.
    //
    // If `a_i >= i` for all `i` from `0` to `k`, then `left_possible[k]` is true.
    // If `a_i >= (n-1-i)` for all `i` from `k` to `n-1`, then `right_possible[k]` is true.
    //
    // If both `left_possible[k]` and `right_possible[k]` are true, it means:
    // `a_0 >= 0, a_1 >= 1, ..., a_k >= k`
    // `a_k >= (n-1-k), a_{k+1} >= (n-1-(k+1)), ..., a_{n-1} >= 0`
    //
    // This implies that `a_k` must be at least `k` AND `a_k` must be at least `n-1-k`.
    // So `a_k >= max(k, n-1-k)`.
    //
    // If these conditions hold, we can construct the array:
    // `a'_i = i` for `0 <= i < k`
    // `a'_i = n-1-i` for `k < i <= n-1`
    // `a'_k = max(k, n-1-k)`
    //
    // This construction gives:
    // `0, 1, ..., k-1, max(k, n-1-k), n-1-(k+1), ..., 0`
    //
    // We need `a'_{k-1} < a'_k` and `a'_k > a'_{k+1}`.
    // `k-1 < max(k, n-1-k)` is true if `k-1 < k` (always) and `k-1 < n-1-k`.
    // `max(k, n-1-k) > n-1-(k+1)` is true if `k > n-1-(k+1)` and `n-1-k > n-1-(k+1)`.
    //
    // Let's check the conditions:
    // 1. `k-1 < max(k, n-1-k)`:
    //    If `k >= n-1-k`, then `max(k, n-1-k) = k`. We need `k-1 < k`, which is true.
    //    If `k < n-1-k`, then `max(k, n-1-k) = n-1-k`. We need `k-1 < n-1-k`, which is `2k < n`, or `k < n/2`.
    //    This is true if `k < n-1-k`.
    //    So `k-1 < max(k, n-1-k)` is always true.
    //
    // 2. `max(k, n-1-k) > n-1-(k+1)`:
    //    `n-1-(k+1) = n-k-2`.
    //    If `k >= n-1-k`, then `max(k, n-1-k) = k`. We need `k > n-k-2`, which is `2k > n-2`, or `k > (n-2)/2`.
    //    This is true if `k >= n-1-k` (which means `2k >= n-1`).
    //    If `k < n-1-k`, then `max(k, n-1-k) = n-1-k`. We need `n-1-k > n-k-2`, which is `-1 > -2`, which is true.
    //    So `max(k, n-1-k) > n-1-(k+1)` is always true.
    //
    // Therefore, if `left_possible[k]` and `right_possible[k]` are both true for some `k`,
    // we can always form a sharpened array.

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (left_possible[k] && right_possible[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

