#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Condition: current_sum = 2 * current_xor_sum
    // If already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // We need to append elements b1, b2, ... such that:
    // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))

    // Strategy: Append two elements.
    // Let the two elements be X_0 and S_0 + X_0.
    // Let X_0 be current_xor_sum.
    // Let S_0 be current_sum.
    // We want to find b1, b2 such that:
    // (S_0 + b1 + b2) = 2 * (X_0 ^ b1 ^ b2)

    // Let's try to append b1 = current_xor_sum.
    // New XOR sum becomes X_0 ^ current_xor_sum = 0.
    // New sum becomes S_0 + current_xor_sum.
    // Now we need to append one more element, say b2, such that:
    // (S_0 + current_xor_sum + b2) = 2 * (0 ^ b2)
    // (S_0 + current_xor_sum + b2) = 2 * b2
    // S_0 + current_xor_sum = b2

    // So, the two elements to append are:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum

    // Let's verify this:
    // New sum S' = current_sum + b1 + b2
    // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S' = 2 * current_sum + 2 * current_xor_sum

    // New XOR sum X' = current_xor_sum ^ b1 ^ b2
    // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X' = 0 ^ (current_sum + current_xor_sum)
    // X' = current_sum + current_xor_sum

    // Check condition: S' = 2 * X'
    // (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This is true.

    // The problem guarantees that a solution always exists by appending at most 3 elements.
    // This strategy uses 2 elements.
    // The elements are non-negative because current_sum and current_xor_sum are non-negative.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So b2 can be up to 10^14 + 10^9, which fits in long long (10^18 max).

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

