// Opponent (N=1, odd): takes 1. Opponent_coins=2+1=3. N=0.
// Result: Chanek 5, Opponent 3. Total 8.
// This matches C(8)=5 from the DP table.

// If N is even, not a power of 2, say N=10.
// Chanek (N=10, even, not power of 2): takes 1. Chanek_coins=1. N=9.
// Opponent (N=9, odd): takes 1. Opponent_coins=1. N=

#include <iostream>
#include <vector>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (i.e., identical points)
    // These pairs were counted twice: once in x_counts and once in y_counts.
    // We need to subtract them once.
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // Step 1: Determine necessary 0s in w based on s_i = '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s_i is '0', then both w_{i-x} and w_{i+x} must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_reconstructed(n, '0');
    for (int i = 0; i < n; ++i) {
        // Check w_{i-x}
        if (i - x >= 0 && w[i - x] == '1') {
            s_reconstructed[i] = '1';
        }
        // Check w_{i+x}
        if (i + x < n && w[i + x] == '1') {
            s_reconstructed[i] = '1';
        }
    }

    if (s == s_reconstructed) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
