// Function to convert a number to its 18-digit parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern += '0';
            } else { // Odd digit
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 digits long
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should normalize both to a fixed length, say 18, by padding with '0's.
    // For a number, its pattern is built from right to left. So, padding with '0's from the left
    // means adding '0's to the end of our `pattern` string (which is built in reverse order).
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 digits long
            // The pattern `s` is given from left to right.
            // The matching rule is "i-th from the right digit".
            // So, if s = "010", it means rightmost is 0, second from right is 1, third from right is 0.
            // Our `to_parity_pattern` function generates patterns in reverse order (rightmost digit first).
            // So, for s = "010", the internal representation should be "010" (reversed).
            // If s = "1", it means rightmost is 1. Internal representation "1".
            // If s = "0101", internal representation "1010".
            // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we should normalize both to 18 digits.
            // For a query pattern `s`, if it's shorter than 18, it's padded with '0's from the left.
            // Example: s = "1" (length 1). Padded to "00...01" (18 digits).
            // When we convert this to our internal reversed format, it becomes "10...00".
            // So, we need to reverse `s` and then pad with '0's to 18.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

