// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest divisor x of p such that x is not divisible by q.
        // Let q = r1^a1 * r2^a2 * ... * rk^ak be the prime factorization of q.
        // If x is divisible by q, then x must be divisible by rj^aj for all j.
        // To make x not divisible by q, we must ensure that for at least one rj,
        // the power of rj in x is less than the power of rj in q.
        // To maximize x, we should try to reduce the power of only one prime factor rj as little as possible.

        std::vector<long long> prime_factors_of_q = get_prime_factors(q);
        long long max_x = 0;

        for (long long r : prime_factors_of_q) {
            // For each prime factor r of q, we want to find the largest divisor of p
            // that is not divisible by q, by "removing" factors of r from p.

            // Calculate the current p_val by dividing p by r until it's no longer divisible by q.
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= r;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

