#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::vector<int> p1_digits;
        std::vector<int> p2_digits;
        std::string current_coloring(n, ' ');
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < pivot_digit) {
                // Must be color 1
                if (!p1_digits.empty() && digit < p1_digits.back()) {
                    possible_with_pivot = false;
                    break;
                }
                p1_digits.push_back(digit);
                current_coloring[i] = '1';
            } else if (digit > pivot_digit) {
                // Must be color 2
                if (!p2_digits.empty() && digit < p2_digits.back()) {
                    possible_with_pivot = false;
                    break;
                }
                p2_digits.push_back(digit);
                current_coloring[i] = '2';
            } else { // digit == pivot_digit
                // Try to assign to color 2 first if possible
                // This greedy choice helps satisfy the condition last1 <= first2
                // by making S1 as small as possible and S2 as large as possible.
                // If we assign to color 2, it must be >= last2.
                // If we assign to color 1, it must be >= last1.
                // The critical point is that if we assign to color 1, it must be <= pivot_digit.
                // If we assign to color 2, it must be >= pivot_digit.
                // So, if we assign to color 1, the last element of S1 will be pivot_digit.
                // If we assign to color 2, the first element of S2 will be pivot_digit.
                // This choice ensures last1 <= first2 if both are pivot_digit.

                // If we can put it in p2 and it maintains non-decreasing order for p2
                if (p2_digits.empty() || digit >= p2_digits.back()) {
                    p2_digits.push_back(digit);
                    current_coloring[i] = '2';
                } else if (p1_digits.empty() || digit >= p1_digits.back()) {
                    // If not, try putting it in p1
                    p1_digits.push_back(digit);
                    current_coloring[i] = '1';
                } else {
                    // Cannot place it in either while maintaining non-decreasing order
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            // Final check: last digit of S1 <= first digit of S2
            // This is implicitly handled by the greedy choice for pivot_digit.
            // If a digit < pivot_digit is assigned to 1, then last1 < pivot_digit.
            // If a digit > pivot_digit is assigned to 2, then first2 > pivot_digit.
            // If a digit == pivot_digit is assigned to 1, then last1 = pivot_digit.
            // If a digit == pivot_digit is assigned to 2, then first2 = pivot_digit.
            // The greedy choice for digit == pivot_digit (prefer 2) ensures that
            // if there's a choice, we push to 2, making S1 end earlier with a smaller value
            // and S2 start earlier with a larger value.
            // This strategy ensures that if a solution exists for a given pivot_digit,
            // this construction finds it.

            // The only remaining check is if p1_digits and p2_digits are individually sorted.
            // This is done by `digit >= p1_digits.back()` and `digit >= p2_digits.back()`.
            // The overall sorted property (S1 then S2) is guaranteed if
            // max(S1) <= min(S2).
            // max(S1) will be at most pivot_digit.
            // min(S2) will be at least pivot_digit.
            // So max(S1) <= min(S2) is always true.

            result = current_coloring;
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

