#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    for (char c : used_in_s) {
        if (adj[c].size() <= 1 && visited_in_layout.find(c) == visited_in_layout.end()) {
            // This character is either an endpoint of a chain or an isolated character
            // Start building a chain from here
            char current = c;
            char prev = '\0'; // Sentinel for the previous character

            while (current != '\0') {
                layout_str += current;
                visited_in_layout.insert(current);

                char next_char = '\0';
                for (char neighbor : adj[current]) {
                    if (neighbor != prev) {
                        next_char = neighbor;
                        break;
                    }
                }
                prev = current;
                current = next_char;
            }
        }
    }

    if (layout_str.length() != used_in_s.size()) {
        // This means there's a cycle or a chain where all nodes have degree 2
        // and we couldn't start from a degree-1 node.
        // Since we already checked for degree > 2, this implies a cycle.
        // A cycle cannot be represented in a single row.
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters not in 's'
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

