int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // If b = 1, mod(x, 1) is always 0.
    // The condition mod(x, b) != 0 is never met.
    // So, there are no nice integers.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // The sum is sum_{k=1}^{a} sum_{r=1}^{b-1} r * (k * b + 1)
    // This can be rewritten as:
    // (sum_{k=1}^{a} (k * b + 1)) * (sum_{r=1}^{b-1} r)

    // Calculate sum_{r=1}^{b-1} r
    // This is (b-1) * b / 2
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term % MOD * (b % MOD)) % MOD;

    // We need to divide by 2. Since MOD is prime, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004.
    long long inv2 = 500000004;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Calculate sum_{k=1}^{a} (k * b + 1)
    // This is sum_{k=1}^{a} (k * b) + sum_{k=1}^{a} 1
    // = b * sum_{k=1}^{a} k + a
    // = b * (a * (a + 1) / 2) + a

    long long sum_k_term_part1 = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * inv2) % MOD;
    sum_k_term_part1 = (sum_k_term_part1 * (b % MOD)) % MOD;

    long long sum_k_term_part2 = a % MOD;

    long long sum_k_term = (sum_k_term_part1 + sum_k_term_part2) % MOD;

    // Total sum is (sum_k_term * sum_r_term) % MOD
    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < n; ++k_actual) {
        char c_first = s[k_actual];

        // Find all possible k' values that could result in c_first
        const std::vector<int>& possible_k_values = char_indices[c_first - 'a'];

        if (possible_k_values.empty()) { // Should not happen if s is non-empty
            continue;
        }

        if (possible_k_values.size() == 1) {
            // If only one k' matches c_first, Vasya wins immediately without asking for t[p]
            // This k' must be k_actual.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal p
        int max_winning_p_count = 0; // Max number of k_actual values for which Vasya wins with this p

        // Iterate over all possible positions p (1 to n-1)
        for (int p = 1; p < n; ++p) {
            std::vector<int> counts_for_p(n, 0); // counts_for_p[k_prime] = number of (k, c_p) pairs that match k_prime

            // For each k' that could be the actual k (i.e., s[k'] == c_first)
            for (int k_prime : possible_k_values) {
                char c_p = s[(k_prime + p) % n];
                // We are interested in how many k_prime values match (c_first, c_p)
                // This is equivalent to counting how many k_prime values result in the same (s[k_prime], s[(k_prime+p)%n]) pair.
                // We can use a map or a 2D array for this, but since we only care about the current c_first,
                // we can just count how many k_prime values result in the same c_p.
                // The problem states "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                // So, for a given (c_first, c_p), Vasya wins if exactly one k_prime satisfies s[k_prime]=c_first AND s[(k_prime+p)%n]=c_p.
                // We need to count how many k_prime values satisfy this.
                // A map from char_p to count of k_prime values that produce it.
                // std::map<char, int> char_p_counts;
                // For a fixed p, and fixed c_first, we count how many k_prime values result in each possible c_p.
                // If any c_p has a count of 1, then for that c_p, Vasya wins.
                // We want to maximize the number of k_actual values for which Vasya wins.
                // This is equivalent to maximizing the number of k_prime values that result in a unique (c_first, c_p) pair.
                // For a fixed p, we can count how many k_prime values result in a unique (c_first, s[(k_prime+p)%n]) pair.
                // This is what the problem means by "Vasya wants to know the value of k uniquely".
                // So, for a given p, we iterate through all k_prime in possible_k_values.
                // For each k_prime, we get s[(k_prime+p)%n].
                // We need to count how many k_prime values result in a unique pair (c_first, s[(k_prime+p)%n]).
                // This is equivalent to counting how many k_prime values have s[(k_prime+p)%n] such that no other k_prime has the same s[(k_prime+p)%n].
                // Let's use a frequency map for s[(k_prime+p)%n] values.
            }

            std::vector<int> char_p_freq(26, 0);
            for (int k_prime : possible_k_values) {
                char_p_freq[s[(k_prime + p) % n] - 'a']++;
            }

            int current_p_winning_k_count = 0;
            for (int k_prime : possible_k_values) {
                if (char_p_freq[s[(k_prime + p) % n] - 'a'] == 1) {
                    current_p_winning_k_count++;
                }
            }
            max_winning_p_count = std::max(max_winning_p_count, current_p_winning_k_count);
        }

        // The probability of winning for this specific k_actual is max_winning_p_count / possible_k_values.size()
        // This is because if Vasya sees c_first, he knows the actual k must be one of possible_k_values.
        // He then chooses p to maximize the number of k_prime values in possible_k_values that become uniquely identifiable.
        // The problem asks for the overall probability of winning, averaged over all k_actual.
        // So, for each k_actual, we add the probability of winning given that k_actual was chosen.
        // This is (max_winning_p_count / possible_k_values.size()) * (1/n)
        // Or, more simply, we sum up max_winning_p_count for each k_actual, and divide by n at the end.
        // The max_winning_p_count here is the number of k_prime values (from possible_k_values) that would lead to a win.
        // If k_actual is one of these, Vasya wins.
        // So, if k_actual is one of the `max_winning_p_count` values, Vasya wins.
        // This means we add 1 to total_win_prob if k_actual is one of the `max_winning_p_count` values.
        // But this is not quite right. The `max_winning_p_count` is the count of *potential* k values that would lead to a win *if* Vasya chose that p.
        // We need to check if the *actual* k_actual is one of those.
        // The problem states: "Vasya wants to know the value of k uniquely, it means, that if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
        // This means, for a given k_actual, Vasya sees c_first = s[k_actual].
        // He then chooses p.
        // He then sees c_p = s[(k_actual + p) % n].
        // He wins if there is exactly one k' such that s[k'] = c_first AND s[(k'+p)%n] = c_p.
        // So, for each k_actual, we find the optimal p.
        // For that optimal p, we check if the pair (s[k_actual], s[(k_actual+p)%n]) is unique among all (s[k'], s[(k'+p)%n]) for k' in possible_k_values.

        int best_p_for_k_actual = -1;
        bool k_actual_wins_with_best_p = false;

        if (possible_k_values.size() == 1) {
            k_actual_wins_with_best_p = true;
        } else {
            int max_unique_count = 0;
            for (int p = 1; p < n; ++p) {
                std::vector<int> char_p_freq(26, 0);
                for (int k_prime : possible_k_values) {
                    char_p_freq[s[(k_prime + p) % n] - 'a']++;
                }

                int current_unique_count = 0;
                for (int k_prime : possible_k_values) {
                    if (char_p_freq[s[(k_prime + p) % n] - 'a'] == 1) {
                        current_unique_count++;
                    }
                }

                if (current_unique_count > max_unique_count) {
                    max_unique_count = current_unique_count;
                    best_p_for_k_actual = p;
                }
            }

            if (best_p_for_k_actual != -1) {
                char c_p_actual = s[(k_actual + best_p_for_k_actual) % n];
                int count_matching_k_prime = 0;
                for (int k_prime : possible_k_values) {
                    if (s[(k_prime + best_p_for_k_actual) % n] == c_p_actual) {
                        count_matching_k_prime++;
                    }
                }
                if (count_matching_k_prime == 1) {
                    k_actual_wins_with_best_p = true;
                }
            }
        }

        if (k_actual_wins_with_best_p) {
            total_win_prob += 1.0;
        }
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

