    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // We are interested in diff_L[k] for k from 0 to n.
    // diff_L[0] = 0 (empty prefix)
    // diff_L[k] = diff_L[k-1] + (a[k-1] == 1 ? 1 : -1)
    std::map<int, int> diff_to_k_left; // Stores diff -> k (number of jars eaten from left)
    diff_to_k_left[0] = 0; // 0 jars eaten, diff is 0

    int current_diff_L = 0;
    for (int k = 1; k <= n; ++k) {
        current_diff_L += (a[n - k] == 1 ? 1 : -1); // Iterate from n-1 down to 0
        if (diff_to_k_left.find(current_diff_L) == diff_to_k_left.end()) {
            diff_to_k_left[current_diff_L] = k;
        }
    }

    // Calculate prefix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[n...n+k-1]) - (count of 2s in a[n...n+k-1])
    // We are interested in diff_R[k] for k from 0 to n.
    // diff_R[0] = 0 (empty prefix)
    // diff_R[k] = diff_R[k-1] + (a[n+k-1] == 1 ? 1 : -1)
    std::map<int, int> diff_to_k_right; // Stores diff -> k (number of jars eaten from right)
    diff_to_k_right[0] = 0; // 0 jars eaten, diff is 0

    int current_diff_R = 0;
    for (int k = 1; k <= n; ++k) {
        current_diff_R += (a[n + k - 1] == 1 ? 1 : -1); // Iterate from n up to 2n-1
        if (diff_to_k_right.find(current_diff_R) == diff_to_k_right.end()) {
            diff_to_k_right[current_diff_R] = k;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible diffs from the left side
    // For each diff_L, we need to find a diff_R such that diff_L + diff_R = 0
    // This means diff_R = -diff_L
    for (auto const& [diff_L_val, k_L] : diff_to_k_left) {
        int target_diff_R = -diff_L_val;
        if (diff_to_k_right.count(target_diff_R)) {
            int k_R = diff_to_k_right[target_diff_R];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

