        // If current_x <= 0 or current_x > n, program terminates.
        // Otherwise, we need to perform step_minus from current_x.
        // The state after step_minus is (dp_x[current_x], current_y + dp_y[current_x]).
        // This is exactly what the DP computes.

        // So, for each i from 1 to n-1:
        // Set a[1] = i.
        // Calculate the state after the first step_plus:
        // x_after_plus = 1 + a[1]
        // y_after_plus = a[1]
        // If x_after_plus <= 0 or x_after_plus > n:
        //   Result is y_after_plus.
        // Else:
        //   We need to find the result of starting at x_after_plus and performing step_minus.
        //   This is exactly what dp_x[x_after_plus] and dp_y[x_after_plus] give.
        //   Result is y_after_plus + dp_y[x_after_plus].
        //   If dp_y[x_after_plus] is -1, then the result is -1.

        // The DP states are computed for starting with step_minus.
        // dp_x[k] = final x if starting at k with step_minus
        // dp_y[k] = final y if starting at k with step_minus

        // We need to compute dp_x and dp_y for k from 2 to n.
        // The values a[k] are fixed for k >= 2.
        // The values a[1] change for each query.
        // So, we can precompute dp_x and dp_y for k from 2 to n.
        // For k=1, it depends on a[1].

        // Let's compute dp_x and dp_y for k from 2 to n.
        // dp_x[k] and dp_y[k] represent the outcome if we are at position k
        // and the next operation is step_minus.
        // So, x becomes k - a[k], y becomes a[k].
        // Let next_x = k - a[k].
        // If next_x <= 0 or next_x > n, then dp_x[k] = next_x, dp_y[k] = a[k].
        // Else, we are at next_x and the next operation is step_plus.
        // So, x becomes next_x + a[next_x], y becomes a[next_x].
        // Let next_next_x = next_x + a[next_x].
        // If next_next_x <= 0 or next_next_x > n, then dp_x[k] = next_next_x, dp_y[k] = a[k] + a[next_x].
        // Else, we are at next_next_x and the next operation is step_minus.
        // This is a recursive call to dp_x[next_next_x] and dp_y[next_next_x].
        // So, dp_x[k] = dp_x[next_next_x] and dp_y[k] = a[k] + a[next_x] + dp_y[next_next_x].

        // This is a standard DP with cycle detection.
        // We can use a visited array or mark states as "currently computing".
        // Let's use dp_y values: -2 uncomputed, -1 computing (cycle), >=0 computed.

        // Iterate k from 2 to n.
        // For each k, if dp_y[k] is -2, compute it.
        // Path: k -> (k - a[k]) -> (k - a[k] + a[k - a[k]]) -> ...
    }

    for (int k = 2; k <= n; ++k) {
        if (dp_y[k] != -2) continue; // Already computed or in a cycle

        std::vector<int> path;
        int current_k = k;
        while (current_k >= 1 && current_k <= n && dp_y[current_k] == -2) {
            dp_y[current_k] = -1; // Mark as currently computing (potential cycle)
            path.push_back(current_k);

            long long val_at_current_k = a[current_k];
            long long x_after_minus = current_k - val_at_current_k;

            if (x_after_minus <= 0 || x_after_minus > n) {
                dp_x[current_k] = x_after_minus;
                dp_y[current_k] = val_at_current_k;
                break;
            }

            long long val_at_x_after_minus = a[x_after_minus];
            long long x_after_plus = x_after_minus + val_at_x_after_minus;

            if (x_after_plus <= 0 || x_after_plus > n) {
                dp_x[current_k] = x_after_plus;
                dp_y[current_k] = val_at_current_k + val_at_x_after_minus;
                break;
            }
            current_k = x_after_plus;
        }

        // After loop, current_k is either out of bounds, or points to an already computed/cyclic state.
        long long final_y_val;
        int final_x_val;

        if (current_k < 1 || current_k > n) { // Terminated out of bounds
            final_y_val = 0; // Base case for sum
            final_x_val = current_k;
        } else { // Hit an already computed state or a cycle
            final_y_val = dp_y[current_k];
            final_x_val = dp_x[current_k];
        }

        // Backtrack through the path to fill DP values
        for (int i = path.size() - 1; i >= 0; --i) {
            int p = path[i];
            if (final_y_val == -1) { // If we hit a cycle, all states in path are part of cycle
                dp_y[p] = -1;
                dp_x[p] = -1;
            } else {
                long long val_at_p = a[p];
                long long x_after_minus = p - val_at_p;
                long long val_at_x_after_minus = a[x_after_minus];

                dp_y[p] = val_at_p + val_at_x_after_minus + final_y_val;
                dp_x[p] = final_x_val;
            }
            // Update final_y_val and final_x_val for the next step in path
            // This is effectively summing up the a[x] values along the path
            // and propagating the final x.
            // The values val_at_p and val_at_x_after_minus are already included in dp_y[p].
            // So for the next iteration, final_y_val should be dp_y[p] and final_x_val should be dp_x[p].
            final_y_val = dp_y[p];
            final_x_val = dp_x[p];
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for this run

        long long x_after_plus = 1 + a[1];
        long long y_after_plus = a[1];

        if (x_after_plus <= 0 || x_after_plus > n) {
            std::cout << y_after_plus << "\n";
        } else {
            if (dp_y[x_after_plus] == -1) {
                std::cout << -1 << "\n";
            } else {
                std::cout << y_after_plus + dp_y[x_after_plus] << "\n";
            }
        }
    }

    return 0;
}

