struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type;
        if (ops[i].type == 1) {
            std::cin >> ops[i].l >> ops[i].r >> ops[i].val;
            ops[i].l--; 
            ops[i].r--; 
        } else {
            std::cin >> ops[i].l >> ops[i].r >> ops[i].val;
            ops[i].l--; 
            ops[i].r--; 
        }
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Stores upper bounds for initial_a[i]
    std::vector<long long> current_deltas(n, 0); // Stores sum of d's applied to a[i] up to current op

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: Increase a[j] by d
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else {
            // Type 2: Max of a[l...r] is m
            // This implies initial_a[j] + current_deltas[j] <= m for all j in [l, r]
            // So, initial_a[j] <= m - current_deltas[j]
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_deltas[j]);
            }
        }
    }

    // If initial_a[i] is still LLONG_MAX, it means no upper bound was imposed.
    // We can set it to 0, as it satisfies |a[i]| <= 10^9.
    // Or, more generally, any value that satisfies the constraints.
    // Since we want to maximize the chance of finding a solution,
    // setting it to 0 (or any value within bounds) is fine.
    // The problem asks for *any* suitable array.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution
    std::fill(current_deltas.begin(), current_deltas.end(), 0); // Reset deltas for verification
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else {
            long long max_val = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_deltas[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            // This case should ideally not be reached if the problem guarantees a solution
            // within bounds, or if our logic correctly handles it.
            // Our current logic sets initial_a[i] to 0 if no constraint, or to m - current_deltas[j].
            // m is up to 5e7, current_deltas can be up to 5000 * 10^4 = 5e7.
            // So m - current_deltas can be 5e7 - (-5e7) = 1e8, or -5e7 - 5e7 = -1e8.
            // These values are within [-10^9, 10^9].
            // So this check is mostly for robustness, but should pass.
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

