        if (i >= 4 && s[i] == s[i-2] && s[i-2] == s[i-4]) {
            min_start_idx[i] = std::max(min_start_idx[i], i - 4 + 1); // x = i-4, x+4 = i. So l must be > x.
                                                                       // Any good substring s[l...i] must have l > i-4.
                                                                       // So l must be at least i-3.
        }
        // Check for s[x] = s[x+3] = s[x+6]
        if (i >= 6 && s[i] == s[i-3] && s[i-3] == s[i-6]) {
            min_start_idx[i] = std::max(min_start_idx[i], i - 6 + 1); // x = i-6, x+6 = i. So l must be > x.
                                                                       // Any good substring s[l...i] must have l > i-6.
                                                                       // So l must be at least i-5.
        }

        // The minimum l for s[l...i] to be good is min_start_idx[i].
        // The number of good substrings ending at i is (i - min_start_idx[i] + 1).
        good_pairs += (long long)(i - min_start_idx[i] + 1);
    }

    std::cout << total_pairs - good_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_left_reach(n);
    std::vector<long long> head_right_reach(n);
    for (int i = 0; i < n; ++i) {
        head_left_reach[i] = h[i] - T;
        head_right_reach[i] = h[i] + T;
    }

    std::vector<long long> dp_prev(n + 1, -1); // dp_prev[j] = max_p_idx covered by first j heads
    dp_prev[0] = -1; // No heads cover nothing, effectively before p[0]

    for (int i = 0; i < n; ++i) { // Iterate through heads
        std::vector<long long> dp_curr(n + 1, -1);

        // Option 1: Don't use head i for the current segment (or it's already used by a previous head)
        // This means dp_curr[j] = dp_prev[j] for j <= i
        for(int j=0; j<=i; ++j) {
            dp_curr[j] = dp_prev[j];
        }

        // Option 2: Use head i to cover a segment starting from dp_prev[j]+1
        // This head is the (j+1)-th head used.
        for (int j = 0; j <= i; ++j) { // j is the count of heads used before current head i
            if (dp_prev[j] == -1 && j > 0) continue; // If dp_prev[j] is -1 and j>0, it means j heads couldn't cover up to dp_prev[j].
                                                      // For j=0, dp_prev[0]=-1 is valid, meaning no tracks covered yet.

            long long start_p_idx = dp_prev[j] + 1;
            if (start_p_idx >= m) { // All tracks already covered
                dp_curr[j + 1] = std::max(dp_curr[j + 1], (long long)m - 1);
                continue;
            }

            // Find the first target track p[start_p_idx] that head_left_reach[i] can cover
            // This is equivalent to finding the first p_k >= head_left_reach[i]
            auto it_start = std::lower_bound(p.begin() + start_p_idx, p.end(), head_left_reach[i]);
            long long actual_start_p_idx = std::distance(p.begin(), it_start);

            if (actual_start_p_idx >= m) { // Head i cannot cover any remaining tracks
                continue;
            }

            // If head i can cover p[actual_start_p_idx], it can cover up to p[k] such that p[k] <= head_right_reach[i]
            // Find the last target track p[end_p_idx] that head_right_reach[i] can cover
            auto it_end = std::upper_bound(p.begin() + actual_start_p_idx, p.end(), head_right_reach[i]);
            long long actual_end_p_idx = std::distance(p.begin(), it_end) - 1;

            if (actual_end_p_idx >= actual_start_p_idx) { // Head i covers at least one track
                dp_curr[j + 1] = std::max(dp_curr[j + 1], actual_end_p_idx);
            }
        }
        dp_prev = dp_curr;
    }

    return dp_prev[n] == m - 1;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between p_m and h_1, or p_1 and h_n.
                               // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                               // Max h_i is 10^10, min p_i is 1. Max diff is 10^10.
                               // So 10^10 is a safe upper bound. Add a small buffer.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // (n+1)/2 - 1 for 0-indexed array

    // Make the median element equal to s
    operations += std::abs(a[mid_idx] - s);

    // Adjust elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // These elements must be >= s
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s)
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition into two non-empty subsequences
    // This strategy aims to minimize max_f and maximize min_f.
    // The optimal strategy for this case is to put a_0 into one subsequence (say, 1)
    // and all other elements into the other subsequence (say, 2).
    //
    // Subsequence 1: {a_0}
    // Subsequence 2: {a_1, a_2, ..., a_{n-1}}
    //
    // Pairs within subsequence 1: None (if n=1, but n>=2)
    // Pairs within subsequence 2:
    //   min_val_same = a_1 + a_2
    //   max_val_same = a_{n-2} + a_{n-1}
    // Pairs between subsequences:
    //   min_val_diff = a_0 + a_1 + h
    //   max_val_diff = a_0 + a_{n-1} + h
    //
    // Overall min_f = min(a_1 + a_2, a_0 + a_1 + h)
    // Overall max_f = max(a_{n-2} + a_{n-1}, a_0 + a_{n-1} + h)
    //
    // This is only valid if n >= 3 for a_1+a_2 to exist.
    // If n=2, then subsequence 2 has only one element, so no pairs within it.
    // In that case, all pairs are between subsequences: a_0 and a_1.
    // f(a_0, a_1) = a_0 + a_1 + h. min_f = max_f = a_0 + a_1 + h. Goodness = 0.
    // This is covered by the general formula if we consider min_val_same and max_val_same to be infinity/-infinity if no pairs.
    //
    // Let's be precise for n=2:
    // If n=2, elements are a_0, a_1.
    // Case 1: {a_0, a_1} in subseq 1. f(a_0, a_1) = a_0 + a_1. Goodness = 0.
    // Case 2: {a_0} in subseq 1, {a_1} in subseq 2. f(a_0, a_1) = a_0 + a_1 + h. Goodness = 0.
    // So for n=2, goodness is always 0.
    // The current logic for goodness1: (a_0+a_1) - (a_0+a_1) = 0. This is correct.
    //
    // For n >= 3:
    // min_f_val = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    // max_f_val = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    // goodness2 = max_f_val - min_f_val;
    //
    // This specific partition (a_0 in one, rest in other) is chosen because it minimizes the range of values
    // for pairs that cross subsequences (a_0+a_1+h to a_0+a_{n-1}+h) and also for pairs within the larger subsequence
    // (a_1+a_2 to a_{n-2}+a_{n-1}).
    // The smallest possible sum is a_0+a_1. The largest is a_{n-1}+a_{n-2}.
    // The smallest possible sum with h is a_0+a_1+h. The largest is a_{n-1}+a_{n-2}+h.
    //
    // The key observation is that the minimum possible value of f is always a_0 + a_1 (either same or diff + h).
    // The maximum possible value of f is always a_{n-2} + a_{n-1} + h (either same or diff + h).
    //
    // Let's consider the four extreme values:
    // V1 = a_0 + a_1
    // V2 = a_{n-2} + a_{n-1}
    // V3 = a_0 + a_1 + h
    // V4 = a_{n-2} + a_{n-1} + h
    //
    // The overall min_f will be one of V1 or V3.
    // The overall max_f will be one of V2 or V4.
    //
    // If all elements are in one group (e.g., all 1s):
    // min_f = V1
    // max_f = V2
    // goodness = V2 - V1
    //
    // If all elements are in different groups (not possible for n > 2, but if we imagine a_0 in 1, a_1 in 2, a_2 in 1, etc.)
    // This is not a simple case.
    //
    // Consider the partition where a_0 is in group 1, and all other elements a_1, ..., a_{n-1} are in group 2.
    // min_f = min(a_1 + a_2, a_0 + a_1 + h) (if n >= 3, else a_0+a_1+h)
    // max_f = max(a_{n-2} + a_{n-1}, a_0 + a_{n-1} + h) (if n >= 3, else a_0+a_1+h)
    //
    // Let's re-evaluate the goodness for the second strategy.
    // The strategy is: put `elements[0]` in group 1, and `elements[1]` in group 2.
    // All other elements `elements[2], ..., elements[n-1]` can be put in group 1.
    //
    // Subsequence 1: {elements[0], elements[2], ..., elements[n-1]}
    // Subsequence 2: {elements[1]}
    //
    // Pairs within Subsequence 1:
    //   min_same_1 = elements[0].value + elements[2].value (if n >= 3)
    //   max_same_1 = elements[n-2].value + elements[n-1].value (if n >= 3)
    // Pairs within Subsequence 2: None
    // Pairs between Subsequences:
    //   min_diff = elements[0].value + elements[1].value + h
    //   max_diff = elements[1].value + elements[n-1].value + h
    //
    // If n=2:
    // Subseq 1: {elements[0]}
    // Subseq 2: {elements[1]}
    // min_f = elements[0].value + elements[1].value + h
    // max_f = elements[0].value + elements[1].value + h
    // goodness = 0.
    // This is consistent with goodness1 for n=2.
    //
    // If n >= 3:
    // min_f_val_2 = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h);
    // max_f_val_2 = std::max(elements[n-2].value + elements[n-1].value, elements[1].value + elements[n-1].value + h);
    // goodness2 = max_f_val_2 - min_f_val_2;
    //
    // This is the "a_0 in group 1, a_1 in group 2, rest in group 1" strategy.
    // This strategy is good because it tries to make the min_f and max_f values close.
    // The smallest sum is a_0+a_1. The largest sum is a_{n-1}+a_{n-2}.
    // By putting a_0 and a_1 in different groups, we force a_0+a_1+h to be a candidate for min_f.
    // By putting a_0 and a_1 in different groups, we force a_0+a_1+h to be a candidate for max_f.
    //
    // Let's check the example 1: 3 2, 1 2 3
    // Sorted: 1 2 3. h=2.
    // elements[0]=1, elements[1]=2, elements[2]=3.
    //
    // Case 1 (all 1s):
    // goodness1 = (elements[1].value + elements[2].value) - (elements[0].value + elements[1].value)
    //           = (2 + 3) - (1 + 2) = 5 - 3 = 2.
    // Partition: 1 1 1
    // f(1,2)=1+2=3, f(1,3)=1+3=4, f(2,3)=2+3=5. max=5, min=3. goodness=2.
    //
    // Case 2 (a_0 in 1, a_1 in 2, rest in 1):
    // Subseq 1: {1, 3}
    // Subseq 2: {2}
    // Pairs within Subseq 1: f(1,3) = 1+3 = 4
    // Pairs between Subseqs: f(1,2) = 1+2+h = 1+2+2 = 5
    //                        f(2,3) = 2+3+h = 2+3+2 = 7
    // min_f = 4, max_f = 7. Goodness = 7 - 4 = 3.
    // This is not the sample output. The sample output is 1.
    //
    // Sample output partition: 1 2 2
    // Subseq 1: {1}
    // Subseq 2: {2, 3}
    // Pairs within Subseq 2: f(2,3) = 2+3 = 5
    // Pairs between Subseqs: f(1,2) = 1+2+h = 1+2+2 = 5
    //                        f(1,3) = 1+3+h = 1+3+2 = 6
    // min_f = 5, max_f = 6. Goodness = 6 - 5 = 1.
    // This is the partition where elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    //
    // Let's call this "Strategy A": elements[0] in group 1, elements[1]...elements[n-1] in group 2.
    // If n >= 3:
    //   min_f_A = min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //   max_f_A = max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)
    //   goodness_A = max_f_A - min_f_A
    // If n=2:
    //   min_f_A = elements[0].value + elements[1].value + h
    //   max_f_A = elements[0].value + elements[1].value + h
    //   goodness_A = 0
    //
    // This is the strategy that produced the sample output for example 1.
    // Let's re-calculate for example 1 (3 2, 1 2 3) with Strategy A:
    // elements[0]=1, elements[1]=2, elements[2]=3. h=2. n=3.
    // min_f_A = min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //         = min(2 + 3, 1 + 2 + 2) = min(5, 5) = 5
    // max_f_A = max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)
    //         = max(elements[1].value + elements[2].value, elements[0].value + elements[2].value + h)
    //         = max(2 + 3, 1 + 3 + 2) = max(5, 6) = 6
    // goodness_A = 6 - 5 = 1. This matches the sample output.

    // So we have two main candidates for optimal partition:
    // 1. All elements in one group (e.g., all 1s). Goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1).
    // 2. elements[0] in group 1, elements[1]...elements[n-1] in group 2.
    //    Goodness calculated as goodness_A above.

    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    // Calculate goodness for Strategy A
    long long current_min_f, current_max_f;
    if (n == 2) {
        current_min_f = elements[0].value + elements[1].value + h;
        current_max_f = elements[0].value + elements[1].value + h;
    } else { // n >= 3
        current_min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        current_max_f = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    }
    long long goodness_A = current_max_f - current_min_f;

    if (goodness_A < min_goodness) {
        min_goodness = goodness_A;
        best_partition.assign(n, 2); // All 2s
        best_partition[elements[0].original_index] = 1; // Except elements[0]
    }

    // What if h is very large?
    // Example 2: 5 10, 0 1 0 2 1
    // Sorted: 0 0 1 1 2. h=10.
    // elements[0]=0, elements[1]=0, elements[2]=1, elements[3]=1, elements[4]=2.
    //
    // Case 1 (all 1s):
    // goodness1 = (elements[3].value + elements[4].value) - (elements[0].value + elements[1].value)
    //           = (1 + 2) - (0 + 0) = 3 - 0 = 3.
    // Partition: 1 1 1 1 1
    //
    // Case 2 (Strategy A: elements[0] in 1, rest in 2):
    // elements[0]=0, elements[1]=0, elements[2]=1, elements[3]=1, elements[4]=2. h=10. n=5.
    // Subseq 1: {elements[0]} = {0}
    // Subseq 2: {elements[1], elements[2], elements[3], elements[4]} = {0, 1, 1, 2}
    //
    // Pairs within Subseq 2:
    //   min_same_2 = elements[1].value + elements[2].value = 0 + 1 = 1
    //   max_same_2 = elements[3].value + elements[4].value = 1 + 2 = 3
    // Pairs between Subseqs:
    //   min_diff = elements[0].value + elements[1].value + h = 0 + 0 + 10 = 10
    //   max_diff = elements[0].value + elements[4].value + h = 0 + 2 + 10 = 12
    //
    // min_f_A = min(1, 10) = 1
    // max_f_A = max(3, 12) = 12
    // goodness_A = 12 - 1 = 11.
    //
    // Comparing goodness1=3 and goodness_A=11, goodness1 is better.
    // So for example 2, the output should be 3 and all 1s.
    // The sample output is 3 and all 2s. This is equivalent to all 1s.
    // My code would output 3 and all 1s. This is fine as "any of them".

    // The logic seems to cover the examples correctly.
    // The two main strategies are:
    // 1. All elements in one group. This minimizes the range of (a_i+a_j) values.
    //    min_f = a_0+a_1, max_f = a_{n-2}+a_{n-1}. Goodness = (a_{n-2}+a_{n-1}) - (a_0+a_1).
    // 2. One element (a_0) in one group, and the rest (a_1...a_{n-1}) in another group.
    //    This strategy is effective when h is not too large, as it tries to make the min_f and max_f values
    //    from different types of pairs (same group vs. different groups) overlap or be close.
    //    min_f = min(a_1+a_2, a_0+a_1+h) (for n>=3)
    //    max_f = max(a_{n-2}+a_{n-1}, a_0+a_{n-1}+h) (for n>=3)
    //    For n=2, both strategies yield goodness 0.

    std::cout << min_goodness << std::endl;
    std::vector<int> final_partition(n);
    for (int i = 0; i < n; ++i) {
        final_partition[elements[i].original_index] = best_partition[i];
    }
    for (int i = 0; i < n; ++i) {
        std::cout << final_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zero_run(n, 0);
    std::vector<int> right_zero_run(n, 0);
    std::vector<int> left_one_run(n, 0);
    std::vector<int> right_one_run(n, 0);

    // Calculate left runs
    if (a[0] == 0) left_zero_run[0] = 1;
    else left_one_run[0] = 1;

    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_one_run[i] = left_one_run[i - 1] + 1;
            left_zero_run[i] = 0;
        }
    }

    // Calculate right runs
    if (a[n - 1] == 0) right_zero_run[n - 1] = 1;
    else right_one_run[n - 1] = 1;

    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_one_run[i] = right_one_run[i + 1] + 1;
            right_zero_run[i] = 0;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0 && a[i - 1] == 1 && a[i + 1] == 1) { // 101 pattern
            int l = left_one_run[i - 1];
            int r = right_one_run[i + 1];
            int k = std::min(l, r);
            max_steps = std::max(max_steps, k);
            // Change 0s to 1s
            for (int j = 0; j < k; ++j) {
                final_a[i - j] = 1;
                final_a[i + j] = 1;
            }
        } else if (a[i] == 1 && a[i - 1] == 0 && a[i + 1] == 0) { // 010 pattern
            int l = left_zero_run[i - 1];
            int r = right_zero_run[i + 1];
            int k = std::min(l, r);
            max_steps = std::max(max_steps, k);
            // Change 1s to 0s
            for (int j = 0; j < k; ++j) {
                final_a[i - j] = 0;
                final_a[i + j] = 0;
            }
        }
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
