void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_val_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_val_idx]) {
            min_val_idx = i;
        }
    }

    long long min_val = a[min_val_idx];
    long long total_operations = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_val_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // as many times as possible without exceeding k.
        // The number of times is floor((k - a[i]) / min_val).
        if (a[i] < k) { // Only add if there's room
            total_operations += (k - a[i]) / min_val;
        }
    }
    std::cout << total_operations << std::endl;
}

