#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reverse of a permutation p, p_rev, will always have the same fingerprint as p.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // F(p_rev) = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // Since addition is commutative, p_i+p_{i+1} = p_{i+1}+p_i.
    // The set of sums {p_1+p_2, ..., p_{n-1}+p_n} is identical to {p_n+p_{n-1}, ..., p_2+p_1}.
    // Therefore, their sorted versions (fingerprints) will be identical.

    // We need to find a *different* permutation p'.
    // If p is not a palindrome (i.e., p != reverse(p)), then reverse(p) is a valid p'.
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // For example, [1,2,3,2,1] is a palindrome.
    // However, a permutation must contain distinct integers from 1 to n.
    // A permutation can only be a palindrome if n=1 (trivial, [1]) or if it's impossible.
    // For n > 1, if p_i = p_{n-1-i}, then for i=0, p_0 = p_{n-1}.
    // For i=1, p_1 = p_{n-2}.
    // If n is odd, say n=3, p=[1,2,3]. Reverse is [3,2,1]. Not a palindrome.
    // If n is even, say n=4, p=[1,2,3,4]. Reverse is [4,3,2,1]. Not a palindrome.
    // In fact, for any n > 1, a permutation cannot be a palindrome because it would require
    // p_i = p_{n-1-i} for distinct i and n-1-i, which means two elements would have to be equal,
    // unless i = n-1-i, which only happens for the middle element if n is odd.
    // But even then, p_0 must equal p_{n-1}, p_1 must equal p_{n-2}, etc.
    // Since all elements must be distinct, this is only possible if n=1.
    // For n >= 2, p_0 and p_{n-1} must be distinct. So p_0 != p_{n-1}.
    // Thus, p is never equal to its reverse for n >= 2.
    // The problem states n >= 2.

    // So, simply reversing the given permutation p will always yield a different permutation p'
    // with the same fingerprint.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << "\n";
}

