void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) {
        // Pile index is i, 0-indexed.
        // Original pile number is i+1, 1-indexed.
        // Distance to pile 1 (0-indexed) is i.
        // Cost to move one haybale from pile i+1 to pile 1 is i days.

        int haybales_in_current_pile = a[i];
        int cost_per_haybale = i; // days

        if (cost_per_haybale == 0) { // This should only happen for pile 0 itself, which is skipped
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // given the remaining days and cost per haybale.
        long long max_haybales_to_move = remaining_days / cost_per_haybale;

        // The actual number of haybales moved is limited by
        // 1. the number of haybales available in the pile (a[i])
        // 2. the number of haybales that can be moved within remaining_days
        long long haybales_to_move = std::min((long long)haybales_in_current_pile, max_haybales_to_move);

        current_a1 += haybales_to_move;
        remaining_days -= haybales_to_move * cost_per_haybale;

        if (remaining_days <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

