void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n > 1, we can construct a number.
        // A simple construction is to use '2' as the first digit
        // and '3' for all subsequent digits.
        // Let s = 233...3 (n-1 times '3').
        //
        // Check divisibility by 2:
        // The number ends in 3, which is odd. So it's not divisible by 2.
        //
        // Check divisibility by 3:
        // The sum of digits is 2 + (n-1)*3.
        // If n-1 is a multiple of 3, then (n-1)*3 is a multiple of 9,
        // and 2 + (n-1)*3 will be 2 + (multiple of 9), which is not a multiple of 3.
        // If n-1 is not a multiple of 3, then (n-1)*3 is a multiple of 3,
        // and 2 + (n-1)*3 will be 2 + (multiple of 3), which is not a multiple of 3.
        // In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        // 3n - 1 is never divisible by 3 (it always leaves a remainder of 2 when divided by 3).
        // So, the number is not divisible by 3.
        //
        // Since the only digits are 2 and 3, and we've shown it's not divisible by 2 or 3,
        // this construction works for all n > 1.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

