void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    // Re-evaluate has_pos_one and has_neg_one for elements *before* current index
    // For index 0, we already checked a[0] == b[0].
    // For index 1, we need to know if a[0] is 1 or -1.
    // For index i, we need to know if any a[k] for k < i is 1 or -1.
    // So, we can iterate from i=1 to n-1.
    // has_pos_one_prefix and has_neg_one_prefix track if a 1 or -1 exists in a[0...i-1]
    bool current_has_pos_one_prefix = (a[0] == 1);
    bool current_has_neg_one_prefix = (a[0] == -1);

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!current_has_pos_one_prefix) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!current_has_neg_one_prefix) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation needed for this element.
        // Update prefix flags for the next iteration.
        if (a[i] == 1) {
            current_has_pos_one_prefix = true;
        } else if (a[i] == -1) {
            current_has_neg_one_prefix = true;
        }
    }

    std::cout << "YES\n";
}

