int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_for_i) {
                max_val_for_i = a[i][j];
            }
        }
        p[i] = max_val_for_i;
    }

    // Check if any p[i] is n-1 and no p[j] is n.
    // This happens if the true maximum value n is not present in any min(p_i, p_j)
    // because it's always the larger of the two.
    // In such a case, the maximum value in p will be n-1, and we need to change it to n.
    bool n_minus_1_found = false;
    for (int val : p) {
        if (val == n - 1) {
            n_minus_1_found = true;
            break;
        }
    }

    if (!n_minus_1_found) {
        // If n-1 is not present in the reconstructed p, it means that
        // the true maximum value 'n' was always the larger element in min(p_i, p_j)
        // for the element that should be 'n'.
        // In this case, the maximum value in p will be n-1, and we need to change it to n.
        // This logic is slightly flawed. The correct logic is:
        // If the maximum value in the *reconstructed* p is less than n,
        // it means the true maximum value 'n' was never the minimum in any pair.
        // So, we need to find the maximum value in the reconstructed p and increment it.
        // Since the problem guarantees a solution, and p is a permutation of 1..n,
        // if the maximum value in p is not n, it must be n-1.
        // And there must be exactly one such element.
        int max_in_p = 0;
        for (int val : p) {
            if (val > max_in_p) {
                max_in_p = val;
            }
        }
        if (max_in_p < n) { // This implies max_in_p is n-1
            for (int i = 0; i < n; ++i) {
                if (p[i] == max_in_p) {
                    p[i] = n;
                    break; // Only one such element needs to be changed
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

