                // We need d to be at least this value.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current cell (i+1)
                                    // because we can jump right from here.
            }
        }

        // After iterating through the string, we need to consider the jump
        // from the last 'R' cell (or cell 0 if no 'R's) to cell n+1.
        // The distance required for this final jump is (n+1) - last_R_pos.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The number of teams is limited by the minimum of coders and mathematicians,
        // as each team needs at least one of each.
        // It's also limited by the total number of students divided by 3.
        // So, an initial upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'low_bound'.
        // The actual answer will be between 0 and this low_bound.

        // We can use binary search for the answer.
        // Let's say we want to form 'k' teams.
        // To form 'k' teams, we need at least 'k' coders and 'k' mathematicians.
        // So, c >= k and m >= k must hold.
        // Also, we need 3*k students in total.
        // The total students available are c + m + x.
        // So, c + m + x >= 3*k must hold.

        // The most restrictive condition is usually min(c, m).
        // If we have k teams, we use k coders and k mathematicians at minimum.
        // The remaining students are (c-k) coders, (m-k) mathematicians, and x unspecialized.
        // These remaining students must fill the remaining k slots (3k total students - k coders - k mathematicians = k remaining slots).
        // The total number of remaining students is (c-k) + (m-k) + x.
        // This sum must be at least k.
        // So, (c-k) + (m-k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // (c + m + x) / 3 >= k

        // So, k must satisfy:
        // 1. k <= c
        // 2. k <= m
        // 3. k <= (c + m + x) / 3

        // Combining these, k <= min(c, m, (c + m + x) / 3).
        // This minimum value is the maximum possible number of teams.

        long long ans = std::min({c, m, (c + m + x) / 3});

        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top part of the carrot up to the i-th cut (from apex)
        // should be i times the area of a single piece.
        // Total area of carrot = (1/2) * base * height = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area of top part up to i-th cut = i * (h / (2n)).
        //
        // Let x_i be the distance from the apex to the i-th cut.
        // The small triangle formed by the cut at x_i is similar to the original carrot.
        // If its height is x_i, its base is x_i / h (since original base is 1, height h).
        // Area of this small triangle = (1/2) * (x_i / h) * x_i = x_i^2 / (2h).
        //
        // Equating the two expressions for the area:
        // x_i^2 / (2h) = i * (h / (2n))
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left++;
        } else {
            p[i] = right--;
        }
    }

    // The remaining elements are just increasing sequence
    // from the last used number (either left or right)
    // The last number used was either left-1 or right+1.
    // The next number to use is left (if k is even) or right (if k is odd).
    // Since left was incremented and right was decremented,
    // if k is even, p[k] = left-1, and next available is left.
    // if k is odd, p[k] = right+1, and next available is right.
    // In both cases, the next available number is min(left, right).
    // Since left has been incremented k/2 + 1 times and right has been decremented (k+1)/2 times,
    // and they started as 1 and k+1,
    // the next available number is left.
    // For example, if k=2: p[0]=1, p[1]=3, p[2]=2. left=2, right=2. Next is 2.
    // For example, if k=3: p[0]=1, p[1]=4, p[2]=2, p[3]=3. left=3, right=3. Next is 3.
    // So the next number to fill is `left`.
    for (int i = k + 1; i < n; ++i) {
        p[i] = left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            // We can pick an opening bracket if we still need more opening brackets
            // AND if picking it won't make it impossible to form a valid sequence of length k.
            // Specifically, we need to ensure that after picking this '(',
            // the remaining length to fill (k - result.length() - 1) is at least 'balance + 1'
            // (the number of closing brackets needed to balance current 'balance + 1').
            // Or, more simply, we need to ensure we don't pick too many '(' such that we can't balance them with ')'
            // from the remaining 'close_count_needed' slots.
            // The number of ')' we can still pick is k/2 - close_count.
            // If we pick '(', balance becomes 'balance + 1'.
            // We need 'balance + 1' closing brackets to balance.
            // We have 'k/2 - close_count' available ')' slots.
            // So, we must have 'balance + 1 <= k/2 - close_count'.
            // This is equivalent to 'balance < k/2 - close_count'.
            // Or, 'balance + close_count < k/2'.
            // This is the same as 'open_count < k/2'.
            // So, if we still need opening brackets (open_count < k/2), we can pick it.
            // The balance condition for regular bracket sequence will be maintained by the problem constraints
            // and the fact that we only pick k/2 open and k/2 close.
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // We can pick a closing bracket if we still need more closing brackets
            // AND if the current balance is positive (to maintain regularity).
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

