    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. min_idx and max_idx are pos[1].
        // Length is 1. Max value is 1.
        // For m > 1, we consider the number m.
        // The segment that contains 1, 2, ..., m must span from min(pos[1...m]) to max(pos[1...m]).
