        // When we consider m, we update min_idx and max_idx to include pos[m].
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // The current segment spans from min_idx to max_idx.
        // Its length is (max_idx - min_idx + 1).
        // For this segment to be a permutation of 1...m, two conditions must hold:
        // 1. Its length must be exactly m.
        // 2. The maximum value in this segment must be m. (This is implicitly true because we are expanding the segment to include m, and all values 1 to m-1 are already covered, and m is the largest value considered so far).
        if ((max_idx - min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
