void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_ok: minimum value for a[i] to satisfy a[0] < a[1] < ... < a[i]
    // Specifically, a[i] must be at least i.
    // prefix_ok[i] is true if a[i] >= i.
    std::vector<bool> prefix_ok(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            prefix_ok[i] = true;
        } else {
            prefix_ok[i] = false;
        }
    }

    // Calculate suffix_ok: minimum value for a[i] to satisfy a[i] > a[i+1] > ... > a[n-1]
    // Specifically, a[i] must be at least (n-1-i).
    // suffix_ok[i] is true if a[i] >= (n-1-i).
    std::vector<bool> suffix_ok(n);
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            suffix_ok[i] = true;
        } else {
            suffix_ok[i] = false;
        }
    }

    // Check if there exists a peak index k (0-indexed) such that:
    // 1. a[0] < a[1] < ... < a[k] (can be satisfied if a[i] >= i for all i <= k)
    // 2. a[k] > a[k+1] > ... > a[n-1] (can be satisfied if a[i] >= (n-1-i) for all i >= k)
    // The condition for a peak k is that prefix_ok[k] is true AND suffix_ok[k] is true.
    // This means we can make b_k = k and b_k = n-1-k.
    // The actual value of b_k would be max(k, n-1-k).
    // Since a[k] must be able to be decreased to satisfy both, a[k] must be >= max(k, n-1-k).
    // Our prefix_ok[k] checks a[k] >= k.
    // Our suffix_ok[k] checks a[k] >= n-1-k.
    // So if both are true, a[k] >= k AND a[k] >= n-1-k, which implies a[k] >= max(k, n-1-k).
    // This is exactly what we need for the peak element.

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (prefix_ok[k] && suffix_ok[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

