int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for the elements we want to place (larger ones)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (smaller ones)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1], a[j+2], ... will also be > a[i]
        // We want to use the smallest possible a[j] that satisfies a[j] > a[i]
        // This greedy approach maximizes the remaining elements for subsequent comparisons.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'larger' pool
        } else {
            // No more elements in 'a' are greater than a[i]
            // Since 'a' is sorted, no subsequent a[k] (k > i) will have a greater element available either.
            break; 
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create a map to store the original indices of B values
    // For each B_i, we need to know its original position to place A'_i
    std::vector<int> b_original_indices(m);
    for (int i = 0; i < m; ++i) {
        b_original_indices[b_elements[i].original_index] = i;
    }

    // Calculate A'_i values
    // A'_i = A[m-1-j] where j is the rank of B_i in sorted B
    // This means A'_i = a_elements[m - 1 - b_original_indices[i]].value
    std::vector<long long> a_prime(m);
    for (int i = 0; i < m; ++i) {
        // b_original_indices[i] gives the rank of original B[i] in the sorted B array.
        // We want to pair the smallest B values with the largest A values.
        // So, if original B[i] is the j-th smallest B value (0-indexed),
        // we pair it with the (m-1-j)-th largest A value.
        // The (m-1-j)-th largest A value is a_elements[m-1-j].value
        // where j = b_original_indices[i].
        a_prime[i] = a_elements[m - 1 - b_original_indices[i]].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

