    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[k] is true if a[0...k-1] is a permutation of length k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[k - 1];
        if (val > k || seen_prefix[val]) {
            possible_prefix = false;
        }
        if (!possible_prefix) {
            is_prefix_perm[k] = false;
        } else {
            seen_prefix[val] = true;
            current_max_prefix = std::max(current_max_prefix, val);
            if (current_max_prefix == k) {
                is_prefix_perm[k] = true;
            } else {
                is_prefix_perm[k] = false;
            }
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[k] is true if a[n-k...n-1] is a permutation of length k
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[n - k];
        if (val > k || seen_suffix[val]) {
            possible_suffix = false;
        }
        if (!possible_suffix) {
            is_suffix_perm[k] = false;
        } else {
            seen_suffix[val] = true;
            current_max_suffix = std::max(current_max_suffix, val);
            if (current_max_suffix == k) {
                is_suffix_perm[k] = true;
            } else {
                is_suffix_perm[k] = false;
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 is length of p1, l2 is length of p2
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

