char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char ch : s) {
            counts[ch]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Prioritize R, then P, then S for tie-breaking if counts are equal
        // This is not strictly necessary for correctness, any choice among max_count is fine.
        // But it ensures deterministic output matching example if tie-breaking is needed.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        // If all counts are 0 (empty string, though n >= 1), or if only one type of char,
        // the above logic correctly picks it.
        // If multiple types have max_count, the one with highest priority (P then R then S) is chosen.
        // Example: R=2, P=2, S=1. max_count=2.
        // Initially R is picked. Then P is checked, P=2 > max_count=2 is false.
        // This means the order of if statements matters.
        // Let's re-evaluate to pick the one that wins against the most frequent.
        // We want to pick a move that beats the most frequent bot move.
        // So we need to find the most frequent bot move first.

        // Correct logic for finding most frequent:
        // Iterate through R, P, S and find the one with max count.
        // If counts are equal, any choice is fine.
        // To be deterministic, we can pick 'R' if counts['R'] is max,
        // else 'P' if counts['P'] is max, else 'S'.
        // Or simply, the one that appears first in 'RPS' order.

        max_count = counts['R'];
        most_frequent_bot_move = 'R';

        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // This ensures that if R, P, S all have same max count, R is chosen.
        // If P, S have same max count and R is less, P is chosen.
        // If S has max count and R, P are less, S is chosen.
        // This is a valid tie-breaking rule.

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
