#include <functional>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We want to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
        // Let S = current_sum, X = current_xor_sum
        // We need S' = 2 * X'
        // S' = S + b1 + b2 + b3
        // X' = X ^ b1 ^ b2 ^ b3

        // Strategy: Append at most 3 elements.
        // The problem statement guarantees a solution always exists.
        // A common strategy for these problems is to try to make the XOR sum equal to the sum divided by 2.
        // Or, more generally, to make the sum and XOR sum satisfy the property.

        // Consider appending two elements: X and S + X.
        // Let's try to append two elements:
        // b1 = current_xor_sum
        // b2 = current_sum + current_xor_sum
        //
        // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum
        //
        // New sum: S' = current_sum + b1 + b2
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * (current_sum + current_xor_sum)
        //
        // Check condition: S' = 2 * X'
        // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
        // This always holds!

        // So, we can always append two elements: current_xor_sum and current_sum + current_xor_sum.
        // The problem asks for at most 3 elements. This solution uses 2 elements.
        // The values can be large, up to 10^9 for initial elements, so current_sum can be up to 10^5 * 10^9 = 10^14.
        // current_xor_sum can be up to 2^30 (approx 10^9).
        // So b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
    return 0;
}

#include <iostream>
