int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that were counted twice (i.e., points with same (x,y) coordinates)
    // These are points that lie on the same vertical line AND same horizontal line.
    // If there are 'k' identical points, they form k*(k-1)/2 pairs.
    // Each such pair (P_i, P_j) where P_i = P_j = (x,y) is counted in x_counts and y_counts.
    // So, for each group of 'k' identical points, k*(k-1)/2 pairs are counted twice.
    // We need to subtract k*(k-1)/2 for each such group.
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
    // This is the only way to definitively set characters in w to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // For each s[i], check if it can be '1' based on w.
    // If s[i] is '1', but our w cannot make it '1', then it's impossible.
    for (int i = 0; i < n; ++i) {
        bool can_be_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            can_be_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            can_be_one = true;
        }

        if (s[i] == '1' && !can_be_one) {
            std::cout << -1 << std::endl;
            return;
        }
        // If s[i] is '0', and can_be_one is true, it means our w would make s[i] a '1'.
        // But we initialized w such that if s[i] was '0', we forced w[i-x] and w[i+x] to '0'.
        // So, if s[i] is '0', can_be_one must be false.
        // This check is implicitly handled by the construction of w.
        // If s[i] was '0', we set w[i-x] and w[i+x] to '0'.
        // Then, when we check can_be_one for this s[i], both w[i-x] and w[i+x] will be '0' (if they exist),
        // so can_be_one will correctly be false.
    }

    std::cout << w << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

