long long solve() {
    long long n;
    std::cin >> n;

    if (n % 2 != 0) {
        // If N is odd, Chanek must take 1 coin.
        // N becomes N-1 (even).
        // The opponent will then face an even number of coins.
        // Chanek gets 1 coin.
        return 1;
    } else {
        // N is even. Chanek has two choices: take 1 or take N/2.
        // Chanek wants to maximize his coins.
        // Opponent wants to maximize his coins.

        // Case 1: Chanek takes 1 coin.
        // N becomes N-1 (odd).
        // Opponent faces N-1 coins. Since N-1 is odd, opponent must take 1 coin.
        // N becomes N-2 (even).
        // The game continues with N-2 coins, and it's Chanek's turn.
        // This strategy gives Chanek 1 coin in this turn.

        // Case 2: Chanek takes N/2 coins.
        // N becomes N/2.
        // Opponent faces N/2 coins.
        // This strategy gives Chanek N/2 coins in this turn.

        // Let's analyze the optimal strategy for Chanek when N is even.
        // Chanek wants to maximize his coins.
        // If Chanek takes N/2, he gets N/2. The remaining N/2 coins are for the opponent to play with.
        // If Chanek takes 1, he gets 1. The remaining N-1 coins are for the opponent to play with.

        // Consider powers of 2.
        // If N is a power of 2 (N = 2^k for k >= 1):
        // Chanek's turn, N coins.
        // If Chanek takes 1: N-1 coins remain. Opponent takes 1 (since N-1 is odd). N-2 coins remain. Chanek's turn.
        // If Chanek takes N/2: N/2 coins remain. Opponent's turn.
        // If N = 2, Chanek takes 1. N=1. Opponent takes 1. Chanek 1, Opponent 1.
        // If N = 4, Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek 2, Opponent 2.
        // If N = 4, Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek 3, Opponent 1.
        // So for N=4, Chanek takes N/2.

        // Let's generalize.
        // If N is a power of 2, say N = 2^k.
        // Chanek's optimal move is to take N/2.
        // He gets N/2. Remaining N/2. Opponent faces N/2.
        // Opponent takes N/4. Remaining N/4. Chanek faces N/4.
        // This continues until N=2.
        // Chanek takes N/2, Opponent takes N/4, Chanek takes N/8, ...
        // The total coins Chanek gets: N/2 + N/8 + N/32 + ...
        // The total coins Opponent gets: N/4 + N/16 + N/64 + ...
        // This sum is N/2 * (1 + 1/4 + 1/16 + ...) = N/2 * (1 / (1 - 1/4)) = N/2 * (1 / (3/4)) = N/2 * 4/3 = 2N/3.
        // This is not quite right because the game ends when N=1.
        // Let's trace N=2^k:
        // C: N/2. Rem: N/2.
        // O: N/4. Rem: N/4.
        // C: N/8. Rem: N/8.
        // ...
        // C: 2. Rem: 2.
        // O: 1. Rem: 1.
        // C: 1. Rem: 0.
        // Chanek's total: N/2 + N/8 + ... + 2 + 1.
        // Opponent's total: N/4 + N/16 + ... + 1.
        // This is a geometric series.
        // Chanek's sum: N/2 + N/8 + ... + 2 + 1 = N/2 * (1 + 1/4 + ... + 1/(2^(k-2))) + 1.
        // This is (N/2) * ( (1 - (1/4)^(k-1)) / (1 - 1/4) ) + 1.
        // This is (N/2) * ( (1 - 1/(2^(2k-2))) / (3/4) ) + 1 = (2N/3) * (1 - 1/(2^(2k-2))) + 1.
        // This is getting complicated.

        // Let's consider the structure of N.
        // If N is even, Chanek can take N/2.
        // If N/2 is odd, then the opponent faces an odd number. Opponent must take 1.
        // N becomes N/2 - 1 (even). Chanek faces N/2 - 1.
        // Chanek gets N/2.
        // If N/2 is even, then the opponent faces an even number. Opponent can take N/4.
        // N becomes N/4. Chanek faces N/4.
        // Chanek gets N/2.

        // The strategy is:
        // If N is odd, Chanek takes 1.
        // If N is even:
        //   If N is a power of 2 (N = 2^k): Chanek takes N/2.
        //   If N is even but not a power of 2 (N = 2^k * M, where M > 1 and M is odd):
        //     Chanek takes 1. N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
        //     Chanek takes N/2. N becomes N/2.

        // Let's test the example N=6.
        // N=6 (even, not power of 2).
        // Option 1: Chanek takes 1. N=5.
        //   Opponent faces 5 (odd). Opponent takes 1. N=4.
        //   Chanek faces 4 (even, power of 2). Chanek takes 4/2=2. N=2.
        //   Opponent faces 2 (even, power of 2). Opponent takes 2/2=1. N=1.
        //   Chanek faces 1 (odd). Chanek takes 1. N=0.
        //   Chanek's total: 1 + 2 + 1 = 4. Opponent's total: 1 + 1 = 2.
        // Option 2: Chanek takes N/2 = 3. N=3.
        //   Opponent faces 3 (odd). Opponent takes 1. N=2.
        //   Chanek faces 2 (even, power of 2). Chanek takes 2/2=1. N=1.
        //   Opponent faces 1 (odd). Opponent takes 1. N=0.
        //   Chanek's total: 3 + 1 = 4. Opponent's total: 1 + 1 = 2.
        // Both options give Chanek 4.

        // It seems that if N is even and not a power of 2, Chanek can choose to take 1 or N/2.
        // If N is even and not a power of 2, it means N = 2^k * M where M > 1 and M is odd.
        // If Chanek takes N/2: he gets N/2. Remaining N/2 = 2^(k-1) * M.
        // If Chanek takes 1: he gets 1. Remaining N-1. Opponent takes 1. Remaining N-2.
        // This is a game where players try to maximize their own score.
        // This is a greedy approach.

        // If N is even:
        // Chanek's turn.
        // If N is a power of 2 (N = 2^k):
        //   Chanek takes N/2. He gets N/2. Remaining N/2.
        //   Opponent faces N/2 (which is 2^(k-1)). Opponent takes N/4. Remaining N/4.
        //   Chanek faces N/4 (which is 2^(k-2)). Chanek takes N/8. Remaining N/8.
        //   ...
        //   This continues until N=2.
        //   Chanek takes 2. Remaining 2.
        //   Opponent takes 1. Remaining 1.
        //   Chanek takes 1. Remaining 0.
        //   Chanek's total: N/2 + N/8 + N/32 + ... + 2 + 1.
        //   Opponent's total: N/4 + N/16 + N/64 + ... + 1.
        //   Let S_C be Chanek's score, S_O be Opponent's score.
        //   S_C = N/2 + N/8 + ... + 2 + 1
        //   S_O = N/4 + N/16 + ... + 1
        //   S_C - S_O = N/2 - N/4 + N/8 - N/16 + ... + 2 - 1 + 1 (if k is odd) or + 2 - 1 (if k is even)
        //   This is N/4 + N/16 + ... + 1.
        //   The total sum is N.
        //   S_C + S_O = N.
        //   S_C = N - S_O.
        //   S_C = N/2 + (N/8 + N/32 + ... + 2) + 1.
        //   S_O = (N/4 + N/16 + ... + 1).
        //   Let's calculate for N=2^k.
        //   N=2: C:1, O:1. Chanek gets 1.
        //   N=4: C:2, O:1, C:1. Chanek gets 3.
        //   N=8: C:4, O:2, C:1, O:1. Chanek gets 5.
        //   N=16: C:8, O:4, C:2, O:1, C:1. Chanek gets 12.
        //   This is not N/2 + N/8 + ... + 1.
        //   The sequence of coins taken by Chanek is N/2, N/8, N/32, ..., 2, 1.
        //   The sequence of coins taken by Opponent is N/4, N/16, N/64, ..., 1.
        //   This is correct.
        //   For N=2^k, Chanek's score is (2^k)/2 + (2^k)/8 + ... + 1.
        //   This is 2^(k-1) + 2^(k-3) + ... + 2^1 + 2^0 if k is odd.
        //   This is 2^(k-1) + 2^(k-3) + ... + 2^2 + 2^0 if k is even.
        //   This is sum of 2^i where i has same parity as k-1, from 0 to k-1.
        //   This is sum_{j=0}^{floor((k-1)/2)} 2^(k-1-2j).
        //   This is a geometric series sum.
        //   For N=2^k, Chanek gets N - (N/4 + N/16 + ... + 1).
        //   S_O = N/4 + N/16 + ... + 1.
        //   S_O = N/4 * (1 + 1/4 + ... + 1/(4^(floor((k-1)/2)-1))).
        //   S_O = N/4 * ( (1 - (1/4)^m) / (1 - 1/4) ) where m is number of terms.
        //   This is too complex.

        // Let's re-evaluate the greedy strategy.
        // If N is even:
        //   If N is a power of 2 (N = 2^k):
        //     Chanek takes N/2. He gets N/2. Remaining N/2.
        //     Opponent faces N/2. Opponent takes N/4. Remaining N/4.
        //     Chanek faces N/4. Chanek takes N/8. Remaining N/8.
        //     ...
        //     This continues until N=2.
        //     Chanek takes 2. Remaining 2.
        //     Opponent takes 1. Remaining 1.
        //     Chanek takes 1. Remaining 0.
        //     Chanek's total: N/2 + N/8 + ... + 2 + 1.
        //     Opponent's total: N/4 + N/16 + ... + 1.
        //     Example N=4: C:2, O:1, C:1. Chanek gets 3.
        //     Example N=8: C:4, O:2, C:1, O:1. Chanek gets 5.
        //     Example N=16: C:8, O:4, C:2, O:1, C:1. Chanek gets 12.
        //     This is not N/2 + N/8 + ... + 1.
        //     The sequence of coins taken by Chanek is N/2, N/8, N/32, ..., 2, 1.
        //     The sequence of coins taken by Opponent is N/4, N/16, N/64, ..., 1.
        //     This is correct.
        //     For N=2^k, Chanek's score is (2^k)/2 + (2^k)/8 + ... + 1.
        //     This is 2^(k-1) + 2^(k-3) + ... + 2^1 + 2^0 if k is odd.
        //     This is 2^(k-1) + 2^(k-3) + ... + 2^2 + 2^0 if k is even.
        //     This is sum of 2^i where i has same parity as k-1, from 0 to k-1.
        //     This is a geometric series sum.
        //     For N=2^k, Chanek gets N - (N/4 + N/16 + ... + 1).
        //     S_O = N/4 + N/16 + ... + 1.
        //     S_O = N/4 * (1 + 1/4 + ... + 1/(4^(floor((k-1)/2)-1))).
        //     S_O = N/4 * ( (1 - (1/4)^m) / (1 - 1/4) ) where m is number of terms.
        //     This is too complex.

        // Let's re-evaluate the greedy strategy.
        // If N is even:
        //   If N is a power of 2 (N = 2^k):
        //     Chanek takes N/2. Remaining N/2.
        //     Opponent faces N/2. Opponent takes N/4. Remaining N/4.
        //     Chanek faces N/4. Chanek takes N/8. Remaining N/8.
        //     ...
        //     This continues until N=2.
        //     Chanek takes 2. Remaining 2.
        //     Opponent takes 1. Remaining 1.
        //     Chanek takes 1. Remaining 0.
        //     Chanek's total: N/2 + N/8 + ... + 2 + 1.
