int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    for (int k = 0; k <= n; ++k) { // k is the number of items taken from the left
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[k-1]
        current_energy += prefix_sum[k] * l;

        // Energy for items taken from the right
        // These are w[k]...w[n-1]
        // The number of items taken from the right is n - k
        current_energy += (prefix_sum[n] - prefix_sum[k]) * r;

        // Add penalty for taking more items from one side
        int num_left = k;
        int num_right = n - k;

        if (num_left > num_right) {
            int diff = num_left - num_right;
            // If diff is 1, no extra penalty.
            // If diff is 2, 1 extra Ql.
            // If diff is 3, 2 extra Ql.
            // In general, (diff - 1) * Ql
            current_energy += (long long)(diff - 1) * Ql;
        } else if (num_right > num_left) {
            int diff = num_right - num_left;
            // Similar logic for Qr
            current_energy += (long long)(diff - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

