    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<int> px(n + 1, 0);
    std::vector<int> py(n + 1, 0);
    std::vector<int> pz(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        px[i + 1] = px[i];
        py[i + 1] = py[i];
        pz[i + 1] = pz[i];
        if (s[i] == 'x') {
            px[i + 1]++;
        } else if (s[i] == 'y') {
            py[i + 1]++;
        } else { // s[i] == 'z'
            pz[i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = px[r] - px[l - 1];
        int count_y = py[r] - py[l - 1];
        int count_z = pz[r] - pz[l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>
#include <map>

// Function to get prime factors of a number
// Returns a map where keys are prime factors and values are their exponents
std::map<long long, int> get_prime_factors(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors[i] = count;
        }
    }
    if (n > 1) {
        factors[n] = 1;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means x must not be divisible by q.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least a_i factors of f_i for all i.
        // To make x not divisible by q, we need to remove at least one factor f_i from p
        // such that the resulting x has fewer than a_i factors of f_i.
        // To maximize x, we should remove as few factors as possible, and specifically,
        // remove factors of f_i that are "least significant" in terms of reducing p.

        std::map<long long, int> q_factors = get_prime_factors(q);
        long long max_x = 1;

        for (auto const& [factor, exponent_q] : q_factors) {
            // For each prime factor 'factor' of q, we need to find a candidate x.
            // This candidate x will be p divided by some power of 'factor'.
            // We want to find the smallest power of 'factor' (let's say factor^k)
            // such that p / (factor^k) is not divisible by q.

            // First, count how many times 'factor' divides p.
            long long temp_p = p;
            int exponent_p = 0;
            while (temp_p > 0 && temp_p % factor == 0) {
                temp_p /= factor;
                exponent_p++;
            }

            // If p has fewer factors of 'factor' than q, then p is not divisible by q.
            // But we already handled p % q != 0 case. So exponent_p must be >= exponent_q.
            // We need to reduce the count of 'factor' in p to be less than exponent_q.
            // The smallest power of 'factor' to divide p by is factor^(exponent_p - exponent_q + 1).
            // This ensures that the resulting number has exponent_q - 1 factors of 'factor',
            // which is less than exponent_q, so it won't be divisible by q (at least for this factor).

            long long current_x = p;
            for (int i = 0; i < exponent_p - exponent_q + 1; ++i) {
                current_x /= factor;
            }

            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::vector<int> colors(n);
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = 1;
                s1_digits.push_back(d[i]);
            } else if (d[i] > p) {
                colors[i] = 2;
                s2_digits.push_back(d[i]);
            }
        }

        // Check if s1_digits is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if s2_digits is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Now handle digits equal to p
        // First pass: assign '1' to d_i == p if it maintains non-decreasing S1
        // Second pass: assign '2' to d_i == p if it maintains non-decreasing S2

        // Find the last digit of S1 before adding p's
        int last_s1 = -1;
        if (!s1_digits.empty()) {
            last_s1 = s1_digits.back();
        }

        // Find the first digit of S2 before adding p's
        int first_s2 = 10;
        if (!s2_digits.empty()) {
            first_s2 = s2_digits.front();
        }

        // Assign digits equal to p
        for (int i = 0; i < n; ++i) {
            if (d[i] == p) {
                if (d[i] >= last_s1) { // Can potentially be part of S1
                    colors[i] = 1;
                    last_s1 = d[i]; // Update last_s1 for subsequent p's
                } else { // Must be part of S2
                    colors[i] = 2;
                }
            }
        }

        // Reconstruct S1 and S2 to check final validity
        s1_digits.clear();
        s2_digits.clear();
        for (int i = 0; i < n; ++i) {
            if (colors[i] == 1) {
                s1_digits.push_back(d[i]);
            } else {
                s2_digits.push_back(d[i]);
            }
        }

        // Check if s1_digits is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if s2_digits is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check the transition between S1 and S2
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_p = false;
            }
        }

        if (possible_p) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

