    long long max_X = 2000000000LL;  // Effectively positive infinity
    long long min_Y = -2000000000LL;
    long long max_Y = 2000000000LL;

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 1: can move left (x_c - 1, y_c)
        // If f1 is 0, robot cannot move left.
        // This means if X < x, the robot cannot reach X.
        // So, X must be >= x.
        if (f1 == 0) {
            min_X = std::max(min_X, x);
        }

        // f2 = 1: can move up (x_c, y_c + 1)
        // If f2 is 0, robot cannot move up.
        // This means if Y > y, the robot cannot reach Y.
        // So, Y must be <= y.
        if (f2 == 0) {
            max_Y = std::min(max_Y, y);
        }

        // f3 = 1: can move right (x_c + 1, y_c)
        // If f3 is 0, robot cannot move right.
        // This means if X > x, the robot cannot reach X.
        // So, X must be <= x.
        if (f3 == 0) {
            max_X = std::min(max_X, x);
        }

        // f4 = 1: can move down (x_c, y_c - 1)
        // If f4 is 0, robot cannot move down.
        // This means if Y < y, the robot cannot reach Y.
        // So, Y must be >= y.
        if (f4 == 0) {
            min_Y = std::max(min_Y, y);
        }
    }

    if (min_X <= max_X && min_Y <= max_Y) {
        // A valid point exists. We can pick any point in the intersection.
        // The problem guarantees that if a solution exists, one exists with
        // coordinates not exceeding 10^5 by absolute value.
        // So, we can clamp min_X and min_Y to this range if they fall outside,
        // but since we are just picking *any* valid point, min_X and min_Y
        // themselves are valid choices if they are within the overall bounds.
        // The initial bounds for min_X/max_X/min_Y/max_Y are large enough
        // to cover the problem's coordinate range.
        // The problem statement guarantees that if a solution exists,
        // one exists with |X|, |Y| <= 10^5.
        // So, we can just output min_X and min_Y.
        std::cout << 1 << " " << min_X << " " << min_Y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

