#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> seen_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        seen_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_for_layout;

    // Find starting points for paths (characters with degree 1 in the adjacency graph)
    // Or any character if all have degree 2 (cycle or single path)
    char start_char = '\0';
    for (char c : seen_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char has degree 1, it means all chars in 's' form a cycle or a single path where all internal nodes have degree 2.
    // If it's a cycle, any char can be a start. If it's a path, and we didn't find degree 1, it means it's a path of length 1 (two chars)
    // or a path where all chars have degree 2 (which is impossible for a path unless it's a cycle).
    // The only case where all chars in 's' have degree 2 is if they form a cycle.
    // If it's a cycle, we can pick any character as a start.
    // If seen_in_s is not empty and start_char is still '\0', it means all characters in seen_in_s have degree 2.
    // This implies a cycle. We can pick any character from seen_in_s as a starting point.
    if (start_char == '\0' && !seen_in_s.empty()) {
        start_char = *seen_in_s.begin();
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first step

        while (visited_for_layout.find(current_char) == visited_for_layout.end()) {
            layout += current_char;
            visited_for_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
            if (current_char == '\0' && adj[prev_char].size() == 2) { // This means we are at the end of a path, but it has two neighbors, implying a cycle.
                                                                       // If it's a cycle, current_char will eventually be the start_char again.
                                                                       // If it's a path, current_char will be '\0' when we reach the end.
                                                                       // The loop condition `visited_for_layout.find(current_char) == visited_for_layout.end()` handles cycles.
            }
        }
    }

    // Add remaining characters not in 's' and not yet in layout
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_for_layout.find(c) == visited_for_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

