int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of k from 1 to a: a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = sum_k * ((MOD + 1) / 2) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = sum_r * ((MOD + 1) / 2) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // The total sum is sum_{k=1 to a} sum_{r=1 to b-1} (k*b*r + r)
    // = sum_{k=1 to a} (k*b * sum_{r=1 to b-1} r + sum_{r=1 to b-1} r)
    // = sum_{k=1 to a} ((k*b + 1) * sum_{r=1 to b-1} r)
    // = (sum_{r=1 to b-1} r) * sum_{k=1 to a} (k*b + 1)
    // = (sum_{r=1 to b-1} r) * (b * sum_{k=1 to a} k + sum_{k=1 to a} 1)
    // = (sum_r) * (b * sum_k + a)

    long long term1 = (b % MOD * sum_k) % MOD;
    long long term2 = (term1 + a % MOD) % MOD;
    long long total_sum = (sum_r * term2) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long N = std::abs(n);
        long long M = std::abs(m);

        if (N > M) {
            std::swap(N, M);
        }

        // N is min(abs(n), abs(m)), M is max(abs(n), abs(m))

        long long ans;
        if ((k - M) % 2 != 0) { // If k and M have different parity
            // We need to make an odd number of "wasted" moves.
            // This means we must use at least one straight move to change parity.
            // The minimum number of moves to reach (N,M) is M.
            // If k < M, it's impossible.
            // If k >= M, we need to make k-M additional moves.
            // Each additional move must be paired with a move back to cancel its effect on distance,
            // or move in a way that doesn't increase distance.
            // For example, (x,y) -> (x+1,y) -> (x,y) uses 2 moves and ends at same spot.
            // (x,y) -> (x+1,y+1) -> (x,y) uses 2 moves and ends at same spot.
            // (x,y) -> (x+1,y) -> (x+1,y+1) -> (x,y+1) uses 3 moves and ends at (x,y+1).
            // The parity of (x+y) changes with each move.
            // The parity of (N+M) must be the same as the parity of k.
            // If (N+M) and k have different parity, it's impossible.
            // (N+M) % 2 != k % 2  is equivalent to (k - (N+M)) % 2 != 0.
            // This is equivalent to (k - M) % 2 != 0 if N is even.
            // This is equivalent to (k - M) % 2 == 0 if N is odd.
            // Let's check the parity of (N+M) and k.
            if ((N + M) % 2 != k % 2) {
                ans = -1;
            } else {
                // If k and M have different parity, and (N+M) and k have same parity,
                // it means N must be odd.
                // We need to make k-M moves.
                // If k-M is odd, we need to make one move that changes parity of (x+y)
                // and then an even number of moves.
                // The maximum number of diagonal moves is k-1.
                // This happens if we make one straight move and k-1 diagonal moves.
                // For example, if we are at (X,Y) and need to reach (X+1, Y+1) in 2 moves.
                // We can do (X,Y) -> (X+1,Y) -> (X+1,Y+1). 1 diagonal.
                // Or (X,Y) -> (X,Y+1) -> (X+1,Y+1). 1 diagonal.
                // Or (X,Y) -> (X+1,Y+1) -> (X,Y). 2 diagonals, but not reaching target.
                // The problem is that we need to reach (N,M) in exactly k moves.
                // If k-M is odd, we must use at least one "wasted" move that changes parity.
                // The most efficient way to change parity of (x+y) without changing final (x,y)
                // is to make a straight move and then a diagonal move that cancels it out.
                // E.g., (0,0) -> (1,0) -> (0,1) -> (1,1). This is 3 moves to reach (1,1).
                // (0,0) -> (1,0) (straight)
                // (1,0) -> (0,1) (diagonal)
                // (0,1) -> (1,1) (diagonal)
                // Total 3 moves, 2 diagonal.
                // The target is (N,M). We can reach (N,M) in M moves using N diagonal moves and M-N straight moves.
                // This path has (N+M) parity.
                // If k has different parity than M, we need to adjust.
                // If k-M is odd, we must use at least one move that changes parity.
                // The maximum number of diagonal moves is k-1.
                // This is achieved by making k-1 diagonal moves and one straight move.
                // For example, if we need to reach (N,M) in k moves.
                // We can reach (N,M) in M moves.
                // If k-M is odd, we need to make an odd number of "wasted" moves.
                // The minimum number of "wasted" moves is 1.
                // This means we use k-1 moves to reach (N,M) and 1 move to go somewhere else and back.
                // Or, we use k-1 moves to reach (N,M) and 1 move to go to (N+1,M) or (N,M+1) etc.
                // The maximum number of diagonal moves is k-1.
                // This is because we must use at least one straight move to change the parity.
                // Example: (2,2) in 3 moves. N=2, M=2, k=3.
                // (k-M)%2 = (3-2)%2 = 1. Odd.
                // (N+M)%2 = (2+2)%2 = 0. k%2 = 1. Different parity.
                // So, ans = -1.
                // Example: (4,3) in 7 moves. N=3, M=4, k=7.
                // (k-M)%2 = (7-4)%2 = 1. Odd.
                // (N+M)%2 = (3+4)%2 = 1. k%2 = 1. Same parity.
                // So, ans = k-1 = 6.
                // This logic seems correct.
                ans = k - 1;
            }
        } else { // If k and M have same parity
            // (k - M) is even.
            // This means we can reach (N,M) in M moves, and then make (k-M)/2 pairs of moves
            // like (x,y) -> (x+1,y) -> (x,y) or (x,y) -> (x+1,y+1) -> (x,y).
            // Each such pair uses 2 moves and results in 0 or 2 diagonal moves.
            // To maximize diagonal moves, we use (x,y) -> (x+1,y+1) -> (x,y).
            // This adds 2 diagonal moves for 2 total moves.
            // So, we can make M moves to reach (N,M), and then (k-M)/2 * 2 moves.
            // The M moves can be N diagonal and M-N straight.
            // The (k-M)/2 pairs can be (k-M)/2 * 2 diagonal moves.
            // Total diagonal moves = N + (k-M).
            // This is k - (M-N).
            // This is the maximum possible.
            ans = k;
        }

        if (k < M) { // If k is less than the maximum coordinate, it's impossible.
            ans = -1;
        }

        std::cout << ans << "\n";
    }
    return 0;
}

