#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

// Function to compute Z-array for a string
std::vector<int> compute_z_array(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Precompute Z-arrays for all cyclic shifts of s
    // z_arrays[i] stores the Z-array for s[i..n-1] + s[0..i-1]
    std::vector<std::vector<int>> z_arrays(n);
    for (int i = 0; i < n; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_arrays[i] = compute_z_array(shifted_s);
    }

    double total_win_prob = 0.0;

    // Iterate over all possible first characters t[0]
    // For each character, find all k such that s[k] == t[0]
    for (char c_val = 'a'; c_val <= 'z'; ++c_val) {
        std::vector<int> k_indices_for_c;
        for (int k = 0; k < n; ++k) {
            if (s[k] == c_val) {
                k_indices_for_c.push_back(k);
            }
        }

        if (k_indices_for_c.empty()) {
            continue; // This character does not appear in s
        }

        // If only one k produces this t[0], Vasya wins for sure
        if (k_indices_for_c.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // If multiple k values produce this t[0], Vasya needs to choose p
        // to maximize his win probability for this specific t[0].
        // The win probability for this t[0] is the maximum over all p.
        double max_win_prob_for_c = 0.0;

        // Iterate over all possible positions p (1-indexed, so p-1 is 0-indexed)
        // Vasya can choose p from 1 to n-1.
        for (int p = 1; p < n; ++p) {
            // For a fixed t[0] (which is c_val) and a fixed p,
            // count how many k values from k_indices_for_c are uniquely determined.
            int unique_k_count_for_p = 0;

            // Iterate over each k_i in k_indices_for_c
            for (int i = 0; i < k_indices_for_c.size(); ++i) {
                int k_i = k_indices_for_c[i];
                char c2_i = s[(k_i + p) % n]; // t[p-1] for this k_i

                bool is_unique = true;
                // Check if any other k_j in k_indices_for_c (j != i)
                // produces the same (t[0], t[p-1]) pair.
                for (int j = 0; j < k_indices_for_c.size(); ++j) {
                    if (i == j) continue;
                    int k_j = k_indices_for_c[j];
                    char c2_j = s[(k_j + p) % n]; // t[p-1] for this k_j

                    if (c2_i == c2_j) {
                        // If t[0] and t[p-1] are the same for k_i and k_j,
                        // Vasya needs to check if the full strings t_i and t_j are identical.
                        // If they are identical, Vasya cannot distinguish them.
                        // If they are different, Vasya might still win if he can distinguish them later.
                        // But the problem states "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                        // This means if (t[0], t[p-1]) pair is not unique, Vasya loses.
                        // However, the problem also says "Vasya wants to know the value of k uniquely".
                        // This implies that if multiple k's produce the same (t[0], t[p-1]) pair,
                        // but those k's correspond to different full strings t, Vasya still loses.
                        // The only way Vasya wins is if the (t[0], t[p-1]) pair uniquely identifies k.
                        // So, if c2_i == c2_j, then k_i is NOT uniquely determined by (c_val, c2_i).
                        is_unique = false;
                        break;
                    }
                }
                if (is_unique) {
                    unique_k_count_for_p++;
                }
            }
            max_win_prob_for_c = std::max(max_win_prob_for_c, (double)unique_k_count_for_p / k_indices_for_c.size());
        }
        total_win_prob += max_win_prob_for_c;
    }

    // The total_win_prob is the sum of (P(t[0]=c) * P(win | t[0]=c)) over all c.
    // P(t[0]=c) is (count of k where s[k]=c) / n.
    // P(win | t[0]=c) is max_win_prob_for_c, which is (count of uniquely determined k) / (count of k where s[k]=c).
    // So, the product is (count of uniquely determined k) / n.
    // The sum of these products is (total count of uniquely determined k over all c and optimal p) / n.
    // This is exactly what total_win_prob accumulates.

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
