int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m;

        // The last digits of k*m repeat in a cycle.
        // The length of the cycle is at most 10, because (k+10)*m % 10 == k*m % 10.
        // Specifically, (k+10)*m % 10 = (k*m + 10*m) % 10 = (k*m % 10 + 10*m % 10) % 10 = (k*m % 10 + 0) % 10 = k*m % 10.
        // So, we only need to compute the first 10 last digits.

        std::vector<long long> cycle_last_digits(10);
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            cycle_sum += cycle_last_digits[i - 1];
        }

        long long num_full_cycles = count / 10;
        long long remaining_elements = count % 10;

        long long total_sum = num_full_cycles * cycle_sum;

        for (int i = 0; i < remaining_elements; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <array>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), track how an input 0 and an input 1 would be transformed.
    // state[bit_idx][input_bit_val]
    // state[b][0] = final value of bit b if initial bit b was 0
    // state[b][1] = final value of bit b if initial bit b was 1
    std::array<std::array<int, 2>, 10> state;

    // Initialize: if input bit is 0, output is 0. If input bit is 1, output is 1.
    for (int b = 0; b < 10; ++b) {
        state[b][0] = 0;
        state[b][1] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int b = 0; b < 10; ++b) {
            int x_b = (x >> b) & 1; // b-th bit of constant x

            if (op_char == '&') {
                state[b][0] &= x_b;
                state[b][1] &= x_b;
            } else if (op_char == '|') {
                state[b][0] |= x_b;
                state[b][1] |= x_b;
            } else { // '^'
                state[b][0] ^= x_b;
                state[b][1] ^= x_b;
            }
        }
    }

    // Now, for each bit b, we have (state[b][0], state[b][1]).
    // This pair represents the transformation:
    // (0,0) -> always 0
    // (0,1) -> identity (x_b)
    // (1,0) -> NOT (1-x_b)
    // (1,1) -> always 1

    // We want to find constants A, B, C such that:
    // (x & A) | B ^ C is equivalent to the final state for all x.
    // This is equivalent to:
    // (x_b & A_b) | B_b ^ C_b = state[b][x_b] for x_b in {0,1}

    // Let's determine A_b, B_b, C_b for each bit b.
    // We need to find a minimal set of operations.
    // The general form is (x & A) | B ^ C.
    // This can be simplified.
    // If we have (x & A) | B, then for x=0, it's B. For x=1, it's A|B.
    // If we have (x ^ C), then for x=0, it's C. For x=1, it's 1^C.

    // Let's try to find A_b, B_b, C_b for each bit b.
    // For each bit b:
    // If (state[b][0], state[b][1]) is (0,0):
    //   We need (0 & A_b) | B_b ^ C_b = 0  => B_b ^ C_b = 0
    //   We need (1 & A_b) | B_b ^ C_b = 0  => A_b | B_b ^ C_b = 0
    //   From B_b ^ C_b = 0, we have B_b = C_b.
    //   Then A_b | B_b = 0. This implies A_b = 0 and B_b = 0.
    //   So, A_b=0, B_b=0, C_b=0.
    //   This means the bit is always 0. This can be achieved by `& 0`.
    //   A_b = 0, B_b = 0, C_b = 0.

    // If (state[b][0], state[b][1]) is (0,1): (identity)
    //   We need (0 & A_b) | B_b ^ C_b = 0  => B_b ^ C_b = 0
    //   We need (1 & A_b) | B_b ^ C_b = 1  => A_b | B_b ^ C_b = 1
    //   From B_b ^ C_b = 0, we have B_b = C_b.
    //   Then A_b | B_b = 1.
    //   This can be achieved by A_b=1, B_b=0, C_b=0. (x & 1) | 0 ^ 0 = x
    //   A_b = 1, B_b = 0, C_b = 0.

    // If (state[b][0], state[b][1]) is (1,0): (NOT)
    //   We need (0 & A_b) | B_b ^ C_b = 1  => B_b ^ C_b = 1
    //   We need (1 & A_b) | B_b ^ C_b = 0  => A_b | B_b ^ C_b = 0
    //   From B_b ^ C_b = 1, we have B_b = 1 - C_b.
    //   Then A_b | 1 = 0. This is impossible.
    //   This means the form (x & A) | B ^ C is not general enough if we restrict A, B, C to be single operations.
    //   Let's re-evaluate. We need to find a sequence of operations.
    //   The problem states "no more than 5 lines".
    //   A sequence of operations can be reduced to at most one AND, one OR, and one XOR.
    //   The order matters: (x & A) | B ^ C is different from (x | B) & A ^ C.
    //   However, it is known that any boolean function of one variable can be expressed as:
    //   f(x) = (x & A) | B  OR  f(x) = (x | B) & A  OR  f(x) = x ^ C  OR  f(x) = C
    //   More generally, any function f(x) can be written as (x & M) ^ K.
    //   Let's check this:
    //   If f(0)=0, f(1)=0: M=0, K=0. (x & 0) ^ 0 = 0.
    //   If f(0)=0, f(1)=1: M=1, K=0. (x & 1) ^ 0 = x.
    //   If f(0)=1, f(1)=0: M=1, K=1. (x & 1) ^ 1 = 1-x.
    //   If f(0)=1, f(1)=1: M=0, K=1. (x & 0) ^ 1 = 1.
    //   This means for each bit b, we can find M_b and K_b such that the transformation is (x_b & M_b) ^ K_b.
    //   So, the entire transformation can be written as (x & M) ^ K.
    //   This is two operations: one AND and one XOR.

    // Let's calculate M and K.
    int M = 0; // Mask for AND operation
    int K = 0; // Mask for XOR operation

    for (int b = 0; b < 10; ++b) {
        if (state[b][0] == 0 && state[b][1] == 0) { // Always 0
            // (x_b & 0) ^ 0 = 0
            // M_b = 0, K_b = 0
        } else if (state[b][0] == 0 && state[b][1] == 1) { // Identity
            // (x_b & 1) ^ 0 = x_b
            M |= (1 << b); // M_b = 1
            // K_b = 0
        } else if (state[b][0] == 1 && state[b][1] == 0) { // NOT
            // (x_b & 1) ^ 1 = 1 - x_b
            M |= (1 << b); // M_b = 1
            K |= (1 << b); // K_b = 1
        } else { // state[b][0] == 1 && state[b][1] == 1 (Always 1)
            // (x_b & 0) ^ 1 = 1
            // M_b = 0
            K |= (1 << b); // K_b = 1
        }
    }

    // The resulting program is (x & M) ^ K.
    // This is at most two operations.
    // However, the problem statement implies we might need up to 5 operations.
    // The standard reduction for arbitrary boolean functions of one variable is:
    // f(x) = (x & A) | (x' & B)
    // where x' is NOT x.
    // This can be written as (x & A) | ((~x) & B).
    // For a single bit: f(x_b) = (x_b & A_b) | ((1-x_b) & B_b).
    // Let's check this:
    // f(0) = (0 & A_b) | (1 & B_b) = B_b
    // f(1) = (1 & A_b) | (0 & B_b) = A_b
    // So, A_b = state[b][1] and B_b = state[b][0].
    // This means the function is (x & state[b][1]) | ((~x) & state[b][0]).
    // This is equivalent to (x & state[b][1]) | (~x & state[b][0]).
    // This can be implemented with 3 operations:
    // 1. x = x & state[b][1] (let's call this A_val)
    // 2. x = x | state[b][0] (let's call this B_val)
    // 3. x = x ^ C_val (if needed)

    // Let's define three constants:
    // AND_const: bits that must be 1 for identity or NOT, 0 for always 0 or 1.
    // OR_const: bits that must be 1 for always 1, 0 for identity or NOT.
    // XOR_const: bits that must be flipped for NOT or always 1.

    int final_AND_val = 1023; // Start with all bits 1 for AND
    int final_OR_val = 0;     // Start with all bits 0 for OR
    int final_XOR_val = 0;    // Start with all bits 0 for XOR

    for (int b = 0; b < 10; ++b) {
        if (state[b][0] == 0 && state[b][1] == 0) { // Always 0
            // To make bit b always 0:
            // AND with 0: final_AND_val &= ~(1 << b);
            // OR with 0: final_OR_val |= 0;
            // XOR with 0: final_XOR_val ^= 0;
            // This means: (x & 0) | 0 ^ 0 = 0
            final_AND_val &= ~(1 << b); // Set A_b to 0
            // B_b = 0, C_b = 0
        } else if (state[b][0] == 0 && state[b][1] == 1) { // Identity
            // To make bit b identity:
            // AND with 1: final_AND_val |= (1 << b);
            // OR with 0: final_OR_val |= 0;
            // XOR with 0: final_XOR_val ^= 0;
            // This means: (x & 1) | 0 ^ 0 = x
            // A_b = 1, B_b = 0, C_b = 0
        } else if (state[b][0] == 1 && state[b][1] == 0) { // NOT
            // To make bit b NOT:
            // AND with 1: final_AND_val |= (1 << b);
            // OR with 0: final_OR_val |= 0;
            // XOR with 1: final_XOR_val ^= (1 << b);
            // This means: (x & 1) | 0 ^ 1 = 1-x
            // A_b = 1, B_b = 0, C_b = 1
            final_XOR_val |= (1 << b);
        } else { // state[b][0] == 1 && state[b][1] == 1 (Always 1)
            // To make bit b always 1:
            // AND with 0: final_AND_val &= ~(1 << b);
            // OR with 1: final_OR_val |= (1 << b);
            // XOR with 0: final_XOR_val ^= 0;
            // This means: (x & 0) | 1 ^ 0 = 1
            final_AND_val &= ~(1 << b); // Set A_b to 0
            final_OR_val |= (1 << b);   // Set B_b to 1
            // C_b = 0
        }
    }

    // The operations are applied in the order: AND, then OR, then XOR.
    // (x & final_AND_val) | final_OR_val ^ final_XOR_val
    // This is a sequence of at most 3 operations.

    std::vector<std::pair<char, int>> result_ops;
    if (final_AND_val != 1023) { // If not all bits are 1 for AND, we need an AND operation
        result_ops.push_back({'&', final_AND_val});
    }
    if (final_OR_val != 0) { // If not all bits are 0 for OR, we need an OR operation
        result_ops.push_back({'|', final_OR_val});
    }
    if (final_XOR_val != 0) { // If not all bits are 0 for XOR, we need an XOR operation
        result_ops.push_back({'^', final_XOR_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1; // Blueberry jam
        } else {
            a[i] = 1; // Strawberry jam
        }
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // and suffix sums for the right half (jars n+1 to 2n)
    // The sums are differences (strawberry count - blueberry count)

    // Left half: jars 0 to n-1 (0-indexed)
    // prefix_diff[k] = sum of a[0]...a[k-1]
    // prefix_diff[0] = 0 (empty prefix)
    // prefix_diff[k] = sum of first k jars from left
    std::vector<int> prefix_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_diff[i + 1] = prefix_diff[i] + a[i];
    }

    // Right half: jars n to 2n-1 (0-indexed)
    // suffix_diff[k] = sum of a[2n-1]...a[2n-k]
    // suffix_diff[0] = 0 (empty suffix)
    // suffix_diff[k] = sum of first k jars from right
    std::vector<int> suffix_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        suffix_diff[i + 1] = suffix_diff[i] + a[2 * n - 1 - i];
    }

    // Map to store the minimum number of jars removed from the left
    // to achieve a certain balance difference.
    // key: balance difference, value: number of jars removed (L)
    std::map<int, int> left_diff_to_L;
    for (int L = 0; L <= n; ++L) {
        int current_diff = prefix_diff[L];
        if (left_diff_to_L.find(current_diff) == left_diff_to_L.end()) {
            left_diff_to_L[current_diff] = L;
        }
    }

    int min_jars_removed = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars removed from the right (R)
    for (int R = 0; R <= n; ++R) {
        int current_right_diff = suffix_diff[R];
        // We want the remaining jars to have a total balance of 0.
        // The jars removed from the left have balance `prefix_diff[L]`.
        // The jars removed from the right have balance `suffix_diff[R]`.
        // The total initial balance is `prefix_diff[n] + suffix_diff[n]`.
        // The remaining balance is `(prefix_diff[n] + suffix_diff[n]) - prefix_diff[L] - suffix_diff[R]`.
        // We want this to be 0.
        // So, `prefix_diff[L] + suffix_diff[R]` must be equal to `prefix_diff[n] + suffix_diff[n]`.
        // Let `total_initial_diff = prefix_diff[n] + suffix_diff[n]`.
        // We need `prefix_diff[L] = total_initial_diff - suffix_diff[R]`.

        int target_left_diff = (prefix_diff[n] + suffix_diff[n]) - current_right_diff;

        if (left_diff_to_L.count(target_left_diff)) {
            int L = left_diff_to_L[target_left_diff];
            min_jars_removed = std::min(min_jars_removed, L + R);
        }
    }

    std::cout << min_jars_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

