#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // When an 'a' interacts with this 'b', it effectively
            // "jumps over" it and creates a new 'b'.
            // The number of 'a's currently to the left (count_a)
            // will each interact with this 'b'.
            // Each interaction adds count_a to total_steps.
            // After these interactions, this 'b' effectively doubles
            // the number of 'a's that will interact with 'b's further left.
            // So, count_a doubles for the next 'b' encountered.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // interact with all 'b's to its right.
            // The number of 'b's it will interact with is count_a.
            // So, we increment count_a by 1.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

