struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> min_val_at_idx(n, LLONG_MAX); // min_val_at_idx[i] stores the maximum possible value for initial_a[i]

    // Initialize min_val_at_idx based on type 2 operations
    // For each type 2 op (l, r, m), initial_a[j] + current_d[j] <= m for all j in [l, r]
    // This means initial_a[j] <= m - current_d[j]
    // We need to find the maximum possible initial_a[j] that satisfies all constraints.
    // Let's iterate through operations in reverse to determine initial_a[j] bounds.
    // This approach is incorrect. The current_d[j] depends on operations *before* the current one.
    // We need to determine initial_a[j] values.
    // A good strategy is to set initial_a[j] to be as small as possible,
    // then check if it satisfies all conditions.
    // Or, set initial_a[j] to be as large as possible.

    // Let's try to determine the maximum possible value for each initial_a[i].
    // For each type 2 operation (l, r, m), we know that for all j in [l, r],
    // initial_a[j] + (sum of d's applied to j before this op) <= m.
    // This means initial_a[j] <= m - (sum of d's applied to j before this op).
    // We want to find the largest possible initial_a[j] that satisfies all such constraints.
    // So, initial_a[j] must be less than or equal to the minimum of (m - current_d[j]) over all relevant type 2 ops.

    // First, calculate the maximum possible value for each initial_a[i].
    // We can iterate through operations and maintain a prefix sum of d's.
    // For each type 2 operation, update the upper bound for initial_a[j].

    std::vector<long long> current_d_prefix_sum(n + 1, 0); // current_d_prefix_sum[i] = sum of d's for a[i-1]
    std::vector<long long> current_d_at_op_start(n, 0); // current_d_at_op_start[i] stores the sum of d's applied to a[i] *before* any operations are processed.
                                                        // This is not what we need. We need current_d[j] *at the time of the type 2 operation*.

    // Let's store the current_d values for each index at the time of each type 2 operation.
    std::vector<std::vector<long long>> d_values_at_type2_ops(m, std::vector<long long>(n));

    std::vector<long long> current_d_for_simulation(n, 0); // This will track the accumulated d for each index
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_d_for_simulation[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = 0; j < n; ++j) {
                d_values_at_type2_ops[i][j] = current_d_for_simulation[j];
            }
        }
    }

    // Now, determine the maximum possible initial_a[j] values
    for (int j = 0; j < n; ++j) {
        min_val_at_idx[j] = LLONG_MAX; // Represents the upper bound for initial_a[j]
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long m_val = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                // initial_a[j] + d_values_at_type2_ops[i][j] <= m_val
                // initial_a[j] <= m_val - d_values_at_type2_ops[i][j]
                min_val_at_idx[j] = std::min(min_val_at_idx[j], m_val - d_values_at_type2_ops[i][j]);
            }
        }
    }

    // If min_val_at_idx[j] is still LLONG_MAX, it means initial_a[j] has no upper bound from type 2 ops.
    // We can set it to 0, or any value within [-10^9, 10^9]. Let's set it to 0.
    for (int j = 0; j < n; ++j) {
        if (min_val_at_idx[j] == LLONG_MAX) {
            initial_a[j] = 0;
        } else {
            initial_a[j] = min_val_at_idx[j];
        }
    }

    // Now, verify if this initial_a works
    std::fill(current_d_for_simulation.begin(), current_d_for_simulation.end(), 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_d_for_simulation[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_d_for_simulation[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
