struct Child {
    long long v, d, p;
    int original_idx;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_in_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_in_line.push_back({v_val, d_val, p_val, i + 1});
    }

    std::vector<int> treated_children_indices;

    while (!children_in_line.empty()) {
        Child current_child = children_in_line.front();
        children_in_line.pop_front();
        treated_children_indices.push_back(current_child.original_idx);

        long long current_v_cry = current_child.v;
        long long accumulated_d_cry = 0;

        auto it = children_in_line.begin();
        while (it != children_in_line.end()) {
            // Apply current_v_cry reduction
            if (current_v_cry > 0) {
                it->p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated_d_cry reduction
            it->p -= accumulated_d_cry;

            if (it->p < 0) {
                accumulated_d_cry += it->d;
                it = children_in_line.erase(it); // Child leaves, iterator invalidated
            } else {
                ++it; // Move to next child
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

