#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> assignment(n);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // This means all f(a_i, a_j) = a_i + a_j.
    // min_f = a_1 + a_2, max_f = a_{n-1} + a_n.
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2).
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);

    // Case 2: Partition into two non-empty subsequences.
    // The minimum possible f value is a_1 + a_2.
    // The maximum possible f value is a_{n-1} + a_n + h.
    // This happens if a_1 and a_2 are in the same group, and a_{n-1} and a_n are in different groups.
    // Or if a_1 and a_2 are in different groups, and a_{n-1} and a_n are in the same group.
    // Or if a_1 and a_2 are in different groups, and a_{n-1} and a_n are in different groups.
    // The minimum f value is always a_1 + a_2 (if a_1, a_2 are same group) or a_1 + a_2 + h (if a_1, a_2 are diff group).
    // The maximum f value is always a_{n-1} + a_n (if a_{n-1}, a_n are same group) or a_{n-1} + a_n + h (if a_{n-1}, a_n are diff group).

    // Consider a partition where elements[0] is in S1, and elements[1] is in S2.
    // And elements[n-1] is in S2, elements[n-2] is in S1.
    // This ensures a_1+a_2+h is a possible value, and a_{n-1}+a_n+h is a possible value.
    // The minimum f value is min(a_1+a_2+h, a_1+a_k, a_2+a_k, ...).
    // The maximum f value is max(a_{n-1}+a_n+h, a_{n-1}+a_k, a_n+a_k, ...).

    // Let's consider the specific partition strategy:
    // elements[0] in S1.
    // elements[1] to elements[n-1] in S2.
    // This ensures a_1 and a_2 are in different groups.
    // This ensures a_{n-1} and a_n are in the same group (if n > 2).
    // min_f = elements[0].value + elements[1].value + h (from elements[0] in S1, elements[1] in S2)
    // max_f = elements[n-1].value + elements[n-2].value (from elements[n-1], elements[n-2] in S2)
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value + h)
    // This is only valid if elements[n-1].value + elements[n-2].value >= elements[0].value + elements[1].value + h.
    // If not, then the min_f is not elements[0].value + elements[1].value + h.
    // The minimum value of f is min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value).
    // The maximum value of f is max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value).

    // Let's analyze the two main cases for optimal partition:
    // 1. All elements in one group.
    //    min_f = a_1 + a_2
    //    max_f = a_{n-1} + a_n
    //    Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    //    This is `goodness1`.

    // 2. Elements are split into two groups.
    //    The minimum possible value for f is `min(a_1 + a_2, a_1 + a_2 + h)`.
    //    The maximum possible value for f is `max(a_{n-1} + a_n, a_{n-1} + a_n + h)`.
    //    To minimize goodness, we want to make min_f as large as possible and max_f as small as possible.
    //    If we put a_1 and a_2 in different groups, min_f becomes a_1 + a_2 + h.
    //    If we put a_{n-1} and a_n in the same group, max_f becomes a_{n-1} + a_n.
    //    This strategy gives goodness = (a_{n-1} + a_n) - (a_1 + a_2 + h).
    //    This is a candidate for minimal goodness.
    //    This strategy is achieved by putting a_1 in group 1, and all other elements (a_2, ..., a_n) in group 2.
    //    With this partition:
    //    - Pairs (a_1, a_j) for j > 1: f = a_1 + a_j + h. Smallest is a_1 + a_2 + h. Largest is a_1 + a_n + h.
    //    - Pairs (a_i, a_j) for i, j > 1: f = a_i + a_j. Smallest is a_2 + a_3. Largest is a_{n-1} + a_n.
    //    So, min_f = min(a_1 + a_2 + h, a_2 + a_3).
    //    And max_f = max(a_1 + a_n + h, a_{n-1} + a_n).
    //    Goodness = max(a_1 + a_n + h, a_{n-1} + a_n) - min(a_1 + a_2 + h, a_2 + a_3).
    //    Let's call this `goodness2`.

    long long min_f_val_case2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    if (n == 2) { // Special case for n=2, a_2+a_3 is not possible
        min_f_val_case2 = elements[0].value + elements[1].value + h;
    }

    long long max_f_val_case2 = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 1].value + elements[n - 2].value);

    long long goodness2 = max_f_val_case2 - min_f_val_case2;

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << std::endl;
        for (int i = 0; i < n; ++i) {
            assignment[elements[i].original_index] = 1;
        }
    } else {
        std::cout << goodness2 << std::endl;
        assignment[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            assignment[elements[i].original_index] = 2;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << assignment[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

