    // dp[x] will store a pair {delta_x, delta_y}
    // If we start at x and take one "full cycle" (x+a_x, y+a_x then x-a_x, y+a_x),
    // and land at x', then dp[x] = {x' - x, total_y_change}.
    // This is not quite right. dp[x] should store the final y value if we start at x
    // and the first move is x = x - a_x, y = y + a_x.
    // Let's redefine dp[x] as the pair {final_x, final_y_increment}
    // if we start at position x and the *next* operation is x = x - a_x, y = y + a_x.
    // This means we are at a state (x, current_y) and the previous operation was x = x + a_prev_x, y = y + a_prev_x.
    // So, the current a_x is a_values[x-1].
    // The operation is: y += a_x, x -= a_x.
    // If this new x is out of bounds, we terminate.
    // Otherwise, we are at (x - a_x, current_y + a_x).
    // From here, the next operation is x += a_new_x, y += a_new_x.
    // This is a recursive structure.
    // Let's define dp[x] as the pair {final_x_offset, final_y_offset}
    // if we are at position x and the *next* operation is x = x + a_x, y = y + a_x.
    // This is the state after the first step (x=1, y=0 -> x=1+a_1, y=a_1).
    // So, for a given x, we are at (x, current_y).
    // The next step is: x_new = x + a_x, y_new = current_y + a_x.
    // If x_new is out of bounds, we terminate.
    // Otherwise, we are at (x_new, y_new).
    // The next step is: y_final = y_new + a_new_x, x_final = x_new - a_new_x.
    // This is a cycle.
    // Let's define dp[x] as the pair {final_x_val, final_y_val} if we start at x
    // and the *first* operation is x = x + a_x, y = y + a_x.
    // This means dp[x] stores the result of the entire game if the game starts with x and the first move is "add a_x".
    // This is exactly what we need for the initial state (1, 0) with a_1.

    // dp[k] stores {final_x, final_y} if we start at position k and the first move is x += a_k, y += a_k.
    // We need to compute this for k from n down to 1.
    // a_k is a_values[k-1] for k > 1.
    // For k = 1, a_1 is the input 'i'.
    std::vector<std::pair<long long, long long>> dp(n + 1);
    std::vector<bool> visited(n + 1, false); // To detect cycles

    // Iterate backwards from n-1 down to 1.
    // For each x, we want to compute dp[x].
    // The value a_x is a_values[x-1].
    // The loop for i from 1 to n-1 means a_1 = i.
    // So, for dp[x], a_x is a_values[x-1] if x > 1.
    // For x=1, a_1 is the current 'i' from the outer loop.
    // This means dp[1] needs to be recomputed for each 'i'.
    // The other dp[x] values (for x > 1) are fixed.

    // Let's compute dp[x] for x from n down to 2.
    // dp[x] = {final_x, final_y_increment} if we start at x and the first move is x += a_x, y += a_x.
    // Here, a_x is a_values[x-1].
    for (int x = n; x >= 2; --x) {
        long long current_a_x = a_values[x - 1]; // a_x for current x

        // Step 1: x_new = x + a_x, y_new = a_x
        long long next_x_after_add = x + current_a_x;
        long long current_y_after_add = current_a_x;

        if (next_x_after_add > n) { // Terminate after first step
            dp[x] = {next_x_after_add, current_y_after_add};
        } else {
            // Step 2: y_final = y_new + a_new_x, x_final = x_new - a_new_x
            // Here a_new_x is a_{next_x_after_add}
            long long a_at_next_x = a_values[next_x_after_add - 1];
            long long next_x_after_sub = next_x_after_add - a_at_next_x;
            long long current_y_after_sub = current_y_after_add + a_at_next_x;

            if (next_x_after_sub <= 0) { // Terminate after second step
                dp[x] = {next_x_after_sub, current_y_after_sub};
            } else {
                // We are now at (next_x_after_sub, current_y_after_sub).
                // The next operation is x += a_x, y += a_x.
                // This is exactly the state for which dp[next_x_after_sub] is defined.
                // So, we can use dp[next_x_after_sub].
                // This is a recursive call. Since we iterate x downwards, dp[next_x_after_sub] should be computed.
                // next_x_after_sub can be > n, in which case it's a termination.
                // next_x_after_sub can be 1, in which case it's a special case for the outer loop.
                // next_x_after_sub can be between 2 and n.
                if (next_x_after_sub > n) { // Terminate
                    dp[x] = {next_x_after_sub, current_y_after_sub};
                } else if (next_x_after_sub == 1) {
                    // This case is tricky. If it lands on 1, it means it will depend on the current 'i'
                    // from the outer loop. We cannot precompute this.
                    // For now, let's mark it as a special value or handle it later.
                    // For now, let's assume it's a termination or a cycle.
                    // This means dp[x] cannot be fully computed if it lands on 1.
                    // This implies that the DP approach needs to be slightly different.
                    // We need to handle the '1' case dynamically.
                    // Let's use a path-finding approach with memoization.
                    // For each starting 'i', we simulate. If we hit a state (x, y) where x > 1,
                    // we can use memoization. If we hit x=1, we need to re-evaluate.
                    // This means dp[x] for x > 1 can be precomputed.
                    // If next_x_after_sub == 1, it means we are back to the start of a new "game"
                    // but with a different a_1. This is not a simple DP.

                    // Let's re-evaluate the DP state.
                    // dp[x] = {final_x_offset, final_y_offset} if we start at x and the first move is x += a_x, y += a_x.
                    // This is for x > 1.
                    // If we land on 1, we cannot use dp[1] because a_1 changes.
                    // So, if next_x_after_sub == 1, we cannot use dp[1].
                    // This means we need to simulate from 1 again.
                    // This suggests that the path from x to 1 is not a simple DP.

                    // Let's use a standard DFS with memoization.
                    // For each starting 'i', we run a DFS.
                    // The DFS state is just `x`.
                    // `solve(x, a_1_val)` returns {final_x, final_y_increment}.
                    // `a_1_val` is the current `i`.
                    // This `a_1_val` makes it difficult to memoize.

                    // The problem states: "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
                    // This means a_1 is set to 'i'.
                    // The values a_2, ..., a_n are fixed.
                    // Let's define `memo[x]` as the result {final_x, final_y_increment} if we start at `x`
                    // and `a_x` is `a_values[x-1]` (i.e., `x > 1`).
                    // This `memo` table can be computed once.
                    // `memo[x]` will store the result of the game if we start at `x` and `x > 1`.
                    // If the path from `x` eventually leads to `1`, then `memo[x]` cannot be fully determined
                    // without knowing `a_1`.
                    // So, `memo[x]` should store {final_x_val, final_y_val} if the path *doesn't* hit `1`.
                    // If it hits `1`, it should store {1, y_increment_to_reach_1}.

                    // Let's define `memo[x]` for `x > 1` as a pair `{target_x, y_accumulated}`.
                    // `target_x` is the final `x` if the path terminates without hitting `1`.
                    // Or `target_x` is `1` if the path hits `1`.
                    // `y_accumulated` is the `y` value accumulated until `target_x` is reached.
                    // If `target_x` is `1`, then `y_accumulated` is the `y` value when `x` becomes `1`.
                    // If `target_x` is `0` or `> n`, then `y_accumulated` is the final `y`.

                    // Initialize `memo` with a special value indicating not computed.
                    std::vector<std::pair<long long, long long>> memo(n + 1, {-2, -2}); // -2 indicates uncomputed
                    std::vector<bool> in_path(n + 1, false); // For cycle detection during DFS

                    // DFS function to compute memo[x] for x > 1
                    // Returns {final_x, final_y_increment}
                    auto compute_memo = [&](auto self, int current_x) -> std::pair<long long, long long> {
                        if (current_x <= 0 || current_x > n) {
                            return {current_x, 0}; // Base case: terminated
                        }
                        if (current_x == 1) {
                            return {1, 0}; // Base case: reached 1. y_increment is 0 from this point.
                        }
                        if (memo[current_x].first != -2) {
                            return memo[current_x]; // Already computed
                        }
                        if (in_path[current_x]) {
                            // Cycle detected. This means non-termination.
                            // Mark as non-terminating.
                            memo[current_x] = {-1, -1};
                            return {-1, -1};
                        }

                        in_path[current_x] = true;

                        long long a_val = a_values[current_x - 1];

                        // Step 1: x_new = current_x + a_val, y_new = a_val
                        long long next_x_after_add = current_x + a_val;
                        long long y_accumulated = a_val;

                        if (next_x_after_add <= 0 || next_x_after_add > n) {
                            in_path[current_x] = false;
                            memo[current_x] = {next_x_after_add, y_accumulated};
                            return memo[current_x];
                        }

                        // Step 2: y_final = y_new + a_new_x, x_final = x_new - a_new_x
                        // a_new_x is a_{next_x_after_add}
                        long long a_at_next_x = a_values[next_x_after_add - 1];
                        long long next_x_after_sub = next_x_after_add - a_at_next_x;
                        y_accumulated += a_at_next_x;

                        // Now we are at (next_x_after_sub, y_accumulated).
                        // The next operation is x += a_x, y += a_x.
                        // This is a recursive call to self.
                        std::pair<long long, long long> res = self(self, next_x_after_sub);

                        in_path[current_x] = false;

                        if (res.first == -1) { // Non-terminating path
                            memo[current_x] = {-1, -1};
                        } else {
                            memo[current_x] = {res.first, y_accumulated + res.second};
                        }
                        return memo[current_x];
                    };

                    // Precompute memo for x from 2 to n
                    for (int x = 2; x <= n; ++x) {
                        if (memo[x].first == -2) { // If not computed yet
                            compute_memo(compute_memo, x);
                        }
                    }

                    // Now, for each i from 1 to n-1:
                    for (int i = 1; i < n; ++i) {
                        long long a_1_val = i; // Current a_1

                        long long current_x = 1;
                        long long current_y = 0;

                        // First step: x = x + a_x, y = y + a_x
                        // Here x=1, a_x = a_1_val
                        current_x += a_1_val;
                        current_y += a_1_val;

                        if (current_x <= 0 || current_x > n) {
                            std::cout << current_y << "\n";
                            continue;
                        }

                        // Second step: y = y + a_x, x = x - a_x
                        // Here a_x is a_{current_x}
                        long long a_at_current_x = a_values[current_x - 1];
                        current_y += a_at_current_x;
                        current_x -= a_at_current_x;

                        if (current_x <= 0 || current_x > n) {
                            std::cout << current_y << "\n";
                            continue;
                        }

                        // Now we are at (current_x, current_y).
                        // The next operation is x += a_x, y += a_x.
                        // We can use the precomputed memo table for current_x > 1.
                        // If current_x == 1, we need to re-evaluate.
                        // This means we have a cycle if we hit 1 again.
                        // This is a tricky part. The problem implies that if it hits 1, it's a new game.
                        // But the problem says "repeatedly until it terminates".
                        // If it hits 1, it means the next a_x is a_1_val again.
                        // This forms a cycle if current_x becomes 1.

                        // Let's simulate this part.
                        // We are at (current_x, current_y).
                        // If current_x == 1, it's a cycle.
                        // If current_x > 1, we can use memo[current_x].

                        if (current_x == 1) {
                            // Cycle detected: 1 -> ... -> 1
