#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>
#include <vector>

// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate the maximum possible parity count for string a
    // This is the initial parity plus the number of '1's that can be appended.
    // The maximum length of a string is 1000.
    // If a string has length L, it can have at most L '1's.
    // If we append a '1', the parity count increases by 1.
    // If we append a '0', the parity count remains the same.
    // The maximum number of '1's we can append is (1000 - |a|).
    // So, the maximum possible parity count for string a is parity_a + (1000 - |a|).
    // However, we only care about the parity value (0 or 1).
    // The maximum number of '1's that can be *effectively* added to change parity
    // is related to the maximum length we can reach.
    // The maximum length of string 'a' we might need to consider is |b|.
    // If |a| < |b|, we need to append |b| - |a| characters.
    // The maximum number of '1's we can append is |b| - |a|.
    // So, the maximum parity count for 'a' (considering only '1's appended)
    // would be parity_a + (number of '1's appended).
    // The maximum number of '1's we can append is |b| - |a|.
    // So, the maximum possible parity sum for 'a' is parity_a + (|b| - |a|).
    // This is the maximum number of '1's that could be in the string 'a'
    // if we only appended '1's until it reached length |b|.
    // If we append '0's, the parity sum doesn't change.
    // So, the actual maximum parity sum for 'a' (before taking modulo 2)
    // is parity_a + (length of 'a' after appending - current length of 'a').
    // The maximum length 'a' can reach is effectively |b| + |a| - 1 (if we remove all but one char, then append).
    // But we only care about reaching length |b|.
    // So, the maximum number of '1's that can be in 'a' when it reaches length |b|
    // is `parity_a + (length_b - length_a)`.
    // Let's call this `max_ones_in_a_at_len_b`.
    // If `length_a > length_b`, we don't append, we only remove.
    // In this case, `max_ones_in_a_at_len_b` is just `parity_a`.
    // This is because removing characters doesn't change the *total* number of '1's
    // that could have been appended. It only changes the current string.
    // The key insight is that we can always choose to append a '0' or a '1'.
    // If we need to increase the parity sum (number of '1's), we append '1'.
    // If we need to keep it the same, we append '0'.
    // So, the maximum number of '1's we can have in `a` when it reaches length `|b|`
    // is `parity_a + std::max(0, (int)b.length() - (int)a.length())`.
    // This is the maximum possible sum of '1's in `a` if we only append '1's
    // until `a` reaches length `|b|`.
    // Let's call this `max_possible_ones_count_in_a`.
    int max_possible_ones_count_in_a = parity_a + std::max(0, (int)b.length() - (int)a.length());

    // Calculate parity of string b
    int parity_b = calculate_parity(b);

    // Condition for YES:
    // 1. The length of 'a' must be less than or equal to the length of 'b'
    //    after considering all possible appends and removals.
    //    This means we must be able to make 'a' at least as long as 'b'.
    //    The minimum length 'a' can be is 1 (if we remove all but one char).
    //    The maximum length 'a' can be is effectively infinite, but we only care up to |b|.
    //    If |a| < |b|, we must append |b| - |a| characters.
    //    If |a| >= |b|, we can remove |a| - |b| characters.
    //    The length constraint is simply that |a| can be made to be |b|.
    //    This is always possible if |a| >= 1.
    //    We can always remove characters until |a| becomes 1.
    //    Then we can append characters until |a| becomes |b|.
    //    So, the length constraint is not really about initial |a| vs |b|,
    //    but about whether we can reach a state where `a` has length `|b|`.
    //    The only way we can't reach length `|b|` is if `|a|` is initially 0, which is not allowed.
    //    So, we can always make `a` have length `|b|`.

    // 2. The parity of 'b' must be achievable from 'a'.
    //    We can always choose to append '0' or '1'.
    //    If we need to change the parity of 'a' (from 0 to 1, or 1 to 0),
    //    we must append a '1'. This requires that we have enough "append slots"
    //    to append a '1'.
    //    The number of '1's in `a` can be increased by appending '1's.
    //    The number of '1's in `a` can be kept the same by appending '0's.
    //    So, if `parity_b` is 0, we need `max_possible_ones_count_in_a` to be even.
    //    If `parity_b` is 1, we need `max_possible_ones_count_in_a` to be odd.
    //    More precisely, we need `max_possible_ones_count_in_a % 2` to be equal to `parity_b`.
    //    This is because we can always choose to append '0's to reduce the number of '1's
    //    (or keep it the same) until the parity matches.
    //    For example, if `max_possible_ones_count_in_a` is 5 (odd) and `parity_b` is 0 (even),
    //    we can append one less '1' (or one more '0') to make the count 4 (even).
    //    This is possible as long as `max_possible_ones_count_in_a` is at least `parity_b`.
    //    (e.g., if `parity_b` is 1, we need at least one '1' in `a` after appends).
    //    The minimum number of '1's we can have in `a` when it reaches length `|b|`
    //    is `parity_a` (if we append only '0's) or `parity_a + 1` (if `parity_a` is 0 and we append one '1' and then '0's).
    //    Essentially, we can achieve any parity `P` for `a` at length `|b|`
    //    if `P` has the same parity as `max_possible_ones_count_in_a`
    //    AND `P` is less than or equal to `max_possible_ones_count_in_a`.
    //    Since `parity_b` is either 0 or 1, this simplifies.
    //    If `parity_b` is 0, we need `max_possible_ones_count_in_a` to be even.
    //    If `parity_b` is 1, we need `max_possible_ones_count_in_a` to be odd.
    //    This is equivalent to `(max_possible_ones_count_in_a % 2) == parity_b`.

    if ((max_possible_ones_count_in_a % 2) == parity_b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

