int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of costs can exceed int if n is large
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Start with initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            long long pile_idx_cost = i; // Cost to move one haybale from pile (i+1) to pile 1
                                         // For pile a[i], its index is i, so distance to a[0] is i.

            if (d >= pile_idx_cost) { // Check if we have enough days to move at least one haybale
                long long haybales_to_move = a[i]; // Max haybales available in this pile

                // Calculate how many haybales we can actually move given remaining days
                long long max_possible_from_this_pile = d / pile_idx_cost;

                long long actual_moved = std::min(haybales_to_move, max_possible_from_this_pile);

                current_a1 += actual_moved;
                d -= actual_moved * pile_idx_cost;
            } else {
                // If we don't have enough days for even one haybale from this pile,
                // we won't have enough for any subsequent piles either (as they are further).
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

