int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is i, it means the frog is at cell i.
                             // The actual cell index is last_r_pos + 1 for string s.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1.
                // The previous 'R' or start was at last_r_pos.
                // The distance between the current 'R' and the previous 'R' (or start) is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // Or, more simply, the distance between indices is i - last_r_pos.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' (or start if no 'R's) to n+1.
        // The last 'R' was at index last_r_pos. The cell is last_r_pos + 1.
        // The target is n+1.
        // The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, (int)s.length() - last_r_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

