#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the alternating part

    // Generate k distinct differences: k, k-1, ..., 1
    // This is achieved by alternating between left and right pointers
    // For example, if k=4, we use numbers 1, 2, 3, 4, 5.
    // Sequence: 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1
    // This gives k distinct differences: 1, 2, 3, 4.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            std::cout << left++;
        } else { // Odd index, take from right
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k+1 numbers, we have used numbers from 1 to k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // We append them in increasing order to ensure they only introduce
    // a difference of 1 (e.g., |(k+1) - (k+2)| = 1).
    // Since 1 is already one of the k distinct differences, this doesn't
    // introduce new distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

