    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m; // Number of multiples of m up to n

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for the first 10 multiples of m
        // This sum will repeat for every block of 10 multiples.
        long long sum_of_first_10_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_10_last_digits += (m * i) % 10;
        }

        // Number of full blocks of 10 multiples
        long long num_blocks = count / 10;
        long long total_sum = num_blocks * sum_of_first_10_last_digits;

        // Add the sum of last digits for the remaining multiples
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m = 1, the subsegment [1] always exists.
    // It's p[pos[1]] itself.
    // min_idx = pos[1], max_idx = pos[1]
    // current_min_val = 1, current_max_val = 1
    result[0] = '1';

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // The number 'm' is at pos[m].
        // We need to expand the current range [current_min_idx, current_max_idx]
        // to include 'm'.
        // The new range will be [min(current_min_idx, pos[m]), max(current_max_idx, pos[m])].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the expanded range satisfies the condition for 'm'.
        // The length of the subsegment is (current_max_idx - current_min_idx + 1).
        // For 'm' to be beautiful, this length must be equal to 'm'.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

