int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            if (discriminant < 0) { // Should not happen if d >= 4, but for floating point safety
                std::cout << "N\n";
            } else {
                double sqrt_discriminant = std::sqrt(discriminant);
                double a1 = (d + sqrt_discriminant) / 2.0;
                double b1 = (d - sqrt_discriminant) / 2.0;

                // Ensure a and b are non-negative.
                // Since d >= 4, d^2 >= 4d, so d^2 - 4d >= 0.
                // sqrt(d^2 - 4d) <= d (because d^2 - 4d <= d^2).
                // So d - sqrt(d^2 - 4d) >= 0.
                // Both a1 and b1 will be non-negative.

