        }
    }

    // Calculate max_right_val[i]: the maximum possible value for a_i
    // such that a_i > a_{i+1} > ... > a_n is satisfied.
    // This means a_i must be at least n-1-i (0-indexed)
    // and a_i must be at most a[i].
    // So, a_i' must be at least n-1-i.
    // a_i' <= a[i]
    // a_i' >= n-1-i
    // So, a[i] must be at least n-1-i.
    // If a[i] < n-1-i, then it's impossible to make a_i' = n-1-i, so we can't satisfy the condition.
    // `right_limit` is the minimum `i` such that `a[i] >= n-1-i`.
    // We iterate from right to left.
    int right_limit = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_limit = i;
        } else {
            break;
        }
    }

    // A sharpened array can be formed if there exists a peak index k (0-indexed)
    // such that:
    // 1. The prefix a_0, ..., a_k can be made strictly increasing (0, 1, ..., k).
    //    This means k <= left_limit.
    // 2. The suffix a_k, ..., a_{n-1} can be made strictly decreasing (k, k-1, ..., 0).
    //    This means k >= right_limit.
    // 3. The peak element a_k' must be at least k (from prefix condition)
    //    and at least n-1-k (from suffix condition).
    //    Since we can decrease elements, we can always make a_k' = max(k, n-1-k) if a[k] is large enough.
    //    The crucial part is that a_k' must be able to be both the end of an increasing sequence
    //    and the start of a decreasing sequence.
    //    The minimum value a_k' can take is max(k, n-1-k).
    //    The maximum value a_k' can take is a[k].
    //    So we need a[k] >= max(k, n-1-k).
    //    However, our `left_limit` and `right_limit` already capture this.
    //    `left_limit` is the largest `i` such that `a[i] >= i`.
    //    `right_limit` is the smallest `i` such that `a[i] >= n-1-i`.
    //    If there is an overlap, i.e., `right_limit <= left_limit`, then there exists at least one `k`
    //    such that `a[k] >= k` AND `a[k] >= n-1-k`.
    //    For any `k` in the range `[right_limit, left_limit]`, we have:
    //    `a[k] >= k` (from `left_limit` definition)
    //    `a[k] >= n-1-k` (from `right_limit` definition)
    //    So, for such a `k`, we can set `a_0' = 0, ..., a_k' = k` and `a_k' = k, ..., a_{n-1}' = k-(n-1-k)`.
    //    Wait, this is not quite right. The peak value `a_k'` must be `k` for the left side and `n-1-k` for the right side.
    //    No, `a_k'` must be `k` for the left side (0-indexed) and `a_k'` must be `n-1-k` for the right side (0-indexed).
    //    The value of `a_k'` must be at least `k` to satisfy `a_0' < ... < a_k'`.
    //    The value of `a_k'` must be at least `n-1-k` to satisfy `a_k' > ... > a_{n-1}'`.
    //    So, `a_k'` must be at least `max(k, n-1-k)`.
    //    And we must be able to achieve this value, i.e., `a[k] >= max(k, n-1-k)`.
    //    The `left_limit` ensures `a[i] >= i` for `i <= left_limit`.
    //    The `right_limit` ensures `a[i] >= n-1-i` for `i >= right_limit`.
    //    So, if `right_limit <= left_limit`, then for any `k` in `[right_limit, left_limit]`,
    //    both conditions `a[k] >= k` and `a[k] >= n-1-k` hold.
    //    Thus, we can choose such a `k` as the peak.

    if (right_limit <= left_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

