        // to save larger elements for later, potentially larger a[i]'s.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'larger' pool
        } else {
            // No more elements in 'a' are greater than a[i]
            // Since 'a' is sorted, no subsequent a[k] (k > i) will have a greater element available either.
            break; 
        }
