#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B elements based on their values in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The largest A_i should be paired with the largest B_i (in terms of F(A,B) value)
    // F(n, k) = n / (k+1)
    // To maximize sum(A'_i / (B_i + 1)), we should pair largest A'_i with smallest (B_i + 1)
    // which means largest A'_i with smallest B_i.
    // So, sort A ascending, sort B ascending.
    // Then A'_i = A[m-1-i] and B_i = B[i] for the original B_i's position.
    // This means A[m-1] goes to the position of B[0], A[m-2] to B[1], etc.
    // Or, A[0] goes to the position of B[m-1], A[1] to B[m-2], etc.
    // Let's use the latter: A[i] goes to the position of B[m-1-i].

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest A value (a[i]) should be paired with the (m-1-i)-th smallest B value (b_elements[m-1-i].value)
        // and placed at its original index.
        result_a_prime[b_elements[m - 1 - i].original_index] = a[i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

