void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_occupied(n, false);
    std::vector<bool> col_occupied(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_occupied[i] = true;
                col_occupied[j] = true;
            }
        }
    }

    int free_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_occupied[i]) {
            free_rows++;
        }
    }

    int free_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_occupied[j]) {
            free_cols++;
        }
    }

    // The number of moves possible is the minimum of free_rows and free_cols.
    // Each move claims one free row and one free column.
    int num_moves = std::min(free_rows, free_cols);

    if (num_moves % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

