int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        // If l == r, we need to find a divisor of l (other than 1).
        // Since l >= 2, l itself is a divisor.
        // If l is prime, l is the only divisor > 1.
        // If l is composite, it has other divisors, but l itself is always a divisor.
        // The problem asks for *any* integer if there are multiple answers.
        // The smallest prime factor is a good candidate, but l itself is simpler.
        // However, the problem asks for the integer that appears maximum number of times.
        // For a single number 'l', all its divisors (except 1) appear exactly once.
        // So any divisor > 1 is a valid answer. The smallest prime factor is usually 2.
        // If l is odd, 2 is not a divisor.
        // The simplest answer is to return 2 if l is even, or l if l is odd.
        // But the problem statement implies we should find *the* divisor.
        // For l=3, r=3, answer is 3.
        // For l=4, r=4, answer is 2 (divisors are 2, 4). Both appear once. 2 is smaller.
        // The example 3 6 -> 3.
        // The example 19 29 -> 2.
        // If l == r, and l is even, 2 is a divisor.
        // If l == r, and l is odd, 2 is not a divisor.
        // In this specific case (l==r), any divisor > 1 is equally frequent (1 time).
        // The problem asks for *any* of them.
        // The smallest prime factor is a good choice.
        // For l=3, r=3, smallest prime factor is 3.
        // For l=5, r=5, smallest prime factor is 5.
        // For l=7, r=7, smallest prime factor is 7.
        // For l=9, r=9, smallest prime factor is 3.
        // For l=10, r=10, smallest prime factor is 2.
        // The simplest is to return 2 if l is even, otherwise l.
        // This is consistent with the general logic that 2 is often the most frequent.
        // If l is odd, 2 cannot be a divisor.
        // If l is odd, and l=r, then 2 cannot be the answer.
        // In this case, the smallest divisor > 1 is the smallest prime factor of l.
        // For l=3, r=3, answer is 3.
        // For l=5, r=5, answer is 5.
        // For l=9, r=9, answer is 3.
        // The problem states "If there are multiple answers, print any of them."
        // For l=r, all divisors > 1 appear exactly once.
        // So, for l=r, we can just print l.
        // This is consistent with the example 3 6 -> 3. If it was 3 3, 3 would be the answer.
        // If l=4, r=4, divisors are 2, 4. Both appear once. Printing 4 is valid.
        // The general solution for l != r will likely pick 2.
        // Let's stick to the general logic: 2 is the most frequent if it can be.
        // If l=r, and l is even, 2 is a divisor.
        // If l=r, and l is odd, 2 is not a divisor.
        // In the l=r case, if l is odd, 2 is not a candidate.
        // The smallest prime factor of l would be the answer.
        // But the problem says "any of them". So l itself is a valid divisor.
        // Let's just return l for l==r.
        // This is simpler and satisfies "any of them".
        // Example: l=3, r=3 -> output 3. Correct.
        // Example: l=4, r=4 -> output 4. Correct (2 is also valid).
        std::cout << l << std::endl;
    } else {
        // If l != r, the range contains at least two numbers.
        // The number 2 is a divisor for every even number.
        // The count of even numbers in [l, r] is floor(r/2) - ceil(l/2) + 1.
        // This count is often very high.
        // For any other divisor d > 2, its multiples are d, 2d, 3d, ...
        // The density of multiples of d is 1/d.
        // The density of multiples of 2 is 1/2.
        // Since 1/2 is the highest density for any integer divisor > 1,
        // 2 will almost always be the most frequent divisor if it can divide numbers in the range.
        // The only exception would be if the range is very small and specifically chosen
        // such that 2 doesn't appear much, but another number does.
        // For example, if l=3, r=6.
        // Numbers: 3, 4, 5, 6.
        // Divisors (excluding 1):
        // 3: {3}
        // 4: {2, 4}
        // 5: {5}
        // 6: {2, 3, 6}
        // Counts:
        // 2: appears for 4, 6 (2 times)
        // 3: appears for 3, 6 (2 times)
        // 4: appears for 4 (1 time)
        // 5: appears for 5 (1 time)
        // 6: appears for 6 (1 time)
        // Here, 2 and 3 both appear 2 times. The example output is 3.
        // This implies that if there's a tie, any is fine.
        // The simplest answer is 2, because it's the most common divisor for a general range.
        // The only case where 2 might not be the answer is if l=r and l is odd.
        // But we handled l=r separately.
        // For l != r, the range [l, r] will always contain at least one even number
        // (unless l is odd and r is l+1, but then l+1 is even).
        // If l is odd, l+1 is even. If l is even, l is even.
        // So there's always an even number in [l, r] if r > l.
        // Thus, 2 will always be a divisor for at least one number in the range.
        // And its frequency will be (r/2 - (l+1)/2 + 1) if l is odd, or (r/2 - l/2 + 1) if l is even.
        // This count is approximately (r-l)/2.
        // For any other d > 2, its count is approximately (r-l)/d.
        // Since d > 2, (r-l)/d < (r-l)/2.
        // So 2 is indeed the most frequent.
        std::cout << 2 << std::endl;
    }

    return 0;
}

