#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case: if N=2, taking 1 is better than N/2 for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n != 4) { // N/2 is odd, and N is not 4
                    // If Chanek takes N/2, opponent faces an odd number.
                    // Opponent will take 1, leaving an even number for Chanek.
                    // This seems good for Chanek.
                    // Example: N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 3+1=4. Opponent: 1+1=2.
                    // If Chanek takes 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2.
                    // Both lead to 4.
                    // The logic here is that if N/2 is odd, taking N/2 leaves an odd number for the opponent.
                    // The opponent will be forced to take 1, leaving an even number for Chanek.
                    // This is generally a good strategy for Chanek.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even, or N=4
                    // If N/2 is even, taking N/2 leaves an even number for the opponent.
                    // The opponent might also take N/2, which is bad for Chanek.
                    // Example: N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    // Chanek: 2+1=3. Opponent: 1.
                    // If Chanek takes 1: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 1+1=2. Opponent: 1+1=2.
                    // Taking 2 is better for Chanek.
                    //
                    // The general strategy for Chanek when N is even:
                    // If N/2 is odd (and N != 2), take N/2. This leaves an odd number for the opponent, forcing them to take 1.
                    // If N/2 is even (or N=2), take 1. This leaves an odd number for the opponent.
                    // This simplifies to: if N is even, and N/2 is odd, take N/2. Otherwise, take 1.
                    // This is equivalent to: if N is even, and N is not a power of 2, take N/2. Otherwise, take 1.
                    // (A number N is a power of 2 if N & (N-1) == 0).
                    //
                    // Let's re-evaluate:
                    // If N is even:
                    // Option 1: Take 1. N becomes N-1 (odd). Opponent faces odd.
                    // Option 2: Take N/2. N becomes N/2. Opponent faces N/2.
                    //
                    // If N/2 is odd:
                    //   Taking N/2: Chanek gets N/2. Opponent faces N/2 (odd). Opponent takes 1. Chanek faces N/2-1 (even).
                    //   Taking 1: Chanek gets 1. Opponent faces N-1 (odd). Opponent takes 1. Chanek faces N-2 (even).
                    //   Compare N/2 vs 1. N/2 is better if N > 2.
                    //   So if N is even and N/2 is odd (i.e., N = 2 * (odd number)), Chanek takes N/2.
                    //
                    // If N/2 is even:
                    //   Taking N/2: Chanek gets N/2. Opponent faces N/2 (even). Opponent might take N/4 or 1.
                    //   Taking 1: Chanek gets 1. Opponent faces N-1 (odd). Opponent takes 1. Chanek faces N-2 (even).
                    //   In this case, taking 1 seems safer to force opponent into an odd state.
                    //   This happens when N is a multiple of 4.
                    //   Example N=4: N/2=2 (even).
                    //     Take 1: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+1=2. Opponent: 1+1=2.
                    //     Take 2: N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3. Opponent: 1.
                    //     Here, taking N/2 is better.
                    //
                    // The optimal strategy for Chanek when N is even:
                    // If N is a power of 2 (e.g., 2, 4, 8, 16, ...):
                    //   Chanek should take N/2. This leaves N/2 for opponent.
                    //   If N=2, Chanek takes 1. (This is covered by the N=2 special case).
                    //   If N=4, Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 3. Opponent: 1.
                    //   If N=8, Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 4+1=5. Opponent: 2+1=3.
                    //   It seems for powers of 2, taking N/2 is always optimal for Chanek.
                    //
                    // If N is even but not a power of 2 (e.g., 6, 10, 12, ...):
                    //   N = 2^k * M, where M is odd and M > 1.
                    //   Chanek takes N/2. N becomes N/2.
                    //   N/2 = 2^(k-1) * M.
                    //   If k=1 (N = 2 * M, M odd > 1, e.g., N=6, M=3):
                    //     Chanek takes N/2 (M). N becomes M (odd). Opponent takes 1. N becomes M-1 (even).
                    //     This seems good.
                    //   If k > 1 (N = 4 * M', M' can be odd/even, e.g., N=12, M=3, k=2):
                    //     Chanek takes N/2 (6). N becomes N/2 (6). Opponent faces 6.
                    //     Opponent will take 3. N becomes 3. Chanek takes 1. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    //     Chanek: N/2 + 1 + 1 = 6+1+1=8. Opponent: 3+1=4.
                    //     What if Chanek takes 1? N=11. Opponent takes 1. N=10. Chanek takes 5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    //     Chanek: 1+5+2+1=9. Opponent: 1+1+1=3.
                    //     Taking 1 is better for N=12.
                    //
                    // This implies the strategy is:
                    // If N is odd: take 1.
                    // If N is even:
                    //   If N is a power of 2 (N & (N-1) == 0): take N/2.
                    //   If N is not a power of 2: take 1.
                    //
                    // Let's test this refined strategy:
                    // N=5: Chanek takes 1. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 1+1=2. Opponent: 2+1=3. (Correct for example)
                    //
                    // N=6: Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2. (Correct for example)
                    //
                    // This strategy seems to work for the examples.
                    //
                    // Let's implement this.
                    // N is even.
                    // Check if N is a power of 2: (n > 0 && (n & (n - 1)) == 0)
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        chanek_coins += n / 2;
                        n /= 2;
                    } else { // N is even but not a power of 2
                        chanek_coins += 1;
                        n -= 1;
                    }
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                // Opponent also plays optimally to maximize their own coins.
                // The opponent's strategy will be symmetric to Chanek's.
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

