        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor ^= a;
        }

        // We need current_sum + S_b = 2 * (current_xor ^ X_b)
        // Let X_b = current_xor.
        // Then we need current_sum + S_b = 2 * (current_xor ^ current_xor) = 2 * 0 = 0.
        // This is only possible if current_sum and S_b are both 0, which is not generally true.

        // Let's try to make the XOR sum 0.
        // If we append current_xor, the new XOR sum becomes current_xor ^ current_xor = 0.
        // Let b1 = current_xor.
        // New XOR sum X' = current_xor ^ b1 = current_xor ^ current_xor = 0.
        // New sum S' = current_sum + b1.
        // We need S' = 2 * X' => current_sum + b1 = 2 * 0 = 0.
        // This implies current_sum + current_xor = 0.
        // Since all a_i >= 0, current_sum >= 0. current_xor >= 0.
        // This is only possible if current_sum = 0 and current_xor = 0.
        // If current_sum = 0 and current_xor = 0, the array is already good.

        // The strategy is to append two numbers:
        // 1. The current XOR sum (current_xor). This makes the new XOR sum 0.
        // 2. The new sum (current_sum + current_xor). This makes the total sum 0.
        // Let b1 = current_xor.
        // After adding b1:
        // sum_1 = current_sum + b1
        // xor_1 = current_xor ^ b1 = current_xor ^ current_xor = 0
        // Now we need sum_1 = 2 * xor_1, which means sum_1 = 2 * 0 = 0.
        // If sum_1 is not 0, we need to add another number, say b2, such that:
        // sum_1 + b2 = 0
        // xor_1 ^ b2 = 0
        // From xor_1 ^ b2 = 0, since xor_1 = 0, we get 0 ^ b2 = 0, which means b2 = 0.
        // If b2 = 0, then sum_1 + 0 = 0, which means sum_1 = 0.
        // So, if sum_1 is not 0, we can't just add 0.

        // Let's try to make the final XOR sum equal to some value X_final.
        // We need S_final = 2 * X_final.
        // Consider appending two numbers: b1 and b2.
        // Let b1 = current_xor.
        // New XOR sum becomes current_xor ^ b1 = current_xor ^ current_xor = 0.
        // New sum becomes current_sum + b1.
        // Now we need to append b2 such that:
        // (current_sum + b1) + b2 = 2 * (0 ^ b2)
        // current_sum + b1 + b2 = 2 * b2
        // current_sum + b1 = b2
        // So, b2 = current_sum + current_xor.
        // The two numbers to append are:
        // b1 = current_xor
        // b2 = current_sum + current_xor

        // Let's verify this.
        // Initial: sum = current_sum, xor = current_xor
        // Append b1 = current_xor:
        // sum' = current_sum + current_xor
        // xor' = current_xor ^ current_xor = 0
        // Append b2 = sum':
        // sum'' = sum' + b2 = sum' + sum' = 2 * sum'
        // xor'' = xor' ^ b2 = 0 ^ sum' = sum'
        // Check condition: sum'' = 2 * xor''
        // 2 * sum' = 2 * sum'
        // This works!

        // So, we always append two numbers:
        // b1 = current_xor
        // b2 = current_sum + current_xor

        // Example 1: [1, 2, 3, 6]
        // sum = 12, xor = 6
        // 12 = 2 * 6, already good. Output 0.
        // My strategy would output 2 numbers: b1=6, b2=12+6=18.
        // Array becomes [1,2,3,6,6,18]. Sum=12+6+18=36. XOR=6^6^18=18. 36 = 2*18. Good.
        // The problem states "you don't have to minimize the number of added elements!".
        // So, outputting 2 elements even if 0 is sufficient is allowed.

        // Example 2: [8]
        // sum = 8, xor = 8
        // b1 = xor = 8
        // b2 = sum + xor = 8 + 8 = 16
        // Output: 2 numbers: 8, 16.
        // Array becomes [8, 8, 16]. Sum = 8+8+16 = 32. XOR = 8^8^16 = 16. 32 = 2*16. Good.
        // Example output: 2 numbers: 4, 4.
        // Array becomes [8, 4, 4]. Sum = 8+4+4 = 16. XOR = 8^4^4 = 8. 16 = 2*8. Good.
        // My solution is valid.

        // Example 3: [1, 1]
        // sum = 2, xor = 0
        // b1 = xor = 0
        // b2 = sum + xor = 2 + 0 = 2
        // Output: 2 numbers: 0, 2.
        // Array becomes [1, 1, 0, 2]. Sum = 1+1+0+2 = 4. XOR = 1^1^0^2 = 2. 4 = 2*2. Good.
        // Example output: 3 numbers: 2, 6, 2.
        // Array becomes [1, 1, 2, 6, 2]. Sum = 1+1+2+6+2 = 12. XOR = 1^1^2^6^2 = 6. 12 = 2*6. Good.
        // My solution is valid.

        // The problem statement says "at most 3 elements". My solution always adds 2 elements.
        // This is fine.

        std::cout << 2 << "\n";
        std::cout << current_xor << " " << current_sum + current_xor << "\n";
    }
    return 0;
}

