}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        return "0"; // Special case for 0
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get correct order
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            // Pad with leading zeros to length 18
            std::string padded_pattern(18 - pattern.length(), '0');
            padded_pattern += pattern;
            counts[padded_pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            // Pad with leading zeros to length 18
            std::string padded_pattern(18 - pattern.length(), '0');
            padded_pattern += pattern;
            counts[padded_pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad with leading zeros to length 18
            std::string padded_s(18 - s.length(), '0');
            padded_s += s;
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

