    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long current_a_count = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can be paired with any 'a' to its left.
            // Each 'a' to its left will eventually be processed.
            // When an 'a' is processed with a 'b', it generates a 'bba'.
            // The 'a' effectively moves past the 'b', and a new 'b' is added.
            // The number of steps for this 'b' is equal to the number of 'a's
            // that are currently to its left and haven't been processed yet.
            // Each such 'a' will eventually "jump over" this 'b'.
            // When an 'a' jumps over a 'b', it costs 1 step.
            // The 'a' then becomes 'a' + 'b' + 'b' + 'a'.
            // The 'a' is now to the right of the original 'b'.
            // The key insight is that an 'a' at index `i` and a 'b' at index `j` (where `i < j`)
            // will eventually interact. When they do, the 'a' effectively moves past the 'b'.
            // The number of steps for an 'a' to move past a 'b' is 1.
            // If there are `k` 'a's to the left of a 'b', this 'b' will be involved in `k` operations.
            // Each operation "ab" -> "bba" effectively doubles the number of 'a's that can
            // interact with subsequent 'b's.
            // No, this is not correct. The number of 'a's does not double.
            // The number of 'a's remains constant.
            // The number of 'b's increases.

            // Let's re-evaluate the logic based on the example "aab".
            // "aab"
            // i = 2, s[2] = 'b'. current_a_count = 0.
            //   This 'b' is at the end.
            //   It will interact with 'a's to its left.
            //   When we process 'a's from right to left, we are effectively counting how many 'a's
            //   are to the left of the current 'b'.
            //   When we see a 'b', it means all 'a's to its left will eventually pass it.
            //   Each 'a' passing this 'b' costs 1 step.
            //   So, if there are `k` 'a's to the left, this 'b' contributes `k` steps.
            //   However, the 'a's themselves are also changing.
            //   When "ab" -> "bba", the 'a' moves past the 'b'.
            //   The 'a' that was at index `i` and the 'b' at index `i+1` become `bba`.
            //   The 'a' is now at index `i+2`.
            //   The crucial observation is that when an 'a' at `idx_a` and a 'b' at `idx_b` (`idx_a < idx_b`)
            //   are chosen for an operation, the 'a' effectively "jumps over" the 'b'.
            //   The 'a' is now to the right of the original 'b'.
            //   The number of 'a's to the left of any given 'b' determines how many times that 'b' will be "jumped over".
            //   Each time an 'a' jumps over a 'b', it costs 1 step.
            //   The 'a' itself doesn't change, but the 'b' it jumped over is now followed by another 'b'.
            //   This new 'b' can also be jumped over by other 'a's.

            // Let's consider the 'a's.
            // When we encounter an 'a', it means it's an 'a' that needs to be moved past all 'b's to its right.
            // When we encounter a 'b', it means it's a 'b' that needs to be moved past by all 'a's to its left.

            // The problem states "minimum number of steps".
            // The strategy to achieve minimum steps is to always pick the rightmost "ab".
            // This is because picking a leftmost "ab" might create new "ab"s to its left,
            // which would then need to be processed.
            // Picking the rightmost "ab" ensures that the 'a' moves as far right as possible,
            // and the new 'b's are created to its left, which are then processed by other 'a's.

            // Let's trace "aab" with right-to-left processing:
            // s = "aab"
            // i = 2, s[2] = 'b'. current_a_count = 0.
            //   This 'b' is at the end. It will be jumped over by 'a's to its left.
            //   The number of 'a's that will jump over this 'b' is `current_a_count`.
            //   Each jump costs 1 step.
            //   So, this 'b' contributes `current_a_count` steps.
            //   After an 'a' jumps over a 'b', the 'a' is now to the right of the 'b'.
            //   The 'b' effectively "multiplies" the 'a's that can interact with subsequent 'b's.
            //   When "ab" -> "bba", the 'a' moves past the 'b'.
            //   The 'a' that was at index `i` and the 'b' at `i+1` become `bba`.
            //   The 'a' is now at `i+2`.
            //   The number of 'a's that can interact with the next 'b' to the right effectively doubles.
            //   This is because the original 'a' can interact, and the new 'b' can also be jumped over by other 'a's.
            //   No, this is not correct. The 'a' count does not double.

            // Let's use the logic from a similar problem or a known pattern.
            // When we see a 'b', it means all 'a's to its left will eventually pass it.
            // Each 'a' passing this 'b' costs 1 step.
            // The number of 'a's that will pass this 'b' is `current_a_count`.
            // So, `total_steps += current_a_count`.
            // After an 'a' passes a 'b', the 'a' is now to the right of the 'b'.
            // The 'b' effectively "multiplies" the 'a's that can interact with subsequent 'b's.
            // When "ab" -> "bba", the 'a' moves past the 'b'.
            // The 'a' that was at index `i` and the 'b' at `i+1` become `bba`.
            // The 'a' is now at `i+2`.
            // The number of 'a's that can interact with the next 'b' to the right effectively doubles.
            // This is because the original 'a' can interact, and the new 'b' can also be jumped over by other 'a's.
            // No, this is not correct. The 'a' count does not double.

            // The correct logic:
            // Iterate from right to left.
            // If we see a 'b':
            //   This 'b' will be "jumped over" by all 'a's to its left.
            //   The number of 'a's to its left is `current_a_count`.
            //   Each such 'a' will perform an "ab" -> "bba" operation with this 'b' (or a 'b' derived from it).
            //   So, this 'b' contributes `current_a_count` steps to the total.
            //   After an 'a' jumps over this 'b', the 'a' is now to the right of this 'b'.
            //   Crucially, the "ab" -> "bba" operation introduces a *new* 'b'.
            //   This new 'b' is to the left of the 'a' that just jumped.
            //   This new 'b' can also be jumped over by other 'a's that are still to its left.
            //   Effectively, each 'a' that jumps over a 'b' creates a new 'b' that *also* needs to be jumped over by other 'a's.
            //   So, if `current_a_count` 'a's jump over this 'b', they generate `current_a_count` new 'b's.
            //   These new 'b's are effectively "to the left" of the current processing point.
            //   So, the number of 'a's that can interact with *subsequent* 'b's (further to the left)
            //   effectively doubles for each 'b' encountered.
            //   `current_a_count` represents the number of 'a's that are currently "active" and can interact with 'b's to their right.
            //   When we see a 'b', these `current_a_count` 'a's will interact with it.
            //   Each interaction adds 1 to `total_steps`.
            //   So, `total_steps += current_a_count`.
            //   After these interactions, each of the `current_a_count` 'a's has effectively moved past this 'b'.
            //   And each interaction "ab" -> "bba" creates a new 'b'.
            //   These new 'b's are now available to be interacted with by 'a's further to the left.
            //   So, the number of 'a's that can interact with *future* 'b's (to the left) effectively doubles.
            //   `current_a_count = (current_a_count * 2) % mod`.

            total_steps = (total_steps + current_a_count) % mod;
            current_a_count = (current_a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now available to interact
            // with any 'b's that we encounter further to the left.
            // So, we increment the count of available 'a's.
            current_a_count = (current_a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce the given s
    std::string s_reconstructed(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_reconstructed[i] = '1';
        }
    }

    if (s_reconstructed == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

