#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_divisor_not_divisible_by_q(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            long long current_prime_factor = i;
            long long p_copy = p;
            long long count_p_factor = 0;
            while (p_copy > 0 && p_copy % current_prime_factor == 0) {
                p_copy /= current_prime_factor;
                count_p_factor++;
            }

            long long count_q_factor = 0;
            while (temp_q % current_prime_factor == 0) {
                temp_q /= current_prime_factor;
                count_q_factor++;
            }

            // If p is divisible by q, then count_p_factor must be >= count_q_factor
            // We need to reduce p by current_prime_factor^(count_q_factor - 1)
            // to make it not divisible by current_prime_factor^count_q_factor (which is part of q)
            long long factor_to_remove = 1;
            for(int k = 0; k < count_q_factor; ++k) {
                factor_to_remove *= current_prime_factor;
            }
            max_x = std::max(max_x, p / factor_to_remove);
        }
    }

    if (temp_q > 1) { // temp_q is now a prime factor itself
        long long current_prime_factor = temp_q;
        long long p_copy = p;
        long long count_p_factor = 0;
        while (p_copy > 0 && p_copy % current_prime_factor == 0) {
            p_copy /= current_prime_factor;
            count_p_factor++;
        }

        // Here count_q_factor is 1 for this prime
        long long factor_to_remove = current_prime_factor;
        max_x = std::max(max_x, p / factor_to_remove);
    }

    return max_x;
}

