#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<int> degree(26, 0);
    std::vector<bool> in_s(26, false);

    for (char c : s) {
        in_s[c - 'a'] = true;
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u_char = s[i];
        char v_char = s[i+1];
        int u = u_char - 'a';
        int v = v_char - 'a';

        if (adj[u].find(v_char) == adj[u].end()) { // If this is a new adjacency
            adj[u].insert(v_char);
            adj[v].insert(u_char);
            degree[u]++;
            degree[v]++;
        }

        if (degree[u] > 2 || degree[v] > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find starting points for paths (degree 1 nodes or isolated nodes in s)
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && degree[i] <= 1 && !visited[i]) {
            char current_char = (char)('a' + i);

            // Traverse the path
            while (true) {
                layout += current_char;
                visited[current_char - 'a'] = true;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }

                if (next_char == 0) { // End of path
                    break;
                }
                current_char = next_char;
            }
        }
    }

    // Check if all characters from s are included in the layout
    // This also implicitly checks for cycles or paths with degree > 2 that weren't caught earlier
    // because if there was a cycle, a node would have degree 2 and would be visited,
    // but it wouldn't be a starting point (degree 1 or 0).
    // If all nodes in s are part of a valid path, they will be visited.
    for (int i = 0; i < 26; ++i) {
        if (in_s[i] && !visited[i]) {
            // This means there's a character from s that wasn't part of a path starting from a degree 0/1 node.
            // This can happen if there's a cycle or a path where all nodes have degree 2.
            // For example, if s="abcba", a-b-c-b-a. a-b, b-c. degree(a)=1, degree(c)=1, degree(b)=2.
            // This should be handled by the degree check.
            // The only way a node in_s is not visited is if it's part of a cycle or a path where all nodes have degree 2.
            // But if all nodes have degree 2, it means it's a cycle.
            // A cycle is not allowed in a single row layout.
            // The degree check `degree[u] > 2` already handles most invalid cases.
            // If a character has degree 2 and is part of a path, it will be visited.
            // If it's part of a cycle, it won't be visited by the current logic.
            // So, if any in_s character is not visited, it implies an invalid structure (a cycle).
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters not in s
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_r = sum_{r=1 to b-1} r
    // Sum_r = (b-1) * b / 2
    long long sum_r_val = (b - 1);
    sum_r_val = (sum_r_val % MOD * (b % MOD)) % MOD;

    // We need to divide by 2. Since MOD is prime, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 10^9 + 8 / 2 = 500000004.
    long long inv2 = 500000004;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Sum_k_term = sum_{k=1 to a} (k * b + 1)
    // Sum_k_term = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // Sum_k_term = b * sum_{k=1 to a} k + a
    // Sum_k_term = b * (a * (a+1) / 2) + a

    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD; // a * (a+1) / 2

    sum_k_val = (sum_k_val % MOD * (b % MOD)) % MOD; // b * (a * (a+1) / 2)
    sum_k_val = (sum_k_val + (a % MOD)) % MOD; // + a

    long long total_sum = (sum_r_val * sum_k_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Total number of toys
    long long total_toys = A + B + C + D;

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Box 1: (-inf, -1]
    // Can it be the special box?
    // Final product must be negative and <= -1.
    // This requires an odd number of negative factors.
    // The magnitude must be >= 1.
    //
    // Scenario 1: Final product is negative.
    // This means (A+B) must be odd.
    // If A+B is odd, we can always make the final product negative.
    //
    // Scenario 2: Final product magnitude >= 1.
    // This requires at least one toy from Box 1 or Box 4, OR
    // a sequence of multiplications that eventually produces a value >= 1 or <= -1.
    //
    // If A+B is odd:
    //   If A+D >= 1 (at least one toy with magnitude >= 1):
    //     We can potentially make the final product <= -1.
    //     Example: (-2) * (0.5) * (0.5) = -0.5 (Box 2)
    //     Example: (-2) * (3) * (0.5) = -3 (Box 1)
    //     If A+D >= 1, we can always ensure the magnitude is >= 1.
    //     If A+D == 0, then all initial toys are in B or C.
    //       If A+B is odd, then B must be odd.
    //       If A+D == 0, then A=0, D=0. So B is odd.
    //       All toys are in B or C. All products will be in (0,1) or (-1,0).
    //       So, if A+D == 0, Box 1 is impossible.
    //
    // So, for Box 1: (A+B) is odd AND (A+D >= 1 OR (A+D == 0 AND B+C > 0 AND B is odd))
    // The condition (A+D >= 1 OR (A+D == 0 AND B+C > 0 AND B is odd)) simplifies.
    // If A+D == 0, then A=0, D=0. All toys are in B or C.
    //   If B is odd, the final product is negative.
    //   All products of toys from B and C will be in (-1, 1).
    //   So, if A+D == 0, the final product cannot be <= -1.
    // Therefore, A+D must be >= 1 for Box 1 to be possible.
    //
    // Simplified condition for Box 1: (A + B) % 2 == 1 && (A + D >= 1)
    if ((A + B) % 2 == 1 && (A + D >= 1)) {
        ans1 = "Ya";
    }

    // Box 2: (-1, 0)
    // Final product must be negative and between -1 and 0.
    // This requires an odd number of negative factors.
    // The magnitude must be < 1.
    //
    // Scenario 1: Final product is negative.
    // This means (A+B) must be odd.
    //
    // Scenario 2: Final product magnitude < 1.
    // This requires that we can make the final product magnitude < 1.
    // This is always possible if there are toys in B or C.
    // If A+D >= 1, we can always multiply by a small number from B or C to reduce magnitude.
    // If A+D == 0, then all toys are in B or C. All products will be in (-1, 1).
    //
    // So, for Box 2: (A + B) % 2 == 1
    // This is always possible if A+B is odd.
    if ((A + B) % 2 == 1) {
        ans2 = "Ya";
    }

    // Box 3: (0, 1)
    // Final product must be positive and between 0 and 1.
    // This requires an even number of negative factors.
    // The magnitude must be < 1.
    //
    // Scenario 1: Final product is positive.
    // This means (A+B) must be even.
    //
    // Scenario 2: Final product magnitude < 1.
    // This is always possible if there are toys in B or C.
    // If A+D >= 1, we can always multiply by a small number from B or C to reduce magnitude.
    // If A+D == 0, then all toys are in B or C. All products will be in (-1, 1).
    //
    // So, for Box 3: (A + B) % 2 == 0
    // This is always possible if A+B is even.
    if ((A + B) % 2 == 0) {
        ans3 = "Ya";
    }

    // Box 4: [1, inf)
    // Final product must be positive and >= 1.
    // This requires an even number of negative factors.
    // The magnitude must be >= 1.
    //
    // Scenario 1: Final product is positive.
    // This means (A+B) must be even.
    //
    // Scenario 2: Final product magnitude >= 1.
    // This requires at least one toy from Box 1 or Box 4, OR
    // a sequence of multiplications that eventually produces a value >= 1 or <= -1.
    //
    // If A+D >= 1, we can always ensure the magnitude is >= 1.
    // If A+D == 0, then all initial toys are in B or C.
    //   All products of toys from B and C will be in (-1, 1).
    //   So, if A+D == 0, Box 4 is impossible.
    //
    // So, for Box 4: (A + B) % 2 == 0 && (A + D >= 1)
    if ((A + B) % 2 == 0 && (A + D >= 1)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

