#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current_val_if_0 and current_val_if_1 for each bit
    // current_val_if_0[j] stores the j-th bit of the result if input x_j was 0
    // current_val_if_1[j] stores the j-th bit of the result if input x_j was 1
    // Initially, if x_j is 0, result is 0. If x_j is 1, result is 1.
    std::vector<int> current_val_if_0(10, 0); // All bits 0
    std::vector<int> current_val_if_1(10, 1); // All bits 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int j = 0; j < 10; ++j) {
            int x_bit = (x >> j) & 1;

            if (op_char == '&') {
                current_val_if_0[j] &= x_bit;
                current_val_if_1[j] &= x_bit;
            } else if (op_char == '|') {
                current_val_if_0[j] |= x_bit;
                current_val_if_1[j] |= x_bit;
            } else { // op_char == '^'
                current_val_if_0[j] ^= x_bit;
                current_val_if_1[j] ^= x_bit;
            }
        }
    }

    // Reconstruct the equivalent operations
    // We need to find A, B, C such that:
    // (x & A | B) ^ C
    // For each bit j:
    // if x_j = 0, then (0 & A_j | B_j) ^ C_j = B_j ^ C_j must be current_val_if_0[j]
    // if x_j = 1, then (1 & A_j | B_j) ^ C_j = (A_j | B_j) ^ C_j must be current_val_if_1[j]

    int final_A = 0;
    int final_B = 0;
    int final_C = 0;

    for (int j = 0; j < 10; ++j) {
        int v0 = current_val_if_0[j];
        int v1 = current_val_if_1[j];

        // Case 1: (0 -> 0, 1 -> 0)
        // B_j ^ C_j = 0
        // (A_j | B_j) ^ C_j = 0
        // This implies B_j = C_j.
        // Then (A_j | B_j) ^ B_j = 0.
        // If B_j = 0, then (A_j | 0) ^ 0 = A_j = 0. So A_j=0, B_j=0, C_j=0.
        // If B_j = 1, then (A_j | 1) ^ 1 = 0. (A_j | 1) is always 1. So 1 ^ 1 = 0. This works.
        // So A_j=0, B_j=1, C_j=1 is also a solution.
        // We prefer A_j=0, B_j=0, C_j=0 for simplicity.
        if (v0 == 0 && v1 == 0) {
            // A_j = 0, B_j = 0, C_j = 0
            // (x_j & 0 | 0) ^ 0 = 0
            // This is the default state, no bits set in A, B, C for this bit.
        }
        // Case 2: (0 -> 0, 1 -> 1)
        // B_j ^ C_j = 0
        // (A_j | B_j) ^ C_j = 1
        // This implies B_j = C_j.
        // Then (A_j | B_j) ^ B_j = 1.
        // If B_j = 0, then (A_j | 0) ^ 0 = A_j = 1. So A_j=1, B_j=0, C_j=0.
        // If B_j = 1, then (A_j | 1) ^ 1 = 1. (A_j | 1) is always 1. So 1 ^ 1 = 0 != 1. This doesn't work.
        // So A_j=1, B_j=0, C_j=0.
        else if (v0 == 0 && v1 == 1) {
            // A_j = 1, B_j = 0, C_j = 0
            // (x_j & 1 | 0) ^ 0 = x_j
            final_A |= (1 << j);
        }
        // Case 3: (0 -> 1, 1 -> 0)
        // B_j ^ C_j = 1
        // (A_j | B_j) ^ C_j = 0
        // This implies B_j != C_j.
        // If B_j = 0, then C_j = 1.
        // Then (A_j | 0) ^ 1 = 0 => A_j ^ 1 = 0 => A_j = 1. So A_j=1, B_j=0, C_j=1.
        // If B_j = 1, then C_j = 0.
        // Then (A_j | 1) ^ 0 = 0 => (A_j | 1) = 0. This is impossible.
        // So A_j=1, B_j=0, C_j=1.
        else if (v0 == 1 && v1 == 0) {
            // A_j = 1, B_j = 0, C_j = 1
            // (x_j & 1 | 0) ^ 1 = x_j ^ 1
            final_A |= (1 << j);
            final_C |= (1 << j);
        }
        // Case 4: (0 -> 1, 1 -> 1)
        // B_j ^ C_j = 1
        // (A_j | B_j) ^ C_j = 1
        // This implies B_j != C_j.
        // If B_j = 0, then C_j = 1.
        // Then (A_j | 0) ^ 1 = 1 => A_j ^ 1 = 1 => A_j = 0. So A_j=0, B_j=0, C_j=1.
        // If B_j = 1, then C_j = 0.
        // Then (A_j | 1) ^ 0 = 1 => (A_j | 1) = 1. This is always true.
        // So A_j=0, B_j=1, C_j=0.
        // We prefer A_j=0, B_j=1, C_j=0 for simplicity.
        else { // v0 == 1 && v1 == 1
            // A_j = 0, B_j = 1, C_j = 0
            // (x_j & 0 | 1) ^ 0 = 1
            final_B |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_B != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', final_B});
    }
    if (final_C != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', final_C});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        long long good_substrings_count = 0;
        int n = s.length();

        // Precompute prefix sums of '0's
        std::vector<int> prefix_zeros(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            prefix_zeros[i + 1] = prefix_zeros[i] + (s[i] == '0' ? 1 : 0);
        }

        for (int i = 0; i < n; ++i) {
            if (s[i] == '0') {
                continue; // A good substring cannot start with '0' unless its value is 0, but length must be positive.
                          // The only case where f(0...0) = 0 is if the length is 0, which is not allowed.
                          // If f(0...0) = 0 and length is L, then L=0, which is impossible.
                          // So, a good substring must start with '1' or be a single '0' (length 1, value 0), but f(0)=0, so length 1 != 0.
                          // Thus, good substrings must start with '1'.
            }

            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                // Calculate current_val for s[i...j]
                // Check for overflow before multiplying
                if (current_val > (2LL * n + 1) / 2) { // Max possible length is n. Max val can be 2n.
                                                      // If current_val * 2 exceeds 2n, it's too large.
                                                      // (2LL * n + 1) / 2 is roughly n.
                                                      // If current_val > n, then current_val * 2 will be > 2n.
                                                      // This check is to prevent overflow and early exit.
                                                      // Max length is 2e5. Max value can be 2e5.
                                                      // If current_val is already > 2e5, then current_val * 2 will be > 4e5.
                                                      // The maximum possible value for current_val is 2*N.
                                                      // If current_val * 2 exceeds 2*N, it's too large.
                                                      // So, if current_val > N, then current_val * 2 > 2*N.
                                                      // A safer upper bound for current_val is 2*N.
                                                      // If current_val > 2*N, then it's definitely too large.
                                                      // The maximum length of s is 2e5.
                                                      // The maximum value of f(t) can be 2e5.
                                                      // If current_val exceeds 2e5, it's too large.
                    break; 
                }
                current_val = current_val * 2 + (s[j] - '0');

                int len = j - i + 1;

                if (current_val > 2LL * n) { // If value exceeds maximum possible length (2*N is a safe upper bound for length)
                    break;
                }

                if (current_val == len) {
                    good_substrings_count++;
                } else if (current_val < len) {
                    // If current_val is less than len, it means the binary string is too short to represent
                    // a value equal to its length. Since we are extending the string to the right,
                    // len will increase by 1, and current_val will at most double and add 1.
                    // For example, if current_val = 3, len = 5. Next: current_val = 6 or 7, len = 6.
                    // It's possible for current_val to catch up.
                    // Example: s[i...j] = 10, len=2, val=2. Good.
                    // Example: s[i...j] = 1, len=1, val=1. Good.
                    // Example: s[i...j] = 101, len=3, val=5. Not good.
                    // Example: s[i...j] = 100, len=3, val=4. Not good.
                    // Example: s[i...j] = 11, len=2, val=3. Not good.
                    // Example: s[i...j] = 1011, len=4, val=11. Not good.

                    // Consider s[i...j] where s[i] is '1'.
                    // If current_val < len, we can potentially add leading zeros to s[i...j]
                    // to make its length equal to current_val.
                    // The number of leading zeros needed would be `current_val - len`.
                    // These leading zeros must come from `s[k...i-1]` where `k` is the start of the actual substring.
                    // So, we need `current_val - len` zeros before index `i`.
                    // The number of zeros before `i` is `prefix_zeros[i]`.
                    // If `current_val - len <= prefix_zeros[i]`, then we can form a good substring.
                    // The substring would be `s[i - (current_val - len) ... j]`.
                    // Its length would be `j - (i - (current_val - len)) + 1 = (j - i + 1) + (current_val - len) = len + (current_val - len) = current_val`.
                    // Its value would be `current_val` (since leading zeros don't change value).
                    // This is a good substring.

                    // The number of zeros available before index `i` is `prefix_zeros[i]`.
                    // The number of zeros required is `len - current_val`.
                    // This is incorrect. The condition is `r - l + 1 = f(s_l \dots s_r)`.
                    // If we have `s[i...j]` with value `val` and length `len`.
                    // If `val < len`, we need to find `k < i` such that `s[k...i-1]` are all '0's.
                    // The substring would be `s[k...j]`. Its value is still `val`.
                    // Its length is `j - k + 1`.
                    // We need `j - k + 1 = val`.
                    // `k = j + 1 - val`.
                    // We need to check if `s[j+1-val ... i-1]` are all '0's.
                    // The number of zeros in `s[j+1-val ... i-1]` is `prefix_zeros[i] - prefix_zeros[j+1-val]`.
                    // The length of this prefix is `i - (j+1-val)`.
                    // If `i - (j+1-val) == prefix_zeros[i] - prefix_zeros[j+1-val]`, then all characters are '0'.
                    // Also, `j+1-val` must be a valid index, i.e., `j+1-val >= 0`.

                    long long required_start_idx = j + 1 - current_val;
                    if (required_start_idx >= 0 && required_start_idx < i) {
                        // Check if s[required_start_idx ... i-1] are all zeros
                        // The number of zeros in this range should be equal to its length
                        if (prefix_zeros[i] - prefix_zeros[required_start_idx] == (i - required_start_idx)) {
                            good_substrings_count++;
                        }
                    }
                }
            }
        }
        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n and m are non-negative. The path can be reflected.
        n = std::abs(n);
        m = std::abs(m);

        // Ensure n >= m for simpler logic.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: Not enough moves to reach (n, m)
        // Minimum moves required is max(n, m)
        if (k < n) { // Since n >= m, this is equivalent to k < max(n, m)
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: Parity check
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // (x_new + y_new) - (x_old + y_old) = (dx + dy)
        // dx, dy can be -1, 0, 1.
        // If dx=0, dy=0, it's not a move.
        // Possible (dx, dy) pairs:
        // (1,0), (0,1), (-1,0), (0,-1) -> dx+dy = 1, 1, -1, -1 (odd)
        // (1,1), (1,-1), (-1,1), (-1,-1) -> dx+dy = 2, 0, 0, -2 (even)
        // So, each move changes the parity of (x+y) by an odd amount (if non-diagonal) or an even amount (if diagonal).
        // This means (x_new + y_new) and (x_old + y_old) have different parities if the move is non-diagonal.
        // And (x_new + y_new) and (x_old + y_old) have the same parity if the move is diagonal.
        //
        // Let P_start = (0+0) % 2 = 0.
        // Let P_end = (n+m) % 2.
        //
        // If k moves are made, and 'd' of them are diagonal, then 'k-d' are non-diagonal.
        // The parity of (n+m) must be the same as the parity of (0+0) + (k-d) * (odd_change) + d * (even_change).
        // This simplifies to (n+m) % 2 == (k-d) % 2.
        //
        // Consider the parity of (k - (n+m)).
        // If (k - (n+m)) is odd, it's impossible.
        // This is because each move changes the parity of (x+y) by 0 or 1 (mod 2).
        // (x_new + y_new) % 2 = ((x_old + y_old) + (dx+dy)) % 2
        // (n+m) % 2 = (0+0) % 2 + (sum of (dx+dy) for k moves) % 2
        // (n+m) % 2 = (sum of (dx+dy) for k moves) % 2
        //
        // For a diagonal move, dx, dy are both non-zero. dx+dy is even.
        // For a non-diagonal move, one of dx, dy is zero, the other is non-zero. dx+dy is odd.
        //
        // Let D be the number of diagonal moves, N be the number of non-diagonal moves. D+N = k.
        // (n+m) % 2 = (D * (even_sum) + N * (odd_sum)) % 2
        // (n+m) % 2 = (N * 1) % 2
        // (n+m) % 2 = (k - D) % 2
        //
        // This means (n+m) and (k-D) must have the same parity.
        // Or, (n+m) and k must have the same parity if D is even.
        // Or, (n+m) and k must have different parities if D is odd.
        //
        // A simpler way:
        // Each move changes the parity of (x+y) by 0 or 1.
        // (x_final + y_final) % 2 = (x_initial + y_initial) % 2 + (number of moves that change parity of x+y) % 2
        // (n+m) % 2 = 0 + (number of non-diagonal moves) % 2
        // (n+m) % 2 = (k - D) % 2
        //
        // If (k - (n+m)) is odd, it's impossible.
        // This is equivalent to (k % 2) != ((n+m) % 2).
        if ((k % 2) != ((n + m) % 2)) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible to reach (n, m) in k moves.
        // We want to maximize diagonal moves.
        // The maximum number of diagonal moves is k.
        // However, we must ensure that the remaining moves (k - max_diag_moves)
        // can be used to adjust the coordinates to (n, m).
        //
        // We can make `m` diagonal moves to reach (m, m). This uses `m` moves.
        // Remaining moves: `k - m`. Remaining target: `(n-m, 0)`.
        //
        // Now we are at (m, m) and need to reach (n, m) in `k-m` moves.
        // This means we need to reach (n-m, 0) from (0,0) in `k-m` moves.
        //
        // To reach (n-m, 0) from (0,0) in `k-m` moves:
        // We need `n-m` moves in the x-direction. These are non-diagonal.
        // Remaining moves: `(k-m) - (n-m) = k-n`.
        // These `k-n` moves must be used to move back and forth without changing the final position.
        // Each such move must be paired with another move to cancel its effect on the final position.
        // E.g., (0,0) -> (1,0) -> (0,0) uses 2 moves.
        // Or (0,0) -> (1,1) -> (0,0) uses 2 moves.
        //
        // The `k-n` moves must be an even number of moves.
        // If `k-n` is even, we can use `(k-n)/2` pairs of moves like (x,y) -> (x+1,y) -> (x,y).
        // Each such pair uses 2 non-diagonal moves.
        //
        // So, the number of diagonal moves is `m`.
        // The number of non-diagonal moves is `n-m` (to cover the difference in x)
        // plus `k-n` (to use up remaining moves).
        // Total non-diagonal moves = `(n-m) + (k-n) = k-m`.
        //
        // This strategy gives `m` diagonal moves.
        // The total moves are `m + (k-m) = k`.
        //
        // What if `k-n` is odd?
        // This means `k` and `n` have different parities.
        // We know `(k % 2) == ((n+m) % 2)`.
        // If `k` and `n` have different parities, then `k % 2 != n % 2`.
        // This implies `n % 2 != (n+m) % 2`, which means `m` must be odd.
        //
        // If `k-n` is odd, we cannot use `(k-n)/2` pairs of moves.
        // We need to change one of the `k-n` moves from a non-diagonal to a diagonal, or vice-versa.
        //
        // Consider the case where `k-n` is odd.
        // This means `k` and `n` have different parities.
        // Since `(k % 2) == ((n+m) % 2)`, it implies `n % 2 != (n+m) % 2`, which means `m` must be odd.
        //
        // If `k-n` is odd, we must use one more diagonal move or one less diagonal move.
        //
        // Let's analyze the parity of `k-n`.
        // If `k-n` is even:
        // We can make `m` diagonal moves to reach `(m,m)`.
        // We then make `n-m` non-diagonal moves (e.g., `(1,0)` moves) to reach `(n,m)`.
        // We have `k - m - (n-m) = k-n` moves left.
        // Since `k-n` is even, we can use `(k-n)/2` pairs of cancelling moves.
        // For example, `(1,0)` then `(-1,0)`. These are 2 non-diagonal moves.
        // Total diagonal moves: `m`.
        //
        // If `k-n` is odd:
        // This means `k` and `n` have different parities.
        // Since `(k % 2) == ((n+m) % 2)`, it implies `n % 2 != (n+m) % 2`, so `m` must be odd.
        //
        // In this case, we cannot use `(k-n)/2` pairs of non-diagonal moves.
        // We need to use one move that changes the parity of `k-n`.
        //
        // Consider the path:
        // 1. `m` diagonal moves to reach `(m,m)`.
        // 2. `n-m` non-diagonal moves (e.g., `(1,0)`) to reach `(n,m)`.
        // Total moves so far: `m + (n-m) = n`.
        // Remaining moves: `k-n`.
        //
        // If `k-n` is odd, we have an odd number of moves left.
        // We need to use these `k-n` moves to end up at `(n,m)`.
        //
        // We can use `(k-n-1)` moves as pairs, and one single move.
        // For example, if we have 1 move left, we can do `(1,0)` to `(n+1,m)`. This is not allowed.
        // We need to end up at `(n,m)`.
        //
        // The only way to use an odd number of moves and end up at the same spot is to change the parity of the coordinates.
        //
        // Let's consider the maximum number of diagonal moves.
        // It's `k` if possible.
        // If `k-n` is even, we can make `m` diagonal moves, `n-m` non-diagonal moves, and `(k-n)/2` pairs of non-diagonal moves.
        // Total diagonal moves: `m`.
        //
        // If `k-n` is odd:
        // We cannot use `(k-n)/2` pairs of non-diagonal moves.
        // We must use one move that changes the parity of the remaining moves.
        //
        // Consider the target `(n,m)` and `k` moves.
        // We can make `k` diagonal moves if `k >= n` and `k >= m`.
        // If `k` diagonal moves are made, we reach `(k,k)` or `(k,-k)` etc.
        //
        // The maximum number of diagonal moves is `k` if `k` is even and `n,m` are both even.
        // Or `k-1` if `k` is odd and `n,m` are both even.
        // Or `k-1` if `k` is even and `n,m` are both odd.
        // Or `k` if `k` is odd and `n,m` are both odd.
        //
        // This is equivalent to:
        // If `(k % 2) == (n % 2)` and `(k % 2) == (m % 2)`:
        //   Result is `k`. (All coordinates and k have same parity)
        // Else if `(k % 2) != (n % 2)` and `(k % 2) != (m % 2)`:
        //   Result is `k-2`. (k has different parity than n and m, so we need to adjust two moves)
        // Else (one of n, m has same parity as k, the other doesn't):
        //   Result is `k-1`. (k has different parity than one of n or m, so we need to adjust one move)
        //
        // Let's re-evaluate the parity condition:
        // We need `(k % 2) == ((n+m) % 2)`. This is already checked.
        //
        // If `k` and `n` have the same parity, and `k` and `m` have the same parity:
        // This means `n, m, k` all have the same parity.
        // In this case, we can make `k` moves.
        // We can make `m` diagonal moves to reach `(m,m)`.
        // We can make `n-m` non-diagonal moves to reach `(n,m)`.
        // We have `k-n` moves left. Since `k` and `n` have same parity, `k-n` is even.
        // We can use `(k-n)/2` pairs of non-diagonal moves.
        // Total diagonal moves: `m`.
        //
        // This logic is flawed. The maximum number of diagonal moves is not necessarily `m`.
        // We want to maximize diagonal moves.
        //
        // The maximum number of diagonal moves is `k` if we can reach `(n,m)` in `k` moves using only diagonal moves.
        // This is only possible if `n=m=k` (and all moves are `(1,1)` or `(-1,-1)` etc.).
        //
        // Let `d` be the number of diagonal moves.
        // Let `s` be the number of straight (non-diagonal) moves.
        // `d + s = k`.
        //
        // Each diagonal move changes both x and y by 1 (in magnitude).
        // Each straight move changes only one of x or y by 1 (in magnitude).
        //
        // To reach `(n,m)` from `(0,0)`:
        // We need at least `n` changes in x-coordinate and `m` changes in y-coordinate.
        //
        // Consider the final position `(n,m)`.
        // The number of moves `k`.
        //
        // If `k` and `n` have the same parity, and `k` and `m` have the same parity:
        // This means `n, m, k` are all even, or all odd.
        // In this case, the answer is `k`.
        // Example: (2,2,2). n=2, m=2, k=2. All even. Output: 2. Path: (0,0)->(1,1)->(2,2).
        // Example: (1,1,1). n=1, m=1, k=1. All odd. Output: 1. Path: (0,0)->(1,1).
        //
        // If `k` has different parity than `n` and `m`:
        // This means `k` is even, `n` is odd, `m` is odd. (e.g., 2,1,1 -> impossible by parity check (2+1)%2 != 2%2)
        // Or `k` is odd, `n` is even, `m` is even. (e.g., 1,2,2 -> impossible by parity check (2+2)%2 != 1%2)
        // This case is covered by the `(k % 2) != ((n+m) % 2)` check.
        //
        // The remaining cases are:
        // 1. `k` has same parity as `n`, but different from `m`. (e.g., k=3, n=2, m=1. (2+1)%2 = 1, k%2 = 1. Parity check passes.)
        //    Here, `n` and `k` are different parities, `m` and `k` are different parities.
        //    No, this is wrong. `k` has same parity as `n` means `k%2 == n%2`.
        //    `k` has different parity from `m` means `k%2 != m%2`.
        //    This implies `n%2 != m%2`.
        //    If `n%2 != m%2`, then `(n+m)%2 == 1`.
        //    So `k%2 == 1`.
        //    Example: (2,1,3). n=2, m=1, k=3. `n%2=0, m%2=1, k%2=1`.
        //    `k%2 == m%2` (both 1). `k%2 != n%2`.
        //    In this case, the answer is `k-1`.
        //    Example: (2,1,3). Output: 2. Path: (0,0)->(1,0)->(1,1)->(2,1). Diagonal moves: 1.
        //    Wait, example (2,1,3) output 2.
