#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int initial_diff = initial_s - initial_b;

    // Calculate prefix sums for the left side (from right to left)
    // For jars a[n-1] down to a[0]
    // diff_left[k] = (count of 1s in a[n-k]...a[n-1]) - (count of 2s in a[n-k]...a[n-1])
    // This means we eat k jars from the left.
    std::map<int, int> diff_left_to_k_eaten; // Stores diff -> k_eaten
    diff_left_to_k_eaten[0] = 0; // 0 jars eaten from left, diff is 0
    int current_s_left = 0;
    int current_b_left = 0;
    for (int k = 1; k <= n; ++k) {
        if (a[n - k] == 1) {
            current_s_left++;
        } else {
            current_b_left++;
        }
        int diff = current_s_left - current_b_left;
        if (diff_left_to_k_eaten.find(diff) == diff_left_to_k_eaten.end()) {
            diff_left_to_k_eaten[diff] = k;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Case 1: No jars eaten from the right side (k_right = 0)
    // We need initial_diff - diff_left = 0 => diff_left = initial_diff
    if (diff_left_to_k_eaten.count(initial_diff)) {
        min_jars_eaten = std::min(min_jars_eaten, diff_left_to_k_eaten[initial_diff]);
    }

    // Iterate through possible jars eaten from the right side
    // For jars a[n] up to a[2n-1]
    // current_diff_right = (count of 1s in a[n]...a[n+k_right-1]) - (count of 2s in a[n]...a[n+k_right-1])
    int current_s_right = 0;
    int current_b_right = 0;
    for (int k_right = 1; k_right <= n; ++k_right) {
        if (a[n + k_right - 1] == 1) {
            current_s_right++;
        } else {
            current_b_right++;
        }
        int diff_right = current_s_right - current_b_right;

        // We need initial_diff - diff_left - diff_right = 0
        // So, diff_left = initial_diff - diff_right
        int target_diff_left = initial_diff - diff_right;

        if (diff_left_to_k_eaten.count(target_diff_left)) {
            min_jars_eaten = std::min(min_jars_eaten, k_right + diff_left_to_k_eaten[target_diff_left]);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

