#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_i to a very large value (effectively infinity)
    // b_i represents the maximum possible initial value for a[i]
    std::vector<long long> b(n, 2000000000LL); // Max initial value can be 10^9, but intermediate sums can be larger.
                                            // 2*10^9 is a safe upper bound for initial b_i.
                                            // The problem states |a_i| <= 10^9, so 10^9 is fine.
                                            // Let's use 10^9 as the initial upper bound.
    for(int i=0; i<n; ++i) b[i] = 1000000000LL;

    // Process operations in reverse to determine upper bounds for initial_a[i]
    // For type 1: a_j = a_j + d. This means initial_a_j + current_delta_j = initial_a_j + (current_delta_j - d) + d.
    // So, if we know the value of initial_a_j + current_delta_j, we can deduce initial_a_j + (current_delta_j - d).
    // For type 2: max(a_j) = m. This means initial_a_j + current_delta_j <= m for all j in [l,r].
    // So, initial_a_j <= m - current_delta_j. This gives an upper bound for initial_a_j.
    // We need to track the total delta applied to each element.
    std::vector<long long> current_delta(n, 0);

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // This operation adds d to a[l...r].
            // When going backwards, this means we subtract d from the current_delta for elements in [l,r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // This operation states max(a[l...r]) = m.
            // This implies that for all j in [l,r], a[j] <= m.
            // In terms of initial values: initial_a[j] + current_delta[j] <= m.
            // So, initial_a[j] <= m - current_delta[j].
            // We update b[j] (the upper bound for initial_a[j]) with this new constraint.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Now, b[i] contains the maximum possible initial value for a[i] that satisfies all type 2 constraints.
    // We can choose initial_a[i] = b[i] as a candidate solution.
    // Let's verify this candidate solution.
    std::vector<long long> initial_a = b;

    // Simulate operations with the chosen initial_a and check if all constraints are met.
    std::vector<long long> a = initial_a; // This will be the current state of the array
    bool possible = true;

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a[j] += ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                possible = false;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
        for (int i = 0; i < n; ++i) {
            std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i is now cured

        long long current_v_effect = children[i].v;
        long long d_chain_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply d_chain_effect from previous children who left
            if (d_chain_effect > 0) {
                children[j].p -= d_chain_effect;
            }

            // Apply current_v_effect from child i
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                d_chain_effect += children[j].d; // Add to chain effect for subsequent children
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1)
    // This means no pairs are in different subsequences.
    // f values are all a_i + a_j.
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // Goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness_all_same = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition_all_same(n, 1);

    // Case 2: At least one element in each subsequence.
    // This means there will be pairs in different subsequences, so f values of type a_i + a_j + h will exist.
    // The minimum possible f value is a_0 + a_1.
    // The maximum possible f value is a_{n-1} + a_{n-2} + h (if a_{n-1} and a_{n-2} are in different subsequences)
    // OR a_{n-1} + a_{n-2} (if a_{n-1} and a_{n-2} are in the same subsequence).
    //
    // To minimize max_f - min_f, we want to make min_f as large as possible and max_f as small as possible.
    //
    // Consider the partition where elements[0] is in subsequence 1, and all other elements are in subsequence 2.
    // min_f:
    //   - If n > 2: elements[1] + elements[2] (same subsequence 2)
    //   - elements[0] + elements[1] + h (different subsequences)
    //   So, min_f = min(elements[1] + elements[2], elements[0] + elements[1] + h)
    //   However, if elements[0] is in sub 1 and elements[1] is in sub 2, then elements[0]+elements[1]+h is a candidate for min_f.
    //   If elements[1] and elements[2] are in sub 2, then elements[1]+elements[2] is a candidate for min_f.
    //   The smallest possible sum of two elements is elements[0] + elements[1].
    //   So, min_f will be at least elements[0] + elements[1].
    //   If elements[0] and elements[1] are in different subsequences, min_f = elements[0] + elements[1] + h.
    //   If elements[0] and elements[1] are in the same subsequence, min_f = elements[0] + elements[1].
    //
    // Let's consider the strategy: put elements[0] in sub 1, and all other elements in sub 2.
    // This ensures that elements[0] and elements[1] are in different subsequences.
    // So, min_f = elements[0] + elements[1] + h.
    // max_f:
    //   - elements[n-1] + elements[n-2] (same subsequence 2)
    //   - elements[0] + elements[n-1] + h (different subsequences)
    //   So, max_f = max(elements[n-1] + elements[n-2], elements[0] + elements[n-1] + h)
    //
    // Goodness = max(elements[n-1] + elements[n-2], elements[0] + elements[n-1] + h) - (elements[0] + elements[1] + h)
    //
    // This simplifies to:
    // max(elements[n-1] + elements[n-2] - (elements[0] + elements[1] + h), elements[0] + elements[n-1] + h - (elements[0] + elements[1] + h))
    // max(elements[n-1] + elements[n-2] - elements[0] - elements[1] - h, elements[n-1] - elements[1])
    //
    // This is the goodness for the partition where elements[0] is in sub 1, and all others are in sub 2.
    // Let's call this `goodness_one_split`.
    //
    // The minimum f value will be `elements[0] + elements[1]`.
    // The maximum f value will be `elements[n-1] + elements[n-2]`.
    // If we split elements[0] and elements[1], then `elements[0] + elements[1] + h` is a candidate for min_f.
    // If we split elements[n-1] and elements[n-2], then `elements[n-1] + elements[n-2] + h` is a candidate for max_f.
    //
    // The crucial observation is that to minimize the range, we want to make the smallest possible `a_i + a_j + h`
    // as close as possible to the largest possible `a_i + a_j`.
    //
    // The smallest possible sum of two elements is `elements[0].value + elements[1].value`.
    // The largest possible sum of two elements is `elements[n-1].value + elements[n-2].value`.
    //
    // If we put `elements[0]` in one group and all others in another group:
    // Min f value: `elements[0].value + elements[1].value + h` (from `elements[0]` and `elements[1]`)
    // Max f value: `max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)`
    //
    // Let's calculate this goodness:
    long long min_f_val_split = elements[0].value + elements[1].value + h;
    long long max_f_val_split = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
    long long goodness_one_split = max_f_val_split - min_f_val_split;

    std::vector<int> partition_one_split(n);
    partition_one_split[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_one_split[elements[i].original_index] = 2;
    }

    if (goodness_one_split < goodness_all_same) {
        std::cout << goodness_one_split << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_one_split[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_all_same << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition_all_same[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

