    // Cut s into s1 and s2. Form s2 + s1.
    // Check if s2 + s1 is a palindrome and s2 + s1 != s.
    for (int i = 1; i < n; ++i) { // i is the length of s1
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case for k=2 (3 pieces)
    // If no solution with k=1, we need to check k=2.
    // The problem statement implies that if a solution exists, it's either 1 or 2.
    // This is because if all characters are the same (e.g., "aaaa"), it's impossible.
    // If there are at least two distinct characters, we can always achieve k=2.
    // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
    // Example: "abacaba" -> "aba|c|aba" -> "aba|c|aba" (no change)
    // But we can do "a|bacab|a" -> "a|bacab|a" (no change)
    // The logic for k=2 is that if not all characters are the same,
    // we can always find a way to make a new palindrome.
    // Consider s = c_1 c_2 ... c_N.
    // If not all characters are the same, there exists some c_i != c_1.
    // Since s is a palindrome, c_i = c_{N-i+1}.
    // If c_1 != c_2, then s_new = s_2 s_1 is a candidate for k=1.
    // If c_1 = c_2 = ... = c_{N/2} but c_1 != c_{N/2+1} (for odd N),
    // then s = "aa...ab...aa".
    // If all characters are the same, e.g., "aaaaa", then any permutation of pieces
    // will result in "aaaaa". In this case, it's impossible.
    // We need to check if all characters in s are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 must be the answer.
        // This is because we can always find a cut that creates a new palindrome.
        // For example, take s = "abacaba". k=1 fails.
        // Cut "a|bacab|a". Reorder to "a|bacab|a" (no change).
        // Cut "ab|acab|a". Reorder to "acab|ab|a" (not palindrome).
        // The problem statement guarantees that if a solution exists, it's 1 or 2.
        // The only case where it's impossible is if all characters are the same.
        // If not all characters are the same, and k=1 didn't yield a solution,
        // then k=2 must be the minimum.
        std::cout << 2 << std::endl;
    }

    return 0;
}

