            continue; // Don't copy a pile into itself
        }
        // For each other pile a[i], we want to add a[min_idx] to it as many times as possible
        // without a[i] exceeding k.
        // The current value of a[i] is a[i].
        // We can add a[min_idx] to it (k - a[i]) / a[min_idx] times.
        // This is integer division, which correctly gives the floor.
        total_spells += (k - a[i]) / min_val;
    }

    std::cout << total_spells << std::endl;
}

