            // Or 2 presses (e.g., +5, -2, -2)
            // The optimal is 1 press.
            ans += 1;
        } else if (diff == 2) {
            // Can be 1 press (+2 or -2)
            // The optimal is 1 press.
            ans += 1;
        } else if (diff == 3) {
            // Can be 2 presses (+1, +2 or -1, -2)
            // Or 2 presses (+5, -2)
            // Or 2 presses (-5, +2)
            // The optimal is 2 presses.
            ans += 2;
        } else if (diff == 4) {
            // Can be 2 presses (+2, +2 or -2, -2)
