#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d; // d can be up to 100, a_i up to 100. n up to 100.
                 // Total haybales can be 100*100 = 10000.
                 // Days needed can be (n-1)*total_haybales = 99*10000 = 990000.
                 // d is small, but the calculation for days_needed can exceed int if not careful.
                 // However, d is the limit, so we just subtract from d.
                 // The number of haybales moved is what matters.
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0]; // Start with initial haybales in pile 1

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile (i+1) to pile 1 is i days.
        // (e.g., pile 2 (index 1) costs 1 day, pile 3 (index 2) costs 2 days)
        long long cost_per_haybale = i; 

        if (d >= cost_per_haybale) { // If we have enough days to move at least one haybale from this pile
            // Calculate how many haybales we can move from this pile
            // We have a[i] haybales in this pile.
            // We have d days remaining.
            // Each haybale costs cost_per_haybale days.
            long long haybales_to_move = std::min((long long)a[i], d / cost_per_haybale);

            current_a1 += haybales_to_move;
            d -= haybales_to_move * cost_per_haybale;
        } else {
            // If we don't even have enough days to move one haybale from this pile,
            // we can't move any haybales from this pile or any further piles (as they cost more).
            break; 
        }
    }

    std::cout << current_a1 << std::endl;
}

