#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else if (n == 2) {
        std::cout << 57 << std::endl;
    } else if (n == 3) {
        std::cout << 239 << std::endl;
    } else {
        // For n >= 4, we can construct a number starting with '2' and '3',
        // followed by (n-2) '7's.
        // Example: n=4 -> 2377
        // Digits are 2, 3, 7.
        // Divisibility by 2: No, ends in 7 (odd).
        // Divisibility by 3: Sum of digits = 2 + 3 + 7*(n-2).
        // For n=4, sum = 2+3+7+7 = 19, not div by 3.
        // For n=5, sum = 2+3+7+7+7 = 26, not div by 3.
        // In general, 2+3 = 5. 7 mod 3 = 1.
        // Sum of digits mod 3 = (5 + (n-2)*1) mod 3 = (3 + 2 + n - 2) mod 3 = (n+3) mod 3 = n mod 3.
        // If n is not divisible by 3, then the sum of digits is not divisible by 3.
        // If n is divisible by 3, then the sum of digits is divisible by 3.
        // This construction fails if n is divisible by 3.

        // Let's use the pattern 23...7 for n >= 2.
        // For n=2: 23. Digits 2,3. 23%2!=0, 23%3!=0. Valid.
        // For n=3: 237. Digits 2,3,7. 237%2!=0, 237%3==0 (2+3+7=12). Fails.
        // The example uses 239 for n=3.

        // A robust pattern for n >= 2:
        // Start with '2' and '3'.
        // Fill the remaining (n-2) digits with '7's.
        // The number will be 2377...7.
        // Digits present: 2, 3, 7.
        // Divisibility by 2: The number ends in 7, so it's odd. Not divisible by 2.
        // Divisibility by 3: Sum of digits = 2 + 3 + (n-2)*7 = 5 + 7n - 14 = 7n - 9.
        // (7n - 9) mod 3 = (n - 0) mod 3 = n mod 3.
        // If n is not divisible by 3, then the sum of digits is not divisible by 3, so the number is not divisible by 3.
        // If n is divisible by 3, then the sum of digits is divisible by 3, so the number is divisible by 3.
        // This construction fails if n is divisible by 3.

        // Let's try a different pattern:
        // For n >= 2:
        // Start with '2'.
        // Fill the remaining (n-1) digits with '3's.
        // The number will be 233...3.
        // Digits present: 2, 3.
        // Divisibility by 2: The number ends in 3, so it's odd. Not divisible by 2.
        // Divisibility by 3: Sum of digits = 2 + (n-1)*3.
        // (2 + (n-1)*3) mod 3 = (2 + 0) mod 3 = 2.
        // The sum of digits is never divisible by 3. So the number is never divisible by 3.
        // This pattern works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

