int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where l < r, the number 2 will always be a divisor
        // for at least floor(r/2) - floor((l-1)/2) numbers.
        // This count is maximized when l and r are far apart.
        // For example, if l=2, r=10^9, count for 2 is 10^9/2.
        // For any d > 2, the count floor(r/d) - floor((l-1)/d) will be less than or equal to
        // floor(r/2) - floor((l-1)/2).
        // The only exception is when l and r are very close, and 2 is not a divisor
        // for many numbers, but some other prime is.
        // Example: l=3, r=6.
        // Count for 2: floor(6/2) - floor(2/2) = 3 - 1 = 2 (numbers: 4, 6)
        // Count for 3: floor(6/3) - floor(2/3) = 2 - 0 = 2 (numbers: 3, 6)
        // In this case, 2 and 3 both appear 2 times. Any is fine.
        // The problem asks for *any* integer if there are multiple answers.
        // The number 2 is the most frequent divisor (or tied for most frequent)
        // for any range [l, r] where l < r.
        // This is because 2 is the smallest prime, and thus its multiples are the densest.
        // The only case where 2 might not be the answer is if l=r, in which case l itself is the answer.
        // But the problem states "divisors except 1". If l=r=2, answer is 2.
        // If l=r=3, answer is 3.
        // If l=r=4, answer is 2 or 4.
        // The problem statement implies l and r can be equal.
        // If l=r, the only number is l. Its divisors (excluding 1) are what we consider.
        // The most frequent divisor is l itself (if l > 1).
        // For example, if l=19, r=29, output is 2.
        // For l=3, r=6, output is 3.
        // The example output for 3,6 is 3.
        // Count for 2: floor(6/2) - floor(2/2) = 3 - 1 = 2 (4, 6)
        // Count for 3: floor(6/3) - floor(2/3) = 2 - 0 = 2 (3, 6)
        // Both 2 and 3 are valid answers. The problem says "print any of them".
        // The simplest answer that is always valid for l < r is 2.
        // If l=r, the answer is l.
        // Since l >= 2, l is always a valid divisor for itself.
        // The condition l == r is handled.
        // For l < r, 2 is always a good candidate.
        // The number of multiples of 2 in [l, r] is floor(r/2) - floor((l-1)/2).
        // The number of multiples of any d > 2 in [l, r] is floor(r/d) - floor((l-1)/d).
        // Since d > 2, r/d < r/2 and (l-1)/d < (l-1)/2.
        // Thus, floor(r/d) - floor((l-1)/d) <= floor(r/2) - floor((l-1)/2).
        // So 2 is always a maximal answer (or tied for maximal).
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    // Iterate from right to left
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // If a[i] and b[i] are already equal, no operation is needed for this position.
            // However, we still need to update has_pos_one and has_neg_one for elements to its left.
            if (a[i] == 1) {
                has_pos_one = true;
            } else if (a[i] == -1) {
                has_neg_one = true;
            }
            continue;
        }

        // If a[i] != b[i], we need to change a[i].
        // This change must come from an element a[k] where k < i.
        // The current a[i] value is fixed for operations on elements to its right.
        // For elements to its left, a[i] is still its original value.

        if (b[i] > a[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // b[i] < a[i], need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }

        // Update has_pos_one and has_neg_one based on the original a[i]
        // for elements to its left.
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

