    // i=0, p[0]=2. M_0 = max(min(2,5), min(2,4), min(2,1), min(2,3)) = max(2,2,1,2) = 2. So p[0]=2.
    // i=1, p[1]=5. M_1 = max(min(5,2), min(5,4), min(5,1), min(5,3)) = max(2,4,1,3) = 4. Since M_1=4=n-1, p[1]=n=5.
    // i=2, p[2]=4. M_2 = max(min(4,2), min(4,5), min(4,1), min(4,3)) = max(2,4,1,3) = 4. So p[2]=4.
    // i=3, p[3]=1. M_3 = max(min(1,2), min(1,5), min(1,4), min(1,3)) = max(1,1,1,1) = 1. So p[3]=1.
    // i=4, p[4]=3. M_4 = max(min(3,2), min(3,5), min(3,4), min(3,1)) = max(2,3,3,1) = 3. So p[4]=3.
    // This logic is correct.

    for (int i = 0; i < n; ++i) {
