void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_price_so_far = a[n - 1]; // Initialize with the last price

    // Iterate from right to left, starting from the second to last element
    // (index n-2) down to the first element (index 0).
    // The last element a[n-1] can never be a bad price because there are
    // no days after it.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_price_so_far) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_price_so_far, it means a[i]
            // is less than or equal to the minimum price encountered so far
            // from a[i+1] to a[n-1].
            // So, a[i] itself becomes the new minimum for elements to its left.
            min_price_so_far = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

