        int last_r_pos = -1; // Represents the last position where an 'R' was encountered, or -1 for cell 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The distance from the previous 'R' (or cell 0) to the current 'R'
                // is (i + 1) - (last_r_pos + 1) = i - last_r_pos.
