                // then the distance is 0 - (-1) = 1.
                // If last_r_pos = 0, and current 'R' is at i=2 (s[1] is 'L'),
                // then the distance is 2 - 0 = 2.
                max_dist = std::max(max_dist, i - last_r_pos);
                last_r_pos = i;
            }
        }

        // After iterating through the string, consider the jump from the last 'R'
        // (or cell 0 if no 'R's) to cell n+1.
        // The distance is (n + 1) - (last_r_pos + 1) = n - last_r_pos.
        max_dist = std::max(max_dist, n - last_r_pos);

        std::cout << max_dist << "\n";
