        // We need k such students.
        // So, k <= (c-k) + (m-k) + x
        // k <= c + m + x - 2k
        // 3k <= c + m + x
        // k <= (c + m + x) / 3.
        // This confirms that the minimum of these three values is the answer.
        long long ans = std::min({c, m, (c + m + x) / 3});
