int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we will use to generate k distinct differences

    // Generate k distinct differences: 1, 2, ..., k
    // We can achieve this by alternating between left and right pointers
    // using numbers from 1 to k+1.
    // The sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // This generates differences: k, k-1, k-2, ..., 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers (from k+2 to n) can be appended in increasing order.
    // This will only introduce a difference of 1 (e.g., |(k+1) - (k+2)| = 1),
    // which is already among the k distinct differences we generated (since k >= 1).
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

