    // This `j` is the start of the first non-decreasing suffix.
    // All elements from `a[j]` to `a[n-1]` are in non-increasing order.
    int j = i; // Start search from `i`
    while (j > 0 && a[j - 1] >= a[j]) {
        j--;
    }
    // Now `a[j...n-1]` is non-increasing.
    // If `j` is 0, the whole array is non-increasing.

