#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1.
        // So, m=1 is always beautiful.

        // For m > 1, we expand the current segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min(pos[1], ..., pos[m])
        // to max(pos[1], ..., pos[m]).
        // We maintain current_min_idx and current_max_idx to be the
        // minimum and maximum indices encountered so far for numbers 1 to (m-1).
        // When considering 'm', we update these bounds to include pos[m].

        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The subsegment contains all numbers from 1 to m (guaranteed by how we update bounds).
        // 2. The subsegment contains NO numbers greater than m.
        //    This is equivalent to saying the length of the subsegment must be exactly m.
        //    If the length is greater than m, it means there are other numbers
        //    (which must be > m, because 1..m are all present) within this range.
        //    If the length is less than m, it means not all numbers 1..m are present,
        //    which contradicts our bound update logic.
        // So, the condition simplifies to: current_max_idx - current_min_idx + 1 == m.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

