void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // Box 1: (-inf, -1]
    // Final product must be negative and magnitude >= 1
    // This requires an odd number of negative factors.
    // And at least one factor with magnitude >= 1, or multiple factors with magnitude > 1.
    // If all factors have magnitude < 1, the product will have magnitude < 1.
    // If there's at least one factor with magnitude >= 1, we can potentially make the product magnitude >= 1.

    // Case 1: Final product in Box 1 (negative, magnitude >= 1)
    // Number of negative toys: A + B
    // If A+B is odd: The sign can be negative.
    // If A+D >= 1: There is at least one toy with magnitude >= 1.
    // If A+D == 0: All initial toys have magnitude < 1. The product will have magnitude < 1.
    // If A+D >= 1, we can potentially make the magnitude >= 1.
    // If A+B is odd and A+D >= 1, then Box 1 is possible.
    if ((A + B) % 2 == 1 && (A + D >= 1)) {
        ans1 = "Ya";
    }

    // Case 2: Final product in Box 2 (-1, 0)
    // Final product must be negative and magnitude < 1
    // This requires an odd number of negative factors.
    // And all factors must have magnitude < 1, or we can arrange multiplications to make it < 1.
    // If A+B is odd: The sign can be negative.
    // If C+D >= 1: There is at least one positive toy.
    // If A+D == 0: All initial toys have magnitude < 1. The product will have magnitude < 1.
    // If A+D >= 1: We need to be able to make the magnitude < 1.
    // This is always possible if there are toys in B or C, or if A+D >= 2.
    // If A+D >= 1, we can always make the magnitude < 1 by multiplying with a small number.
    // For example, if we have a toy with value 100 (from D) and a toy with value 0.001 (from C or B), we can make 0.1.
    // The only tricky case is if A+D >= 1 and B+C == 0.
    // If B+C == 0, then all toys are from A or D. Their magnitudes are all >= 1.
    // The product of such toys will always have magnitude >= 1.
    // So, if B+C == 0, Box 2 is impossible.
    // Otherwise (if B+C >= 1), Box 2 is possible if A+B is odd.
    if ((A + B) % 2 == 1 && (B + C >= 1 || (A + D >= 1 && A + D + B + C >= 2))) {
        // If B+C >= 1, we have at least one toy with magnitude < 1.
        // We can always make the final magnitude < 1.
        // If B+C == 0, then all toys are from A or D. Their magnitudes are all >= 1.
        // The product of such toys will always have magnitude >= 1. So Box 2 is impossible.
        // The condition (B+C >= 1 || (A+D >= 1 && A+D + B + C >= 2)) simplifies to B+C >= 1.
        // Because if B+C == 0, then A+D = total_toys. If total_toys >= 2, then A+D >= 2.
        // But if B+C == 0, the magnitude will be >= 1. So this condition is wrong.
        // Let's re-evaluate:
        // To get to Box 2, we need negative sign (A+B odd) and magnitude < 1.
        // Magnitude < 1 is possible if there is at least one toy with magnitude < 1 (B+C >= 1).
        // Or, if we have multiple toys with magnitude >= 1, we can't make magnitude < 1.
        // So, if A+B is odd AND B+C >= 1, then Box 2 is possible.
        if (B + C >= 1) {
            ans2 = "Ya";
        }
    }

    // Case 3: Final product in Box 3 (0, 1)
    // Final product must be positive and magnitude < 1
    // This requires an even number of negative factors.
    // And magnitude < 1.
    // If A+B is even: The sign can be positive.
    // If B+C >= 1: There is at least one toy with magnitude < 1.
    // If B+C == 0: All toys are from A or D. Their magnitudes are all >= 1.
    // The product of such toys will always have magnitude >= 1. So Box 3 is impossible.
    // So, if A+B is even AND B+C >= 1, then Box 3 is possible.
    if ((A + B) % 2 == 0 && (B + C >= 1)) {
        ans3 = "Ya";
    }

    // Case 4: Final product in Box 4 [1, inf)
    // Final product must be positive and magnitude >= 1
    // This requires an even number of negative factors.
    // And magnitude >= 1.
    // If A+B is even: The sign can be positive.
    // If A+D >= 1: There is at least one toy with magnitude >= 1.
    // If A+D == 0: All initial toys have magnitude < 1. The product will have magnitude < 1.
    // So, if A+B is even AND A+D >= 1, then Box 4 is possible.
    if ((A + B) % 2 == 0 && (A + D >= 1)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

