void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops: minimum value a[i] must be to satisfy a[0] < a[1] < ... < a[i]
    // If a[i] is the i-th element (0-indexed), it must be at least i.
    // So, a[i] must be >= i.
    // If a[i] < i, it's impossible to make it strictly increasing from 0.
    // We can only decrease a[i]. So if a[i] is already less than i, we can't make it i.
    // The actual value a[i] must be able to become is a[i].
    // So, we need a[i] >= i for all i in the increasing part.
    // This means a[i] - i >= 0.
    // Let's find the first index `i` from the left where `a[i] < i`.
    // If such an `i` exists, then `a[0] < a[1] < ... < a[i]` cannot be formed
    // because `a[i]` would need to be at least `i`, but its current value `a[i]` is less than `i`.
    // Since we can only decrease, `a[i]` cannot become `i` or more.
    // So, the increasing part can only go up to `i-1`.
    // `left_reach` will be the maximum index `k` such that `a[0] < a[1] < ... < a[k]` can be formed.
    // This means `a[j] >= j` for all `0 <= j <= k`.
    int left_reach = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            break;
        }
        left_reach = i;
    }

    // Calculate suffix_min_ops: minimum value a[i] must be to satisfy a[i] > a[i+1] > ... > a[n-1]
    // If a[i] is the i-th element (0-indexed), it must be at least (n-1-i).
    // So, a[i] must be >= (n-1-i).
    // If a[i] < (n-1-i), it's impossible to make it strictly decreasing to 0.
    // `right_reach` will be the minimum index `k` such that `a[k] > a[k+1] > ... > a[n-1]` can be formed.
    // This means `a[j] >= (n-1-j)` for all `k <= j <= n-1`.
    int right_reach = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            break;
        }
        right_reach = i;
    }

    // If there is any `k` (0-indexed) such that `left_reach >= k` and `right_reach <= k`,
    // then it's possible.
    // This means there is an index `k` that can serve as the peak.
    // For such a `k`, `a[0] < ... < a[k]` is possible (because `k <= left_reach`).
    // And `a[k] > ... > a[n-1]` is possible (because `k >= right_reach`).
    // The condition `left_reach >= right_reach` implies that there is at least one such `k`.
    // For example, if `left_reach = 2` and `right_reach = 1`, then `k=1` and `k=2` are possible peaks.
    // `k=1`: `a[0]<a[1]` is possible, `a[1]>a[2]>...>a[n-1]` is possible.
    // `k=2`: `a[0]<a[1]<a[2]` is possible, `a[2]>a[3]>...>a[n-1]` is possible.
    if (left_reach >= right_reach) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

