int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int ptr_a = 0; // Pointer for elements we are trying to beat (smaller elements)
    int ptr_b = 0; // Pointer for elements we are using to beat (larger elements)

    while (ptr_b < n) {
        // If a[ptr_b] is greater than a[ptr_a], we can use a[ptr_b] to beat a[ptr_a].
        // This contributes to our count. We then move both pointers forward.
        if (a[ptr_b] > a[ptr_a]) {
            count++;
            ptr_a++;
            ptr_b++;
        } else {
            // If a[ptr_b] is not greater than a[ptr_a], we cannot use a[ptr_b]
            // to beat a[ptr_a] (or any smaller element than a[ptr_a] that we might have skipped).
            // Since a is sorted, a[ptr_b] also won't be greater than a[ptr_a+1], a[ptr_a+2], etc.
            // So, we must try a larger element from the 'beating' pool.
            // We move ptr_b forward to find a potentially larger element.
            ptr_b++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

