// Function to check if a subarray is a permutation
// It checks if all numbers from 1 to length are present exactly once.
// This is equivalent to checking if the maximum element is 'length'
// and all elements are distinct.
bool is_permutation(const std::vector<int>& arr, int start_idx, int length) {
    if (length == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
                     // For this problem, l1, l2 >= 1.
    }
    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = 0; i < length; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > length || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix distinct counts
    std::vector<int> prefix_distinct_count(n);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        prefix_distinct_count[i] = current_distinct_prefix;
    }

    // Precompute suffix distinct counts
    std::vector<int> suffix_distinct_count(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        suffix_distinct_count[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;

        // Check if first part is a permutation of length l1
        // 1. Max element in a[0...l1-1] must be l1
        // 2. Number of distinct elements in a[0...l1-1] must be l1
        bool p1_is_perm = (prefix_max[l1 - 1] == l1) && (prefix_distinct_count[l1 - 1] == l1);

        // Check if second part is a permutation of length l2
        // 1. Max element in a[l1...n-1] must be l2
        // 2. Number of distinct elements in a[l1...n-1] must be l2
        bool p2_is_perm = (suffix_max[l1] == l2) && (suffix_distinct_count[l1] == l2);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;

    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is better
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    // Taking N/2 leaves an odd number for opponent.
                    // Taking 1 leaves an odd number for opponent.
                    // Taking N/2 is better if N/2 > 1.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // Taking N/2 leaves an even number for opponent.
                    // Taking 1 leaves an odd number for opponent.
                    // If we take 1, opponent gets an odd N-1.
                    // If we take N/2, opponent gets an even N/2.
                    // Opponent will prefer to take N/4 if N/2 is even.
                    // We want to maximize our coins.
                    // If we take 1, we get 1.
                    // If we take N/2, we get N/2.
                    // N/2 is always better than 1 for us.
                    // The opponent's optimal play is handled by their turn.
                    // We just want to maximize our current gain.
                    // So, take N/2.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is better
                    opponent_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    opponent_coins += n / 2;
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

