char get_winning_move(char opponent_move) {
    if (opponent_move == 'R') return 'P';
    if (opponent_move == 'S') return 'R';
    if (opponent_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int countR = 0;
        int countS = 0;
        int countP = 0;

        for (char c : s) {
            if (c == 'R') {
                countR++;
            } else if (c == 'S') {
                countS++;
            } else { // c == 'P'
                countP++;
            }
        }

        char most_frequent_bot_move;
        if (countR >= countS && countR >= countP) {
            most_frequent_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            most_frequent_bot_move = 'S';
        } else { // countP is strictly greatest or tied with others
            most_frequent_bot_move = 'P';
        }

        char our_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need current_sum + S_app = 2 * (current_xor_sum ^ X_app)
    // Let S_app be the sum of appended elements and X_app be their XOR sum.
    // We want to find b1, b2, b3 such that:
    // current_sum + b1 + b2 + b3 = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)

    // Strategy: Append at most 3 elements.
    // It's always possible to make it good by appending at most 3 elements.
    // Let's try to append two elements, say x and y.
    // We want current_sum + x + y = 2 * (current_xor_sum ^ x ^ y).
    // A simple choice for x and y is to make current_xor_sum ^ x ^ y equal to some value.
    // Let's try to make current_xor_sum ^ x ^ y = current_xor_sum.
    // This means x ^ y = 0, so x = y.
    // If we append x and x, the new XOR sum is current_xor_sum ^ x ^ x = current_xor_sum.
    // The new sum is current_sum + x + x = current_sum + 2x.
    // The condition becomes current_sum + 2x = 2 * current_xor_sum.
    // This implies 2x = 2 * current_xor_sum - current_sum.
    // So x = current_xor_sum - current_sum / 2.
    // This requires current_sum to be even, and current_xor_sum - current_sum / 2 >= 0.
    // This strategy doesn't always work.

    // A more robust strategy:
    // Append two elements: current_xor_sum and current_sum.
    // No, this is not correct.
    // Let's append two elements: X and S.
    // The current sum is S_curr, current XOR sum is X_curr.
    // We want S_curr + b1 + b2 = 2 * (X_curr ^ b1 ^ b2).
    // Consider appending X_curr and some value Y.
    // New XOR sum: X_curr ^ X_curr ^ Y = Y.
    // New sum: S_curr + X_curr + Y.
    // Condition: S_curr + X_curr + Y = 2Y.
    // S_curr + X_curr = Y.
    // So, if we append X_curr and (S_curr + X_curr), the array becomes good.
    // Let b1 = current_xor_sum.
    // Let b2 = current_sum + current_xor_sum.
    // New sum = current_sum + b1 + b2 = current_sum + current_xor_sum + (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum).
    // New XOR sum = current_xor_sum ^ b1 ^ b2 = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum.
    // The condition is satisfied: 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum).
    // This strategy always works and uses 2 elements.
    // The elements are current_xor_sum and current_sum + current_xor_sum.
    // These values can be large, up to 10^5 * 10^9 + 10^9 ~ 10^14, which fits in long long.

    // Example 1: [1, 2, 3, 6]
    // S = 12, X = 6.
    // S = 2X, already good. Output 0.

    // Example 2: [8]
    // S = 8, X = 8.
    // S != 2X.
    // Append X_curr = 8.
    // Append S_curr + X_curr = 8 + 8 = 16.
    // New array: [8, 8, 16].
    // New sum = 8 + 8 + 16 = 32.
    // New XOR sum = 8 ^ 8 ^ 16 = 16.
    // 32 = 2 * 16. Good.
    // Output: 2 elements: 8, 16.
    // The example output is 2 elements: 4, 4.
    // Let's check example output: [8, 4, 4].
    // Sum = 8 + 4 + 4 = 16.
    // XOR sum = 8 ^ 4 ^ 4 = 8.
    // 16 = 2 * 8. Good.
    // This means there are multiple solutions. My strategy is valid.

    // Example 3: [1, 1]
    // S = 2, X = 0.
    // S != 2X.
    // Append X_curr = 0.
    // Append S_curr + X_curr = 2 + 0 = 2.
    // New array: [1, 1, 0, 2].
    // New sum = 1 + 1 + 0 + 2 = 4.
    // New XOR sum = 1 ^ 1 ^ 0 ^ 2 = 0 ^ 0 ^ 2 = 2.
    // 4 = 2 * 2. Good.
    // Output: 2 elements: 0, 2.
    // The example output is 3 elements: 2, 6, 2.
    // Let's check example output: [1, 1, 2, 6, 2].
    // Sum = 1 + 1 + 2 + 6 + 2 = 12.
    // XOR sum = 1 ^ 1 ^ 2 ^ 6 ^ 2 = 0 ^ 2 ^ 6 ^ 2 = 2 ^ 6 ^ 2 = 4 ^ 2 = 6.
    // 12 = 2 * 6. Good.
    // This confirms my strategy is valid, even if it differs from example.

    // The problem states "You don't have to minimize the number of added elements!".
    // My strategy always adds 2 elements, unless the array is already good.
    // This is within the "at most 3 elements" constraint.

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // This 'b' will be pushed to the left of those 'a's.
            // The number of 'a's currently to its left (count_a)
            // determines how many times this 'b' will be involved
            // in an 'ab' -> 'bba' operation.
            // Each such operation effectively doubles the number of 'a's
            // that this 'b' will eventually "pass".
            // So, the current count_a 'a's will cause count_a operations.
            // After these operations, this 'b' will be to the left of all
            // those 'a's.
            // The key insight is that when an 'ab' becomes 'bba', the 'a'
            // effectively moves past the 'b', and a new 'b' is created.
            // The original 'b' is now to the left of the 'a'.
            // The number of 'a's that this 'b' has to "pass" is count_a.
            // Each 'a' that passes this 'b' contributes to the total steps.
            // When 'ab' -> 'bba', the 'a' moves past the 'b'.
            // The number of steps for this 'b' to move past all 'a's to its left
            // is equal to the current count_a.
            // After this 'b' moves past all 'a's, it also creates new 'b's.
            // The number of 'a's that will be affected by subsequent 'b's
            // (those to the left of current 'b') will be doubled.
            // This is because each 'a' that passes this 'b' effectively
            // creates a new 'b' that will also need to be passed by 'a's
            // further to the left.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means it's an 'a' that is
            // currently to the left of some 'b's (those already processed).
            // This 'a' will eventually move past those 'b's.
            // We simply increment the count of 'a's encountered so far
            // from the right.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_val, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_val, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs with same (x,y) coordinates, as they were counted twice
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

