// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get standard order
    return pattern;
}

// Function to normalize a pattern string to a fixed length (18)
// by padding with '0's from the left.
// This is for internal storage in the map.
std::string normalize_pattern_for_map(const std::string& s) {
    std::string normalized_s = s;
    if (normalized_s.length() < 18) {
        normalized_s = std::string(18 - normalized_s.length(), '0') + normalized_s;
    }
    return normalized_s;
}

