    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern_str = to_parity_pattern(a);
            counts[normalize_pattern_for_map(pattern_str)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern_str = to_parity_pattern(a);
            counts[normalize_pattern_for_map(pattern_str)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            std::cout << counts[normalize_pattern_for_map(s)] << "\n";
        }
    }

    return 0;
}

