    }

    std::vector<int> colors(n);
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) { // p is the split point digit
        int last1 = -1;
        int last2 = -1;
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                // Must be color 1
                if (d[i] < last1) {
                    possible_p = false;
                    break;
                }
                colors[i] = 1;
                last1 = d[i];
            } else if (d[i] > p) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_p = false;
                    break;
                }
                colors[i] = 2;
                last2 = d[i];
            } else { // d[i] == p
                // Can be color 1 or 2
                // Prioritize color 2 if possible, to keep last1 small
                if (d[i] >= last2) {
                    colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) {
                    colors[i] = 1;
                    last1 = d[i];
                } else {
                    possible_p = false;
