// Function to find prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the largest divisor
            // that is not divisible by q.
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, we need to find a divisor x of p such that x % q != 0.
        // The largest such x will be p divided by some factor of q.
        // We want to remove the minimum necessary factors from p to make it not divisible by q.
        // This means we want to divide p by the smallest possible factor 'k' such that (p/k) % q != 0.
        // This is equivalent to finding the largest x = p/k such that x % q != 0.

        // Let q = f1^a1 * f2^a2 * ... * fm^am be the prime factorization of q.
        // For p/k not to be divisible by q, p/k must lack at least one prime factor f_i
        // with sufficient power a_i that q has.
        // Specifically, if p = f1^b1 * f2^b2 * ... * fm^bm * ...
        // and q = f1^a1 * f2^a2 * ... * fm^am, then b_i >= a_i for all i.
        // To make p/k not divisible by q, we must reduce the exponent of some f_i in p/k
        // to be less than a_i. The largest such p/k would be obtained by dividing p by
        // f_i^(b_i - a_i + 1) for some i.
        // We want to maximize p/ (f_i^(b_i - a_i + 1)). This is equivalent to minimizing f_i^(b_i - a_i + 1).
        // So we iterate through all prime factors f_i of q.
        // For each f_i, calculate the maximum power of f_i that divides p (let it be f_i^b_i).
        // Then calculate p / (f_i^(b_i - a_i + 1)). This value is a candidate for x.
        // The maximum among these candidates will be the answer.

        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);
        long long max_x = 1; // Since p is divisible by q, p itself is not a candidate.

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            // int a = factor_pair.second; // a is the exponent of f in q

            // Calculate the exponent of f in p
            long long temp_p = p;
            long long current_f_power_in_p = 1; // f^0
            while (temp_p > 0 && temp_p % f == 0) {
                temp_p /= f;
                current_f_power_in_p *= f;
            }

            // The candidate x is p divided by current_f_power_in_p.
            // This removes all occurrences of f from p.
            // This ensures that x is not divisible by q (specifically, by f).
            // However, we want to remove the minimum necessary factors of f.
            // If p = F * f^B and q = G * f^A, where F, G are not divisible by f.
            // Since p % q == 0, we know B >= A.
            // We want x = p / (f^k) such that x % q != 0.
            // To make x not divisible by q, we need to make sure that for at least one prime factor f_i of q,
            // the exponent of f_i in x is less than its exponent in q.
            // The simplest way to do this for a specific f_i is to reduce its exponent in p
            // from B to A-1. This means dividing p by f_i^(B - (A-1)) = f_i^(B - A + 1).
            // The resulting x is p / (f_i^(B - A + 1)).
            // We want to maximize this x, which means minimizing f_i^(B - A + 1).
            // This is equivalent to minimizing (B - A + 1).
            // We iterate over all prime factors f_i of q.
            // For each f_i, we calculate the largest power of f_i that divides p.
            // Let p = P_prime * f_i^B.
            // Let q = Q_prime * f_i^A.
            // We know B >= A.
            // We want to find x = p / (f_i^k) such that x % q != 0.
            // The largest such x is p / (f_i^(B - A + 1)).
            // This value is P_prime * f_i^(A-1).
            // This x is guaranteed to be a divisor of p and not divisible by q (because its f_i exponent is A-1, which is less than A).
            // We take the maximum of these values over all distinct prime factors f_i of q.

            long long candidate_x = p;
            while (candidate_x % q == 0) {
                candidate_x /= f;
            }
            max_x = std::max(max_x, candidate_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

