void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // For any permutation p, its reverse p' will have the same set of adjacent sums.
    // That is, if p = [p_1, p_2, ..., p_n], then p' = [p_n, p_{n-1}, ..., p_1].
    // The adjacent sums for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The adjacent sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These two sets of sums are identical, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, a permutation of distinct integers from 1 to n cannot be a palindrome
    // unless n=1 (which is not allowed, n>=2) or n=0.
    // For n >= 2, p_1 != p_n (since p_1=1, p_n=n or vice versa, or some other distinct values).
    // Thus, reversing a permutation always yields a different permutation.
    // So, reversing the given permutation is a valid strategy.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

