#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_s.insert(c1);
        used_in_s.insert(c2);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_s.insert(s[0]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_for_layout;
    char current_char = '\0';

    // Find a starting point for the layout chain
    // A starting point must be a character with only one required neighbor
    // or the first character of the password if it's isolated or has one neighbor
    for (char c : used_in_s) {
        if (adj[c].size() <= 1) { // Found an endpoint or an isolated character
            current_char = c;
            break;
        }
    }

    // If no endpoint found, it means all characters in s have 2 neighbors, forming a cycle.
    // This is only possible if s itself forms a cycle, e.g., "abacaba" where 'a' has 'b' and 'c' as neighbors.
    // If s forms a cycle, any character can be a starting point.
    // We can just pick s[0] as a starting point if current_char is still null.
    if (current_char == '\0' && !used_in_s.empty()) {
        current_char = s[0]; // Pick any character from s as a starting point
    }

    if (current_char != '\0') {
        // Build the chain
        while (current_char != '\0') {
            layout += current_char;
            visited_for_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (visited_for_layout.find(neighbor) == visited_for_layout.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_for_layout.find(c) == visited_for_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

