int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1 means can move left (x-1). If f1=0, cannot move left.
            // So, if f1=0, the robot must end up at an X >= its current x.
            // This means X >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f3 = 1 means can move right (x+1). If f3=0, cannot move right.
            // So, if f3=0, the robot must end up at an X <= its current x.
            // This means X <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4 = 1 means can move down (y-1). If f4=0, cannot move down.
            // So, if f4=0, the robot must end up at a Y >= its current y.
            // This means Y >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }

            // f2 = 1 means can move up (y+1). If f2=0, cannot move up.
            // So, if f2=0, the robot must end up at a Y <= its current y.
            // This means Y <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one exists within [-10^5, 10^5].
            // So we can just pick any valid point, e.g., (min_x, min_y).
            // We need to clamp the coordinates to the guaranteed range if they fall outside,
            // but since the initial coordinates are within [-10^5, 10^5], and the constraints
            // are based on these coordinates, min_x, max_x, min_y, max_y will also be within
            // a reasonable range (e.g., [-10^5, 10^5] or slightly outside if initial values are at boundaries).
            // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
            // This implies that if min_x > 10^5, we should pick 10^5. If min_x < -10^5, we should pick -10^5.
            // However, the guarantee "if there exists at least one point reachable by all robots,
            // then at least one of such points has both coordinates not exceeding 10^5 by absolute value"
            // means we don't need to clamp. If min_x is, say, 100001, and max_x is 100001, then
            // the only valid X is 100001. But the guarantee implies there must be a valid X <= 100000.
            // This means if min_x > 100000, then max_x must also be > 100000, and there's no solution
            // within the [-10^5, 10^5] range.
            // Let's re-read carefully: "if there exists at least one point reachable by all robots,
            // then at least one of such points has both coordinates not exceeding 10^5 by absolute value."
            // This means if our calculated [min_x, max_x] and [min_y, max_y] are valid,
            // there must be *some* point (X, Y) in this rectangle that satisfies |X| <= 10^5 and |Y| <= 10^5.
            // So, we can just pick min_x and min_y, and they will be within the required range if a solution exists.
            // The maximum possible value for min_x (or min_y) would be 10^5 (if all robots have x_i=10^5 and f_i,1=0).
            // The minimum possible value for max_x (or max_y) would be -10^5 (if all robots have x_i=-10^5 and f_i,3=0).
            // So, min_x and min_y will naturally fall within [-10^5, 10^5] if a solution exists within that range.
            std::cout << "1 " << min_x << " " << min_y << "\n";
        } else {
            std::cout << "0\n";
        }
    }
    return 0;
}

