}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

// Function to compute Z-array for a string
std::vector<int> compute_z_array(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Precompute Z-arrays for all cyclic shifts of s
    // z_arrays[i] stores the Z-array for s[i...n-1] + s[0...i-1]
    std::vector<std::vector<int>> z_arrays(n);
    for (int i = 0; i < n; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_arrays[i] = compute_z_array(shifted_s);
    }

    // Group indices by character s[i]
    std::vector<std::vector<int>> indices_by_char(26);
    for (int i = 0; i < n; ++i) {
        indices_by_char[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    // Iterate over each possible value of k (the true shift)
    for (int k_true = 0; k_true < n; ++k_true) {
        char first_char = s[k_true];
        const std::vector<int>& possible_k_values = indices_by_char[first_char - 'a'];

        if (possible_k_values.size() == 1) {
            // If only one k' produces this first_char, Vasya wins immediately.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p to query.
        // p is 1-indexed in problem statement, but 0-indexed here.
        // So p ranges from 1 to n-1.
        double max_win_prob_for_k_true = 0.0;

        // Iterate over all possible query positions p (1-indexed in problem, 0-indexed here)
        for (int p = 1; p < n; ++p) {
            // For a fixed p, count how many k' values are uniquely identified.
            // The actual character at t[p] is s[(k_true + p) % n].
            char char_at_p = s[(k_true + p) % n];

            int count_unique_for_this_p = 0;
            for (int k_prime : possible_k_values) {
                // If s[k_prime] == first_char and s[(k_prime + p) % n] == char_at_p,
                // then k_prime is a candidate.
                // We need to check if k_prime is uniquely identified by (first_char, char_at_p).
                // This means no other k_double_prime in possible_k_values
                // (where k_double_prime != k_prime) also satisfies
                // s[k_double_prime] == first_char AND s[(k_double_prime + p) % n] == char_at_p.

                // More efficiently, we count how many k' values match (first_char, char_at_p).
                // If this count is 1, then that k' is uniquely identified.
                // We need to check this for each k_prime in possible_k_values.
                // This is equivalent to checking if k_prime is the *only* one that matches.

                // Let's count how many candidates match (first_char, char_at_p)
                int num_matches_for_pair = 0;
                for (int k_cand : possible_k_values) {
                    if (s[(k_cand + p) % n] == char_at_p) {
                        num_matches_for_pair++;
                    }
                }

                // If k_prime is the true k, and it's uniquely identified by (first_char, char_at_p),
                // then Vasya wins.
                // This happens if num_matches_for_pair is 1.
                if (s[(k_prime + p) % n] == char_at_p && num_matches_for_pair == 1) {
                    // This k_prime is uniquely identified by the pair (first_char, char_at_p).
                    // If k_true happens to be this k_prime, Vasya wins.
                    // This logic is slightly off. We need to check if k_true is uniquely identified.
                    // The current k_true is one of the possible_k_values.
                    // We need to check if k_true is the only one among possible_k_values
                    // that produces s[(k_true+p)%n] at position p.

                    // Let's rephrase: for a given k_true and chosen p, Vasya observes s[k_true] and s[(k_true+p)%n].
                    // He wins if there is no other k_prime in possible_k_values (k_prime != k_true)
                    // such that s[k_prime] == s[k_true] AND s[(k_prime+p)%n] == s[(k_true+p)%n].

                    bool is_k_true_unique_for_this_p = true;
                    for (int k_prime_other : possible_k_values) {
                        if (k_prime_other == k_true) continue;
                        if (s[(k_prime_other + p) % n] == s[(k_true + p) % n]) {
                            is_k_true_unique_for_this_p = false;
                            break;
                        }
                    }
                    if (is_k_true_unique_for_this_p) {
                        count_unique_for_this_p = 1; // Vasya wins for this k_true and p
                        break; // No need to check other k_prime values for this p
                    }
                }
            }
            max_win_prob_for_k_true = std::max(max_win_prob_for_k_true, (double)count_unique_for_this_p);
        }
        total_win_prob += max_win_prob_for_k_true;
    }

    // The above logic for `count_unique_for_this_p` is incorrect.
    // Let's restart the inner loop logic.

    total_win_prob = 0.0;
    for (int k_true = 0; k_true < n; ++k_true) {
        char first_char = s[k_true];
        const std::vector<int>& possible_k_values = indices_by_char[first_char - 'a'];

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_this_k_true = 0.0; // Will be 0 or 1

        // Vasya chooses p to maximize his chance of winning for this k_true.
        // He wins if for the chosen p, k_true is uniquely identified.
        // This means no other k_prime in possible_k_values (k_prime != k_true)
        // produces the same character at position p as k_true does.

        for (int p = 1; p < n; ++p) {
            char char_at_p_for_k_true = s[(k_true + p) % n];
            bool k_true_is_unique_for_this_p = true;
            for (int k_prime : possible_k_values) {
                if (k_prime == k_true) continue;
                if (s[(k_prime + p) % n] == char_at_p_for_k_true) {
                    k_true_is_unique_for_this_p = false;
                    break;
                }
            }
            if (k_true_is_unique_for_this_p) {
                max_win_prob_for_this_k_true = 1.0; // Vasya can win for this k_true by choosing this p
                break; // Found an optimal p for this k_true, no need to check other p's
            }
        }
        total_win_prob += max_win_prob_for_this_k_true;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_diff = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s - count of 2s) in jars 1 to k
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s - count of 2s) in jars 2n-k+1 to 2n
    // We store this as a map from diff value to minimum k (jars eaten from right)
    std::map<int, int> diff_R_map;
    diff_R_map[0] = 0; // 0 jars eaten from right, diff is 0
    int current_diff_R = 0;
    for (int i = 0; i < n; ++i) {
        // Jars are 2n, 2n-1, ..., n+1
        // a[2n-1], a[2n-2], ..., a[n]
        current_diff_R += (a[2 * n - 1 - i] == 1 ? 1 : -1);
        if (diff_R_map.find(current_diff_R) == diff_R_map.end()) {
            diff_R_map[current_diff_R] = i + 1;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible numbers of jars eaten from the left (0 to n)
    for (int L = 0; L <= n; ++L) {
        int current_left_diff = diff_L[L];
        int target_right_diff = initial_diff - current_left_diff;

        // We need to find R such that the remaining jars have a total diff of 0.
        // The remaining jars are from L+1 to 2n-R.
        // The initial_diff is for jars 1 to 2n.
        // If we eat L jars from left and R jars from right,
        // the diff of eaten jars from left is current_left_diff.
        // The diff of eaten jars from right is current_right_diff.
        // The diff of remaining jars is initial_diff - current_left_diff - current_right_diff.
        // We want this to be 0.
        // So, initial_diff - current_left_diff = current_right_diff.
        // We need to find R such that diff_R[R] == initial_diff - current_left_diff.

        if (diff_R_map.count(target_right_diff)) {
            int R = diff_R_map[target_right_diff];
            min_jars_eaten = std::min(min_jars_eaten, L + R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
