#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        // The quadratic equation for 'a' is a^2 - d*a + d = 0
        // Discriminant delta = (-d)^2 - 4*1*d = d^2 - 4d
        double delta = d * d - 4 * d;

        if (delta < 0) { // No real solutions
            std::cout << "N\n";
        } else {
            // Solutions for 'a' are (d +/- sqrt(delta)) / 2
            double sqrt_delta = std::sqrt(delta);
            double a1 = (d + sqrt_delta) / 2.0;
            double a2 = (d - sqrt_delta) / 2.0;

            // We need non-negative a and b.
            // If a1 is a solution, then b1 = d - a1.
            // If a2 is a solution, then b2 = d - a2.
            // Note that a1 + a2 = d, so if a1 is a solution, then a2 is its corresponding b.
            // Specifically, if a = (d + sqrt(delta))/2, then b = d - a = d - (d + sqrt(delta))/2 = (2d - d - sqrt(delta))/2 = (d - sqrt(delta))/2.
            // So, the two solutions for (a, b) are ((d + sqrt(delta))/2, (d - sqrt(delta))/2) and ((d - sqrt(delta))/2, (d + sqrt(delta))/2).
            // We just need to pick one pair. Let's pick a = a1 and b = a2.

            // Check if a and b are non-negative.
            // Since d >= 0, and sqrt_delta >= 0 (because delta >= 0),
            // a1 = (d + sqrt_delta) / 2.0 will always be non-negative.
            // We need to check if a2 = (d - sqrt_delta) / 2.0 is non-negative.
            // This is equivalent to checking if d - sqrt_delta >= 0, or d >= sqrt_delta.
            // Squaring both sides (since d >= 0 and sqrt_delta >= 0), d^2 >= delta.
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // So, if d >= 0 and delta >= 0, then both a1 and a2 will be non-negative.
            // The only edge case is when d=0.
            // If d=0, delta = 0, a1 = 0, a2 = 0. So a=0, b=0. This is valid.
            // If d=4, delta = 0, a1 = 2, a2 = 2. So a=2, b=2. This is valid.

            // Since d >= 0 is given, and we already handled delta < 0,
            // both a1 and a2 will always be non-negative.
            // We can print a1 and a2.
            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << a2 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit position (0-9)
    // For each bit, we track what happens if it's initially 0 and if it's initially 1.
    // state[bit_idx][0] = final value if initial bit is 0
    // state[bit_idx][1] = final value if initial bit is 1
    // Initially, if bit is 0, it stays 0. If bit is 1, it stays 1.
    std::vector<std::vector<int>> state(10, std::vector<int>(2));
    for (int i = 0; i < 10; ++i) {
        state[i][0] = 0;
        state[i][1] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // i-th bit of the constant

            if (op_char == '&') {
                state[i][0] &= bit_val;
                state[i][1] &= bit_val;
            } else if (op_char == '|') {
                state[i][0] |= bit_val;
                state[i][1] |= bit_val;
            } else if (op_char == '^') {
                state[i][0] ^= bit_val;
                state[i][1] ^= bit_val;
            }
        }
    }

    // Now, reconstruct the simplified operations.
    // We need to find A, B, C such that:
    // (x & A | B) ^ C
    // or some equivalent form.

    // Let's determine the final values for an input of 0 and an input of 1023.
    // These two inputs cover all combinations of initial bit states.
    // For input 0: all bits are 0. The final value is `final_val_0`.
    // For input 1023: all bits are 1. The final value is `final_val_1023`.
    int final_val_0 = 0;
    int final_val_1023 = 0;
    for (int i = 0; i < 10; ++i) {
        final_val_0 |= (state[i][0] << i);
        final_val_1023 |= (state[i][1] << i);
    }

    // The simplified operations can be represented as:
    // x_new = (x & AND_mask | OR_mask) ^ XOR_mask
    //
    // Let's find AND_mask, OR_mask, XOR_mask.
    //
    // Consider the effect on a bit `i`:
    // If `x_i` is 0, it becomes `state[i][0]`.
    // If `x_i` is 1, it becomes `state[i][1]`.
    //
    // We want to find `a_i`, `o_i`, `x_i` such that:
    // (0 & a_i | o_i) ^ x_i = state[i][0]
    // (1 & a_i | o_i) ^ x_i = state[i][1]
    //
    // This simplifies to:
    // (o_i) ^ x_i = state[i][0]  (Eq 1)
    // (a_i | o_i) ^ x_i = state[i][1] (Eq 2)
    //
    // From (Eq 1), we can say `o_i ^ x_i` is fixed.
    // From (Eq 2), we can say `(a_i | o_i) ^ x_i` is fixed.
    //
    // Let's try to find the masks.
    //
    // XOR_mask:
    // If `state[i][0] == state[i][1]`:
    //   This means the output bit `i` is independent of the input bit `i`.
    //   It's always `state[i][0]`.
    //   To achieve this with `(x_i & a_i | o_i) ^ x_i`:
    //   If `x_i=0`: `o_i ^ x_i = state[i][0]`
    //   If `x_i=1`: `(a_i | o_i) ^ x_i = state[i][0]`
    //   This implies `o_i ^ x_i = (a_i | o_i) ^ x_i`.
    //   This can be satisfied if `a_i=0` and `o_i = state[i][0] ^ x_i`.
    //   Then `(0 & 0 | (state[i][0] ^ x_i)) ^ x_i = state[i][0] ^ x_i ^ x_i = state[i][0]`.
    //   And `(1 & 0 | (state[i][0] ^ x_i)) ^ x_i = (state[i][0] ^ x_i) ^ x_i = state[i][0]`.
    //   So, if `state[i][0] == state[i][1]`, we can set `a_i=0`, `o_i = state[i][0]`, `x_i=0`.
    //   This means `AND_mask` has 0, `OR_mask` has `state[i][0]`, `XOR_mask` has 0.
    //   The bit `i` becomes `(x_i & 0 | state[i][0]) ^ 0 = state[i][0]`. Correct.
    //
    // If `state[i][0] != state[i][1]`:
    //   This means the output bit `i` depends on the input bit `i`.
    //   Specifically, `state[i][1] = 1 - state[i][0]`.
    //   To achieve this with `(x_i & a_i | o_i) ^ x_i`:
    //   If `x_i=0`: `o_i ^ x_i = state[i][0]`
    //   If `x_i=1`: `(a_i | o_i) ^ x_i = state[i][1]`
    //   This implies `o_i ^ x_i = state[i][0]` and `(a_i | o_i) ^ x_i = 1 - state[i][0]`.
    //   This can be satisfied if `a_i=1` and `o_i = state[i][0]`.
    //   Then `(0 & 1 | state[i][0]) ^ x_i = state[i][0] ^ x_i`.
    //   And `(1 & 1 | state[i][0]) ^ x_i = (1 | state[i][0]) ^ x_i = 1 ^ x_i`.
    //   So, if `state[i][0] != state[i][1]`, we can set `a_i=1`, `o_i = state[i][0]`, `x_i=0`.
    //   The bit `i` becomes `(x_i & 1 | state[i][0]) ^ 0`.
    //   If `x_i=0`, it's `(0 | state[i][0]) = state[i][0]`. Correct.
    //   If `x_i=1`, it's `(1 | state[i][0]) = 1`. Correct, since `state[i][1]` must be 1.
    //   This means `AND_mask` has 1, `OR_mask` has `state[i][0]`, `XOR_mask` has 0.
    //
    // This logic is for `(x & A | B) ^ C`.
    // Let's try to simplify the operations to `& A`, `| B`, `^ C`.
    //
    // The final state of bit `i` is `state[i][0]` if input bit `i` is 0, and `state[i][1]` if input bit `i` is 1.
    //
    // Let's define three masks:
    // `and_val`: bits that must be 1 for the output to be 1 (if input bit is 1)
    // `or_val`: bits that must be 1 for the output to be 1 (if input bit is 0)
    // `xor_val`: bits that flip the output
    //
    // Consider the effect of `& A`, `| B`, `^ C` on a single bit `x_i`:
    // `((x_i & a_i) | b_i) ^ c_i`
    //
    // If `x_i = 0`: `(0 & a_i | b_i) ^ c_i = b_i ^ c_i`. This must equal `state[i][0]`.
    // If `x_i = 1`: `(1 & a_i | b_i) ^ c_i = (a_i | b_i) ^ c_i`. This must equal `state[i][1]`.
    //
    // From these two equations, we can determine `a_i, b_i, c_i` for each bit `i`.
    //
    // `b_i ^ c_i = state[i][0]`
    // `(a_i | b_i) ^ c_i = state[i][1]`
    //
    // Case 1: `state[i][0] == 0` and `state[i][1] == 0`
    //   `b_i ^ c_i = 0`  => `b_i = c_i`
    //   `(a_i | b_i) ^ c_i = 0` => `a_i | b_i = c_i`
    //   Since `b_i = c_i`, we have `a_i | b_i = b_i`. This implies `a_i` can be 0 or 1, but `a_i` must be 0 for `a_i | b_i = b_i` to hold for `a_i=1` only if `b_i=1`.
    //   If `a_i=0`, then `0 | b_i = b_i`, which is always true.
    //   So, `a_i=0, b_i=0, c_i=0` works. `((x_i & 0) | 0) ^ 0 = 0`.
    //
    // Case 2: `state[i][0] == 0` and `state[i][1] == 1`
    //   `b_i ^ c_i = 0`  => `b_i = c_i`
    //   `(a_i | b_i) ^ c_i = 1` => `a_i | b_i = 1 ^ c_i`
    //   Since `b_i = c_i`, we have `a_i | b_i = 1 ^ b_i`.
    //   If `b_i = 0`: `a_i | 0 = 1 ^ 0` => `a_i = 1`.
    //     So, `a_i=1, b_i=0, c_i=0` works. `((x_i & 1) | 0) ^ 0 = x_i`.
    //   If `b_i = 1`: `a_i | 1 = 1 ^ 1` => `1 = 0`. Impossible.
    //   So, `a_i=1, b_i=0, c_i=0` is the only solution.
    //
    // Case 3: `state[i][0] == 1` and `state[i][1] == 0`
    //   `b_i ^ c_i = 1`  => `b_i = 1 ^ c_i`
    //   `(a_i | b_i) ^ c_i = 0` => `a_i | b_i = c_i`
    //   Substitute `b_i`: `a_i | (1 ^ c_i) = c_i`.
    //   If `c_i = 0`: `a_i | 1 = 0` => `1 = 0`. Impossible.
    //   If `c_i = 1`: `a_i | 0 = 1` => `a_i = 1`.
    //     So, `a_i=1, c_i=1`. Then `b_i = 1 ^ 1 = 0`.
    //     `a_i=1, b_i=0, c_i=1` works. `((x_i & 1) | 0) ^ 1 = x_i ^ 1`.
    //
    // Case 4: `state[i][0] == 1` and `state[i][1] == 1`
    //   `b_i ^ c_i = 1`  => `b_i = 1 ^ c_i`
    //   `(a_i | b_i) ^ c_i = 1` => `a_i | b_i = 1 ^ c_i`
    //   Substitute `b_i`: `a_i | (1 ^ c_i) = 1 ^ c_i`.
    //   This implies `a_i` must be 0.
    //   So, `a_i=0`. Then `b_i = 1 ^ c_i`.
    //   We can choose `c_i=0`, then `b_i=1`.
    //   So, `a_i=0, b_i=1, c_i=0` works. `((x_i & 0) | 1) ^ 0 = 1`.
    //
    // Summary for `((x_i & a_i) | b_i) ^ c_i`:
    // (s0, s1) = (0,0) => (a,b,c) = (0,0,0)
    // (s0, s1) = (0,1) => (a,b,c) = (1,0,0)
    // (s0, s1) = (1,0) => (a,b,c) = (1,0,1)
    // (s0, s1) = (1,1) => (a,b,c) = (0,1,0)
    //
    // Let's construct the masks:
    int final_AND_mask = 0; // A
    int final_OR_mask = 0;  // B
    int final_XOR_mask = 0; // C

    for (int i = 0; i < 10; ++i) {
        int s0 = state[i][0];
        int s1 = state[i][1];

        if (s0 == 0 && s1 == 0) {
            // a_i=0, b_i=0, c_i=0
        } else if (s0 == 0 && s1 == 1) {
            // a_i=1, b_i=0, c_i=0
            final_AND_mask |= (1 << i);
        } else if (s0 == 1 && s1 == 0) {
            // a_i=1, b_i=0, c_i=1
            final_AND_mask |= (1 << i);
            final_XOR_mask |= (1 << i);
        } else if (s0 == 1 && s1 == 1) {
            // a_i=0, b_i=1, c_i=0
            final_OR_mask |= (1 << i);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_AND_mask != 1023) { // If not all bits are 1, then & operation is meaningful
        result_ops.push_back({'&', final_AND_mask});
    }
    if (final_OR_mask != 0) { // If not all bits are 0, then | operation is meaningful
        result_ops.push_back({'|', final_OR_mask});
    }
    if (final_XOR_mask != 0) { // If not all bits are 0, then ^ operation is meaningful
        result_ops.push_back({'^', final_XOR_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive zeros ending at i
    std::vector<int> left_ones(n, 0);  // left_ones[i] = count of consecutive ones ending at i
    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive zeros starting at i
    std::vector<int> right_ones(n, 0);  // right_ones[i] = count of consecutive ones starting at i

    // Calculate left counts
    if (a[0] == 0) left_zeros[0] = 1; else left_ones[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = left_zeros[i - 1] + 1;
            left_ones[i] = 0;
        } else {
            left_ones[i] = left_ones[i - 1] + 1;
            left_zeros[i] = 0;
        }
    }

    // Calculate right counts
    if (a[n - 1] == 0) right_zeros[n - 1] = 1; else right_ones[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = right_zeros[i + 1] + 1;
            right_ones[i] = 0;
        } else {
            right_ones[i] = right_ones[i + 1] + 1;
            right_zeros[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // a[i] is 0, check for 01...10 pattern
            if (left_ones[i - 1] > 0 && right_ones[i + 1] > 0) {
                max_k = std::max(max_k, std::min(left_ones[i - 1], right_ones[i + 1]));
            }
        } else { // a[i] is 1, check for 10...01 pattern
            if (left_zeros[i - 1] > 0 && right_zeros[i + 1] > 0) {
                max_k = std::max(max_k, std::min(left_zeros[i - 1], right_zeros[i + 1]));
            }
        }
    }

    std::cout << max_k << "\n";

    std::vector<int> result = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // a[i] is 0, check for 01...10 pattern
            if (left_ones[i - 1] > 0 && right_ones[i + 1] > 0) {
                int len = std::min(left_ones[i - 1], right_ones[i + 1]);
                if (len > max_k) { // This condition should not be met if max_k is calculated correctly
                    // This means the element will flip to 1
                } else if (len == max_k) {
                    result[i] = 0; // Stays 0
                } else { // len < max_k
                    result[i] = 0; // Stays 0
                }
            }
        } else { // a[i] is 1, check for 10...01 pattern
            if (left_zeros[i - 1] > 0 && right_zeros[i + 1] > 0) {
                int len = std::min(left_zeros[i - 1], right_zeros[i + 1]);
                if (len > max_k) { // This condition should not be met
                    // This means the element will flip to 0
                } else if (len == max_k) {
                    result[i] = 1; // Stays 1
                } else { // len < max_k
                    result[i] = 1; // Stays 1
                }
            }
        }
    }

    // Apply changes for elements that flip
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // a[i] is 0, check for 01...10 pattern
            if (left_ones[i - 1] > 0 && right_ones[i + 1] > 0) {
                int len = std::min(left_ones[i - 1], right_ones[i + 1]);
                if (len < max_k) {
                    result[i] = 1; // 0 becomes 1
                }
            }
        } else { // a[i] is 1, check for 10...01 pattern
            if (left_zeros[i - 1] > 0 && right_zeros[i + 1] > 0) {
                int len = std::min(left_zeros[i - 1], right_zeros[i + 1]);
                if (len < max_k) {
                    result[i] = 0; // 1 becomes 0
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

