#include <numeric>
#include <algorithm>

// Function to calculate the number of '1's in a string
int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If initial 'a' has an odd number of '1's, we can append '1' to make it even.
    // This effectively increases the count of '1's by 1.
    // So, the maximum number of '1's we can achieve from 'a' is ones_a + (ones_a % 2).
    // Any string derived from 'a' by appending parities will have a number of '1's
    // that is less than or equal to this maximum.
    // The length of 'a' can be increased up to |b|.
    // So, the maximum number of '1's we can have in a string of length |b|
    // that could potentially become 'b' is ones_a + (ones_a % 2).
    // If ones_b is greater than this maximum, it's impossible.
    if (ones_b > ones_a + (ones_a % 2)) {
        std::cout << "NO\n";
        return 0;
    }

    // If the number of '1's in 'b' is less than or equal to the maximum possible '1's
    // we can achieve from 'a' (considering the parity rule), then it is always possible.
    // This is because we can always append '0's (if parity is 0) or '1's (if parity is 1)
    // to reach the desired number of '1's, and then remove characters from the front
    // until the length matches.
    // The key insight is that we can always make the number of '1's even by one append operation
    // (if it's odd, append '1'; if it's even, append '0').
    // After that, any subsequent append operation will append '0' (since the string will have even '1's).
    // So, we can reach any length >= |a| with 'ones_a' or 'ones_a + 1' ones.
    // Specifically, we can reach a string of length |b| with 'ones_a' or 'ones_a + 1' ones.
    // If 'ones_b' is within this range, and 'ones_b' has the same parity as 'ones_a' (or 'ones_a+1'),
    // then it's possible.
    // The condition `ones_b <= ones_a + (ones_a % 2)` covers this.
    // If `ones_a` is even, `ones_a + (ones_a % 2)` is `ones_a`. We need `ones_b <= ones_a`.
    // If `ones_a` is odd, `ones_a + (ones_a % 2)` is `ones_a + 1`. We need `ones_b <= ones_a + 1`.
    // In both cases, `ones_b` must have the same parity as `ones_a` or `ones_a + 1` respectively.
    // This is implicitly handled because we can always append '0's to increase length without changing '1's count,
    // or append '1' if initial parity is odd.
    // The only constraint is that we can't *reduce* the number of '1's below `ones_a` (or `ones_a+1` if we used the parity op).
    // But we can always remove leading characters to match length, and we can always append parities to match length.
    // The crucial part is that we can always reach a state where the string has length |b| and `ones_b` ones,
    // as long as `ones_b` is not too large.
    // The maximum number of '1's we can have in a string of length |b| is `ones_a + (ones_a % 2)`.
    // If `ones_b` is less than or equal to this value, it's always possible.
    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to doctor

        long long current_v_cry = children[i].v;
        long long total_d_cry_effect = 0; // Accumulates d_j cries from children leaving

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry effect
            children[j].p -= total_d_cry_effect;

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <tuple>

const long long INF = 4e18; // A sufficiently large value, larger than any possible sum of d_i

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // For each element a[i], we want to find the maximum possible initial value a_0[i].
    // This is because if a_0[i] is larger, it's more likely to violate a[j] <= m constraints.
    // If we find a valid a_0[i] for all i, then any smaller a_0[i] would also be valid
    // with respect to the a[j] <= m constraints.
    // The a[k] = m constraint will be checked later.

    // Let a_0[i] be the initial value of a[i].
    // Let delta[i] be the sum of all d_k applied to a[i] up to the current point.
    // Then a[i] = a_0[i] + delta[i].
    // The constraint a[j] <= m becomes a_0[j] + delta[j] <= m, or a_0[j] <= m - delta[j].

    // We want to find the maximum possible a_0[i] such that all constraints are met.
    // Initialize a_0[i] to a very large value (effectively infinity)
    // and then take minimums based on constraints.
    std::vector<long long> initial_a(n, INF);

    // Iterate through operations in reverse to find the maximum possible initial_a[i]
    // that satisfies all type 2 constraints.
    // When processing operations in reverse, a type 1 operation (l, r, d) means
    // that the values a_0[j] for j in [l, r] were effectively d less before this operation.
    // So, we need to adjust the upper bounds for a_0[j] by adding d.
    // This is equivalent to saying that if a_0[j] + current_delta[j] <= M,
    // then a_0[j] + (current_delta[j] - d) <= M - d.
    // So, when going backwards, we add d to the upper bounds.

    // `current_delta_sum[i]` stores the sum of `d` values for type 1 operations
    // that affect index `i` *after* the current operation in the forward pass.
    // When processing operations in reverse, this `current_delta_sum` represents
    // the total `d` applied to `a_0[i]` by operations *after* the current one.
    // So, `a_0[i] + current_delta_sum[i]` is the value of `a[i]` at the time
    // of the current operation.
    std::vector<long long> current_delta_sum(n, 0);

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1: Increase a[j] by d for l <= j <= r.
            // When going backwards, this means that for elements in [l, r],
            // their effective `current_delta_sum` was `d` less before this operation.
            // So, we subtract `d` from `current_delta_sum` for `j` in `[l, r]`.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_sum[j] -= ops[i].val;
            }
        } else {
            // Type 2: max(a[j]) = m for l <= j <= r.
            // This implies a[j] <= m for all j in [l, r].
            // At this point, a[j] = a_0[j] + current_delta_sum[j].
            // So, a_0[j] + current_delta_sum[j] <= ops[i].val.
            // This means a_0[j] <= ops[i].val - current_delta_sum[j].
            // We update initial_a[j] with this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta_sum[j]);
            }
        }
    }

    // After the reverse pass, initial_a[i] contains the maximum possible initial value
    // for a_0[i] such that all a[j] <= m constraints are satisfied.
    // If any initial_a[i] is still INF, it means it was never constrained by a type 2 operation.
    // We can set it to 0 (or any value within [-10^9, 10^9]) as a default.
    // The problem statement says |a_i| <= 10^9.
    // Let's cap INF values to 0, as it's a safe choice.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == INF) {
            initial_a[i] = 0;
        }
        // Ensure initial_a[i] is within [-10^9, 10^9]
        // If it's outside, it means no solution exists, but we'll check that later.
        // For now, just cap it to avoid overflow issues with long long,
        // though INF is large enough that it shouldn't be an issue.
        // The problem states that if a solution exists, |a_i| <= 10^9.
        // If our calculated initial_a[i] is outside this range, it implies no solution.
        // However, the constraints on m_i and d_i are such that m_i - sum(d_i)
        // can be outside [-10^9, 10^9]. We should just use the calculated value
        // and check validity later.
    }

    // Now, we have a candidate initial array `initial_a`.
    // We need to verify if this array satisfies all operations.
    // Specifically, we need to check:
    // 1. For type 2 operations (l, r, m), that max(a[j]) == m.
    //    Our construction ensures a[j] <= m. We need to check if max(a[j]) < m
    //    or if max(a[j]) > m (which should not happen if initial_a is correct).

    std::vector<long long> current_a = initial_a; // This will be the array state during forward pass

    // `current_delta_sum` will now store the sum of `d` values for type 1 operations
    // that affect index `i` *up to and including* the current operation in the forward pass.
    std::fill(current_delta_sum.begin(), current_delta_sum.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1: Increase a[j] by d for l <= j <= r.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_sum[j] += ops[i].val;
            }
        } else {
            // Type 2: max(a[j]) = m for l <= j <= r.
            long long max_val = -INF; // Use a very small value for initial max
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, initial_a[j] + current_delta_sum[j]);
            }

            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array.
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

