        // We need to find a target value `b_i` for each `a_i` such that `b_i >= prev_val` and `b_i` is reachable from `a_i` with `x` operations.
        // If `a[i] >= prev_val`:
        //   We want to keep `b_i` as small as possible, so we try `b_i = prev_val`.
        //   Is `prev_val` reachable from `a[i]`?
        //   If `a[i] + x < m`:
        //     `a[i]` can become values in `[a[i], a[i] + x]`.
        //     If `prev_val` is in this range, then `b_i = prev_val` is fine.
        //     If `prev_val` is not in this range (i.e., `prev_val < a[i]`), then we must choose `b_i = a[i]`.
        //     So, if `a[i] >= prev_val`, we can always choose `b_i = a[i]`. This is valid.
        //     The new `prev_val` for the next iteration becomes `a[i]`.
        //   If `a[i] + x >= m`:
        //     `a[i]` can become any value. So `b_i = prev_val` is fine.
        //     The new `prev_val` for the next iteration becomes `prev_val`.
        // This logic is wrong. If `a[i] >= prev_val`, we want to keep `a[i]` as small as possible, which is `prev_val`.
        // But `a[i]` might be much larger than `prev_val`.
        // Example: `m=10, prev_val=0, a[i]=8, x=1`.
        // If we set `b_i = prev_val = 0`, then `a[i]` must be changed from 8 to 0. This requires `(0 - 8 + 10) % 10 = 2` operations.
        // But we only have `x=1` operation. So we cannot make 8 into 0.
        // We must make `b_i` at least `prev_val`.
        // The possible values for `a[i]` are `[a[i], (a[i]+x)%m]` if `a[i]+x < m`.
        // Or `[0, (a[i]+x)%m]` and `[a[i], m-1]` if `a[i]+x >= m`.
        // This means if `a[i]+x >= m`, `a[i]` can become any value. So we can make it `prev_val`.
        // If `a[i]+x < m`, `a[i]` can only become values in `[a[i], a[i]+x]`.
        // So if `a[i] < prev_val`:
        //   We must increment `a[i]`.
        //   If `a[i] + x < prev_val`, then it's impossible to reach `prev_val`. Return `false`.
        //   Otherwise, we can make `a[i]` equal to `prev_val`. So `prev_val` for next iteration remains `prev_val`.
        // If `a[i] >= prev_val`:
        //   We have two choices:
        //   1. Keep `a[i]` as `a[i]`. This is valid if `a[i]` is reachable from `a[i]` with `x` operations (which is always true, just don't increment it).
        //      In this case, `prev_val` for next iteration becomes `a[i]`.
        //   2. Try to make `a[i]` equal to `prev_val`. This is valid if `prev_val` is reachable from `a[i]` with `x` operations.
        //      The number of increments needed is `(prev_val - a[i] + m) % m`.
        //      If `(prev_val - a[i] + m) % m <= x`, then we can make `a[i]` equal to `prev_val`.
        //      In this case, `prev_val` for next iteration remains `prev_val`.
        // We want to choose the option that results in a smaller `prev_val` for the next iteration.
        // So if `a[i] >= prev_val`:
        //   If `(prev_val - a[i] + m) % m <= x`: // This means we can reduce a[i] to prev_val (by wrapping around)
        //     `prev_val` for next iteration remains `prev_val`.
        //   Else (we cannot reduce `a[i]` to `prev_val` by wrapping around with `x` operations):
        //     We must keep `a[i]` at least `a[i]`. So `prev_val` for next iteration becomes `a[i]`.

        // Let's try this logic:
        // For each `a[i]`:
        //   If `a[i] >= prev_val`:
        //     // We have two options for `b_i`: `prev_val` or `a[i]`.
        //     // We want to pick the smaller one if possible.
        //     // Can we make `a[i]` become `prev_val`?
        //     // This requires `(prev_val - a[i] + m) % m` increments.
        //     // If `(prev_val - a[i] + m) % m <= x`, then we can make `a[i]` become `prev_val`.
        //     // In this case, we set `prev_val` for the next iteration to `prev_val`.
        //     // Otherwise, we cannot make `a[i]` become `prev_val` (by wrapping around).
        //     // So we must keep `a[i]` at least `a[i]`.
        //     // In this case, we set `prev_val` for the next iteration to `a[i]`.
        //     if (a[i] + x < m) { // No wrap-around possible to reach prev_val if a[i] is large
        //         // If a[i] is already >= prev_val, and we can't wrap around to make it smaller than prev_val,
        //         // then we must keep it at least a[i].
        //         // So the next prev_val becomes a[i].
        //         prev_val = a[i];
        //     } else { // a[i] + x >= m, wrap-around is possible.
        //         // We can make a[i] any value from 0 to (a[i]+x)%m, or from a[i] to m-1.
        //         // This means we can make a[i] become prev_val.
        //         // So prev_val for next iteration remains prev_val.
        //     }
        //   Else (`a[i] < prev_val`):
        //     // We must increment `a[i]` to be at least `prev_val`.
        //     // The smallest value `a[i]` can become is `a[i]`. The largest is `(a[i] + x) % m`.
        //     // If `a[i] + x < m`:
        //     //   `a[i]` can only become values in `[a[i], a[i] + x]`.
        //     //   If `prev_val` is not in this range (i.e., `prev_val > a[i] + x`), then it's impossible. Return `false`.
        //     //   Otherwise, we can make `a[i]` equal to `prev_val`.
        //     //   So `prev_val` for next iteration remains `prev_val`.
        //     // If `a[i] + x >= m`:
        //     //   `a[i]` can become any value. So we can make it `prev_val`.
        //     //   So `prev_val` for next iteration remains `prev_val`.
        //     if (a[i] + x < prev_val) { // Cannot reach prev_val even with x increments
        //         return false;
        //     }
        //     // Else, we can make a[i] become prev_val. So prev_val for next iteration remains prev_val.
        //     // No change to prev_val.
        // This logic seems more robust.

        // Let's refine the logic for `prev_val` for the next iteration.
        // `prev_val` is the minimum value that `a[i]` must take.
        // `current_val` is `a[i]`.
        // We need to find `b_i` such that `b_i >= prev_val` and `b_i` is reachable from `current_val` with `x` operations.
        // We want to choose the smallest possible `b_i` that satisfies these conditions.
        //
        // If `current_val >= prev_val`:
        //   We have two options for `b_i`:
        //   1. `b_i = prev_val`. This is possible if `prev_val` is reachable from `current_val`.
        //      `prev_val` is reachable if `(prev_val - current_val + m) % m <= x`.
        //   2. `b_i = current_val`. This is always possible (0 operations needed).
        //   We want to pick the smaller of these two valid options.
        //   If `(prev_val - current_val + m) % m <= x`, then `prev_val` is reachable. We can set `b_i = prev_val`.
        //   Otherwise, `prev_val` is not reachable by wrapping around. We must set `b_i = current_val`.
        //   So, if `(prev_val - current_val + m) % m <= x`, then `prev_val` for next iteration is `prev_val`.
        //   Else, `prev_val` for next iteration is `current_val`.
        //
        // If `current_val < prev_val`:
        //   We *must* increment `current_val` to at least `prev_val`.
        //   The smallest value `current_val` can become is `current_val`. The largest is `(current_val + x) % m`.
        //   If `current_val + x < m`:
        //     `current_val` can only become values in `[current_val, current_val + x]`.
        //     If `prev_val` is not in this range (i.e., `prev_val > current_val + x`), then it's impossible. Return `false`.
        //     Otherwise, `prev_val` is in the range. We can make `current_val` equal to `prev_val`.
        //     So `prev_val` for next iteration remains `prev_val`.
        //   If `current_val + x >= m`:
        //     `current_val` can become any value from `0` to `m-1`. So we can make it `prev_val`.
        //     So `prev_val` for next iteration remains `prev_val`.
        //
        // This can be simplified:
        // If `current_val < prev_val`:
        //   We need to increment `current_val` to `prev_val`.
        //   The number of increments needed is `prev_val - current_val`.
        //   If `prev_val - current_val > x`, it's impossible. Return `false`.
        //   Otherwise, it's possible. `prev_val` for next iteration remains `prev_val`.
        // Else (`current_val >= prev_val`):
        //   We want to keep `b_i` as small as possible, which is `prev_val`.
        //   Can we make `current_val` become `prev_val`?
        //   This requires `(prev_val - current_val + m) % m` increments.
        //   If `(prev_val - current_val + m) % m <= x`:
        //     We can make `current_val` become `prev_val`. So `prev_val` for next iteration remains `prev_val`.
        //   Else:
        //     We cannot make `current_val` become `prev_val` by wrapping around.
        //     So we must keep `current_val` at least `current_val`.
        //     `prev_val` for next iteration becomes `current_val`.

        if (current_val < prev_val) {
            // We must increment current_val to be at least prev_val.
            // The minimum increments needed is prev_val - current_val.
            // If we have enough operations (x), we can achieve prev_val.
            if (current_val + x < prev_val) { // current_val + x is the max value without wrap-around
                return false; // Cannot reach prev_val
            }
            // Else, we can reach prev_val. So prev_val for next element remains prev_val.
        } else { // current_val >= prev_val
            // We want to keep the value as small as possible, ideally prev_val.
            // Can we make current_val become prev_val by wrapping around?
            // The number of increments needed is (prev_val - current_val + m) % m.
            long long increments_needed_to_wrap = (prev_val - current_val + m) % m;
            if (increments_needed_to_wrap <= x) {
                // We can make current_val become prev_val.
                // So prev_val for next element remains prev_val.
            } else {
                // We cannot make current_val become prev_val by wrapping around.
                // So we must keep current_val at least current_val.
                // The new prev_val for the next element becomes current_val.
                prev_val = current_val;
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // In this case, all pairs (a_i, a_j) are in the same subsequence.
    // f(a_i, a_j) = a_i + a_j.
    // Min f = elements[0].value + elements[1].value
    // Max f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long goodness_all_same = -1;
    if (n >= 2) {
        goodness_all_same = (long long)elements[n - 1].value + elements[n - 2].value -
                            ((long long)elements[0].value + elements[1].value);
    } else { // n=1, no pairs, goodness is 0. But problem states n >= 2.
        goodness_all_same = 0;
    }

    std::vector<int> partition_all_same(n, 1);

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for minimizing goodness often involves putting the smallest element
    // and the largest element into different subsequences, or the smallest two into different
    // subsequences, or the largest two into different subsequences.
    // Let's consider a specific partition: elements[0] in S1, elements[1]...elements[n-1] in S2.
    // This is a common strategy when h is large.
    //
    // Min f values:
    //   - elements[1].value + elements[2].value (if n >= 3, both in S2)
    //   - elements[0].value + elements[1].value + h (elements[0] in S1, elements[1] in S2)
    // Max f values:
    //   - elements[n-1].value + elements[n-2].value (if n >= 3, both in S2)
    //   - elements[0].value + elements[n-1].value + h (elements[0] in S1, elements[n-1] in S2)
    //
    // Let's analyze the specific partition: elements[0] in S1, all others in S2.
    // This means S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}.
    //
    // If n=2: S1 = {elements[0]}, S2 = {elements[1]}.
    // Only one pair: (elements[0], elements[1]). They are in different subsequences.
    // f = elements[0].value + elements[1].value + h.
    // Min f = Max f = elements[0].value + elements[1].value + h.
    // Goodness = 0.
    // This is better than goodness_all_same if h > 0.
    // If n=2, goodness_all_same is also 0. So 0 is the answer.
    //
    // If n >= 3:
    // Pairs within S1: None.
    // Pairs within S2: (elements[i], elements[j]) for i,j in [1, n-1].
    //   Min same: elements[1].value + elements[2].value
    //   Max same: elements[n-1].value + elements[n-2].value
    // Pairs across S1 and S2: (elements[0], elements[j]) for j in [1, n-1].
    //   Min diff: elements[0].value + elements[1].value + h
    //   Max diff: elements[0].value + elements[n-1].value + h
    //
    // Overall min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // Overall max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // Let's simplify.
    // The minimum possible sum `a_i + a_j` is `elements[0].value + elements[1].value`.
    // The maximum possible sum `a_i + a_j` is `elements[n-1].value + elements[n-2].value`.
    //
    // Consider the partition where `elements[0]` is in S1, and all other `elements[i]` (for `i > 0`) are in S2.
    //
    // The minimum value of `f` will be `min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)`.
    // (Note: if n=2, `elements[1].value + elements[2].value` is not possible, only `elements[0].value + elements[1].value + h` exists.
    //  If n=2, goodness is 0. This is handled by the general logic below.)
    //
    // The maximum value of `f` will be `max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)`.
    //
    // Let's calculate the goodness for this specific partition.
    long long min_f_val_split = -1, max_f_val_split = -1;
    if (n == 2) {
        min_f_val_split = (long long)elements[0].value + elements[1].value + h;
        max_f_val_split = min_f_val_split;
    } else { // n >= 3
        min_f_val_split = std::min((long long)elements[1].value + elements[2].value,
                                   (long long)elements[0].value + elements[1].value + h);
        max_f_val_split = std::max((long long)elements[n - 1].value + elements[n - 2].value,
                                   (long long)elements[0].value + elements[n - 1].value + h);
    }
    long long goodness_split = max_f_val_split - min_f_val_split;

    // Compare goodness_all_same and goodness_split
    if (goodness_all_same <= goodness_split) {
        std::cout << goodness_all_same << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << 1 << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness_split << "\n";
        std::vector<int> partition_split(n);
        partition_split[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition_split[elements[i].original_index] = 2;
        }
        for (int i = 0; i < n; ++i) {
            std::cout << partition_split[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain any 3-AP.
    // Initialize with n, meaning s[i...n] is initially considered valid.
    // We will update this to be smaller if a 3-AP is found.
    std::vector<int> max_r_for_l(n + 1);
    std::iota(max_r_for_l.begin(), max_r_for_l.end(), 0); // max_r_for_l[i] = i initially
    // For 1-based indexing, max_r_for_l[i] = i-1.
    // Let's use 0-based indexing for max_r_for_l to match string indices.
    // max_r_for_l[i] will store the largest index j such that s[i...j] is valid.
    // Initialize max_r_for_l[i] = i-1.
    // This means for a given l (0-indexed), any r < l is invalid.
    // We want to find the smallest r_min such that s[l...r_min] contains a 3-AP.
    // Then all r >= r_min will contain a 3-AP.
    // The number of invalid pairs (l, r) for a fixed l is (r_min - 1) - l + 1 = r_min - l.
    // If no 3-AP starts at or after l, then r_min = n+1.
    // So, for each l, we want to find the smallest r_min such that s[l...r_min] contains a 3-AP.
    // All pairs (l, r) with r < r_min are invalid.
    // The number of such r's is r_min - l.
    // We can iterate l from n-1 down to 0.
    // For each l, the smallest r_min for s[l...] is at most the smallest r_min for s[l+1...].
    // Let's define `min_r_with_3AP[l]` as the smallest `r` (0-indexed) such that `s[l...r]` contains a 3-AP.
    // If no such `r` exists, `min_r_with_3AP[l] = n`.
    // We want to sum `min_r_with_3AP[l] - l` for all `l`.
    // Initialize `min_r_with_3AP[l] = n` for all `l`.
    std::vector<int> min_r_with_3AP(n + 1, n); // min_r_with_3AP[l] stores the smallest r (0-indexed)
                                              // such that s[l...r] contains a 3-AP.
                                              // If no such r, it's n.

    // Iterate through all possible x and k to find 3-APs
    // x is 0-indexed, k is 1-indexed
    // s_x = s_{x+k} = s_{x+2k}
    // x+2k must be < n
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a 3-AP: (x, x+k, x+2k)
                // This 3-AP starts at index x and ends at index x+2k.
                // Any substring s[l...r] where l <= x and r >= x+2k contains this 3-AP.
                // For any l' <= x, the smallest r that makes s[l'...r] contain a 3-AP
                // is at most x+2k.
                // So, we update min_r_with_3AP[l'] for all l' from 0 to x.
                // Specifically, for each l' from 0 to x, min_r_with_3AP[l'] = min(min_r_with_3AP[l'], x+2k).
                // This means we need to update a range.
                // The `min_r_with_3AP` array should be non-increasing.
                // If `min_r_with_3AP[x]` is updated to `x+2k`, then `min_r_with_3AP[x-1]`
                // should be at most `x+2k` (or its previous value if smaller).
                // We can process this efficiently by iterating `l` from `n-1` down to `0`.
                // When we find a 3-AP ending at `x+2k`, it affects `min_r_with_3AP[x]`.
                // The value `min_r_with_3AP[l]` for `l < x` will be `min(min_r_with_3AP[l+1], current_min_r_for_l)`.
                // Let's re-think the loop structure.
                // The current approach is to find all (x, k) and then update min_r_with_3AP.
                // For a fixed x, k, the 3-AP is (x, x+k, x+2k).
                // This means for any l from 0 to x, the substring s[l ... x+2k] contains this 3-AP.
                // So, for any l in [0, x], min_r_with_3AP[l] should be at most x+2k.
                // We want to find the minimum r for each l.
                // So, for each l from 0 to x, we update min_r_with_3AP[l] = min(min_r_with_3AP[l], x+2k).
                // This is a range minimum update.
                // A simpler way is to iterate l from x down to 0.
                // min_r_with_3AP[l] = min(min_r_with_3AP[l], x+2k).
                // This is correct.
                min_r_with_3AP[x] = std::min(min_r_with_3AP[x], x + 2 * k);
            }
        }
    }

    // Now, propagate the minimums.
    // For any l, min_r_with_3AP[l] must be less than or equal to min_r_with_3AP[l+1].
    // If s[l+1...r'] contains a 3-AP, then s[l...r'] also contains it.
    // So, min_r_with_3AP[l] <= min_r_with_3AP[l+1].
    for (int l = n - 2; l >= 0; --l) {
        min_r_with_3AP[l] = std::min(min_r_with_3AP[l], min_r_with_3AP[l + 1]);
    }

    // Calculate the number of invalid pairs (l, r).
    // For each l (0-indexed), any r such that l <= r < min_r_with_3AP[l] is an invalid pair.
    // The number of such r's is min_r_with_3AP[l] - l.
    for (int l = 0; l < n; ++l) {
        invalid_pairs += (min_r_with_3AP[l] - l);
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <iostream>
