#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

long long N, M;
std::vector<long long> H, P;

// Function to check if all tracks can be covered within time T
bool check(long long T) {
    // `covered_until` stores the maximum track index covered by heads up to the current head.
    // Specifically, covered_until[i] means that using heads H[0]...H[i],
    // we can cover all required tracks up to P[covered_until[i]].
    // If covered_until[i] == M, it means all tracks P[0]...P[M-1] can be covered.
    std::vector<int> covered_until(N, -1);

    // For the first head H[0]
    int current_p_idx = 0;
    while (current_p_idx < M && P[current_p_idx] <= H[0] + T) {
        current_p_idx++;
    }
    covered_until[0] = current_p_idx - 1;

    // For subsequent heads H[i]
    for (int i = 1; i < N; ++i) {
        // Option 1: H[i] covers tracks independently, starting from P[0]
        current_p_idx = 0;
        while (current_p_idx < M && P[current_p_idx] <= H[i] + T) {
            current_p_idx++;
        }
        covered_until[i] = std::max(covered_until[i], current_p_idx - 1);

        // Option 2: H[i] extends the coverage of previous heads.
        // It covers tracks starting from P[covered_until[i-1] + 1].
        // If covered_until[i-1] is already M-1, then all tracks are covered.
        if (covered_until[i-1] == M - 1) {
            covered_until[i] = M - 1;
            continue;
        }

        // `start_p_idx` is the first track H[i] needs to cover,
        // assuming previous heads covered up to `covered_until[i-1]`.
        int start_p_idx = covered_until[i-1] + 1;

        // If H[i] is too far to the left to cover P[start_p_idx]
        if (H[i] + T < P[start_p_idx]) {
            // H[i] cannot cover P[start_p_idx] even by moving right as much as possible.
            // So it cannot extend the coverage.
            continue;
        }

        // If H[i] is to the right of P[start_p_idx]
        if (H[i] >= P[start_p_idx]) {
            // H[i] can cover P[start_p_idx] by moving left or staying.
            // It can cover up to H[i] + T.
            // It can also cover tracks to its left, up to H[i] - T.
            // The range covered by H[i] is [H[i]-T, H[i]+T].
            // We need to cover P[start_p_idx] and subsequent tracks.
            // The maximum track index it can cover is `end_p_idx`.
            int end_p_idx = start_p_idx;
            while (end_p_idx < M && P[end_p_idx] <= H[i] + T) {
                end_p_idx++;
            }
            covered_until[i] = std::max(covered_until[i], end_p_idx - 1);
        } else { // H[i] < P[start_p_idx]
            // H[i] is to the left of P[start_p_idx].
            // It must move right to cover P[start_p_idx].
            // The time taken to reach P[start_p_idx] is P[start_p_idx] - H[i].
            // Remaining time for movement is T - (P[start_p_idx] - H[i]).
            // This remaining time can be used to move further right from P[start_p_idx].
            // So, it can cover up to P[start_p_idx] + (T - (P[start_p_idx] - H[i])) = H[i] + T.
            // Or, it can move left from H[i] to cover tracks.
            // The total range covered by H[i] is [H[i]-T, H[i]+T].
            // We need to cover P[start_p_idx] and subsequent tracks.
            // The maximum track index it can cover is `end_p_idx`.

            // Case 1: H[i] moves right to cover P[start_p_idx] and then continues right.
            // Max track covered is H[i] + T.
            int end_p_idx_right = start_p_idx;
            while (end_p_idx_right < M && P[end_p_idx_right] <= H[i] + T) {
                end_p_idx_right++;
            }
            covered_until[i] = std::max(covered_until[i], end_p_idx_right - 1);

            // Case 2: H[i] moves left to cover some track P[k] (k < start_p_idx)
            // and then moves right to cover P[start_p_idx] and subsequent tracks.
            // This is the "two-sided" movement.
            // The total distance covered is (P[end_p_idx_left] - H[i]) + (P[end_p_idx_right] - P[end_p_idx_left])
            // No, this is not how it works.
            // If H[i] covers a range [L, R], the time taken is min(abs(H[i]-L) + (R-L), abs(H[i]-R) + (R-L)).
            // This is equivalent to max(abs(H[i]-L), abs(H[i]-R)) + (R-L) if L and R are on opposite sides of H[i].
            // No, it's simpler: if H[i] covers [L, R], it must visit L and R.
