    long long presses = 0;

    // Greedy approach: prioritize larger denominations
    // Number of 5s
    presses += diff / 5;
    diff %= 5;

    // Now diff can be 0, 1, 2, 3, 4
    if (diff == 0) {
        // No remaining difference
