        // To get 1:
        // Option 1: 1x (+1) -> 1 press
        // Option 2: 1x (+2) then 1x (-1) -> 2 presses (e.g., 5 -> 7 -> 6)
        // Option 3: 1x (+5) then 2x (-2) then 0x (-1) -> 3 presses (e.g., 5 -> 10 -> 8 -> 6)
        // Option 4: 1x (+5) then 4x (-1) -> 5 presses
        // The optimal is 1 press (+1)
        presses += 1;
    } else if (diff == 2) {
        // To get 2:
