void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The simplest way to get a different permutation with the same fingerprint
    // is to reverse the given permutation.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // Let p' be the reversed permutation: p' = [p_n, p_{n-1}, ..., p_1]
    // The adjacent sums for p' are:
    // [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1]
    // This is the same set of sums as for p, just in reverse order.
    // Therefore, F(p') = F(p).
    // The problem guarantees that a solution exists and that p' must be different from p.
    // If p is not a palindrome, then reversing it gives a different permutation.
    // If p is a palindrome, then p_i = p_{n-i+1} for all i.
    // In this case, p_rev = p.
    // However, the problem statement implies that such a p' always exists.
    // The problem constraints (N <= 100) are small enough that reversing is efficient.
    // It's guaranteed that p is a permutation, so p_i are distinct.
    // A permutation cannot be a palindrome if n > 1 and p_i = p_{n-i+1} for all i,
    // unless n is odd and p_{(n+1)/2} is the middle element.
    // But even then, for p to be a palindrome, it would mean p_1 = p_n, which is impossible
    // for a permutation of distinct elements.
    // Wait, this is incorrect. A permutation can be a palindrome if we consider the values.
    // E.g., [1,2,1] is not a permutation. [1,2,3,2,1] is not a permutation.
    // A permutation like [1,2,3] reversed is [3,2,1]. These are different.
    // A permutation like [1,2] reversed is [2,1]. These are different.
    // In fact, for any permutation p of length n >= 2, p cannot be equal to its reverse p_rev.
    // If p = p_rev, then p_1 = p_n. But p_1 and p_n must be distinct elements from 1 to n.
    // This is only possible if n=1, but the problem states n >= 2.
    // So, for n >= 2, p is never equal to p_rev.
    // Thus, reversing p always yields a different permutation p' with the same fingerprint.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

