#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long haybales_in_pile1 = a[0];

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i + 1; // 1-indexed pile number
        long long distance = pile_idx - 1; // days to move one haybale to pile 1

        if (distance == 0) { // Should not happen for i >= 1
            continue;
        }

        // Calculate how many haybales can be moved from pile i to pile 1
        // given the remaining days d.
        // Each haybale costs 'distance' days.
        long long max_haybales_to_move_from_this_pile = d / distance;

        // We can move at most a[i] haybales from pile i.
        long long haybales_to_move = std::min(a[i], max_haybales_to_move_from_this_pile);

        haybales_in_pile1 += haybales_to_move;
        d -= haybales_to_move * distance;

        if (d <= 0) {
            break; // No more days left
        }
    }

    std::cout << haybales_in_pile1 << std::endl;
}

