                if (!prefix_has_neg_one_arr[i-1]) { // Check if there's a -1 in a[0...i-1]
                    possible = false;
                    break;
                }
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

