#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the last element, as it's the minimum
    // for the suffix starting at the last element.
    int min_suffix = a[n - 1];

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i]
            // is a new minimum for the suffix ending at i.
            // Update min_suffix to be the minimum of a[i] and the
            // previous min_suffix.
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

