    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_dist = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The distance from the previous 'R' (or 0) to the current 'R' is (i - last_r_pos).
                // We need to be able to jump this distance.
                max_dist = std::max(max_dist, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or 0 if no 'R's) to the target cell n+1.
        // The distance is (n + 1 - last_r_pos).
        max_dist = std::max(max_dist, n + 1 - last_r_pos);
        std::cout << max_dist << "\n";
    }
    return 0;
}

