int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // The remaining 'mid' slots (3*mid - mid - mid) can be filled by any student.
            // Specifically, we need 'mid' coders, 'mid' mathematicians, and 'mid' other students.
            // The 'mid' other students can be coders, mathematicians, or no-specialization students.
            // So, we need to check if we have enough students for 'mid' teams.
            // Minimum coders needed: mid
            // Minimum mathematicians needed: mid
            // Minimum total students needed: 3 * mid
            // The 'mid' coders and 'mid' mathematicians are taken from c and m.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining no-specialization students: x
            // Total remaining students available for the 'mid' third slots: (c - mid) + (m - mid) + x
            // We need 'mid' students for these third slots.
            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair staircase
        long long sum_of_powers_of_2 = 1; // Sum of 2^0
        while (true) {
            if (x >= current_cost) {
                count++;
                x -= current_cost;
            } else {
                break;
            }
            // Calculate cost for the next nice staircase
            // If current nice staircase has k stairs, it uses 2^0, 2^1, ..., 2^(m-1) squares.
            // The number of stairs is 2^m - 1.
            // The next nice staircase will have 2^(m+1) - 1 stairs.
            // Its cost is (2^(m+1) - 1) * (2^(m+1)) / 2.
            // The difference in number of stairs is 2^m.
            // The cost of the next nice staircase is current_cost + (2^m * (2^m + 1) / 2) * 2
            // No, this is not correct.
            // The number of stairs for the current nice staircase is sum_of_powers_of_2.
            // The next nice staircase will have 2 * sum_of_powers_of_2 + 1 stairs.
            // Let N_k be the number of stairs for the k-th nice staircase.
            // N_1 = 1
            // N_2 = 3
            // N_3 = 7
            // N_k = 2^k - 1
            // The cost for N_k stairs is C_k = N_k * (N_k + 1) / 2 = (2^k - 1) * 2^k / 2.
            // We are currently at N_k. The cost is C_k.
            // We need to find C_{k+1}.
            // C_{k+1} = (2^(k+1) - 1) * 2^(k+1) / 2.
            // Let's use the sum_of_powers_of_2 variable to represent 2^k - 1.
            // So, current_cost = sum_of_powers_of_2 * (sum_of_powers_of_2 + 1) / 2.
            // The next sum_of_powers_of_2 will be 2 * sum_of_powers_of_2 + 1.
            // This is equivalent to sum_of_powers_of_2 = 2^k - 1.
            // Next sum_of_powers_of_2 = 2 * (2^k - 1) + 1 = 2^(k+1) - 2 + 1 = 2^(k+1) - 1.
            // This is correct.

            // The cost of the next staircase is:
            // (2 * current_stairs + 1) * (2 * current_stairs + 2) / 2
            // where current_stairs is sum_of_powers_of_2.
            // This is not the cost of the next staircase, but the number of cells for the next staircase.
            // The number of cells for a staircase with N stairs is N*(N+1)/2.
            // The number of stairs for the k-th nice staircase is 2^k - 1.
            // Let's denote N_k = 2^k - 1.
            // The cost for N_k stairs is C_k = N_k * (N_k + 1) / 2.
            // We start with k=1, N_1 = 1, C_1 = 1 * 2 / 2 = 1.
            // Next, k=2, N_2 = 3, C_2 = 3 * 4 / 2 = 6.
            // Next, k=3, N_3 = 7, C_3 = 7 * 8 / 2 = 28.
            // Next, k=4, N_4 = 15, C_4 = 15 * 16 / 2 = 120.
            // The current_cost variable holds C_k.
            // We need to calculate C_{k+1}.
            // N_{k+1} = 2 * N_k + 1.
            // C_{k+1} = N_{k+1} * (N_{k+1} + 1) / 2.
            // N_{k+1} = 2 * (2^k - 1) + 1 = 2^(k+1) - 1.
            // N_{k+1} + 1 = 2^(k+1).
            // C_{k+1} = (2^(k+1) - 1) * 2^(k+1) / 2.
            // This is equivalent to C_{k+1} = (2 * N_k + 1) * (2 * N_k + 2) / 2.
            // Let's use `num_stairs` to track N_k.
            // Initially, num_stairs = 1. current_cost = 1.
            // In the loop:
            // num_stairs = 2 * num_stairs + 1;
            // current_cost = num_stairs * (num_stairs + 1) / 2;
            // This is the correct recurrence for the cost of the next nice staircase.

            long long next_num_stairs = 2 * sum_of_powers_of_2 + 1;
            long long next_cost = next_num_stairs * (next_num_stairs + 1) / 2;

            // Check for overflow before assigning to current_cost
            // next_num_stairs can be up to 2*10^9 (approx sqrt(2*10^18))
            // next_cost can be up to 10^18.
            // If next_num_stairs is around 2*10^9, then next_num_stairs * (next_num_stairs + 1)
            // is around 4*10^18, which fits in long long.
            // So, no overflow for next_cost.

            sum_of_powers_of_2 = next_num_stairs;
            current_cost = next_cost;
        }
        std::cout << count << "\n";
    }
    return 0;
}

