int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate k distinct differences: k, k-1, ..., 1
    // This is achieved by alternating between left and right pointers
    // Example for k=4:
    // 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1
    // This generates k distinct differences: k, k-1, ..., 1
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        if (i < k) {
            std::cout << " ";
        }
    }

    // The remaining numbers are from k+2 to n.
    // We need to append them such that they don't introduce new distinct differences.
    // The simplest way is to append them in increasing order.
    // Since the last number printed was either left-1 or right+1,
    // and the next available number is left (if last was right+1) or right (if last was left-1),
    // and left is now greater than right, the next number to print is left.
    // The differences will be |(last_printed) - (left)|.
    // If last_printed was right+1, then |(right+1) - left|.
    // If last_printed was left-1, then |(left-1) - left| = 1.
    // In either case, the numbers from left to n are printed sequentially.
    // This ensures all subsequent differences are 1.
    // Since 1 is already among the k distinct differences, no new distinct differences are introduced.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << " " << i;
    }
    std::cout << std::endl;

    return 0;
}

