int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m;
        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long last_digit_m = m % 10;

        // Precompute the sum of last digits for one full cycle (10 multiples)
        // The sequence of last digits (k * m) % 10 repeats every 10 values of k.
        // For example, if m=3, last digits are:
        // (1*3)%10=3, (2*3)%10=6, (3*3)%10=9, (4*3)%10=2, (5*3)%10=5,
        // (6*3)%10=8, (7*3)%10=1, (8*3)%10=4, (9*3)%10=7, (10*3)%10=0.
        // Then (11*3)%10=3 again.
        long long sum_of_cycle_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_cycle_digits += (i * last_digit_m) % 10;
        }

        // Calculate how many full cycles are there
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_of_cycle_digits;

        // Calculate the sum for the remaining multiples
        long long remaining_multiples = count % 10;
        for (int i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * last_digit_m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This means a[i] <= a[i+1] <= ... <= a[n-1].
    // We start from n-1 and move left.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // After this loop, a[i...n-1] is non-decreasing.
    // If i=0, the whole array is non-decreasing.

    // Now, find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This means a[j] >= a[j+1] >= ... >= a[i-1].
    // We start from i-1 and move left.
    // If i=0, this loop won't run, and j will remain 0.
    int j = i; // Initialize j to i. If i=0, j=0. If i>0, we check from i-1.
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // After this loop, a[j...i-1] is non-increasing.
    // If j=0, then a[0...i-1] is non-increasing.

    // The prefix to remove is a[0...j-1]. Its length is j.
    std::cout << j << std::endl;
}

