    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // starting from a_1, such that a_i >= i-1 for all i in the prefix.
    // This is equivalent to finding the largest 'left_len' such that
    // a[i] >= i for 0 <= i < left_len.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // ending at a_n, such that a_i >= n-1-i for all i in the suffix.
    // This is equivalent to finding the largest 'right_len' such that
    // a[i] >= n-1-i for n-right_len <= i < n.
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_len++;
        } else {
            break;
        }
    }

    // If the sum of the lengths of the longest possible increasing prefix
    // and the longest possible decreasing suffix is greater than or equal to n,
    // it means there's at least one element that can serve as the peak 'k'.
    // Specifically, if left_len + right_len > n, it means the "potential"
    // increasing prefix and decreasing suffix overlap, implying there's a 'k'
    // that can satisfy the conditions.
    // The condition is left_len + right_len > n.
    // Example: n=3, left_len=2, right_len=2.
    // left_len covers indices 0, 1.
    // right_len covers indices 1, 2.
    // Overlap at index 1. So k=1 (0-indexed) or k=2 (1-indexed) is possible.
    // The peak can be any index i such that 0 <= i < left_len and n-right_len <= i < n.
    // Such an i exists if left_len > n - right_len, or left_len + right_len > n.
    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

