int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left = 0; // Pointer for the "original" elements (smaller ones)
    int right = 0; // Pointer for the "new" elements (larger ones)
    while (right < n) {
        if (a[right] > a[left]) {
            // If a[right] is strictly greater than a[left],
            // we can place a[right] at the position where a[left] used to be.
            // This increases our count.
            // Then we move both pointers to consider the next pair.
            count++;
            left++;
            right++;
        } else {
            // If a[right] is not greater than a[left] (i.e., a[right] <= a[left]),
            // a[right] cannot be placed at a[left]'s position to satisfy the condition.
            // We need a larger element for a[left], so we try the next element for 'right'.
            right++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

