#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<int> counts(n + 1, 0);
    int distinct_count = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n) { // Optimization: if a[i] is too large, it can't be part of any permutation
            break;
        }
        if (counts[a[i]] == 0) {
            distinct_count++;
        }
        counts[a[i]]++;
        if (counts[a[i]] > 1) { // Duplicate found
            break;
        }
        if (distinct_count == i + 1 && prefix_max[i] == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::fill(counts.begin(), counts.end(), 0);
    distinct_count = 0;
    std::vector<bool> is_suffix_perm(n + 1, false);
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > n) { // Optimization
            break;
        }
        if (counts[a[i]] == 0) {
            distinct_count++;
        }
        counts[a[i]]++;
        if (counts[a[i]] > 1) { // Duplicate found
            break;
        }
        if (distinct_count == current_len && suffix_max[i] == current_len) {
            is_suffix_perm[current_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1 and at most n-1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

