    long long T_half = T / 2;
    int T_half_count = 0;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Smaller elements go to white (c)
        } else if (a[i] > T_half) {
            p[i] = 1; // Larger elements go to black (d)
        } else { // a[i] == T_half
            if (T_is_even) {
                // Distribute T/2 elements alternatingly
                p[i] = T_half_count % 2;
                T_half_count++;
            } else {
                // T is odd, so a[i] == T/2 is impossible for integer a[i]
                // This branch should not be reached if a[i] is an integer and T is odd.
                // However, if T is odd and a[i] is T/2 (e.g., T=7, a[i]=3.5), it's not an integer.
                // The problem states a_i are integers. So if T is odd, a[i] can never be T/2.
                // Thus, this 'else' branch only applies if T is even.
                // But to be safe, if T is odd, any a[i] cannot be T/2, so it falls into < T/2 or > T/2.
                // The problem statement says a_i are non-negative integers.
                // If T is odd, T/2 is not an integer. So a[i] can never be equal to T/2.
                // So this 'else' branch (a[i] == T_half) is only reachable if T is even.
                // The logic for T_half_count % 2 is correct for even T.
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
