#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append elements such that new_sum = 2 * new_xor_sum.
        // Let S_0 be current_sum and X_0 be current_xor_sum.
        // We want to find b1, b2, b3 such that:
        // S_0 + b1 + b2 + b3 = 2 * (X_0 ^ b1 ^ b2 ^ b3)

        // A common strategy for these problems is to make the XOR sum equal to a value,
        // and then adjust the sum.
        // Let's try to make the final XOR sum X_f.
        // We need S_f = 2 * X_f.

        // Consider appending two elements: X_0 and S_0 + X_0.
        // Let b1 = X_0.
        // Let b2 = S_0 + X_0.
        // New XOR sum: X_0 ^ b1 ^ b2 = X_0 ^ X_0 ^ (S_0 + X_0) = S_0 + X_0.
        // New sum: S_0 + b1 + b2 = S_0 + X_0 + (S_0 + X_0) = 2 * S_0 + 2 * X_0.
        // We need: 2 * S_0 + 2 * X_0 = 2 * (S_0 + X_0).
        // This is always true!
        // So, appending X_0 and S_0 + X_0 always makes the array good.
        // The problem states we can append at most 3 elements. This strategy uses 2.

        // Let's verify the example: [8]
        // S_0 = 8, X_0 = 8.
        // S_0 != 2 * X_0 (8 != 16).
        // Append b1 = X_0 = 8.
        // Append b2 = S_0 + X_0 = 8 + 8 = 16.
        // New array: [8, 8, 16]
        // New sum: 8 + 8 + 16 = 32.
        // New XOR sum: 8 ^ 8 ^ 16 = 0 ^ 16 = 16.
        // 32 = 2 * 16. This works.
        // The example output is 2 elements: 4 4.
        // This means there are multiple solutions. My solution is also valid.

        // Let's use the strategy: append X_0 and S_0 + X_0.
        // The values can be large, up to 10^9 for a_i.
        // S_0 can be up to 10^5 * 10^9 = 10^14.
        // X_0 can be up to 2^30 (approx 10^9).
        // S_0 + X_0 can be up to 10^14 + 10^9, which fits in long long.
        // The problem states b_i can be up to 10^18. So this is fine.

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

