#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_b = 0;
    long long power_of_2 = 1; // Represents 2^count_b
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            count_b++;
            power_of_2 = (power_of_2 * 2) % mod; // 2^(count_b)
        } else { // s[i] == 'a'
            if (count_b > 0) {
                // An 'a' at this position will move past all 'b's to its right.
                // The number of 'b's to its right is `count_b`.
                // Each 'b' it moves past effectively doubles the 'a's that need to move past it.
                // The number of operations for this 'a' is 2^count_b.
                // This is equivalent to (2^count_b - 1) + 1.
                // The (2^count_b - 1) part is for the 'a's that are generated by previous 'a's.
                // The +1 is for the current 'a' moving past the first 'b'.
                // The logic derived from the right-to-left scan is simpler:
                // Each 'a' effectively "consumes" all 'b's to its right.
                // If there are `k` 'b's to its right, this 'a' will perform `2^k` operations.
                // The `power_of_2` variable already holds `2^count_b` (modulo mod).
                total_steps = (total_steps + (power_of_2 - 1 + mod) % mod) % mod;

                // After this 'a' moves past all 'b's, it effectively becomes a 'b'
                // for any 'a's further to its left.
                // So, we increment count_b for the next 'a' to its left.
                // This is equivalent to saying that this 'a' will eventually be to the right
                // of any 'a's to its left, and it will be followed by `count_b` 'b's.
                // The `power_of_2` needs to be updated as if this 'a' was a 'b'.
                // This means `power_of_2` should be multiplied by 2.
                // This is because the number of 'b's effectively increases by 1.
                // So, `count_b` increases by 1.
                count_b = 0; // Reset count_b for the next 'a'
                power_of_2 = 1; // Reset power_of_2 for the next 'a'
            }
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

