    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_val, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_val, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs counted twice (those with same x AND same y, i.e., identical points)
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n == 1) {
                chanek_score += 1;
                n = 0;
            } else if (n == 2) {
                chanek_score += 1; // Take 1, opponent takes 1. Or take N/2=1, opponent takes 1. Both give 1.
                n = 0;
            } else if (n == 3) {
                chanek_score += 1; // Take 1, N=2. Opponent takes 1. Chanek takes 1. Total 2.
                                   // If Chanek takes 1, N=2. Opponent takes 1. Chanek takes 1. Chanek gets 2.
                                   // If Chanek takes 1, N=2. Opponent takes 1. Chanek takes 1. Chanek gets 2.
                                   // This logic is tricky. Let's re-evaluate.
                                   // For N=3, Chanek takes 1. N becomes 2. Opponent's turn.
                                   // Opponent sees N=2. Opponent takes 1. N becomes 1. Chanek's turn.
                                   // Chanek sees N=1. Chanek takes 1. N becomes 0. Game ends.
                                   // Chanek gets 1 + 1 = 2. Opponent gets 1.
                                   // So if N=3, Chanek takes 1.
                chanek_score += 1;
                n -= 1;
            } else if (n % 2 != 0) { // N is odd and N > 3
                chanek_score += 1;
                n -= 1;
            } else { // N is even and N > 0
                // Option 1: Take 1. N becomes N-1 (odd). Opponent's turn.
                // Option 2: Take N/2. N becomes N/2. Opponent's turn.

                // If N/2 is odd, and N/2 > 1:
                // Chanek takes N/2. N becomes N/2 (odd). Opponent's turn.
                // Opponent takes 1. N becomes N/2 - 1 (even). Chanek's turn.
                // Chanek takes N/2 - 1 / 2.
                // This path seems to give Chanek less.
                // Consider N = 6.
                // Chanek takes 1. N=5. Opponent's turn.
                // Opponent takes 1. N=4. Chanek's turn.
                // Chanek takes N/2=2. N=2. Opponent's turn.
                // Opponent takes 1. N=1. Chanek's turn.
                // Chanek takes 1. N=0.
                // Chanek: 1+2+1 = 4. Opponent: 1+1 = 2.

                // Chanek takes N/2=3. N=3. Opponent's turn.
                // Opponent takes 1. N=2. Chanek's turn.
                // Chanek takes 1. N=1. Opponent's turn.
                // Opponent takes 1. N=0.
                // Chanek: 3+1 = 4. Opponent: 1+1 = 2.
                // Both options give Chanek 4.

                // The key insight is that if N is even, and N/2 is odd, and N/2 > 1,
                // taking N/2 is generally better or equal.
                // If N/2 is odd, then N = 2 * (odd number).
                // If N/2 is odd and N/2 > 1 (i.e., N > 2):
                //   Option A: Chanek takes 1. N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                //   Option B: Chanek takes N/2. N becomes N/2 (odd). Opponent takes 1. N becomes N/2 - 1 (even).
                // The remaining coins for Chanek to play on are N-2 vs N/2 - 1.
                // If N/2 is odd, then N/2 - 1 is even.
                // If N/2 is odd, then N-2 is even.
                // The opponent will try to leave Chanek with as few coins as possible.
                // If N/2 is odd and N/2 > 1, then N is of form 2 * (2k+1) = 4k+2.
                // N/2 is odd.
                // If N/2 is a power of 2, then N is a power of 2.
                // If N is a power of 2, say N = 2^k (k >= 1).
                // Chanek takes N/2. N becomes N/2 = 2^(k-1). Opponent's turn.
                // Opponent takes N/2 / 2 = 2^(k-2). N becomes 2^(k-2). Chanek's turn.
                // This continues until N=1.
                // Chanek gets N/2 + N/8 + N/32 + ...
                // Opponent gets N/4 + N/16 + N/64 + ...
                // Total Chanek: N/2 * (1 + 1/4 + 1/16 + ...) = N/2 * (1 / (1 - 1/4)) = N/2 * (4/3) = 2N/3.
                // Total Opponent: N/4 * (1 + 1/4 + 1/16 + ...) = N/4 * (4/3) = N/3.
                // This is if N is a power of 2.

                // If N is even, and N/2 is also even (i.e., N is a multiple of 4):
                // Chanek takes N/2. N becomes N/2 (even). Opponent's turn.
                // Opponent takes N/4. N becomes N/4 (even). Chanek's turn.
                // This is the optimal strategy for both players if N is a power of 2.
                // If N is a multiple of 4, taking N/2 is always optimal for the current player.
                // Because it leaves the opponent with an even number, forcing them to also take half,
                // which means the current player gets a larger share of the total.
                // Example N=8. Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 4+1=5. Opponent: 2+1=3.
                // If Chanek takes 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+3+1 = 5. Opponent: 1+1+1 = 3.
                // It seems taking N/2 is always optimal if N is even.

                // The only exception is when N/2 is odd, and N/2 = 1, which means N=2.
                // For N=2, Chanek takes 1. N=1. Opponent takes 1. N=0. Chanek gets 1.
                // If Chanek takes N/2=1. N=1. Opponent takes 1. N=0. Chanek gets 1.
                // So for N=2, both options give 1.

                // The general strategy for an even N:
                // If N is a power of 2 (N = 2^k, k >= 1):
                //   Chanek takes N/2. N becomes N/2.
                //   Opponent takes N/4. N becomes N/4.
                //   ...
                //   This continues until N=1.
                //   Chanek gets N/2 + N/8 + N/32 + ... = N * (1/2 + 1/8 + 1/32 + ...) = N * (2/3).
                //   Opponent gets N/4 + N/16 + N/64 + ... = N * (1/3).
                // If N is even but not a power of 2:
                //   N = 2^k * M, where M is odd and M > 1.
                //   Chanek takes N/2. N becomes N/2 = 2^(k-1) * M.
                //   Opponent takes N/4. N becomes N/4 = 2^(k-2) * M.
                //   ...
                //   This continues until N becomes M (odd).
                //   At this point, the player whose turn it is faces M coins.
                //   The player facing M (odd, M>1) will take 1 coin.
                //   Then the other player faces M-1 (even).
                //   This suggests that if N is even, taking N/2 is always the best move.
                //   The only time taking 1 is better is if N/2 leads to a worse outcome.
                //   Consider N=6. N/2=3.
                //   Chanek takes 3. N=3. Opponent's turn.
                //   Opponent takes 1. N=2. Chanek's turn.
                //   Chanek takes 1. N=1. Opponent's turn.
                //   Opponent takes 1. N=0.
                //   Chanek: 3+1=4. Opponent: 1+1=2.
                //   If Chanek takes 1. N=5. Opponent's turn.
                //   Opponent takes 1. N=4. Chanek's turn.
                //   Chanek takes 2. N=2. Opponent's turn.
                //   Opponent takes 1. N=1. Chanek's turn.
                //   Chanek takes 1. N=0.
                //   Chanek: 1+2+1=4. Opponent: 1+1=2.
                //   Both give 4.

                // The strategy is:
                // If N is odd: take 1.
                // If N is even:
                //   If N is a power of 2: take N/2.
                //   If N is even but not a power of 2: take N/2.
                // This simplifies to: if N is odd, take 1. If N is even, take N/2.
                // This is because taking N/2 leaves the opponent with N/2 coins.
                // If N/2 is even, the opponent will also take N/4, continuing the pattern.
                // If N/2 is odd, the opponent will take 1, leaving N/2-1 (even) for Chanek.
                // This seems to be the greedy strategy.

                // Let's re-evaluate the N=2 case.
                // N=2. Chanek takes 1. N=1. Opponent takes 1. N=0. Chanek gets 1.
                // N=2. Chanek takes N/2=1. N=1. Opponent takes 1. N=0. Chanek gets 1.
                // So for N=2, taking 1 is fine.

                // The only special case is when N is even, and N/2 is odd, and N/2 > 1.
                // This means N = 2 * (odd number > 1).
                // Example N=6. N/2=3.
                // Chanek takes N/2=3. N=3. Opponent's turn.
                // Opponent takes 1. N=2. Chanek's turn.
                // Chanek takes 1. N=1. Opponent's turn.
                // Opponent takes 1. N=0.
                // Chanek gets 3+1=4. Opponent gets 1+1=2.

                // What if Chanek takes 1 when N=6?
                // Chanek takes 1. N=5. Opponent's turn.
                // Opponent takes 1. N=4. Chanek's turn.
                // Chanek takes N/2=2. N=2. Opponent's turn.
                // Opponent takes 1. N=1. Chanek's turn.
                // Chanek takes 1. N=0.
                // Chanek gets 1+2+1=4. Opponent gets 1+1=2.

                // Both options yield 4 for Chanek.
                // It seems the simple greedy strategy works:
                // If N is odd, take 1.
                // If N is even, take N/2.

                // Let's test this strategy.
                // N=5:
                // Chanek (N=5, odd): takes 1. Chanek=1. N=4.
                // Opponent (N=4, even): takes N/2=2. Opponent=2. N=2.
                // Chanek (N=2, even): takes N/2=1. Chanek=1+1=2. N=1.
                // Opponent (N=1, odd): takes 1. Opponent=2+1=3. N=0.
                // Chanek gets 2. Correct for example 1.

                // N=6:
                // Chanek (N=6, even): takes N/2=3. Chanek=3. N=3.
                // Opponent (N=3, odd): takes 1. Opponent=1. N=2.
                // Chanek (N=2, even): takes N/2=1. Chanek=3+1=4. N=1.
                // Opponent (N=1, odd): takes 1. Opponent=1+1=2. N=0.
                // Chanek gets 4. Correct for example 2.

                // This greedy strategy seems to work for the examples.
                // Let's consider the case where N is even, and N/2 is odd, and N/2 > 1.
                // This means N = 2 * (odd number M), where M > 1.
                // If Chanek takes N/2 = M. N becomes M. Opponent's turn.
                // Opponent faces M (odd, M>1). Opponent takes 1. N becomes M-1 (even). Chanek's turn.
                // Chanek faces M-1 (even). Chanek takes (M-1)/2. N becomes (M-1)/2. Opponent's turn.
                // This continues.

                // What if N is even, and N/2 is odd, and N/2 > 1, and Chanek takes 1 instead of N/2?
                // Chanek takes 1. N becomes N-1 (odd). Opponent's turn.
                // Opponent faces N-1 (odd). Opponent takes 1. N becomes N-2 (even). Chanek's turn.
                // Chanek faces N-2 (even). Chanek takes (N-2)/2. N becomes (N-2)/2. Opponent's turn.

                // Let's compare the remaining game states for Chanek:
                // Path 1 (Chanek takes N/2): Chanek gets N/2. Opponent faces M. Opponent takes 1. Chanek faces M-1.
                // Path 2 (Chanek takes 1): Chanek gets 1. Opponent faces N-1. Opponent takes 1. Chanek faces N-2.
                // N = 2M.
                // Path 1: Chanek gets M. Opponent faces M. Opponent takes 1. Chanek faces M-1.
                // Path 2: Chanek gets 1. Opponent faces 2M-1. Opponent takes 1. Chanek faces 2M-2.

                // The crucial observation is that if N is even, and N/2 is odd (i.e., N = 2 * (odd number)),
                // then taking N/2 leaves an odd number for the opponent. The opponent must take 1.
                // This leaves an even number for Chanek.
                // If Chanek takes 1, it leaves an odd number for the opponent. The opponent must take 1.
                // This leaves an even number for Chanek.

                // The only time the greedy strategy (take N/2 if even, take 1 if odd) might fail
                // is if taking N/2 leads to a state where the opponent gets a disproportionately large share
                // compared to taking 1.
                // This happens if N is even, and N/2 is odd, and N/2 is a "bad" state for the next player.
                // A "bad" state for the next player is an odd number, because they can only take 1.
                // So if N is even, and N/2 is odd (N = 2 * M, M odd, M > 1).
                // Chanek takes M. N becomes M. Opponent takes 1. N becomes M-1.
                // Chanek gets M. Opponent gets 1.
                // If Chanek takes 1. N becomes 2M-1. Opponent takes 1. N becomes 2M-2.
                // Chanek gets 1. Opponent gets 1.

                // The remaining game for Chanek starts with M-1 vs 2M-2.
                // M-1 is even. 2M-2 is even.
                // If M-1 is a power of 2, then Chanek gets 2/3 of M-1.
                // If 2M-2 is a power of 2, then Chanek gets 2/3 of 2M-2.

                // This is getting complicated. Let's simplify.
                // The game is about who gets the last coin.
                // If N is odd, the current player takes 1. The next player faces N-1 (even).
                // If N is even, the current player can take 1 or N/2.
                //   If they take 1, the next player faces N-1 (odd).
                //   If they take N/2, the next player faces N/2.

                // Consider the total coins taken by Chanek.
                // If N is odd, Chanek takes 1. N becomes N-1. Opponent's turn.
                // If N is even:
                //   If N is a power of 2 (N = 2^k):
                //     Chanek takes N/2. N becomes N/2. Opponent's turn.
                //     Opponent takes N/4. N becomes N/4. Chanek's turn.
                //     ...
                //     Chanek gets N/2 + N/8 + ... = N * (2/3).
                //     Opponent gets N/4 + N/16 + ... = N * (1/3).
                //   If N is even but not a power of 2 (N = 2^k * M, M odd, M > 1):
                //     Chanek takes N/2. N becomes N/2 = 2^(k-1) * M. Opponent's turn.
                //     This continues until N becomes M (odd).
                //     The player who faces M (odd, M>1) takes 1.
                //     The player who faces M-1 (even) takes (M-1)/2.
                //     This means the player who faces M gets 1 coin, and the other player gets the majority of M-1.

                // Let's trace the game for N = 2^k * M (M odd, M > 1).
                // Chanek's turn, N = 2^k * M.
                // Chanek takes N/2. Chanek gets N/2. N becomes 2^(k-1) * M. Opponent's turn.
                // Opponent takes N/4. Opponent gets N/4. N becomes 2^(k-2) * M. Chanek's turn.
                // ...
                // This continues until N becomes M.
                // The player whose turn it is when N becomes M (odd, M>1) takes 1.
                // Let's say it's Player X's turn when N=M. Player X takes 1. N becomes M-1. Player Y's turn.
                // Player Y faces M-1 (even). Player Y takes (M-1)/2. N becomes (M-1)/2. Player X's turn.
                // ...
                // The player who faces M gets 1 coin. The other player gets the rest of M-1.
                // The total coins from M are M. Player X gets 1 + (coins from (M-1) when Y starts).
                // Player Y gets (coins from (M-1) when Y starts).

                // The crucial part is who gets to face M.
                // If k is odd, Chanek faces M. Chanek gets 1 from M.
                // If k is even, Opponent faces M. Opponent gets 1 from M.

                // Let's count the number of times N is divided by 2 until it becomes odd. This is `k`.
                // `k` is the exponent of 2 in the prime factorization of N.
                // If `k` is odd, Chanek makes the last N/2 move, leaving M for the opponent.
                // If `k` is even, Opponent makes the last N/2 move, leaving M for Chanek.

                // Example N=12. N = 2^2 * 3. k=2 (even). M=3.
                // Chanek (N=12): takes 6. Chanek=6. N=6.
                // Opponent (N=6): takes 3. Opponent=3. N=3.
                // Chanek (N=3): takes 1. Chanek=6+1=7. N=2.
                // Opponent (N=2): takes 1. Opponent=3+1=4. N=1.
                // Chanek (N=1): takes 1. Chanek=7+1=8. N=0.
                // Chanek gets 8. Opponent gets 4.

                // Example N=20. N = 2^2 * 5. k=2 (even). M=5.
                // Chanek (N=20): takes 10. Chanek=10. N=10.
                // Opponent (N=10): takes 5. Opponent=5. N=5.
                // Chanek (N=5): takes 1. Chanek=10+1=11. N=4.
                // Opponent (N=4): takes 2. Opponent=5+2=7. N=2.
                // Chanek (N=2): takes 1. Chanek=11+1=12. N=1.
                // Opponent (N=1): takes 1. Opponent=7+1=8. N=0.
                // Chanek gets 12. Opponent gets 8.

                // Example N=24. N = 2^3 * 3. k=3 (odd). M=3.
                // Chanek (N=24): takes 12. Chanek=12. N=12.
                // Opponent (N=12): takes 6. Opponent=6. N=6.
                // Chanek (N=6): takes 3. Chanek=12+3=15. N=3.
                // Opponent (N=3): takes 1. Opponent=6+1=7. N=2.
                // Chanek (N=2): takes 1. Chanek=15+1=16. N=1.
                // Opponent (N=1): takes 1. Opponent=7+1=8. N=0.
                // Chanek gets 16. Opponent gets 8.

                // The strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   Count `k`, the number of times N is divisible by 2. N = 2^k * M (M odd).
                //   If M=1 (N is a power of 2): take N/2.
                //   If M>1:
                //     If k is odd: take 1. (This leaves N-1, which is odd. Opponent takes 1, leaves N-2 (even). Chanek gets to play on N-2).
                //     If k is even: take N/2. (This leaves N/2. Opponent takes N/4... until M is left for Chanek).

                // Let's re-evaluate N=6. N = 2^1 * 3. k=1 (odd). M=3.
                // According to this strategy, Chanek should take 1.
                // Chanek (N=6): takes 1. Chanek=1. N=5.
                // Opponent (N=5): takes 1. Opponent=1. N=4.
                // Chanek (N=4): takes 2. Chanek=1+2=3. N=2.
                // Opponent (N=2): takes 1. Opponent=1+1=2. N=1.
                // Chanek (N=1): takes 1. Chanek=3+1=4. N=0.
                // Chanek gets 4. This matches the example.

                // Let's re-evaluate N=12. N = 2^2 * 3. k=2 (even). M=3.
                // According to this strategy, Chanek should take N/2.
                // Chanek (N=12): takes 6. Chanek=6. N=6.
                // Opponent (N=6): N=2^1*3. k=1 (odd). Opponent takes 1. Opponent=1. N=5.
                // Chanek (N=5): takes 1. Chanek=6+1=7. N=4.
                // Opponent (N=4): N=2^2*1. k=2 (even). Opponent takes 2. Opponent=1+2=3. N=2.
                // Chanek (N=2): N=2^1*1. k=1 (odd). Chanek takes 1. Chanek=7+1=8. N=1.
                // Opponent (N=1): takes 1. Opponent=3+1=4. N=0.
                // Chanek gets 8. This matches my trace.

                // This refined strategy seems to be correct.
                // Summary of refined strategy for current player (Chanek or Opponent):
                // 1. If N is odd: take 1.
                // 2. If N is even:
                //    a. Find k such that N = 2^k * M, where M is odd.
                //    b. If M=1 (N is a power of 2): take N/2.
                //    c. If M>1:
                //       i. If k is odd: take 1.
                //       ii. If k is even: take N/2.

                // Let's implement this.

                long long temp_n = n;
                int k = 0;
                while (temp_n > 0 && temp_n % 2 == 0) {
                    temp_n /= 2;
                    k++;
                }
                long long M = temp_n;

                if (M == 1) { // N is a power of 2
                    chanek_score += n / 2;
                    n /= 2;
                } else { // N is even, not a power of 2
                    if (k % 2 != 0) { // k is odd
                        chanek_score += 1;
                        n -= 1;
                    } else { // k is even
                        chanek_score += n / 2;
                        n /= 2;
                    }
                }
            }
        } else { // Opponent's turn
            if (n == 1) {
                n = 0; // Opponent takes 1
            } else if (n == 2) {
                n = 0; // Opponent takes 1 or N/2=1
            } else if (n == 3) {
                n -= 1; // Opponent takes 1
            } else if (n % 2 != 0) { // N is odd and N > 3
                n -= 1;
            } else { // N is even and N > 0
                long long temp_n = n;
                int k = 0;
                while (temp_n > 0 && temp_n % 2 == 0) {
                    temp_n /= 2;
                    k++;
                }
                long long M = temp_n;

                if (M == 1) { // N is a power of 2
                    n /= 2;
                } else { // N is even, not a power of 2
                    if (k % 2 != 0) { // k is odd
                        n -= 1;
                    } else { // k is even
                        n /= 2;
                    }
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

