#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left (k)
    // k can range from 0 to n
    for (int k = 0; k <= n; ++k) {
        int items_from_left = k;
        int items_from_right = n - k;

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[items_from_left] * l;

        // Energy for items taken from the right
        // prefix_sum[n] is sum of all weights
        // prefix_sum[n - items_from_right] is sum of first (n - items_from_right) weights
        // So, prefix_sum[n] - prefix_sum[n - items_from_right] is sum of last items_from_right weights
        current_energy += (prefix_sum[n] - prefix_sum[n - items_from_right]) * r;

        // Add penalty for consecutive actions
        if (items_from_left > items_from_right) {
            // More items from left, so the last few items must have been from left
            // The difference is items_from_left - items_from_right
            // The number of extra left items is (items_from_left - items_from_right - 1)
            // if items_from_left = items_from_right + 1, no extra penalty
            // if items_from_left = items_from_right + 2, one extra penalty
            current_energy += (items_from_left - items_from_right - 1) * Ql;
        } else if (items_from_right > items_from_left) {
            // More items from right, so the last few items must have been from right
            // The difference is items_from_right - items_from_left
            // The number of extra right items is (items_from_right - items_from_left - 1)
            current_energy += (items_from_right - items_from_left - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::accumulate with bitwise OR

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> b(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> b[i][j];
        }
    }

    std::vector<int> a(n);
    if (n == 1) {
        a[0] = 0; // As per problem statement, any a_i <= 10^9 is fine. 0 is the simplest.
    } else {
        for (int i = 0; i < n; ++i) {
            int current_a_i = 0;
            for (int j = 0; j < n; ++j) {
                if (i == j) {
                    continue;
                }
                current_a_i |= b[i][j];
            }
            a[i] = current_a_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length of the segment is 1. The max value is 1.
        // So, m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the current segment [p[current_min_idx] ... p[current_max_idx]]
        // must be expanded to include 'm'.
        // The new 'm' is at pos[m].
        // We update current_min_idx and current_max_idx to cover the range [1, m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // is a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The length of the subsegment must be exactly 'm'.
        //    Length = current_max_idx - current_min_idx + 1.
        // 2. The maximum value in this subsegment must be 'm'.
        //    This is implicitly handled by how we expand current_max_idx.
        //    Since we are processing m in increasing order, and current_max_idx
        //    is the maximum index seen so far for values 1 to m, the maximum value
        //    in the segment p[current_min_idx ... current_max_idx] will be 'm'.
        //    (Because all values 1 to m are within this range, and no value > m
        //    could have been included if the length condition holds).

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d >= 4.0, so d^2 - 4d >= 0
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // a = (d + sqrt(d^2 - 4d)) / 2
            double a = (d + sqrt_discriminant) / 2.0;
            // b = (d - sqrt(d^2 - 4d)) / 2
            double b = (d - sqrt_discriminant) / 2.0;

            // Check if a and b are non-negative.
            // Since d >= 4, d^2 >= 4d, so d^2 - 4d >= 0.
            // sqrt(d^2 - 4d) is real.
            // d + sqrt(d^2 - 4d) is clearly non-negative. So a >= 0.
            // For b, we need d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square them:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since d is given as non-negative, b will always be non-negative.
            // The only edge case is d=0, which is handled separately.
            // For d >= 4, b will be positive.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int x = 0; x <= 9; ++x) {
        std::vector<int> colors(n);
        int last1 = -1; // Last digit colored 1
        int first2 = -1; // First digit colored 2
        bool possible_x = true;

        // First pass: assign digits < x to color 1, digits > x to color 2
        // Digits == x are temporarily unassigned (0)
        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                colors[i] = 1;
                if (d[i] < last1) { // Check non-decreasing for color 1
                    possible_x = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > x) {
                colors[i] = 2;
                if (first2 == -1) {
                    first2 = d[i];
                } else if (d[i] < first2) { // Check non-decreasing for color 2
                    possible_x = false;
                    break;
                }
                first2 = d[i];
            } else {
                colors[i] = 0; // Unassigned
            }
        }

        if (!possible_x) {
            continue;
        }

        // Second pass: assign digits == x
        // Try to assign as many as possible to color 1, then switch to color 2
        int current_last1_x = last1;
        int current_first2_x = -1;
        bool switched_x_to_2 = false;

        for (int i = 0; i < n; ++i) {
            if (d[i] == x) {
                if (!switched_x_to_2) {
                    // Try to assign to color 1
                    if (x >= current_last1_x) {
                        colors[i] = 1;
                        current_last1_x = x;
                    } else {
                        // Cannot assign to color 1, must switch to color 2
                        switched_x_to_2 = true;
                        colors[i] = 2;
                        if (current_first2_x == -1) {
                            current_first2_x = x;
                        } else if (x < current_first2_x) {
                            possible_x = false;
                            break;
                        }
                        current_first2_x = x;
                    }
                } else {
                    // Already switched to color 2
                    colors[i] = 2;
                    if (current_first2_x == -1) {
                        current_first2_x = x;
                    } else if (x < current_first2_x) {
                        possible_x = false;
                        break;
                    }
                    current_first2_x = x;
                }
            }
        }

        if (!possible_x) {
            continue;
        }

        // Final check: last digit of color 1 <= first digit of color 2
        int final_last1 = -1;
        int final_first2 = -1;
        for (int i = 0; i < n; ++i) {
            if (colors[i] == 1) {
                final_last1 = d[i];
            }
        }
        for (int i = 0; i < n; ++i) {
            if (colors[i] == 2) {
                final_first2 = d[i];
                break;
            }
        }

        if (final_last1 != -1 && final_first2 != -1 && final_last1 > final_first2) {
            possible_x = false;
        }

        if (possible_x) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

