#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can always assume n is the larger coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: k < n (or k < m, since n >= m).
        // It's impossible to reach (n, m) in k moves if k is less than the maximum coordinate.
        // This is because each move changes at most one coordinate by 1 (for axial moves)
        // or both by 1 (for diagonal moves). To reach (n, m) from (0,0),
        // at least n moves are required to cover the x-distance, and at least m moves
        // to cover the y-distance. So, at least max(n, m) moves are needed.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= n.
        // We can always reach (n, m) in k moves if k >= n and k has the same parity as n and m.
        // If k has different parity, we need to check further.

        // The maximum number of diagonal moves is limited by the smaller coordinate, m.
        // We can make m diagonal moves to reach (m, m) or (m, -m) etc.
        // Let's assume we make m diagonal moves to reach (m, m).
        // Remaining distance in x: n - m.
        // Remaining moves: k - m.
        // We need to cover n - m distance in x using k - m moves.
        // These k - m moves must be axial moves along x-axis or pairs of moves that cancel out.
        // The number of moves to cover n-m distance is exactly n-m.
        // So, we use m diagonal moves and n-m axial moves. Total moves: m + (n-m) = n.
        // This gets us to (n, m) in n moves.
        // We have k - n moves remaining.
        // These k - n moves must be used to "waste" moves without changing the final position.
        // Each such "wasted" move must be paired with another move that cancels its effect.
        // For example, (x,y) -> (x+1,y) -> (x,y) uses 2 moves and changes nothing.
        // Or (x,y) -> (x+1,y+1) -> (x,y) uses 2 moves and changes nothing.
        // In both cases, 2 moves are used to return to the same parity.
        // So, k - n must be an even number.
        // If k - n is odd, it's impossible to reach (n, m) in exactly k moves.
        // This is because each move changes the parity of x or y or both.
        // The parity of (x+y) changes with each move:
        // Diagonal: (x,y) -> (x+1, y+1) or (x+1, y-1) etc.
        // (x+1)+(y+1) = (x+y)+2. Parity of (x+y) remains same.
        // Axial: (x,y) -> (x+1, y) or (x, y+1) etc.
        // (x+1)+y = (x+y)+1. Parity of (x+y) flips.
        // So, the parity of (current_x + current_y) flips with each axial move, and stays same with each diagonal move.
        // Starting at (0,0), (0+0) is even.
        // After k moves, we are at (n,m).
        // If we make D diagonal moves and A axial moves, k = D + A.
        // The parity of (n+m) must be the same as the parity of (0+0) if A is even.
        // The parity of (n+m) must be different from the parity of (0+0) if A is odd.
        // In other words, (n+m) % 2 == A % 2.
        // Since k = D + A, A = k - D.
        // So, (n+m) % 2 == (k - D) % 2.
        // We want to maximize D.
        // The maximum possible D is m.
        // If we use m diagonal moves, we reach (m,m).
        // We need to reach (n,m). We need to cover n-m more distance in x.
        // This requires n-m axial moves.
        // Total moves so far: m (diagonal) + (n-m) (axial) = n moves.
        // We are at (n,m). We have k-n moves left.
        // These k-n moves must be "wasted" moves.
        // Each wasted move must be paired with another move to return to the same position.
        // E.g., (x,y) -> (x+1,y) -> (x,y). This uses 2 axial moves.
        // E.g., (x,y) -> (x+1,y+1) -> (x,y). This uses 2 diagonal moves.
        // In both cases, 2 moves are used.
        // So, k-n must be an even number. If k-n is odd, it's impossible.
        // This is equivalent to checking if k and n have the same parity.
        // If (k % 2) != (n % 2), then it's impossible.
        // Because if k and n have different parities, then k-n is odd.
        // And if k-n is odd, we cannot make up the remaining moves without changing the parity of the final coordinates.
        // More formally, consider the parity of x+y.
        // A diagonal move (dx, dy where |dx|=|dy|=1) changes x to x+dx, y to y+dy.
        // (x+dx) + (y+dy) = (x+y) + (dx+dy). Since dx, dy are $\pm 1$, dx+dy is $\pm 2$ or $0$.
        // So, (x+dx)+(y+dy) has the same parity as (x+y).
        // An axial move (dx, dy where one is 0 and other is $\pm 1$) changes x to x+dx, y to y+dy.
        // (x+dx) + (y+dy) = (x+y) + (dx+dy). Since one is 0 and other is $\pm 1$, dx+dy is $\pm 1$.
        // So, (x+dx)+(y+dy) has different parity from (x+y).
        // Starting at (0,0), x+y=0 (even).
        // After k moves, we are at (n,m).
        // Let $D$ be diagonal moves, $A$ be axial moves. $k = D+A$.
        // The parity of (n+m) must be the same as the parity of (0+0) if $A$ is even.
        // The parity of (n+m) must be different from the parity of (0+0) if $A$ is odd.
        // So, $(n+m) \pmod 2 = A \pmod 2$.
        // We want to maximize $D$. This means minimizing $A$.
        // The minimum $A$ is $n-m$ (to cover the difference in coordinates after $m$ diagonal moves).
        // So, $A_{min} = n-m$.
        // Then $k = D + A$.
        // If $k \ge n$, we can achieve $m$ diagonal moves and $n-m$ axial moves to reach $(n,m)$ in $n$ moves.
        // The remaining $k-n$ moves must be "wasted".
        // Each wasted move must be paired with another move to return to the same parity.
        // So, $k-n$ must be even.
        // If $(k-n) \% 2 \ne 0$, it's impossible.
        // This is equivalent to $(k \% 2) \ne (n \% 2)$.
        if ((k % 2) != (n % 2)) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it means k >= n and (k % 2) == (n % 2).
        // This implies k-n is an even non-negative number.
        // We can make m diagonal moves to reach (m,m).
        // We can make n-m axial moves to reach (n,m).
        // Total moves so far: m + (n-m) = n.
        // We have k-n moves remaining.
        // These k-n moves can be used as pairs of moves that cancel out.
        // For example, (x,y) -> (x+1,y) -> (x,y). This uses 2 axial moves.
        // Or (x,y) -> (x+1,y+1) -> (x,y). This uses 2 diagonal moves.
        // To maximize diagonal moves, we should use the remaining k-n moves as diagonal pairs.
        // Each pair of diagonal moves (e.g., (x,y) -> (x+1,y+1) -> (x,y)) uses 2 diagonal moves.
        // So, we can add (k-n)/2 * 2 diagonal moves.
        // Total diagonal moves = m + (k-n).
        // This is because each "wasted" pair of moves can be chosen to be diagonal.
        // For example, if we are at (n,m) and have 2 moves left, we can do (n,m) -> (n+1,m+1) -> (n,m).
        // This adds 2 diagonal moves to our count.
        // So, the maximum number of diagonal moves is m (to reach (m,m)) + (k-n) (for the wasted moves).
        std::cout << m + (k - n) << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i + 1 < s.length()) {
            adj[s[i]].insert(s[i+1]);
            adj[s[i+1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;
    char start_node = '\0';

    // Find a starting node for the path (a node with degree 1 in the required adjacencies)
    // Or if all nodes have degree 2 (a cycle), pick any node.
    // Or if there's only one character in s, pick that.

    if (used_in_s.empty()) { // Should not happen based on constraints |s| >= 1
        // If s is empty, any layout is fine.
        std::cout << "YES\n";
        for (char c = 'a'; c <= 'z'; ++c) {
            std::cout << c;
        }
        std::cout << "\n";
        return;
    }

    bool found_start = false;
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_node = c;
            found_start = true;
            break;
        }
    }

    if (!found_start) { // All nodes in used_in_s have degree 2 (a cycle) or degree 0 (isolated)
        // If all nodes have degree 2, it implies a cycle.
        // A keyboard layout is a path, so it cannot contain a cycle.
        // Exception: if used_in_s has only one character, it has degree 0.
        // If used_in_s has > 1 character and all have degree 2, it's a cycle.
        if (used_in_s.size() > 1) {
            std::cout << "NO\n";
            return;
        } else { // used_in_s.size() == 1, the single character has degree 0
            start_node = *used_in_s.begin();
            found_start = true;
        }
    }

    char current_node = start_node;
    char prev_node = '\0'; // Sentinel value

    while (visited_in_layout.find(current_node) == visited_in_layout.end()) {
        layout_str += current_node;
        visited_in_layout.insert(current_node);

        char next_node = '\0';
        for (char neighbor : adj[current_node]) {
            if (neighbor != prev_node) {
                next_node = neighbor;
                break;
            }
        }

        prev_node = current_node;
        current_node = next_node;

        if (current_node == '\0') { // Reached end of path
            break;
        }
    }

    // Check if all characters from s are included in the constructed path
    for (char c : used_in_s) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            // This means there are multiple disconnected components in the required adjacencies,
            // which cannot form a single path.
            std::cout << "NO\n";
            return;
        }
    }

    // Append remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) return 0;
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;

    // Sum = n * (n + 1) / 2
    // We need to compute (n * (n + 1) / 2) % MOD
    // Since MOD is prime, we can use modular inverse for division by 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    long long product = (term1 * term2) % MOD;
    long long result = (product * inv2) % MOD;
    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_val = sum_arithmetic_series(b - 1);

    // Calculate sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a

    long long sum_k_val = sum_arithmetic_series(a);

    long long term_b_times_sum_k = (b % MOD * sum_k_val) % MOD;
    long long term_a = a % MOD;

    long long sum_kb_plus_1_val = (term_b_times_sum_k + term_a) % MOD;

    // Total sum = (sum_{r=1 to b-1} r) * (sum_{k=1 to a} (k * b + 1))
    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos_by_char(26);
    for (int i = 0; i < L; ++i) {
        pos_by_char[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_val = 0; k_val < L; ++k_val) { // Iterate over each possible actual k
        char first_char = s[k_val]; // The first character Vasya sees

        // Find all k' that could produce this first_char
        const std::vector<int>& possible_k_prime_indices = pos_by_char[first_char - 'a'];

        if (possible_k_prime_indices.size() == 1) {
            // If only one k' produces this first_char, Vasya wins immediately.
            // This k_val contributes 1.0 to its probability.
            total_win_prob += 1.0;
            continue;
        }

        // If multiple k' produce this first_char, Vasya needs to pick a second position.
        // Vasya wants to maximize his win probability for this specific first_char.
        // He will choose p such that the number of remaining ambiguous k' is minimized.

        int max_unique_count = 0; // Maximize this over choices of p

        // Iterate over all possible second positions p (from 1 to L-1)
        for (int p = 1; p < L; ++p) {
            std::map<char, int> char_counts;
            for (int k_prime : possible_k_prime_indices) {
                char_counts[s[(k_prime + p) % L]]++;
            }

            int current_unique_count = 0;
            for (auto const& [char_val, count] : char_counts) {
                if (count == 1) {
                    current_unique_count++;
                }
            }
            max_unique_count = std::max(max_unique_count, current_unique_count);
        }

        // For this k_val (which determines first_char), the probability of winning
        // is max_unique_count / possible_k_prime_indices.size()
        total_win_prob += static_cast<double>(max_unique_count) / possible_k_prime_indices.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

