#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current state for an input of 0 and an input of 1023
    // We need to track how each bit transforms.
    // For each bit position `b` (0 to 9):
    // `val_0[b]` will store the final value of bit `b` if the initial bit `b` was 0.
    // `val_1[b]` will store the final value of bit `b` if the initial bit `b` was 1.
    // Initially, if input bit is 0, it's 0. If input bit is 1, it's 1.
    std::vector<int> val_0(10); // Stores the final bit value if initial bit was 0
    std::vector<int> val_1(10); // Stores the final bit value if initial bit was 1

    for (int b = 0; b < 10; ++b) {
        val_0[b] = 0;
        val_1[b] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int b = 0; b < 10; ++b) {
            int x_bit = (x >> b) & 1; // b-th bit of constant x

            if (op_char == '&') {
                val_0[b] = val_0[b] & x_bit;
                val_1[b] = val_1[b] & x_bit;
            } else if (op_char == '|') {
                val_0[b] = val_0[b] | x_bit;
                val_1[b] = val_1[b] | x_bit;
            } else if (op_char == '^') {
                val_0[b] = val_0[b] ^ x_bit;
                val_1[b] = val_1[b] ^ x_bit;
            }
        }
    }

    // Now, we have the final transformation for each bit.
    // For each bit `b`:
    // - If `val_0[b] == 0` and `val_1[b] == 0`: The bit always becomes 0.
    // - If `val_0[b] == 1` and `val_1[b] == 1`: The bit always becomes 1.
    // - If `val_0[b] == 0` and `val_1[b] == 1`: The bit remains unchanged (x_b -> x_b).
    // - If `val_0[b] == 1` and `val_1[b] == 0`: The bit is flipped (x_b -> !x_b).

    // We want to represent this using at most 5 operations.
    // A single AND operation can set bits to 0.
    // A single OR operation can set bits to 1.
    // A single XOR operation can flip bits.

    // Let's find the constants for the equivalent operations.
    int and_const = 1023; // Initially, AND with all 1s (no change)
    int or_const = 0;     // Initially, OR with all 0s (no change)
    int xor_const = 0;    // Initially, XOR with all 0s (no change)

    for (int b = 0; b < 10; ++b) {
        if (val_0[b] == 0 && val_1[b] == 0) {
            // Bit b always becomes 0. This means we need to AND with 0 at bit b.
            and_const &= ~(1 << b);
        } else if (val_0[b] == 1 && val_1[b] == 1) {
            // Bit b always becomes 1. This means we need to OR with 1 at bit b.
            or_const |= (1 << b);
        } else if (val_0[b] == 1 && val_1[b] == 0) {
            // Bit b is flipped. This means we need to XOR with 1 at bit b.
            xor_const |= (1 << b);
        }
        // If val_0[b] == 0 and val_1[b] == 1, bit b remains unchanged.
        // This is achieved by ANDing with 1, ORing with 0, XORing with 0.
        // Our initial constants already reflect this.
    }

    // Output the operations.
    // The order of operations matters. A common canonical form is:
    // ( ( (x & C_and) | C_or ) ^ C_xor )
    // This order works because:
    // - AND can only turn 1s into 0s.
    // - OR can only turn 0s into 1s.
    // - XOR flips bits.

    // Let's verify this order.
    // Consider a bit `x_b`.
    // After `& C_and`: `x_b & (C_and)_b`.
    // After `| C_or`: `(x_b & (C_and)_b) | (C_or)_b`.
    // After `^ C_xor`: `((x_b & (C_and)_b) | (C_or)_b) ^ (C_xor)_b`.

    // Case 1: Bit `b` always becomes 0.
    // `val_0[b]=0, val_1[b]=0`.
    // This means `(C_and)_b = 0`, `(C_or)_b = 0`, `(C_xor)_b = 0`.
    // Result: `((x_b & 0) | 0) ^ 0 = (0 | 0) ^ 0 = 0`. Correct.

    // Case 2: Bit `b` always becomes 1.
    // `val_0[b]=1, val_1[b]=1`.
    // This means `(C_and)_b = 1`, `(C_or)_b = 1`, `(C_xor)_b = 0`.
    // Result: `((x_b & 1) | 1) ^ 0 = (x_b | 1) ^ 0 = 1 ^ 0 = 1`. Correct.

    // Case 3: Bit `b` remains unchanged.
    // `val_0[b]=0, val_1[b]=1`.
    // This means `(C_and)_b = 1`, `(C_or)_b = 0`, `(C_xor)_b = 0`.
    // Result: `((x_b & 1) | 0) ^ 0 = (x_b | 0) ^ 0 = x_b ^ 0 = x_b`. Correct.

    // Case 4: Bit `b` is flipped.
    // `val_0[b]=1, val_1[b]=0`.
    // This means `(C_and)_b = 1`, `(C_or)_b = 0`, `(C_xor)_b = 1`.
    // Result: `((x_b & 1) | 0) ^ 1 = (x_b | 0) ^ 1 = x_b ^ 1 = !x_b`. Correct.

    // So, the order `&`, then `|`, then `^` works.
    // We only output operations if their constant is not the identity.
    // Identity for AND is 1023. Identity for OR is 0. Identity for XOR is 0.

    std::vector<std::pair<char, int>> result_ops;
    if (and_const != 1023) {
        result_ops.push_back({'&', and_const});
    }
    if (or_const != 0) {
        result_ops.push_back({'|', or_const});
    }
    if (xor_const != 0) {
        result_ops.push_back({'^', xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Rule 1: If s_i is '0', then w_{i-x} and w_{i+x} must be '0'.
    // This is the only way to definitively set characters in w to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Rule 2: Verify if the constructed w can produce s.
    // For each s_i, check if at least one of w_{i-x} or w_{i+x} is '1'.
    // If s_i is '1' but neither w_{i-x} nor w_{i+x} is '1', then no such w exists.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool possible_one = false;
            if (i - x >= 0 && w[i - x] == '1') {
                possible_one = true;
            }
            if (i + x < n && w[i + x] == '1') {
                possible_one = true;
            }
            if (!possible_one) {
                std::cout << -1 << std::endl;
                return;
            }
        }
    }

    std::cout << w << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    // Max length for which 2^L-1 is roughly N
    // 2^18 = 262144, 2^17 = 131072.
    // If L is the length of the substring, and V is its value, we need L = V.
    // The maximum value for L bits is 2^L - 1.
    // So L <= 2^L - 1.
    // If L is large, say L=20, then V can be up to 2^20-1.
    // But the length of the string is at most N=2e5.
    // So L must be at most N.
    // If L is the value, then L must be at most N.
    // The maximum number of bits required to represent N (2e5) is log2(2e5) approx 17.6.
    // So if the value V is N, it would take about 18 bits.
    // This means if L is the value, L can be at most N.
    // The number of bits to represent L is at most 18.
    // So, if the substring has length L, and its value is L, then L must be representable by its bits.
    // The maximum length of a substring we need to consider for direct binary conversion is small.
    // Let's say max_bits_to_check = 20.
    // If a substring has length L, and its value is L, then L <= N.
    // The number of bits to represent L is at most log2(N) + 1.
    // For N = 2e5, log2(2e5) approx 17.6. So at most 18 bits.
    // Let's use a slightly larger constant, say 20.
    const int MAX_BITS_TO_CHECK = 20; // log2(2e5) + some margin

    for (int i = 0; i < n; ++i) {
        // Case 1: Substrings starting with '1'
        // These substrings have a non-zero value.
        if (s[i] == '1') {
            long long current_val = 0;
            for (int j = 0; j < MAX_BITS_TO_CHECK && i + j < n; ++j) {
                current_val = (current_val << 1) | (s[i + j] - '0');
                // The length of the current substring s[i...i+j] is j+1.
                // We need length = value.
                // So, j+1 = current_val.
                if (current_val == (j + 1)) {
                    count++;
                }
            }
        }

        // Case 2: Substrings starting with '0'
        // These substrings have value 0 if they consist only of '0's.
        // If they contain a '1', their value is determined by the '1's.
        // The condition is length = value.
        // If value is 0, then length must be 0, which is impossible for a non-empty substring.
        // So, a good substring cannot consist only of '0's.
        // This means any good substring starting with '0' must contain at least one '1'.
        // Let's find the first '1' after s[i].
        // If s[i] is '0', we need to find the first '1' at index k > i.
        // The substring s[i...r] has length r-i+1.
        // Its value is f(s[k...r]) where k is the first '1'.
        // So we need r-i+1 = f(s[k...r]).
        // This means r-i+1 >= 1.
        // The maximum value of f(s[k...r]) is 2^(r-k+1)-1.
        // So r-i+1 <= 2^(r-k+1)-1.
        // Also, r-k+1 <= MAX_BITS_TO_CHECK.
        // This implies r-i+1 <= 2^MAX_BITS_TO_CHECK - 1.
        // And r-i+1 <= N.

        // We can iterate through all possible starting positions `i`.
        // For each `i`, we iterate through possible ending positions `j`.
        // If `s[i]` is '1', we calculate the value directly.
        // If `s[i]` is '0', we need to find the first '1' to calculate the value.
        // This approach is O(N * MAX_BITS_TO_CHECK).
        // N * MAX_BITS_TO_CHECK = 2e5 * 20 = 4e6, which is acceptable.

        // Let's refine the loop for '0's.
        // We can process '0's efficiently by finding the next '1'.
        // For each starting position `i`:
        //   If `s[i] == '1'`:
        //     Iterate `j` from `i` up to `min(n-1, i + MAX_BITS_TO_CHECK - 1)`.
        //     Calculate `val = f(s[i...j])`.
        //     If `val == j-i+1`, increment count.
        //   If `s[i] == '0'`:
        //     Find the first `k >= i` such that `s[k] == '1'`.
        //     If no such `k` exists, break (no more good substrings starting with '0' from this `i`).
        //     For each `j` from `k` up to `min(n-1, k + MAX_BITS_TO_CHECK - 1)`:
        //       Calculate `val = f(s[k...j])`.
        //       If `val == j-i+1`, increment count.
        // This is still O(N * MAX_BITS_TO_CHECK) but handles '0's more explicitly.

        // Let's re-evaluate the loop structure.
        // We can iterate `i` from `0` to `n-1`.
        // For each `i`, we iterate `j` from `i` to `min(n-1, i + MAX_BITS_TO_CHECK - 1)`.
        // This covers all substrings of length up to MAX_BITS_TO_CHECK.
        // `current_val` will store `f(s[k...j])` where `k` is the index of the first '1' in `s[i...j]`.
        // `first_one_idx` will store `k`.

        long long current_val = 0;
        int first_one_idx = -1; // Index of the first '1' in s[i...j]

        for (int j = i; j < n; ++j) {
            if (s[j] == '1') {
                if (first_one_idx == -1) {
                    first_one_idx = j;
                }
                // If first_one_idx is set, current_val represents f(s[first_one_idx ... j])
                current_val = (current_val << 1) | 1;
            } else { // s[j] == '0'
                if (first_one_idx != -1) {
                    // If we've seen a '1' before, append '0' to the binary value
                    current_val = (current_val << 1);
                }
            }

            // If current_val exceeds N, or if the number of bits used to form current_val
            // (i.e., j - first_one_idx + 1) exceeds MAX_BITS_TO_CHECK, we can stop for this `i`.
            // The value `current_val` can grow up to 2^MAX_BITS_TO_CHECK - 1.
            // If `current_val` is already greater than `n`, then `j-i+1` (length) can't be equal to `current_val`.
            // Because `j-i+1 <= n`.
            if (first_one_idx != -1) { // Only consider substrings with at least one '1'
                // The length of the substring s[i...j] is (j - i + 1).
                // The value is current_val.
                // We need (j - i + 1) == current_val.

                // Optimization: If current_val is already too large to be a valid length, break.
                // A valid length must be <= n.
                if (current_val > n) {
                    break; // For this `i`, any further `j` will only increase `current_val`, so no more matches.
                }

                // Optimization: If the number of bits used to form current_val is too large, break.
                // The number of bits is (j - first_one_idx + 1).
                // If this exceeds MAX_BITS_TO_CHECK, then current_val might be too large,
                // or the length (j-i+1) might be too large for current_val to be equal to it.
                // Specifically, if (j - first_one_idx + 1) > MAX_BITS_TO_CHECK,
                // then current_val is at least 2^MAX_BITS_TO_CHECK.
                // If 2^MAX_BITS_TO_CHECK > N, then current_val > N.
                // Since length (j-i+1) <= N, current_val cannot equal length.
                if ((j - first_one_idx + 1) > MAX_BITS_TO_CHECK) {
                    break; // For this `i`, any further `j` will only increase `current_val` and bit count.
                }

                if (current_val == (j - i + 1)) {
                    count++;
                }
            } else { // first_one_idx == -1, meaning s[i...j] consists only of '0's
                // A substring of all '0's has value 0.
                // Its length (j-i+1) is always >= 1.
                // So length != value. No good substrings here.
                // We can continue, as a '1' might appear later.
            }
        }
    }

    std::cout << count << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // and suffix sums for the right half (jars n+1 to 2n).
    // For balance, 1 -> +1, 2 -> -1.

    // Left half: jars 1 to n
    // prefix_balance_left[k] = balance of jars 1 to k
    // We are interested in balance of jars 1 to n, 1 to n-1, ..., 1 to 0 (empty)
    // Or, more precisely, balance of jars from index 0 to k-1 (0-indexed)
    // Let's use 0-indexed arrays for convenience. Jars are 0 to 2n-1.
    // Karlsson is between n-1 and n.
    // Left jars: 0 to n-1. Right jars: n to 2n-1.

    // Balances for eating from the left side (jars 0 to k-1)
    // We are interested in the balance of the *remaining* jars on the left side.
    // If we eat k_L jars from the left, jars 0 to k_L-1 are eaten.
    // The remaining left jars are k_L to n-1.
    // The balance of these remaining left jars is total_left_balance - balance(0, k_L-1).
    // Let's compute prefix sums for the left part (0 to n-1)
    // and suffix sums for the right part (n to 2n-1).

    // `left_balances[k]` stores the balance of jars `0` to `k-1`.
    // `left_balances[0]` is 0 (no jars eaten from left).
    // `left_balances[k]` for `k > 0` is `balance(0, k-1)`.
    std::map<int, int> left_balances_map; // balance -> min_k_L (jars eaten from left)
    left_balances_map[0] = 0; // 0 jars eaten from left, balance of eaten jars is 0

    int current_balance = 0;
    for (int k_L = 1; k_L <= n; ++k_L) {
        current_balance += (a[k_L - 1] == 1 ? 1 : -1);
        if (left_balances_map.find(current_balance) == left_balances_map.end()) {
            left_balances_map[current_balance] = k_L;
        }
    }

    // Calculate the total balance of all 2n jars
    int total_balance_all_jars = 0;
    for (int x : a) {
        total_balance_all_jars += (x == 1 ? 1 : -1);
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through possible number of jars eaten from the right side (k_R)
    // k_R can range from 0 to n.
    // If k_R jars are eaten from the right, jars 2n-k_R to 2n-1 are eaten.
    // The balance of these eaten jars is `balance(2n-k_R, 2n-1)`.
    // Let's compute suffix sums for the right part (n to 2n-1)
    // `right_balances[k_R]` stores the balance of jars `2n-k_R` to `2n-1`.
    // `right_balances[0]` is 0 (no jars eaten from right).
    // `right_balances[k_R]` for `k_R > 0` is `balance(2n-k_R, 2n-1)`.

    current_balance = 0;
    // Case k_R = 0: no jars eaten from right.
    // We need total_balance_all_jars - balance_eaten_left = 0
    // So, balance_eaten_left = total_balance_all_jars.
    if (left_balances_map.count(total_balance_all_jars)) {
        min_jars_eaten = std::min(min_jars_eaten, left_balances_map[total_balance_all_jars]);
    }

    // Case k_R > 0:
    for (int k_R = 1; k_R <= n; ++k_R) {
        current_balance += (a[2 * n - k_R] == 1 ? 1 : -1); // Add balance of jar 2n-k_R
        // If k_L jars are eaten from left and k_R jars from right,
        // the balance of eaten jars is `balance(0, k_L-1) + balance(2n-k_R, 2n-1)`.
        // We need `total_balance_all_jars - (balance_eaten_left + balance_eaten_right) = 0`.
        // So, `balance_eaten_left = total_balance_all_jars - balance_eaten_right`.
        int target_balance_eaten_left = total_balance_all_jars - current_balance;
        if (left_balances_map.count(target_balance_eaten_left)) {
            min_jars_eaten = std::min(min_jars_eaten, left_balances_map[target_balance_eaten_left] + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise (stable)
bool apply_median_smoothing(std::vector<int>& a) {
    int n = a.size();
    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        return false;
    }

    std::vector<int> b = a;
    bool changed = false;

    for (int i = 1; i < n - 1; ++i) { // i from 1 to n-2 for 0-indexed array
        int sum = a[i - 1] + a[i] + a[i + 1];
        int new_val = (sum >= 2) ? 1 : 0;
        if (new_val != b[i]) {
            b[i] = new_val;
            changed = true;
        }
    }
    a = b;
    return changed;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Find all maximal consecutive blocks of 0s and 1s
    // Store (start_index, end_index, value)
    std::vector<std::tuple<int, int, int>> blocks;
    if (n > 0) {
        int current_val = a[0];
        int start_idx = 0;
        for (int i = 1; i < n; ++i) {
            if (a[i] != current_val) {
                blocks.emplace_back(start_idx, i - 1, current_val);
                current_val = a[i];
                start_idx = i;
            }
        }
        blocks.emplace_back(start_idx, n - 1, current_val);
    }

    int max_steps = 0;

    // Process blocks that are not at the ends
    for (size_t i = 1; i < blocks.size() - 1; ++i) {
        int prev_val = std::get<2>(blocks[i - 1]);
        int current_val = std::get<2>(blocks[i]);
        int next_val = std::get<2>(blocks[i + 1]);

        if (prev_val == next_val && prev_val != current_val) {
            int len = std::get<1>(blocks[i]) - std::get<0>(blocks[i]) + 1;
            int steps_needed = (len + 1) / 2;
            max_steps = std::max(max_steps, steps_needed);
        }
    }

    // Apply changes to the sequence based on max_steps
    std::vector<int> result_a = a;
    for (size_t i = 1; i < blocks.size() - 1; ++i) {
        int prev_val = std::get<2>(blocks[i - 1]);
        int current_val = std::get<2>(blocks[i]);
        int next_val = std::get<2>(blocks[i + 1]);

        if (prev_val == next_val && prev_val != current_val) {
            int start_idx = std::get<0>(blocks[i]);
            int end_idx = std::get<1>(blocks[i]);
            int len = end_idx - start_idx + 1;

            int fill_count = std::min(max_steps, (len + 1) / 2);

            for (int k = 0; k < fill_count; ++k) {
                if (start_idx + k <= end_idx) {
                    result_a[start_idx + k] = prev_val;
                }
                if (end_idx - k >= start_idx) {
                    result_a[end_idx - k] = prev_val;
                }
            }
        }
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

