}

#include <iostream>
#include <vector>
#include <numeric>

// Using a global array for memoization to avoid passing it around
// and to allow for larger N without stack overflow for recursion.
// Max N is 2e5.
// Each state is (x, parity). x from 1 to N, parity 0 or 1.
// So, 2 * N states.
// We need to store the result (long long) and a visited flag.
// Using a pair {result, visited_flag} or two arrays.
// Let's use two arrays: one for results, one for visited status.
// visited status: 0 = not visited, 1 = visiting (in current recursion stack), 2 = visited (result computed).
long long memo_res[200005][2];
int memo_status[200005][2]; // 0: unvisited, 1: visiting, 2: visited

int N_global;
const std::vector<long long>* A_global_ptr; // Pointer to the input array a

// Function to solve for a given starting x and parity
// x_curr: current x value (1-indexed)
// parity: 0 for step 2 (x+a[x]), 1 for step 3 (x-a[x])
long long solve(int x_curr, int parity) {
    // Check termination conditions
    if (x_curr <= 0 || x_curr > N_global) {
        return 0; // Base case: program terminates, no further y added
    }

    // Check memoization table
    if (memo_status[x_curr][parity] == 2) { // Already visited and result computed
        return memo_res[x_curr][parity];
    }
    if (memo_status[x_curr][parity] == 1) { // Currently visiting (cycle detected)
        return -1; // Indicate non-termination
    }

    // Mark as visiting
    memo_status[x_curr][parity] = 1;

    long long val_a_x = (*A_global_ptr)[x_curr]; // a[x_curr]

    long long next_y_add = val_a_x;
    int next_x;
    int next_parity;

    if (parity == 0) { // Current step is x = x + a[x], y = y + a[x]
        next_x = x_curr + val_a_x;
        next_parity = 1; // Next step will be x = x - a[x], y = y + a[x]
    } else { // Current step is x = x - a[x], y = y + a[x]
        next_x = x_curr - val_a_x;
        next_parity = 0; // Next step will be x = x + a[x], y = y + a[x]
    }

    long long res_from_next_step = solve(next_x, next_parity);

    // Mark as visited
    memo_status[x_curr][parity] = 2;

    if (res_from_next_step == -1) {
        memo_res[x_curr][parity] = -1; // Propagate non-termination
    } else {
        memo_res[x_curr][parity] = next_y_add + res_from_next_step;
    }

    return memo_res[x_curr][parity];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    N_global = n;

    // a_1 is not given, a_2 to a_n are given.
    // We need a 1-indexed array for a.
    // a[0] will be unused. a[1] will be set by the loop.
    // a[2] to a[n] will be read from input.
    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }
    A_global_ptr = &a;

    for (int i = 1; i < n; ++i) {
        // For each i, we run the program with a_1 = i.
        // Reset memoization for each run is too slow.
        // Instead, we can compute the result for each (x, parity) state once.
        // The problem asks to run the program on sequence i, a_2, ..., a_n.
        // This means a[1] is set to i for each run.
        // The initial state is x=1, y=0.
        // The first operation is: val = a[1], x = 1 + val, y = 0 + val.
        // Then the next state is (1 + val, 1) (parity 1 means next step is x-a[x]).
        // So we need to calculate val = a[1], then call solve(1 + val, 1) and add val.

        // Set a[1] for the current run
        a[1] = i;

        // Clear memoization for this specific run.
        // This is not efficient. The states (x, parity) are independent of a[1]
        // except for the initial a[1] value.
        // The problem structure implies that for each i, a[1] changes,
        // but a[2]...a[n] remain constant.
        // The states (x, parity) for x > 1 are always the same.
        // Only the initial call depends on a[1].
        // So, we can compute all (x, parity) for x > 1 once.
        // For x = 1, the value of a[1] changes.
        // The `solve` function is designed to compute the total `y` added
        // from a given state `(x_curr, parity)` onwards.
        // The initial `y` is 0.
        // The first step is: `val = a[1]`, `x = 1 + val`, `y = 0 + val`.
        // Then the program continues from `(1 + val, 1)`.
        // So the total `y` will be `val + solve(1 + val, 1)`.

        // We need to clear memoization for each i because a[1] changes.
        // However, the states (x, parity) for x > 1 are independent of a[1].
        // The states (1, 0) and (1, 1) depend on a[1].
        // So, we only need to clear memo_status[1][0] and memo_status[1][1]
        // for each iteration.
        // But if a cycle involves x=1, then clearing only (1,0) and (1,1)
