// Function to calculate the parity of a 01-string
// Parity is 1 if there's an odd number of '1's, 0 otherwise.
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate the initial parity of string a
    int parity_a = calculate_parity(a);

    // The maximum number of '1's we can ever have in string 'a'
    // is its current count of '1's plus its current length.
    // This is because each '0' can be converted to a '1' by appending '1'
    // and then removing the original '0' (if it was at the front).
    // More simply, each '0' can be replaced by a '1' if we append '1'
    // and then remove the '0' from the front.
    // The most '1's we can have is if we convert all '0's to '1's.
    // This happens if we append '1's until all '0's are gone and replaced by '1's.
    // The maximum number of '1's we can achieve in a string of length L
    // is L itself (all '1's).
    // However, the operation is "append parity(a)".
    // If parity(a) is 0, we append '0'. If parity(a) is 1, we append '1'.
    // The number of '1's can only increase if parity(a) is 1.
    // If we have `k` ones in `a`, and `parity(a)` is 1, we append '1',
    // so `a` becomes `a + '1'`, and it now has `k+1` ones.
    // If `parity(a)` is 0, we append '0', `a` becomes `a + '0'`,
    // and it still has `k` ones.
    //
    // The key insight is that we can always make the parity of `a` become 1
    // if it's currently 0, by appending '0' (which keeps parity 0) and then
    // removing characters until the parity becomes 1.
    // Or, more simply, if we have `k` ones, we can append `parity(a)`.
    // If `parity(a)` is 0, `k` is even. We append '0'. `k` remains even.
    // If `parity(a)` is 1, `k` is odd. We append '1'. `k` becomes `k+1`, which is even.
    //
    // This means that after one append operation, the number of ones can either stay the same (if parity was 0)
    // or increase by one (if parity was 1).
    // If we have `k` ones, and `parity(a)` is 0, we append '0'. `k` ones.
    // If we have `k` ones, and `parity(a)` is 1, we append '1'. `k+1` ones.
    //
    // The maximum number of '1's we can achieve in string `a` is `count_ones(a) + 1`
    // if `count_ones(a)` is odd.
    // If `count_ones(a)` is even, we append '0', and `count_ones(a)` remains even.
    // We can always make the number of ones odd by removing characters from the front
    // until the prefix has an odd number of ones.
    //
    // A simpler way to think about it:
    // The number of '1's in `a` can be `count_ones(a)`.
    // If `count_ones(a)` is odd, we can append '1', making `count_ones(a)+1` ones.
    // If `count_ones(a)` is even, we append '0', `count_ones(a)` remains even.
    //
    // So, the maximum number of '1's we can effectively "generate" in `a`
    // is `count_ones(a)` if `count_ones(a)` is even,
    // and `count_ones(a) + 1` if `count_ones(a)` is odd.
    // This is equivalent to `count_ones(a) + parity_a`.
    // Let `max_ones_a` be this value.
    int max_ones_a = calculate_parity(a) == 1 ? calculate_parity(a) + 1 : calculate_parity(a);

    // The number of '1's in string `a` can be increased by at most 1
    // if its current parity is 1 (by appending '1').
    // If its current parity is 0, appending '0' does not change the count of '1's.
    // So, the maximum number of '1's we can have in `a` (before any removals)
    // is `count_ones(a)` if `count_ones(a)` is even,
    // and `count_ones(a) + 1` if `count_ones(a)` is odd.
    // This can be simplified to `count_ones(a) + (count_ones(a) % 2)`.
    // Let's re-calculate `count_ones(a)` for clarity.
    int initial_ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            initial_ones_a++;
        }
    }

    // The maximum number of '1's we can achieve in string `a` (by appending '1' if parity is 1)
    // is `initial_ones_a` if `initial_ones_a` is even,
    // and `initial_ones_a + 1` if `initial_ones_a` is odd.
    // This is `initial_ones_a + (initial_ones_a % 2)`.
    int effective_ones_a = initial_ones_a + (initial_ones_a % 2);

    // Calculate the number of '1's in string b
    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // Condition 1: The number of '1's in 'b' must be less than or equal to
    // the maximum number of '1's we can effectively generate in 'a'.
    // If `ones_b > effective_ones_a`, it's impossible.
    if (ones_b > effective_ones_a) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must be less than or equal to
    // the maximum length 'a' can achieve.
    // The maximum length 'a' can achieve is `|a| + (effective_ones_a - initial_ones_a)`.
    // This is `|a|` if `initial_ones_a` is even, and `|a|+1` if `initial_ones_a` is odd.
    // This is `|a| + (initial_ones_a % 2)`.
    // If `|b| > |a| + (initial_ones_a % 2)`, it's impossible.
    if (b.length() > a.length() + (initial_ones_a % 2)) {
        std::cout << "NO\n";
        return 0;
    }

    // If both conditions are met, it is always possible.
    // We can always append characters until `a` is long enough and has enough '1's.
    // Then we can remove characters from the front until `a` matches `b`.
    // The crucial part is that we can always achieve any length `L'` >= `|b|`
    // and any number of ones `O'` >= `ones_b` (up to `effective_ones_a`)
    // as long as `L'` >= `O'`.
    // We can always make `a` longer by appending its parity.
    // We can always make `a` shorter by removing its first character.
    // We can always adjust the number of ones up to `effective_ones_a`.
    // Since we can always make `a` longer than `b` and then shorten it,
    // and we can always ensure `a` has at least `ones_b` ones,
    // the only remaining constraint is that `b` itself must be constructible.
    // The operations allow us to effectively create a string of arbitrary length
    // (greater than or equal to `|a|`) and then take any suffix of it.
    // The number of ones constraint is the only non-trivial one.
    // If `ones_b <= effective_ones_a`, we can always achieve `ones_b` ones.
    // For example, if `initial_ones_a` is odd, we append '1'. Now `a` has `initial_ones_a + 1` ones.
    // If `initial_ones_a` is even, we append '0'. Now `a` has `initial_ones_a` ones.
    // In both cases, the number of ones is even.
    // We can then append '0's as many times as needed to increase length without changing ones count.
    // Or we can remove characters from the front.
    // The key is that we can always reach a state where `a` has `effective_ones_a` ones
    // and length `|a| + (initial_ones_a % 2)`.
    // From this state, we can append '0's to increase length without changing ones count.
    // We can also remove characters from the front.
    // The problem simplifies to: can we get enough '1's in `a`?
    // And is `b` not longer than the maximum possible `a`?
    // The maximum length of `a` is not bounded, but the number of '1's is.
    // The length of `b` must be less than or equal to the length of `a` after some operations.
    // The minimum length `a` can have is 1 (if we remove all but one char).
    // The maximum length `a` can have is infinite.
    // So, `|b|` is always achievable as a length.
    // The only constraint is the number of ones.
    // If `ones_b <= effective_ones_a`, then it's YES.
    std::cout << "YES\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool removed;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].removed = false;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (children[i].removed) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].removed = true;

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_removed = 0;

        for (int j = i + 1; j < n; ++j) {
            if (children[j].removed) {
                continue;
            }

            // Apply d_cry from previously removed children
            children[j].p -= total_d_cry_from_removed;

            // Apply v_cry from the child currently being cured
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            if (children[j].p < 0) {
                children[j].removed = true;
                total_d_cry_from_removed += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    std::vector<int> p(n);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);

    // Case 2: One element in one subsequence, rest in another.
    // To minimize goodness, we want to minimize max_f and maximize min_f.
    // The values of f will be:
    //   - a_i + a_j (if both in S1 or both in S2)
    //   - a_i + a_j + h (if one in S1, one in S2)
    //
    // Consider putting a_0 in S1 and all other elements in S2.
    // min_f:
    //   - a_0 + a_1 + h (a_0 in S1, a_1 in S2)
    //   - a_1 + a_2 (a_1, a_2 in S2)
    //   So, min_f = std::min(a_0 + a_1 + h, a_1 + a_2)
    // max_f:
    //   - a_{n-2} + a_{n-1} (a_{n-2}, a_{n-1} in S2)
    //   - a_0 + a_{n-1} + h (a_0 in S1, a_{n-1} in S2)
    //   So, max_f = std::max(a_0 + a_{n-1} + h, a_{n-2} + a_{n-1})
    //
    // This strategy is generally good when h is large.
    // Let's try putting a_0 in S1 and all others in S2.
    // min_f_val = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    // max_f_val = std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);
    // goodness2 = max_f_val - min_f_val;

    // The minimum possible value of f is always a_0 + a_1 (if they are in the same group)
    // or a_0 + a_1 + h (if they are in different groups).
    // The maximum possible value of f is always a_{n-2} + a_{n-1} (if they are in the same group)
    // or a_{n-2} + a_{n-1} + h (if they are in different groups).
    // Or a_0 + a_{n-1} + h (if they are in different groups).

    // Let's consider the partition where a_0 is in group 1, and all other elements are in group 2.
    // The values of f are:
    // 1. a_0 + a_j + h for j = 1, ..., n-1
    // 2. a_i + a_j for i, j = 1, ..., n-1, i != j
    //
    // Minimum f value:
    //   - a_0 + a_1 + h (from type 1)
    //   - a_1 + a_2 (from type 2, if n >= 3)
    //   So, min_f = (n == 2) ? (a[0].value + a[1].value + h) : std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    // Maximum f value:
    //   - a_0 + a_{n-1} + h (from type 1)
    //   - a_{n-2} + a_{n-1} (from type 2, if n >= 3)
    //   So, max_f = (n == 2) ? (a[0].value + a[1].value + h) : std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);
    //
    // This is the "one element separated" strategy.
    // Let's call this strategy "split_min".
    long long min_f_split_min;
    long long max_f_split_min;
    if (n == 2) {
        min_f_split_min = a[0].value + a[1].value + h;
        max_f_split_min = a[0].value + a[1].value + h;
    } else {
        min_f_split_min = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
        max_f_split_min = std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);
    }
    long long goodness_split_min = max_f_split_min - min_f_split_min;

    // Compare goodness1 and goodness_split_min
    if (goodness1 <= goodness_split_min) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            p[a[i].original_index] = 1;
        }
    } else {
        std::cout << goodness_split_min << "\n";
        p[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            p[a[i].original_index] = 2;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

