int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] stores the maximum length of a suffix of s[0...i] that does NOT contain a 3-AP.
    // This is equivalent to the minimum l such that s[l...i] contains a 3-AP.
    // If s[l...i] contains a 3-AP, then s[l...i] is "good".
    // If s[l...i] does not contain a 3-AP, then s[l...i] is "bad".
    // We want to find the smallest l such that s[l...i] is good.
    // Let's define dp[i] as the smallest starting index `l` such that the substring `s[l...i]` contains a 3-AP.
    // If no such `l` exists, dp[i] = 0 (meaning s[0...i] is bad).
    // The problem asks for pairs (l, r) such that s[l...r] is good.
    // For a fixed `r`, if `dp[r]` is the smallest `l_min` such that `s[l_min...r]` is good,
    // then any `l` such that `1 <= l <= l_min` will make `s[l...r]` good.
    // The number of such `l` values is `l_min`.
    // So, for each `r`, we add `dp[r]` to the total count of good pairs.

    // Let's redefine dp[i] as the smallest starting index `l` (0-indexed) such that `s[l...i]` contains a 3-AP.
    // If no such `l` exists, we can set `dp[i] = -1` or `dp[i] = 0` (meaning `s[0...i]` is bad).
    // The problem uses 1-based indexing for l, r.
    // If `s[l...r]` (0-indexed) is good, then `l+1` is the 1-based start index.
    // For a fixed `r` (0-indexed), if `dp[r]` is the smallest `l_min` (0-indexed) such that `s[l_min...r]` is good,
    // then any `l` (0-indexed) such that `0 <= l <= l_min` will make `s[l...r]` good.
    // The number of such `l` values is `l_min + 1`.
    // So, for each `r`, we add `l_min + 1` to the total count of good pairs.

    // Let's use `min_good_l[i]` to store the smallest 0-indexed `l` such that `s[l...i]` contains a 3-AP.
    // If `s[0...i]` does not contain a 3-AP, `min_good_l[i]` will be `i+1` (effectively meaning no such `l` exists in `0...i`).
    std::vector<int> min_good_l(n);

    for (int i = 0; i < n; ++i) {
        // Initialize min_good_l[i] based on previous value.
        // If s[l...i-1] was good, then s[l...i] is also good.
        // So min_good_l[i] is at most min_good_l[i-1].
        if (i > 0) {
            min_good_l[i] = min_good_l[i-1];
        } else {
            min_good_l[i] = i + 1; // No 3-AP in an empty or single-char string.
        }

        // Check for new 3-APs ending at `i`.
        // A 3-AP is s_x = s_{x+k} = s_{x+2k}.
        // Here, x+2k = i. So x = i - 2k.
        // We need to check for k=1, k=2, k=3.
        // For k=1: s[i-2] = s[i-1] = s[i].
        if (i >= 2 && s[i] == s[i-1] && s[i-1] == s[i-2]) {
            min_good_l[i] = std::min(min_good_l[i], i - 2);
        }
        // For k=2: s[i-4] = s[i-2] = s[i].
        if (i >= 4 && s[i] == s[i-2] && s[i-2] == s[i-4]) {
            min_good_l[i] = std::min(min_good_l[i], i - 4);
        }
        // For k=3: s[i-6] = s[i-3] = s[i].
        if (i >= 6 && s[i] == s[i-3] && s[i-3] == s[i-6]) {
            min_good_l[i] = std::min(min_good_l[i], i - 6);
        }
    }

    // The number of good pairs (l, r) is the sum of (i - min_good_l[i] + 1) for each i.
    // No, this is not correct.
    // If min_good_l[i] is the smallest `l_0` (0-indexed) such that `s[l_0...i]` is good,
    // then any `l` (0-indexed) such that `0 <= l <= l_0` makes `s[l...i]` good.
    // The number of such `l` values is `l_0 + 1`.
    // This is the number of good substrings ending at `i`.
    // The problem asks for the number of pairs (l, r) such that $1 \leq l \leq r \leq n$.
    // This is equivalent to counting substrings $s[l-1 \dots r-1]$ (0-indexed) that are good.
    // For each `r` (0-indexed), the number of good `l` values (0-indexed) is `r - min_good_l[r] + 1`.
    // This is because `min_good_l[r]` is the smallest `l_0` such that `s[l_0...r]` is good.
    // Any `l` such that `l_0 <= l <= r` will make `s[l...r]` good.
    // The number of such `l` values is `r - l_0 + 1`.
    // So, for each `r`, we add `r - min_good_l[r] + 1` to the total count.

    // Let's re-evaluate.
    // `min_good_l[i]` is the smallest 0-indexed `l` such that `s[l...i]` contains a 3-AP.
    // If `s[0...i]` does not contain a 3-AP, then `min_good_l[i]` will be `i+1`.
    // For a fixed `r` (0-indexed), we want to count `l` (0-indexed) such that `0 <= l <= r` and `s[l...r]` is good.
    // If `min_good_l[r]` is `l_0`, then `s[l_0...r]` is good.
    // Any `l` such that `0 <= l <= l_0` will make `s[l...r]` good.
    // The number of such `l` values is `l_0 + 1`.
    // So, for each `r`, we add `min_good_l[r] + 1` to the total count of good pairs.

    long long ans = 0;
    for (int i = 0; i < n; ++i) {
        ans += (i + 1) - min_good_l[i];
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // The problem statement implies padding with 0s from the left for shorter numbers.
    // This means we need a fixed length representation for map keys.
    // Max length is 18 for 10^18-1.
    // We can pad to 18 characters.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern.
    // The key will be the 18-character parity pattern string.
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the query pattern to 18 characters with '0's from the left
            // (which means appending '0's to the right of the reversed pattern).
            // Example: s = "010" -> reversed "010" -> padded "01000...0" (18 chars)
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

