bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> current_p = p;
    std::vector<long long> current_h = h;

    // Remove p_j that are already covered by initial h_i within time T
    // A track p_j is covered by h_i if |h_i - p_j| <= T
    std::vector<bool> p_covered_initial(m, false);
    int h_idx = 0;
    for (int p_idx = 0; p_idx < m; ++p_idx) {
        while (h_idx < n && h[h_idx] < p[p_idx] - T) {
            h_idx++;
        }
        if (h_idx < n && h[h_idx] <= p[p_idx] + T) {
            p_covered_initial[p_idx] = true;
        }
    }

    std::vector<long long> remaining_p;
    for (int i = 0; i < m; ++i) {
        if (!p_covered_initial[i]) {
            remaining_p.push_back(p[i]);
        }
    }

    if (remaining_p.empty()) {
        return true;
    }

    // Now we need to cover remaining_p using n heads.
    // Each head h_i can cover a range [x, y] such that y - x + 1 <= 2*T + 1
    // and h_i is within [x, y].
    // The crucial observation is that if a head h_i covers a range [L, R],
    // it must be that L <= h_i + T and R >= h_i - T.
    // The time taken is max(abs(h_i - L), abs(h_i - R)).
    // If a head h_i covers a range [L, R], it must be that
    // max(h_i - L, R - h_i) <= T.
    // This means L >= h_i - T and R <= h_i + T.
    // So, a head h_i can cover any range [L, R] such that L >= h_i - T and R <= h_i + T.
    // The length of such a range is R - L + 1.
    // The total length of tracks a head can visit is 2*T + 1.
    // If a head h_i moves to position x, it takes |h_i - x| time.
    // It can then cover tracks in [x - (T - |h_i - x|), x + (T - |h_i - x|)].
    // This simplifies to: a head h_i can cover any track p_j if there exists an x
    // such that |h_i - x| <= T and |p_j - x| <= T - |h_i - x|.
    // This is equivalent to |h_i - p_j| <= 2*T. This is wrong.
    // The problem states "move the head exactly one track to the right or to the left, or leave it on the current track".
    // "A track is considered read if at least one head has visited this track."
    // This means if a head moves from h_i to x, it visits all tracks on the path [min(h_i, x), max(h_i, x)].
    // The time taken is |h_i - x|.
    // If we have T time, a head at h_i can move to any x such that |h_i - x| <= T.
    // All tracks in [min(h_i, x), max(h_i, x)] are visited.
    // To cover a target track p_j, a head h_i must move to some x such that p_j is in [min(h_i, x), max(h_i, x)]
    // AND |h_i - x| <= T.
    // This means p_j must be in [h_i - T, h_i + T].
    // This is the correct interpretation. The initial check already handles this.
    // So, the remaining_p must be covered by heads that were NOT used for initial coverage.
    // This is not how it works. All heads are available.

    // Let's re-evaluate the check function.
    // We have n heads and m target tracks.
    // We want to cover all p_j using n heads, each moving at most T.
    // This is a greedy approach.
    // Iterate through the target tracks p_j. For each p_j, find the leftmost head h_i
    // that can cover it and has not been used yet.
    // This is not quite right because a head can cover multiple tracks.
    // A head h_i can cover any track p_j such that |h_i - p_j| <= T.
    // If a head h_i is used to cover p_j, it moves to p_j.
    // Then it can cover all tracks in [p_j - (T - |h_i - p_j|), p_j + (T - |h_i - p_j|)].
    // This is the key. A head moves to a specific target track p_j, and then it can cover a range around p_j.
    // The total range covered by a head h_i moving to x is [x - (T - |h_i - x|), x + (T - |h_i - x|)].
    // This range is centered at x and has length 2*(T - |h_i - x|) + 1.
    // The maximum possible range length is 2*T + 1, achieved when x = h_i.
    // The minimum possible range length is 1, achieved when |h_i - x| = T.
    // The range is [h_i - T, h_i + T] if the head moves to h_i.
    // If a head h_i moves to x, it covers [min(h_i, x), max(h_i, x)] and all tracks in [x - (T - |h_i - x|), x + (T - |h_i - x|)].
    // This is equivalent to saying that a head h_i can cover any track p_j if there exists an x such that
    // |h_i - x| <= T and p_j is in [min(h_i, x), max(h_i, x)] OR p_j is in [x - (T - |h_i - x|), x + (T - |h_i - x|)].
    // This is complex. Let's simplify.
    // A head at h_i can reach any point x such that |h_i - x| <= T.
    // When it reaches x, it has visited all points on the path from h_i to x.
    // So, it has visited all points in [min(h_i, x), max(h_i, x)].
    // The problem states "A track is considered read if at least one head has visited this track."
    // This means if a head moves from h_i to x, all tracks in [min(h_i, x), max(h_i, x)] are read.
    // We want to cover all p_j.
    // So, for each p_j, we need to find a head h_k and a target position x_k such that
    // |h_k - x_k| <= T and p_j is in [min(h_k, x_k), max(h_k, x_k)].
    // This means p_j must be in [h_k - T, h_k + T].
    // This is the simplest interpretation and seems to be what the example implies.
    // If p_j is in [h_k - T, h_k + T], then h_k can move to p_j (taking |h_k - p_j| time <= T)
    // and thus p_j is visited.
    // Or h_k can move to some x such that p_j is between h_k and x.
    // For example, if h_k < p_j and h_k + T >= p_j, h_k can move to p_j.
    // If h_k > p_j and h_k - T <= p_j, h_k can move to p_j.
    // So, a head h_k can cover p_j if and only if |h_k - p_j| <= T.

    // Let's use this interpretation.
    // We have `n` heads and `m` target tracks `p`.
    // We need to assign each `p_j` to some `h_i` such that `|h_i - p_j| <= T`.
    // Each head `h_i` can be used to cover one or more `p_j`s.
    // If a head `h_i` covers a set of tracks `P_i = {p_{j_1}, p_{j_2}, ..., p_{j_k}}`,
    // then it must move to some `x_i` such that `|h_i - x_i| <= T` and all `p_{j_s}` are in `[min(h_i, x_i), max(h_i, x_i)]`.
    // To minimize `|h_i - x_i|`, `x_i` should be chosen as the closest point to `h_i` that covers all `p_{j_s}`.
    // This means `x_i` should be `min(p_{j_s})` or `max(p_{j_s})`.
    // Specifically, if `h_i` covers `[L, R]`, then `max(abs(h_i - L), abs(h_i - R))` must be `<= T`.
    // This is equivalent to `L >= h_i - T` and `R <= h_i + T`.
    // So, each head `h_i` can cover any contiguous range `[L, R]` of tracks such that `L >= h_i - T` and `R <= h_i + T`.
    // The length of such a range is `R - L + 1`.
    // We need to cover all `p_j` using `n` such ranges.

    // This is a standard greedy approach for interval covering.
    // We iterate through the target tracks `p_j` from left to right.
    // `p_ptr` is the index of the current leftmost uncovered track.
    // `h_ptr` is the index of the current leftmost available head.
    int p_ptr = 0;
    int h_ptr = 0;
    while (p_ptr < m) {
        if (h_ptr >= n) { // No more heads available
            return false;
        }

        // Find the leftmost head h_k that can reach p[p_ptr]
        // i.e., h[h_k] <= p[p_ptr] + T
        // We need to find a head h_k such that h[h_k] - T <= p[p_ptr] <= h[h_k] + T.
        // This means h[h_k] is in [p[p_ptr] - T, p[p_ptr] + T].
        // We want to use the head that can cover the furthest to the right.
        // This means we want to find a head h_k such that h[h_k] - T <= p[p_ptr]
        // and h[h_k] + T is maximized.
        // This is equivalent to finding h_k such that h[h_k] is in [p[p_ptr] - T, p[p_ptr] + T]
        // and h[h_k] is as large as possible.

        long long current_p_target = p[p_ptr];
        long long max_reach = -1; // The maximum rightmost track that can be covered by an available head
        int best_h_idx = -1;

        // Find the best head to cover current_p_target
        // A head h[i] can cover current_p_target if h[i] is in [current_p_target - T, current_p_target + T].
        // Among such heads, we want to pick one that can cover the furthest to the right.
        // This means we want to maximize h[i] + T.
        // So we need to find the largest h[i] such that h[i] >= current_p_target - T.
        // And this h[i] must also satisfy h[i] <= current_p_target + T.
        // This is equivalent to finding the largest h[i] in the range [current_p_target - T, current_p_target + T].

        // Find the first head h[h_ptr_start] that is >= current_p_target - T
        int h_ptr_start = h_ptr;
        while (h_ptr_start < n && h[h_ptr_start] < current_p_target - T) {
            h_ptr_start++;
        }

        // Now, from h_ptr_start to n-1, find the head that maximizes h[i] + T,
        // subject to h[i] <= current_p_target + T.
        // Since h is sorted, we just need to find the largest h[i] in the range.
        // The largest h[i] that satisfies h[i] <= current_p_target + T is the one that maximizes h[i] + T.
        // So we iterate from h_ptr_start and find the largest h[i] that is <= current_p_target + T.

        long long best_h_val = -1;
        int temp_h_idx = h_ptr_start;
        while (temp_h_idx < n && h[temp_h_idx] <= current_p_target + T) {
            best_h_val = h[temp_h_idx];
            temp_h_idx++;
        }

        if (best_h_val == -1) { // No head can cover current_p_target
            return false;
        }

        // The head at best_h_val can cover up to best_h_val + T.
        max_reach = best_h_val + T;

        // Advance p_ptr past all tracks covered by this head
        while (p_ptr < m && p[p_ptr] <= max_reach) {
            p_ptr++;
        }

        // This head is now used. Move to the next available head.
        // The heads are distinct, so we can't reuse the same head for different ranges.
        // This is the tricky part. If we use h_k to cover [L, R], it's gone.
        // The greedy strategy for interval covering is:
        // 1. Sort intervals by start point.
        // 2. Pick the interval that covers the current leftmost uncovered point and extends furthest to the right.
        // Here, the "intervals" are not fixed. Each head h_i can generate an interval [L, R]
        // such that L >= h_i - T and R <= h_i + T.
        // We need to cover all p_j.
        // For each p_j, we need to find a head h_k such that h_k can cover p_j.
        // This means h_k must be able to reach p_j, i.e., |h_k - p_j| <= T.
        // If h_k covers p_j, it can also cover other tracks in [p_j - (T - |h_k - p_j|), p_j + (T - |h_k - p_j|)].
        // This is the range of tracks visited by moving h_k to p_j.
        // This is the correct interpretation.

        // Let's restart the check function with the correct interpretation.
        // A head h_i can move to any position x such that |h_i - x| <= T.
        // All tracks in [min(h_i, x), max(h_i, x)] are visited.
        // We need to cover all p_j.
        // This means for each p_j, there must exist some h_i and some x such that
        // |h_i - x| <= T and p_j is in [min(h_i, x), max(h_i, x)].
        // This is equivalent to saying that p_j must be in the range [h_i - T, h_i + T].
        // So, each head h_i can cover any track p_j such that |h_i - p_j| <= T.
        // If h_i covers p_j, it moves to p_j.
        // The problem is that a head can cover multiple tracks by moving to one of them.
        // Example: h_i=5, T=2. p={1, 3, 6, 8}.
        // If h_i moves to 3, it covers [3,3]. Time = |5-3|=2.
        // If h_i moves to 1, it covers [1,1]. Time = |5-1|=4 > T. Not possible.
        // If h_i moves to 6, it covers [6,6]. Time = |5-6|=1.
        // If h_i moves to 8, it covers [8,8]. Time = |5-8|=3 > T. Not possible.
        // This is the interpretation used in the first attempt.
        // The example explanation: "during the first second move the 1-st head to the left and let it stay there;
        // move the second head to the left twice; move the third head to the right twice"
        // h = [2, 5, 6], p = [1, 3, 6, 8], T = 2.
        // Head 1 (at 2) moves to 1. Time = |2-1|=1 <= 2. Covers 1.
        // Head 2 (at 5) moves to 3. Time = |5-3|=2 <= 2. Covers 3.
        // Head 3 (at 6) moves to 8. Time = |6-8|=2 <= 2. Covers 8.
        // Track 6 is already covered by initial h_3.
        // All tracks [1, 3, 6, 8] are covered. This works.
        // This means each head is assigned to cover a *single* target track p_j.
        // And the cost is |h_i - p_j|.
        // This is a bipartite matching problem, but with ranges.
        // This is not a simple assignment. A head can cover a range.

        // Let's use the greedy strategy for covering points with intervals.
        // We have `n` heads. Each head `h_i` can be used to cover a range `[L, R]`
        // such that `max(abs(h_i - L), abs(h_i - R)) <= T`.
        // This means `L >= h_i - T` and `R <= h_i + T`.
        // So, each head `h_i` can cover any range `[L, R]` where `L` is at least `h_i - T`
        // and `R` is at most `h_i + T`.
        // We want to cover all `p_j`.
        // Iterate through `p_j` from left to right.
        // `p_idx` is the index of the current leftmost uncovered track.
        // `h_idx` is the index of the current leftmost available head.
        // For `p[p_idx]`, we need to find a head `h[k]` such that `h[k]` can cover `p[p_idx]`.
        // This means `h[k] - T <= p[p_idx] <= h[k] + T`.
        // Among all such available heads `h[k]`, we should pick the one that can cover the furthest to the right.
        // This means we want to maximize `h[k] + T`.
        // So, we need to find the largest `h[k]` such that `h[k] >= p[p_idx] - T` and `h[k] <= p[p_idx] + T`.
        // This is the standard greedy approach for covering points with intervals.

        // `p_idx` points to the first uncovered track.
        // `h_idx` points to the first available head.
        int current_p_idx = 0;
        int current_h_idx = 0;
        while (current_p_idx < m) {
            if (current_h_idx >= n) { // No more heads to cover remaining tracks
                return false;
            }

            long long leftmost_uncovered_p = p[current_p_idx];

            // Find the best head to cover leftmost_uncovered_p.
            // A head h[k] can cover leftmost_uncovered_p if h[k] is in [leftmost_uncovered_p - T, leftmost_uncovered_p + T].
            // Among such heads, we want the one that can reach furthest to the right.
            // This means we want to maximize h[k] + T.
            // Since h is sorted, this means we want to find the largest h[k] such that
            // h[k] >= leftmost_uncovered_p - T AND h[k] <= leftmost_uncovered_p + T.

            long long best_h_val_for_current_p = -1;
            int temp_h_search_idx = current_h_idx;
            while (temp_h_search_idx < n && h[temp_h_search_idx] <= leftmost_uncovered_p + T) {
                if (h[temp_h_search_idx] >= leftmost_uncovered_p - T) {
                    best_h_val_for_current_p = h[temp_h_search_idx];
                }
                temp_h_search_idx++;
            }

            if (best_h_val_for_current_p == -1) { // No available head can cover leftmost_uncovered_p
                return false;
            }

            // This head (at best_h_val_for_current_p) covers up to best_h_val_for_current_p + T.
            long long covered_until = best_h_val_for_current_p + T;

            // Advance current_p_idx past all tracks covered by this head.
            while (current_p_idx < m && p[current_p_idx] <= covered_until) {
                current_p_idx++;
            }

            // This head is now used. Move to the next available head.
            current_h_idx++;
        }
        return true;
}


