#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the largest x.
            // p is a divisor of p, and p is not divisible by q.
            std::cout << p << "\n";
        } else {
            // If p is divisible by q, we need to find a smaller x.
            // x must be a divisor of p, and x must not be divisible by q.
            // We want the largest such x.
            // This means we need to remove "just enough" factors of q from p
            // to make it not divisible by q, while keeping it as large as possible.

            long long max_x = 1;
            std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

            for (const auto& factor_pair : q_factors) {
                long long prime_factor = factor_pair.first;
                // int q_exponent = factor_pair.second; // Not directly used, but conceptually important

                // Calculate how many times prime_factor divides p
                long long temp_p = p;
                int p_exponent = 0;
                while (temp_p > 0 && temp_p % prime_factor == 0) {
                    temp_p /= prime_factor;
                    p_exponent++;
                }

                // Calculate how many times prime_factor divides q
                long long temp_q = q;
                int q_exponent = 0;
                while (temp_q > 0 && temp_q % prime_factor == 0) {
                    temp_q /= prime_factor;
                    q_exponent++;
                }

                // To make x not divisible by q, for this prime_factor,
                // x must have fewer than q_exponent factors of prime_factor.
                // The largest such x would have (q_exponent - 1) factors of prime_factor.
                // So, we divide p by prime_factor until it has (q_exponent - 1) factors.
                // This means dividing p by prime_factor^(p_exponent - (q_exponent - 1))
                // which simplifies to p / prime_factor^(p_exponent - q_exponent + 1)

                // The number of factors to remove is p_exponent - q_exponent + 1.
                // This is equivalent to dividing p by prime_factor^(p_exponent - q_exponent + 1).
                // Or, more simply, divide p by prime_factor until its exponent for prime_factor
                // is exactly q_exponent - 1.

                // The resulting candidate for x is p / (prime_factor ^ (p_exponent - q_exponent + 1))
                // This is equivalent to (p / prime_factor^p_exponent) * prime_factor^(q_exponent - 1)
                // Or, more simply, p / (prime_factor * prime_factor * ... * prime_factor) (p_exponent - q_exponent + 1 times)

                long long current_x_candidate = p;
                for (int i = 0; i < p_exponent - q_exponent + 1; ++i) {
                    current_x_candidate /= prime_factor;
                }
                max_x = std::max(max_x, current_x_candidate);
            }
            std::cout << max_x << "\n";
        }
    }

    return 0;
}

