bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The minimum possible value for the current element
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long lower_bound_for_current_a = prev_val;
        long long upper_bound_for_current_a = (current_a + x) % m;

        if (current_a <= lower_bound_for_current_a) {
            // Case 1: current_a is already >= prev_val.
            // We need (current_a + c_i) % m >= prev_val.
            // The smallest possible value for (current_a + c_i) % m is current_a.
            // If current_a >= prev_val, we can choose c_i = 0.
            // The largest possible value for (current_a + c_i) % m is (current_a + x) % m.
            // If (current_a + x) % m < prev_val, it means we must have wrapped around m.
            // For example, if m=10, prev_val=8, current_a=7, x=2.
            // (7+0)%10 = 7 (too small)
            // (7+1)%10 = 8 (ok)
            // (7+2)%10 = 9 (ok)
            // Here, current_a <= prev_val.
            // We need to find c_i such that (current_a + c_i) % m >= prev_val.
            // This is possible if there is some c_i in [0, x] such that current_a + c_i >= prev_val.
            // If current_a + x < prev_val, then even with max increments, we can't reach prev_val.
            // This means we must have wrapped around m.
            // The values we can achieve are [current_a, (current_a+x)%m] if no wrap, or
            // [current_a, m-1] U [0, (current_a+x)%m] if wrap.
            // If current_a + x < prev_val, it means that even after adding x, current_a is still less than prev_val.
            // This implies that (current_a + c_i) % m will always be less than prev_val,
            // unless current_a + c_i wraps around m.
            // If current_a + x < prev_val, then (current_a + c_i) % m will be in [current_a, current_a + x].
            // All these values are < prev_val. So it's impossible.
            // This condition is equivalent to:
            // If current_a + x < prev_val, then it's impossible.
            // This is true if current_a + x < prev_val.
            // If current_a + x >= prev_val, then we can choose c_i = prev_val - current_a (if prev_val >= current_a)
            // or c_i = 0 (if prev_val < current_a).
            // In this case, we can always achieve prev_val.
            // So, if current_a <= prev_val:
            // We need to check if we can make (current_a + c_i) % m >= prev_val.
            // This is possible if (current_a + x) % m >= prev_val OR (current_a + x) % m < current_a.
            // The second part (current_a + x) % m < current_a means we wrapped around m.
            // If we wrapped around m, then we can achieve any value from current_a to m-1 and from 0 to (current_a+x)%m.
            // Since prev_val <= m-1, we can always achieve prev_val.
            // So, if current_a <= prev_val, we can make it >= prev_val if:
            // 1. current_a + x >= prev_val (no wrap, or wrap but prev_val is in the first segment)
            // 2. (current_a + x) % m < current_a (wrap, so we can reach prev_val)
            // Combining these: if current_a + x < prev_val AND (current_a + x) % m >= current_a, then it's impossible.
            // This means current_a + x is in [current_a, m-1] and is less than prev_val.
            // This is equivalent to saying that the range [current_a, (current_a + x) % m] (without wrap)
            // does not contain prev_val.
            // If current_a + x < prev_val, and (current_a + x) % m is not less than current_a (i.e., no wrap),
            // then it's impossible.
            // This is the condition: current_a + x < prev_val.
            // If current_a + x < prev_val, then we cannot reach prev_val.
            // Otherwise, we can.
            if (current_a + x < prev_val) { // This means (current_a + c_i) % m will always be < prev_val
                return false;
            }
            // If current_a + x >= prev_val, we can achieve prev_val.
            // The new prev_val for the next element will be prev_val.
            // No change to prev_val.
        } else { // current_a > prev_val
            // We need (current_a + c_i) % m >= prev_val.
            // We can choose c_i = 0, then (current_a + 0) % m = current_a, which is >= prev_val.
            // So we can always satisfy the condition.
            // The question is, what is the smallest value we can set for this element?
            // It must be >= prev_val.
            // We can set it to current_a (by choosing c_i=0).
            // Or we can set it to (current_a + x) % m (by choosing c_i=x).
            // If (current_a + x) % m < current_a, it means we wrapped around m.
            // In this case, the values we can achieve are [current_a, m-1] U [0, (current_a+x)%m].
            // Since current_a > prev_val, we can choose c_i=0, and the value is current_a.
            // This is the smallest possible value >= prev_val.
            // So, prev_val for the next element remains current_a.
            // If (current_a + x) % m >= current_a, it means no wrap.
            // The values we can achieve are [current_a, (current_a + x) % m].
            // The smallest value >= prev_val is current_a.
            // So, prev_val for the next element remains current_a.
            // In both subcases where current_a > prev_val, the next prev_val is current_a.
            // However, if (current_a + x) % m < prev_val, it means that even with max increments,
            // the value wraps around and becomes smaller than prev_val.
            // Example: m=10, prev_val=2, current_a=8, x=3.
            // (8+0)%10 = 8 (ok)
            // (8+1)%10 = 9 (ok)
            // (8+2)%10 = 0 (not ok, < prev_val)
            // (8+3)%10 = 1 (not ok, < prev_val)
            // Here, current_a > prev_val.
            // We can choose c_i=0, value is 8. This is >= prev_val.
            // So, the next prev_val should be 8.
            // The logic is: if current_a > prev_val, we can always satisfy the condition by choosing c_i=0.
            // The new prev_val for the next element should be the smallest possible value for the current element
            // that is >= prev_val.
            // This value is current_a, unless current_a + x wraps around m and (current_a + x) % m is less than prev_val.
            // If (current_a + x) % m < prev_val, it means that the range of values we can achieve
            // [current_a, m-1] U [0, (current_a+x)%m]
            // has its smallest value >= prev_val as current_a.
            // But if (current_a + x) % m < current_a, and (current_a + x) % m < prev_val,
            // then we must use current_a as the value for this element.
            // So, if current_a > prev_val:
            // If (current_a + x) % m < current_a AND (current_a + x) % m < prev_val,
            // then we must use current_a as the value for this element.
            // So, prev_val for next element becomes current_a.
            // Otherwise, we can potentially use a smaller value.
            // If (current_a + x) % m >= prev_val, then we can use prev_val.
            // So, prev_val for next element becomes prev_val.
            // This is the case where current_a > prev_val.
            // We want to set the current element to `val` such that `val >= prev_val` and `val` is minimized.
            // The possible values for `(a_i + c_i) % m` are in the range `[a_i, (a_i+x)%m]` if `a_i <= (a_i+x)%m` (no wrap).
            // Or `[a_i, m-1] U [0, (a_i+x)%m]` if `a_i > (a_i+x)%m` (wrap).
            // If `a_i > prev_val`:
            //   If `(a_i + x) % m >= prev_val`:
            //     We can choose `c_i` such that `(a_i + c_i) % m = prev_val`.
            //     This is possible if `prev_val` is in the range `[a_i, (a_i+x)%m]` (no wrap)
            //     or `[a_i, m-1] U [0, (a_i+x)%m]` (wrap).
            //     Since `a_i > prev_val`, `prev_val` is not in `[a_i, m-1]`.
            //     So `prev_val` must be in `[0, (a_i+x)%m]`.
            //     This means `(a_i+x)%m >= prev_val` and `a_i > (a_i+x)%m` (wrap).
            //     If this is true, we can set the current element to `prev_val`.
            //     So, `prev_val` for next element remains `prev_val`.
            //   Else (`(a_i + x) % m < prev_val`):
            //     This means `prev_val` is not in `[0, (a_i+x)%m]`.
            //     Since `a_i > prev_val`, `prev_val` is not in `[a_i, m-1]`.
            //     So, `prev_val` is not achievable.
            //     The smallest value we can achieve that is `>= prev_val` is `a_i` (by choosing `c_i=0`).
            //     So, `prev_val` for next element becomes `a_i`.
            // This logic can be simplified:
            // If `(current_a + x) % m < current_a` (wrap around m):
            //   This means we can achieve any value in `[current_a, m-1]` and `[0, (current_a+x)%m]`.
            //   Since `current_a > prev_val`, we can always achieve `prev_val` (by choosing `c_i` such that `(current_a+c_i)%m = prev_val`).
            //   So, `prev_val` for next element remains `prev_val`.
            // Else (`(current_a + x) % m >= current_a`, no wrap):
            //   The values we can achieve are `[current_a, (current_a+x)%m]`.
            //   Since `current_a > prev_val`, we can achieve `current_a`.
            //   We want the smallest value >= `prev_val`.
            //   If `(current_a + x) % m >= prev_val`, we can achieve `prev_val`.
            //   So, `prev_val` for next element remains `prev_val`.
            //   Else (`(current_a + x) % m < prev_val`), we cannot achieve `prev_val`.
            //   The smallest value we can achieve that is `>= prev_val` is `current_a`.
            //   So, `prev_val` for next element becomes `current_a`.
            //
            // Combining these:
            // If `current_a > prev_val`:
            //   If `(current_a + x) % m < current_a` (wrap):
            //     `prev_val` for next element remains `prev_val`.
            //   Else (`(current_a + x) % m >= current_a`, no wrap):
            //     If `(current_a + x) % m >= prev_val`:
            //       `prev_val` for next element remains `prev_val`.
            //     Else (`(current_a + x) % m < prev_val`):
            //       `prev_val` for next element becomes `current_a`.
            // This can be written as:
            // If `current_a > prev_val` and `(current_a + x) % m >= current_a` and `(current_a + x) % m < prev_val`:
            //   `prev_val` for next element becomes `current_a`.
            // Else:
            //   `prev_val` for next element remains `prev_val`.
            // This is the same as:
            // If `current_a > prev_val` and `(current_a + x) % m < prev_val` and `(current_a + x) % m >= current_a`:
            //   `prev_val` = `current_a`.
            // Else:
            //   `prev_val` = `prev_val`.
            // This is the same as:
            // If `current_a > prev_val` and `(current_a + x) % m < prev_val` and `(current_a + x) % m >= current_a`:
            //   `prev_val` = `current_a`.
            // Else if `current_a > prev_val` and `(current_a + x) % m < current_a` (wrap):
            //   `prev_val` = `prev_val`.
            // Else if `current_a > prev_val` and `(current_a + x) % m >= current_a` and `(current_a + x) % m >= prev_val`:
            //   `prev_val` = `prev_val`.
            //
            // Simplified logic for `current_a > prev_val`:
            // If `(current_a + x) % m < prev_val` AND `(current_a + x) % m >= current_a` (no wrap, but max value is too small):
            //   `prev_val` = `current_a`.
            // Else:
            //   `prev_val` = `prev_val`.
            // This is the correct logic.
            if ((current_a + x) % m < prev_val && (current_a + x) % m >= current_a) {
                prev_val = current_a;
            }
        }
    }
    return true;
}

